# -----------------------------------------------------------------------------
# Clase principal: InstrumentoClasificado
# -----------------------------------------------------------------------------
class InstrumentoClasificado:
    """Representa un instrumento ya filtrado y clasificado."""
    # Ticker temporal procesado en este bloque.
    ticker: str
    # Campo de datos para tipo.
    tipo: str
    # Campo de datos para vencimiento.
    vencimiento: str | None
    # Campo de datos para strike.
    strike: float | int | None
    # Campo de datos para cficode.
    cficode: str
    # Campo de datos para security description.
    security_description: str | None
    # Campo de datos para underlying.
    underlying: str | None
    # Campo de datos para instrument.
    instrument: dict[str, Any] = field(default_factory=dict)

# -----------------------------------------------------------------------------
# Clase principal: EstadoMercado
# -----------------------------------------------------------------------------
class EstadoMercado:
    """Mantiene en memoria el estado de market data y OI para la interfaz."""
    # Inicializa la estructura interna del estado de mercado.
    def __init__(self) -> None:
        # Lock interno para proteger el acceso concurrente al estado.
        self._lock = threading.Lock()
        # Diccionario con las filas vivas del mercado indexadas por ticker.
        self._rows: dict[str, dict[str, Any]] = {}
        # Índice auxiliar para matchear instrumentos y OI entre distintas fuentes.
        self._match_index: dict[str, set[str]] = {}
        # Mensaje general de estado del mercado o de la interfaz.
        self._status_message = "Inicializando..."
        # Último mensaje de error detectado.
        self._error_message = ""
        # Marca temporal del último evento de mercado recibido.
        self._last_event_at: str | None = None
        # Mensaje informativo interno para OI.
        self._oi_info: dict[str, Any] = {
            "status": "pendiente",
            "message": "OI aún no consultado",
            "matched": 0,
            "available": 0,
            "date": None,
        }
    def inicializar(self, instrumentos: Iterable[InstrumentoClasificado]) -> None:
        """Carga el estado inicial de todos los instrumentos a monitorear."""
        with self._lock:
            self._rows = {}
            self._match_index = {}
            for inst in instrumentos:
                if not inst.ticker:
                    continue
                self._rows[inst.ticker] = {
                    "ticker": inst.ticker,
                    "tipo": inst.tipo,
                    "vencimiento": inst.vencimiento,
                    "strike": inst.strike,
                    "cficode": inst.cficode,
                    "securityDescription": inst.security_description,
                    "underlying": inst.underlying,
                    "bid": None,
                    "bid_size": None,
                    "ask": None,
                    "ask_size": None,
                    "last": None,
                    "last_size": None,
                    "updated_at": None,
                    "oi": None,
                    "oi_date": None,
                    "oi_source": None,
                }
                for clave in generar_claves_match_instrumento(inst):
                    self._match_index.setdefault(clave, set()).add(inst.ticker)
            self._status_message = f"Suscriptos {len(self._rows)} instrumentos"
            self._error_message = ""
    def actualizar_marketdata(self, ticker: str, market_data: dict[str, Any]) -> None:
        """Actualiza un instrumento con la última market data recibida."""
        bid, bid_size = extraer_price_size(market_data.get("BI"))
        ask, ask_size = extraer_price_size(market_data.get("OF"))
        last, last_size = extraer_price_size(market_data.get("LA"))
        # Variable local para timestamp.
        timestamp = ahora_texto()
        with self._lock:
            # Fila temporal procesada en este paso.
            fila = self._rows.setdefault(
                ticker,
                {
                    "ticker": ticker,
                    "tipo": "sin_clasificar",
                    "vencimiento": None,
                    "strike": None,
                    "cficode": "",
                    "securityDescription": None,
                    "underlying": None,
                    "bid": None,
                    "bid_size": None,
                    "ask": None,
                    "ask_size": None,
                    "last": None,
                    "last_size": None,
                    "updated_at": None,
                    "oi": None,
                    "oi_date": None,
                    "oi_source": None,
                },
            )
            if bid is not None:
                fila["bid"] = bid
            if bid_size is not None:
                fila["bid_size"] = bid_size
            if ask is not None:
                fila["ask"] = ask
            if ask_size is not None:
                fila["ask_size"] = ask_size
            if last is not None:
                fila["last"] = last
            if last_size is not None:
                fila["last_size"] = last_size
            fila["updated_at"] = timestamp
            self._last_event_at = timestamp
            self._status_message = f"Última actualización: {ticker}"
    def aplicar_open_interest(self, oi_map: dict[str, dict[str, Any]], info: dict[str, Any]) -> None:
        """Aplica el Open Interest diario sobre los instrumentos que pudo matchear."""
        with self._lock:
            for fila in self._rows.values():
                fila["oi"] = None
                fila["oi_date"] = None
                fila["oi_source"] = None
            # Contador temporal de elementos matcheados.
            matched = 0
            # Variable local para used tickers.
            used_tickers: set[str] = set()
            for clave, payload in oi_map.items():
                # Lista o conjunto temporal de tickers procesados en este bloque.
                tickers = self._match_index.get(clave, set())
                for ticker in tickers:
                    # Fila temporal procesada en este paso.
                    fila = self._rows.get(ticker)
                    if fila is None:
                        continue
                    fila["oi"] = payload.get("oi")
                    fila["oi_date"] = payload.get("date")
                    fila["oi_source"] = payload.get("source") or "postrade"
                    matched += 1
                    used_tickers.add(ticker)
            self._oi_info = {
                "status": info.get("status", "ok"),
                "message": info.get("message", "OI cargado"),
                "matched": matched,
                "available": len(oi_map),
                "date": info.get("date"),
                "base_url": info.get("base_url"),
                "credential_mode": info.get("credential_mode"),
                "matched_unique": len(used_tickers),
            }
    def set_status(self, message: str) -> None:
        """Actualiza el mensaje de estado general."""
        # Variable local para nuevo.
        nuevo = str(message).strip()
        with self._lock:
            # Variable local para previo.
            previo = self._status_message
            self._status_message = nuevo
        if nuevo and nuevo != previo:
            LOGGER.info("Estado mercado: %s", nuevo)
    def set_error(self, message: str) -> None:
        """Guarda un mensaje de error para mostrarlo en la interfaz."""
        # Variable local para nuevo.
        nuevo = str(message).strip()
        with self._lock:
            self._error_message = nuevo
            self._status_message = "Se detectó un error en la conexión"
        if nuevo:
            LOGGER.error("Error mercado: %s", nuevo)

    def clear_error(self) -> None:
        """Limpia el último error de conexión sin tocar el resto del estado."""
        with self._lock:
            self._error_message = ""
    def set_oi_status(self, status: str, message: str, **extra: Any) -> None:
        """Guarda metadatos del proceso de OI aunque falle la consulta."""
        LOGGER.info("Estado OI: %s | %s", status, message)
        with self._lock:
            self._oi_info = {
                "status": status,
                "message": message,
                "matched": int(extra.get("matched", 0) or 0),
                "available": int(extra.get("available", 0) or 0),
                "date": extra.get("date"),
                "base_url": extra.get("base_url"),
                "credential_mode": extra.get("credential_mode"),
                "matched_unique": int(extra.get("matched_unique", 0) or 0),
            }
    def snapshot_rows(self) -> list[dict[str, Any]]:
        """Devuelve una copia plana del estado actual."""
        with self._lock:
            return [dict(item) for item in self._rows.values()]
    def snapshot_info(self) -> dict[str, Any]:
        """Devuelve los metadatos del estado actual."""
        with self._lock:
            return {
                "status": self._status_message,
                "error": self._error_message,
                "last_event_at": self._last_event_at,
                "count": len(self._rows),
                "oi_info": dict(self._oi_info),
            }
# Instancia global con el estado vivo del mercado.
ESTADO = EstadoMercado()
