# -----------------------------------------------------------------------------
# Clase principal: HistorialSQLite
# -----------------------------------------------------------------------------
class HistorialSQLite:
    """Persistencia local en SQLite para snapshots por minuto y cierres diarios.

    Usa WAL + índices para acelerar lecturas del comparador y del gráfico de ratios.
    """

    # Campos de cierre histórico que se guardan y comparan en SQLite.
    CAMPOS_CIERRE = {"last", "iv", "delta", "vega", "gamma", "theta"}

    # Abre la base SQLite y prepara la persistencia histórica.
    def __init__(self, ruta: Path) -> None:
        # Ruta del archivo o recurso usado en este bloque.
        self.ruta = ruta
        self.ruta.parent.mkdir(parents=True, exist_ok=True)
        self._lock = threading.Lock()
        # Caché liviano para consultas históricas repetidas.
        self._query_cache: dict[tuple[Any, ...], Any] = {}
        self._query_cache_version: int = 0
        self._query_cache_max_entries: int = 256
        # Conexión SQLite reutilizable de la instancia.
        self._conn = sqlite3.connect(self.ruta, check_same_thread=False)
        self._conn.row_factory = sqlite3.Row
        self._inicializar()

    def _invalidate_query_cache_locked(self) -> None:
        """Invalida el caché interno de consultas históricas."""
        self._query_cache_version += 1
        self._query_cache.clear()

    def _build_query_cache_key(self, nombre: str, *componentes: Any) -> tuple[Any, ...]:
        """Construye una clave estable para el caché de lecturas SQLite."""
        return (str(nombre), self._query_cache_version, *componentes)

    def _get_query_cache_copy(self, clave: tuple[Any, ...]) -> tuple[bool, Any]:
        """Devuelve una copia profunda del valor cacheado, si existe."""
        with self._lock:
            if clave not in self._query_cache:
                return False, None
            return True, deepcopy(self._query_cache[clave])

    def _set_query_cache_copy(self, clave: tuple[Any, ...], valor: Any) -> Any:
        """Guarda una copia profunda en caché y devuelve el valor original."""
        with self._lock:
            if len(self._query_cache) >= self._query_cache_max_entries:
                try:
                    self._query_cache.pop(next(iter(self._query_cache)))
                except Exception:
                    self._query_cache.clear()
            self._query_cache[clave] = deepcopy(valor)
        return valor

    # Función auxiliar para inicializar.
    def _inicializar(self) -> None:
        with self._lock:
            self._conn.execute("PRAGMA journal_mode=WAL")
            self._conn.execute("PRAGMA synchronous=NORMAL")
            self._conn.execute("PRAGMA temp_store=MEMORY")
            self._conn.execute("PRAGMA cache_size=-20000")
            self._conn.execute(
                """
                CREATE TABLE IF NOT EXISTS snapshots_minuto (
                    timestamp TEXT NOT NULL,
                    fecha TEXT NOT NULL,
                    ticker TEXT NOT NULL,
                    tipo TEXT,
                    vencimiento TEXT,
                    strike REAL,
                    bid REAL,
                    bid_size REAL,
                    ask REAL,
                    ask_size REAL,
                    last REAL,
                    last_size REAL,
                    iv REAL,
                    delta REAL,
                    vega REAL,
                    gamma REAL,
                    theta REAL,
                    updated_at TEXT,
                    PRIMARY KEY (timestamp, ticker)
                )
                """
            )
            self._asegurar_columnas_snapshots_minuto()

            self._conn.execute(
                "CREATE INDEX IF NOT EXISTS idx_snapshots_ticker_ts ON snapshots_minuto(ticker, timestamp)"
            )
            self._conn.execute(
                "CREATE INDEX IF NOT EXISTS idx_snapshots_fecha_ts ON snapshots_minuto(fecha, timestamp)"
            )
            self._conn.execute(
                "CREATE INDEX IF NOT EXISTS idx_snapshots_fecha_ticker_ts ON snapshots_minuto(fecha, ticker, timestamp)"
            )
            self._conn.execute(
                """
                CREATE TABLE IF NOT EXISTS cierres_metricas (
                    fecha TEXT NOT NULL,
                    ticker TEXT NOT NULL,
                    last REAL,
                    iv REAL,
                    delta REAL,
                    vega REAL,
                    gamma REAL,
                    theta REAL,
                    PRIMARY KEY (fecha, ticker)
                )
                """
            )
            self._conn.execute(
                "CREATE INDEX IF NOT EXISTS idx_cierres_ticker_fecha ON cierres_metricas(ticker, fecha)"
            )
            self._conn.execute(
                """
                CREATE TABLE IF NOT EXISTS archivos_cierre_importados (
                    nombre TEXT PRIMARY KEY,
                    mtime REAL NOT NULL
                )
                """
            )
            self._conn.execute(
                """
                CREATE TABLE IF NOT EXISTS parches_historicos_aplicados (
                    patch_key TEXT PRIMARY KEY,
                    created_at TEXT NOT NULL,
                    details TEXT
                )
                """
            )
            self._conn.commit()

    def _asegurar_columnas_snapshots_minuto(self) -> None:
        """Agrega columnas nuevas a snapshots_minuto cuando se reutiliza una base vieja."""
        # Variable local para columnas existentes.
        columnas_existentes = {
            str(fila["name"])
            for fila in self._conn.execute("PRAGMA table_info(snapshots_minuto)").fetchall()
        }
        # Variable local para columnas requeridas.
        columnas_requeridas = {
            "bid_size": "REAL",
            "ask_size": "REAL",
            "last_size": "REAL",
            "iv": "REAL",
            "delta": "REAL",
            "vega": "REAL",
            "gamma": "REAL",
            "theta": "REAL",
        }
        for nombre, tipo in columnas_requeridas.items():
            if nombre not in columnas_existentes:
                self._conn.execute(f"ALTER TABLE snapshots_minuto ADD COLUMN {nombre} {tipo}")

    def aliasar_historico_ticker(self, ticker_origen: str, ticker_destino: str, fecha_hasta_exclusiva: str | None = None) -> tuple[int, int]:
        """Duplica histórico de un ticker viejo a uno nuevo sin pisar datos existentes.

        Se usa para el cambio de liquidación de opciones 24hs -> CI. Copia snapshots
        y cierres anteriores a la fecha de corte para que las consultas históricas por
        ticker actual encuentren continuidad completa.
        """
        ticker_origen = str(ticker_origen or '').strip()
        ticker_destino = str(ticker_destino or '').strip()
        fecha_corte = str(fecha_hasta_exclusiva or '').strip()
        if not ticker_origen or not ticker_destino or ticker_origen == ticker_destino:
            return 0, 0
        with self._lock:
            total_antes = self._conn.total_changes
            if fecha_corte:
                self._conn.execute(
                    """
                    INSERT OR IGNORE INTO snapshots_minuto (
                        timestamp, fecha, ticker, tipo, vencimiento, strike, bid, bid_size, ask, ask_size, last, last_size, iv, delta, vega, gamma, theta, updated_at
                    )
                    SELECT timestamp, fecha, ?, tipo, vencimiento, strike, bid, bid_size, ask, ask_size, last, last_size, iv, delta, vega, gamma, theta, updated_at
                    FROM snapshots_minuto
                    WHERE ticker = ? AND fecha < ?
                    """,
                    (ticker_destino, ticker_origen, fecha_corte),
                )
                cambios_snap = self._conn.total_changes - total_antes
                total_medio = self._conn.total_changes
                self._conn.execute(
                    """
                    INSERT OR IGNORE INTO cierres_metricas (
                        fecha, ticker, last, iv, delta, vega, gamma, theta
                    )
                    SELECT fecha, ?, last, iv, delta, vega, gamma, theta
                    FROM cierres_metricas
                    WHERE ticker = ? AND fecha < ?
                    """,
                    (ticker_destino, ticker_origen, fecha_corte),
                )
                cambios_cierre = self._conn.total_changes - total_medio
            else:
                self._conn.execute(
                    """
                    INSERT OR IGNORE INTO snapshots_minuto (
                        timestamp, fecha, ticker, tipo, vencimiento, strike, bid, bid_size, ask, ask_size, last, last_size, iv, delta, vega, gamma, theta, updated_at
                    )
                    SELECT timestamp, fecha, ?, tipo, vencimiento, strike, bid, bid_size, ask, ask_size, last, last_size, iv, delta, vega, gamma, theta, updated_at
                    FROM snapshots_minuto
                    WHERE ticker = ?
                    """,
                    (ticker_destino, ticker_origen),
                )
                cambios_snap = self._conn.total_changes - total_antes
                total_medio = self._conn.total_changes
                self._conn.execute(
                    """
                    INSERT OR IGNORE INTO cierres_metricas (
                        fecha, ticker, last, iv, delta, vega, gamma, theta
                    )
                    SELECT fecha, ?, last, iv, delta, vega, gamma, theta
                    FROM cierres_metricas
                    WHERE ticker = ?
                    """,
                    (ticker_destino, ticker_origen),
                )
                cambios_cierre = self._conn.total_changes - total_medio
            if cambios_snap or cambios_cierre:
                self._conn.commit()
                self._invalidate_query_cache_locked()
            return int(cambios_snap), int(cambios_cierre)

    def patch_historico_fue_aplicado(self, patch_key: str) -> bool:
        """Indica si un parche histórico ya fue marcado como aplicado."""
        clave = str(patch_key or '').strip()
        if not clave:
            return False
        with self._lock:
            fila = self._conn.execute(
                "SELECT 1 FROM parches_historicos_aplicados WHERE patch_key = ? LIMIT 1",
                (clave,),
            ).fetchone()
        return fila is not None

    def registrar_patch_historico(self, patch_key: str, details: str = '') -> None:
        """Marca un parche histórico como aplicado para no repetirlo en futuros inicios."""
        clave = str(patch_key or '').strip()
        if not clave:
            return
        with self._lock:
            self._conn.execute(
                "INSERT OR REPLACE INTO parches_historicos_aplicados (patch_key, created_at, details) VALUES (?, ?, ?)",
                (clave, ahora_texto(), str(details or '')),
            )
            self._conn.commit()

    def ticker_tiene_historico_antes_de(self, ticker: str, fecha_hasta_exclusiva: str | None = None) -> bool:
        """Indica si un ticker ya tiene snapshots o cierres antes de una fecha dada."""
        ticker_txt = str(ticker or '').strip()
        fecha_corte = str(fecha_hasta_exclusiva or '').strip()
        if not ticker_txt:
            return False
        with self._lock:
            if fecha_corte:
                fila_snap = self._conn.execute(
                    "SELECT 1 FROM snapshots_minuto WHERE ticker = ? AND fecha < ? LIMIT 1",
                    (ticker_txt, fecha_corte),
                ).fetchone()
                if fila_snap is not None:
                    return True
                fila_cierre = self._conn.execute(
                    "SELECT 1 FROM cierres_metricas WHERE ticker = ? AND fecha < ? LIMIT 1",
                    (ticker_txt, fecha_corte),
                ).fetchone()
                return fila_cierre is not None
            fila_snap = self._conn.execute(
                "SELECT 1 FROM snapshots_minuto WHERE ticker = ? LIMIT 1",
                (ticker_txt,),
            ).fetchone()
            if fila_snap is not None:
                return True
            fila_cierre = self._conn.execute(
                "SELECT 1 FROM cierres_metricas WHERE ticker = ? LIMIT 1",
                (ticker_txt,),
            ).fetchone()
            return fila_cierre is not None

    # Cierra o libera los recursos de la instancia.
    def close(self) -> None:
        with self._lock:
            try:
                self._conn.commit()
            except Exception:
                pass
            try:
                self._conn.close()
            except Exception:
                pass

    # Función auxiliar para obtener ultimo minuto.
    def obtener_ultimo_minuto(self, fecha: str) -> str | None:
        with self._lock:
            # Variable local para row.
            row = self._conn.execute(
                "SELECT MAX(substr(timestamp, 1, 16)) AS ultimo FROM snapshots_minuto WHERE fecha = ?",
                (fecha,),
            ).fetchone()
        return str(row["ultimo"]) if row and row["ultimo"] else None

    # Función auxiliar para guardar snapshot minuto.
    def guardar_snapshot_minuto(self, timestamp: str, filas_activas: list[dict[str, Any]]) -> None:
        # Fecha temporal usada en este cálculo.
        fecha = timestamp[:10]
        # Variable local para registros.
        registros: list[tuple[Any, ...]] = []
        for fila in filas_activas:
            # Ticker temporal procesado en este bloque.
            ticker = str(fila.get("ticker") or "")
            if not ticker:
                continue
            registros.append((
                timestamp,
                fecha,
                ticker,
                fila.get("tipo"),
                fila.get("vencimiento"),
                convertir_a_numero(fila.get("strike")),
                convertir_a_numero(fila.get("bid")),
                convertir_a_numero(fila.get("bid_size")),
                convertir_a_numero(fila.get("ask")),
                convertir_a_numero(fila.get("ask_size")),
                convertir_a_numero(fila.get("last")),
                convertir_a_numero(fila.get("last_size")),
                convertir_a_numero(fila.get("iv")),
                convertir_a_numero(fila.get("delta")),
                convertir_a_numero(fila.get("vega")),
                convertir_a_numero(fila.get("gamma")),
                convertir_a_numero(fila.get("theta")),
                fila.get("updated_at"),
            ))
        if not registros:
            return
        LOGGER.debug("Guardando snapshot minuto | timestamp=%s | filas=%s", timestamp, len(registros))
        with self._lock:
            self._conn.executemany(
                """
                INSERT OR REPLACE INTO snapshots_minuto (
                    timestamp, fecha, ticker, tipo, vencimiento, strike, bid, bid_size, ask, ask_size, last, last_size, iv, delta, vega, gamma, theta, updated_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                registros,
            )
            self._conn.commit()
            self._invalidate_query_cache_locked()

    # Función auxiliar para obtener serie ratio minuto.
    def obtener_serie_ratio_minuto(self, fecha: str, ticker_a: str, ticker_b: str) -> list[tuple[datetime, float]]:
        # Consulta temporal, normalmente SQL o de búsqueda, usada en este bloque.
        consulta = """
            SELECT a.timestamp AS ts, a.last AS valor_a, b.last AS valor_b
            FROM snapshots_minuto a
            JOIN snapshots_minuto b
              ON a.fecha = b.fecha AND a.timestamp = b.timestamp
            WHERE a.fecha = ? AND a.ticker = ? AND b.ticker = ?
              AND a.last IS NOT NULL AND b.last IS NOT NULL AND b.last != 0
            ORDER BY a.timestamp
        """
        with self._lock:
            # Filas temporales recuperadas o construidas en este paso.
            filas = list(self._conn.execute(consulta, (fecha, ticker_a, ticker_b)).fetchall())
        # Serie temporal construida en este bloque.
        serie: list[tuple[datetime, float]] = []
        for fila in filas:
            try:
                # Marca temporal normalizada de la observación actual.
                ts = datetime.strptime(str(fila["ts"]), "%Y-%m-%d %H:%M:%S")
                # Ratio calculado para la observación actual.
                ratio = float(fila["valor_a"]) / float(fila["valor_b"])
            except Exception:
                continue
            serie.append((ts, ratio))
        return serie

    def obtener_fechas_snapshots(self, limite: int = 120) -> list[str]:
        """Lista las fechas disponibles en snapshots_minuto, de la más nueva a la más vieja."""
        with self._lock:
            # Filas temporales recuperadas o construidas en este paso.
            filas = list(
                self._conn.execute(
                    "SELECT DISTINCT fecha FROM snapshots_minuto ORDER BY fecha DESC LIMIT ?",
                    (int(max(limite, 1)),),
                ).fetchall()
            )
        return [str(fila["fecha"]) for fila in filas if fila and fila["fecha"]]

    def obtener_fechas_cierres(self, limite: int = 120) -> list[str]:
        """Lista las fechas disponibles en cierres_metricas, de la más nueva a la más vieja."""
        with self._lock:
            # Filas temporales recuperadas o construidas en este paso.
            filas = list(
                self._conn.execute(
                    "SELECT DISTINCT fecha FROM cierres_metricas ORDER BY fecha DESC LIMIT ?",
                    (int(max(limite, 1)),),
                ).fetchall()
            )
        return [str(fila["fecha"]) for fila in filas if fila and fila["fecha"]]


    def obtener_tickers_intradia_fecha(self, fecha: str) -> list[str]:
        """Devuelve los tickers presentes en snapshots_minuto para una fecha dada."""
        if not fecha:
            return []
        with self._lock:
            # Filas temporales recuperadas o construidas en este paso.
            filas = list(
                self._conn.execute(
                    "SELECT DISTINCT ticker FROM snapshots_minuto WHERE fecha = ? ORDER BY ticker",
                    (fecha,),
                ).fetchall()
            )
        return [str(fila["ticker"]) for fila in filas if fila and fila["ticker"]]

    def obtener_tickers_cierre_fecha(self, fecha: str | None = None) -> list[str]:
        """Devuelve los tickers con métricas de cierre guardadas, opcionalmente filtrados por fecha."""
        # Consulta temporal, normalmente SQL o de búsqueda, usada en este bloque.
        consulta = "SELECT DISTINCT ticker FROM cierres_metricas"
        # Parámetros temporales usados en esta llamada.
        params: tuple[Any, ...] = ()
        if fecha:
            consulta += " WHERE fecha = ?"
            params = (fecha,)
        consulta += " ORDER BY ticker"
        with self._lock:
            # Filas temporales recuperadas o construidas en este paso.
            filas = list(self._conn.execute(consulta, params).fetchall())
        return [str(fila["ticker"]) for fila in filas if fila and fila["ticker"]]

    def obtener_series_intradia_multiples(
        self,
        fecha: str,
        ticker_a: str,
        ticker_b: str,
        campos: Iterable[str] | None = None,
        hora_desde: str = "10:30",
        hora_hasta: str = "17:00",
    ) -> dict[str, list[tuple[datetime, float]]]:
        """Trae ratios intradía por minuto para varias métricas en una sola consulta SQL."""
        # Variable local para campos validos.
        campos_validos = [campo for campo in (campos or self.CAMPOS_CIERRE) if campo in self.CAMPOS_CIERRE]
        if not fecha or not ticker_a or not ticker_b or not campos_validos:
            return {}
        # Variable local para selects.
        selects = ", ".join([f"a.{campo} AS a_{campo}, b.{campo} AS b_{campo}" for campo in campos_validos])
        # Consulta temporal, normalmente SQL o de búsqueda, usada en este bloque.
        consulta = f"""
            SELECT a.timestamp AS ts, {selects}
            FROM snapshots_minuto a
            JOIN snapshots_minuto b
              ON a.fecha = b.fecha AND a.timestamp = b.timestamp
            WHERE a.fecha = ? AND a.ticker = ? AND b.ticker = ?
              AND substr(a.timestamp, 12, 5) >= ?
              AND substr(a.timestamp, 12, 5) <= ?
            ORDER BY a.timestamp
        """
        with self._lock:
            # Filas temporales recuperadas o construidas en este paso.
            filas = list(self._conn.execute(consulta, (fecha, ticker_a, ticker_b, hora_desde, hora_hasta)).fetchall())
        # Colección de series construidas en este bloque.
        series: dict[str, list[tuple[datetime, float]]] = {campo: [] for campo in campos_validos}
        for fila in filas:
            try:
                # Marca temporal normalizada de la observación actual.
                ts = datetime.strptime(str(fila["ts"]), "%Y-%m-%d %H:%M:%S")
            except Exception:
                continue
            for campo in campos_validos:
                try:
                    # Variable local para valor A.
                    valor_a = fila[f"a_{campo}"]
                    # Variable local para valor B.
                    valor_b = fila[f"b_{campo}"]
                    if valor_a is None or valor_b in (None, 0):
                        continue
                    series[campo].append((ts, float(valor_a) / float(valor_b)))
                except Exception:
                    continue
        return series

    def obtener_series_intradia_paquete(
        self,
        fecha: str,
        ticker_a: str,
        ticker_b: str,
        hora_desde: str = "10:30",
        hora_hasta: str = "17:00",
    ) -> dict[str, list[tuple[datetime, float]]]:
        """Trae en una sola consulta los ratios intradía y los costos compuestos ask/bid/last."""
        if not fecha or not ticker_a or not ticker_b:
            return {}
        clave_cache = self._build_query_cache_key(
            "obtener_series_intradia_paquete",
            str(fecha), str(ticker_a), str(ticker_b), str(hora_desde), str(hora_hasta),
        )
        hit, valor_cache = self._get_query_cache_copy(clave_cache)
        if hit:
            return valor_cache
        consulta = """
            SELECT
                a.timestamp AS ts,
                a.last AS a_last, b.last AS b_last,
                a.delta AS a_delta, b.delta AS b_delta,
                a.vega AS a_vega, b.vega AS b_vega,
                a.gamma AS a_gamma, b.gamma AS b_gamma,
                a.ask AS a_ask, b.ask AS b_ask,
                a.bid AS a_bid, b.bid AS b_bid
            FROM snapshots_minuto a
            JOIN snapshots_minuto b
              ON a.fecha = b.fecha AND a.timestamp = b.timestamp
            WHERE a.fecha = ? AND a.ticker = ? AND b.ticker = ?
              AND substr(a.timestamp, 12, 5) >= ?
              AND substr(a.timestamp, 12, 5) <= ?
            ORDER BY a.timestamp
        """
        with self._lock:
            filas = list(self._conn.execute(consulta, (fecha, ticker_a, ticker_b, hora_desde, hora_hasta)).fetchall())
        series: dict[str, list[tuple[datetime, float]]] = {
            "last": [],
            "delta": [],
            "vega": [],
            "gamma": [],
            "costo_compra": [],
            "costo_venta": [],
            "costo_last": [],
            "costo_buy_a_sell_b": [],
            "costo_sell_a_buy_b": [],
            "costo_last_buy_a_sell_b": [],
            "costo_last_sell_a_buy_b": [],
        }
        if not filas:
            return self._set_query_cache_copy(clave_cache, series)
        timestamps: list[datetime | None] = []
        columnas: dict[str, list[float]] = {k: [] for k in [
            "a_last", "b_last", "a_delta", "b_delta", "a_vega", "b_vega", "a_gamma", "b_gamma", "a_ask", "b_ask", "a_bid", "b_bid"
        ]}
        for fila in filas:
            try:
                timestamps.append(datetime.strptime(str(fila["ts"]), "%Y-%m-%d %H:%M:%S"))
            except Exception:
                timestamps.append(None)
            for clave in columnas:
                columnas[clave].append(float(fila[clave]) if fila[clave] is not None else math.nan)
        ts_mask = np.asarray([isinstance(ts, datetime) for ts in timestamps], dtype=bool)
        ratio_map = {
            "last": _np_safe_div(columnas["a_last"], columnas["b_last"]),
            "delta": _np_safe_div(columnas["a_delta"], columnas["b_delta"]),
            "vega": _np_safe_div(columnas["a_vega"], columnas["b_vega"]),
            "gamma": _np_safe_div(columnas["a_gamma"], columnas["b_gamma"]),
        }
        for clave, arr in ratio_map.items():
            arr = np.asarray(arr, dtype=float)
            mask = ts_mask & np.isfinite(arr)
            series[clave] = [(timestamps[idx], float(arr[idx])) for idx in np.flatnonzero(mask)]
        a_ask = np.asarray(columnas["a_ask"], dtype=float)
        b_ask = np.asarray(columnas["b_ask"], dtype=float)
        a_bid = np.asarray(columnas["a_bid"], dtype=float)
        b_bid = np.asarray(columnas["b_bid"], dtype=float)
        a_last = np.asarray(columnas["a_last"], dtype=float)
        b_last = np.asarray(columnas["b_last"], dtype=float)
        compuestas = {
            "costo_compra": a_ask + b_ask,
            "costo_venta": a_bid + b_bid,
            "costo_last": a_last + b_last,
            "costo_buy_a_sell_b": a_ask - b_bid,
            "costo_sell_a_buy_b": -a_bid + b_ask,
            "costo_last_buy_a_sell_b": a_last - b_last,
            "costo_last_sell_a_buy_b": -a_last + b_last,
        }
        for clave, arr in compuestas.items():
            arr = np.asarray(arr, dtype=float)
            mask = ts_mask & np.isfinite(arr)
            series[clave] = [(timestamps[idx], float(arr[idx])) for idx in np.flatnonzero(mask)]
        return self._set_query_cache_copy(clave_cache, series)

    def obtener_filas_intradia_par(
        self,
        fecha: str,
        ticker_a: str,
        ticker_b: str,
        hora_desde: str = "10:30",
        hora_hasta: str = "17:00",
    ) -> list[dict[str, Any]]:
        """Trae por minuto precios y puntas de dos bases para un backtest intradía simple."""
        if not fecha or not ticker_a or not ticker_b:
            return []
        clave_cache = self._build_query_cache_key(
            "obtener_filas_intradia_par",
            str(fecha), str(ticker_a), str(ticker_b), str(hora_desde), str(hora_hasta),
        )
        hit, valor_cache = self._get_query_cache_copy(clave_cache)
        if hit:
            return valor_cache
        inicio_ts = f"{fecha} {hora_desde}:00"
        fin_ts = f"{fecha} {hora_hasta}:59"
        consulta = """
            SELECT
                a.timestamp AS ts,
                a.last AS a_last,
                b.last AS b_last,
                a.bid AS a_bid,
                a.ask AS a_ask,
                b.bid AS b_bid,
                b.ask AS b_ask
            FROM snapshots_minuto a
            JOIN snapshots_minuto b
              ON a.fecha = b.fecha AND a.timestamp = b.timestamp
            WHERE a.fecha = ? AND a.ticker = ? AND b.ticker = ?
              AND a.timestamp >= ?
              AND a.timestamp <= ?
            ORDER BY a.timestamp
        """
        with self._lock:
            filas = list(self._conn.execute(consulta, (fecha, ticker_a, ticker_b, inicio_ts, fin_ts)).fetchall())
        salida: list[dict[str, Any]] = []
        for fila in filas:
            try:
                ts = datetime.strptime(str(fila["ts"]), "%Y-%m-%d %H:%M:%S")
            except Exception:
                continue
            a_last = convertir_a_numero(fila["a_last"])
            b_last = convertir_a_numero(fila["b_last"])
            ratio_last = None
            if a_last is not None and b_last not in (None, 0):
                try:
                    ratio_last = float(a_last) / float(b_last)
                except Exception:
                    ratio_last = None
            salida.append({
                "ts": ts,
                "a_last": float(a_last) if a_last is not None else None,
                "b_last": float(b_last) if b_last is not None else None,
                "a_bid": convertir_a_numero(fila["a_bid"]),
                "a_ask": convertir_a_numero(fila["a_ask"]),
                "b_bid": convertir_a_numero(fila["b_bid"]),
                "b_ask": convertir_a_numero(fila["b_ask"]),
                "ratio_last": ratio_last,
            })
        return self._set_query_cache_copy(clave_cache, salida)

