    def obtener_serie_mariposa_cierres(
        self,
        ticker_a: str,
        ticker_b: str,
        ticker_c: str,
        campo: str = "last",
    ) -> list[tuple[datetime, float]]:
        """Devuelve la serie histórica de una mariposa comprada A - 2*B + C."""
        if campo not in self.CAMPOS_CIERRE:
            return []
        # Consulta temporal, normalmente SQL o de búsqueda, usada en este bloque.
        consulta = f"""
            SELECT
                a.fecha AS fecha,
                a.{campo} AS valor_a,
                b.{campo} AS valor_b,
                c.{campo} AS valor_c
            FROM cierres_metricas a
            JOIN cierres_metricas b
              ON a.fecha = b.fecha
            JOIN cierres_metricas c
              ON a.fecha = c.fecha
            WHERE a.ticker = ? AND b.ticker = ? AND c.ticker = ?
              AND a.{campo} IS NOT NULL AND b.{campo} IS NOT NULL AND c.{campo} IS NOT NULL
            ORDER BY a.fecha
        """
        with self._lock:
            # Filas temporales recuperadas o construidas en este paso.
            filas = list(self._conn.execute(consulta, (ticker_a, ticker_b, ticker_c)).fetchall())
        # Serie temporal construida en este bloque.
        serie: list[tuple[datetime, float]] = []
        for fila in filas:
            try:
                # Marca temporal normalizada de la observación actual.
                ts = datetime.strptime(str(fila["fecha"]), "%Y-%m-%d")
                # Valor temporal usado en este cálculo.
                valor = float(fila["valor_a"]) - 2.0 * float(fila["valor_b"]) + float(fila["valor_c"])
            except Exception:
                continue
            serie.append((ts, valor))
        return serie
    def obtener_series_mariposa_puntas_diarias(
        self,
        ticker_a: str,
        ticker_b: str,
        ticker_c: str,
        tipo: str = "comprada",
    ) -> dict[str, list[tuple[datetime, float]]]:
        """Devuelve series diarias de apertura y cierre por puntas para una mariposa."""
        # Variable local para tipo norm.
        tipo_norm = "vendida" if str(tipo or "").strip().lower().startswith("vend") else "comprada"
        # Consulta temporal, normalmente SQL o de búsqueda, usada en este bloque.
        consulta = """
            WITH ultimos_a AS (
                SELECT s.fecha AS fecha, s.bid AS a_bid, s.ask AS a_ask
                FROM snapshots_minuto s
                JOIN (
                    SELECT fecha, MAX(timestamp) AS max_ts
                    FROM snapshots_minuto
                    WHERE ticker = ?
                    GROUP BY fecha
                ) ult
                  ON s.fecha = ult.fecha AND s.timestamp = ult.max_ts
                WHERE s.ticker = ?
            ),
            ultimos_b AS (
                SELECT s.fecha AS fecha, s.bid AS b_bid, s.ask AS b_ask
                FROM snapshots_minuto s
                JOIN (
                    SELECT fecha, MAX(timestamp) AS max_ts
                    FROM snapshots_minuto
                    WHERE ticker = ?
                    GROUP BY fecha
                ) ult
                  ON s.fecha = ult.fecha AND s.timestamp = ult.max_ts
                WHERE s.ticker = ?
            ),
            ultimos_c AS (
                SELECT s.fecha AS fecha, s.bid AS c_bid, s.ask AS c_ask
                FROM snapshots_minuto s
                JOIN (
                    SELECT fecha, MAX(timestamp) AS max_ts
                    FROM snapshots_minuto
                    WHERE ticker = ?
                    GROUP BY fecha
                ) ult
                  ON s.fecha = ult.fecha AND s.timestamp = ult.max_ts
                WHERE s.ticker = ?
            )
            SELECT
                ua.fecha AS fecha,
                ua.a_bid AS a_bid,
                ua.a_ask AS a_ask,
                ub.b_bid AS b_bid,
                ub.b_ask AS b_ask,
                uc.c_bid AS c_bid,
                uc.c_ask AS c_ask
            FROM ultimos_a ua
            JOIN ultimos_b ub
              ON ua.fecha = ub.fecha
            JOIN ultimos_c uc
              ON ua.fecha = uc.fecha
            ORDER BY ua.fecha
        """
        with self._lock:
            # Filas temporales recuperadas o construidas en este paso.
            filas = list(self._conn.execute(consulta, (ticker_a, ticker_a, ticker_b, ticker_b, ticker_c, ticker_c)).fetchall())
        # Colección de series construidas en este bloque.
        series: dict[str, list[tuple[datetime, float]]] = {"abrir": [], "cerrar": []}
        for fila in filas:
            try:
                # Marca temporal normalizada de la observación actual.
                ts = datetime.strptime(str(fila["fecha"]), "%Y-%m-%d")
            except Exception:
                continue
            # Variable local para A bid.
            a_bid = convertir_a_numero(fila["a_bid"])
            # Variable local para A ask.
            a_ask = convertir_a_numero(fila["a_ask"])
            # Variable local para B bid.
            b_bid = convertir_a_numero(fila["b_bid"])
            # Variable local para B ask.
            b_ask = convertir_a_numero(fila["b_ask"])
            # Variable local para C bid.
            c_bid = convertir_a_numero(fila["c_bid"])
            # Variable local para C ask.
            c_ask = convertir_a_numero(fila["c_ask"])
            try:
                if tipo_norm == "vendida":
                    if a_bid is not None and b_ask is not None and c_bid is not None:
                        series["abrir"].append((ts, -float(a_bid) + 2.0 * float(b_ask) - float(c_bid)))
                    if a_ask is not None and b_bid is not None and c_ask is not None:
                        series["cerrar"].append((ts, -float(a_ask) + 2.0 * float(b_bid) - float(c_ask)))
                else:
                    if a_ask is not None and b_bid is not None and c_ask is not None:
                        series["abrir"].append((ts, float(a_ask) - 2.0 * float(b_bid) + float(c_ask)))
                    if a_bid is not None and b_ask is not None and c_bid is not None:
                        series["cerrar"].append((ts, float(a_bid) - 2.0 * float(b_ask) + float(c_bid)))
            except Exception:
                continue
        return series

    def obtener_serie_ratio_invertido_cierres(
        self,
        ticker_a: str,
        ticker_b: str,
        coef_venta: float,
        campo: str = "last",
    ) -> list[tuple[datetime, float]]:
        """Devuelve la serie histórica de un ratio invertido A - n*B."""
        if campo not in self.CAMPOS_CIERRE:
            return []
        try:
            # Variable local para coeficiente.
            coef = float(coef_venta)
        except Exception:
            coef = 1.0
        # Consulta temporal, normalmente SQL o de búsqueda, usada en este bloque.
        consulta = f"""
            SELECT a.fecha AS fecha, a.{campo} AS valor_a, b.{campo} AS valor_b
            FROM cierres_metricas a
            JOIN cierres_metricas b
              ON a.fecha = b.fecha
            WHERE a.ticker = ? AND b.ticker = ?
              AND a.{campo} IS NOT NULL AND b.{campo} IS NOT NULL
            ORDER BY a.fecha
        """
        with self._lock:
            # Filas temporales recuperadas o construidas en este paso.
            filas = list(self._conn.execute(consulta, (ticker_a, ticker_b)).fetchall())
        # Serie temporal construida en este bloque.
        serie: list[tuple[datetime, float]] = []
        for fila in filas:
            try:
                # Marca temporal normalizada de la observación actual.
                ts = datetime.strptime(str(fila["fecha"]), "%Y-%m-%d")
                # Valor temporal usado en este cálculo.
                valor = float(fila["valor_a"]) - coef * float(fila["valor_b"])
            except Exception:
                continue
            serie.append((ts, valor))
        return serie

    def obtener_tabla_cierres_par(self, ticker_a: str, ticker_b: str, limite: int = 90) -> list[dict[str, Any]]:
        """Devuelve cierres diarios alineados para dos tickers, con métricas útiles para la tabla histórica."""
        if not ticker_a or not ticker_b:
            return []
        clave_cache = self._build_query_cache_key("obtener_tabla_cierres_par", str(ticker_a), str(ticker_b), int(max(limite, 1)))
        hit, valor_cache = self._get_query_cache_copy(clave_cache)
        if hit:
            return valor_cache
        consulta = """
            SELECT
                a.fecha AS fecha,
                a.last AS precio_a, b.last AS precio_b,
                a.delta AS delta_a, b.delta AS delta_b,
                a.vega AS vega_a, b.vega AS vega_b,
                a.theta AS theta_a, b.theta AS theta_b
            FROM cierres_metricas a
            JOIN cierres_metricas b
              ON a.fecha = b.fecha
            WHERE a.ticker = ? AND b.ticker = ?
              AND a.last IS NOT NULL AND b.last IS NOT NULL
            ORDER BY a.fecha DESC
            LIMIT ?
        """
        with self._lock:
            filas = list(self._conn.execute(consulta, (ticker_a, ticker_b, int(max(limite, 1)))).fetchall())
        salida: list[dict[str, Any]] = []
        for fila in reversed(filas):
            try:
                salida.append({
                    "fecha": str(fila["fecha"]),
                    "precio_a": float(fila["precio_a"]),
                    "precio_b": float(fila["precio_b"]),
                    "delta_a": convertir_a_numero(fila["delta_a"]),
                    "delta_b": convertir_a_numero(fila["delta_b"]),
                    "vega_a": convertir_a_numero(fila["vega_a"]),
                    "vega_b": convertir_a_numero(fila["vega_b"]),
                    "theta_a": convertir_a_numero(fila["theta_a"]),
                    "theta_b": convertir_a_numero(fila["theta_b"]),
                })
            except Exception:
                continue
        return self._set_query_cache_copy(clave_cache, salida)

