    # Inicializa la ventana principal, su estado y los caches de la interfaz.
    def __init__(
        self,
        instrumentos: list[InstrumentoClasificado],
        salida_dir: Path,
        subyacente: str,
        environment,
        usar_postrade: bool,
        hora_cierre: str = "17:05",
        offline_mode: bool = False,
    ) -> None:
        # Colección temporal de instrumentos usada en este bloque.
        self.instrumentos = self._filtrar_instrumentos_activos_configurados(list(instrumentos))
        # Índice de instrumentos por ticker para acceso rápido.
        self.instrumentos_por_ticker = {inst.ticker: inst for inst in self.instrumentos}
        # Variable interna para salida dir.
        self.salida_dir = salida_dir
        # Símbolo del subyacente monitoreado.
        self.subyacente = subyacente
        # Entorno pyRofex activo de la ejecución.
        self.environment = environment
        # Variable interna para usar postrade.
        self.usar_postrade = usar_postrade
        # Bandera que indica si la interfaz corre en modo offline.
        self.offline_mode = bool(offline_mode)
        # Ventana principal de Tkinter del monitor.
        self.root = Tk()
        # Variable local para titulo.
        titulo = f"Monitor {subyacente.upper()} en tiempo real"
        if self.offline_mode:
            titulo = f"Monitor {subyacente.upper()} offline"
        self.root.title(titulo)
        self.root.geometry("1660x930")
        self.root.protocol("WM_DELETE_WINDOW", self.al_cerrar)
        self.root.bind("<FocusIn>", self._al_recuperar_foco_ventana, add="+")
        # Variable interna para vencimientos.
        self._vencimientos_todos = sorted({inst.vencimiento for inst in self.instrumentos if inst.vencimiento})
        self._mostrar_vencimientos_historicos = BooleanVar(value=False)
        self.var_toggle_vencimientos_historicos = StringVar(value="Ver historicos")
        self._vencimientos = self._vencimientos_visibles()
        # Variable de Tkinter de texto para vencimiento.
        self.var_vencimiento = StringVar(value=self._vencimientos[0] if self._vencimientos else (self._vencimientos_todos[0] if self._vencimientos_todos else ""))
        # Variable de Tkinter de texto para tasa.
        self.var_tasa = StringVar(value="25.0")
        # Variable de Tkinter de texto para estado.
        self.var_estado = StringVar(value="Modo offline: usando datos guardados." if self.offline_mode else "Inicializando...")
        # Variable de Tkinter de texto para resumen.
        self.var_resumen = StringVar(value="")
        # Variable de Tkinter de texto para GEX.
        self.var_gex = StringVar(value="GEX: sin calcular")
        # Variable de Tkinter de texto para GEX ayuda.
        self.var_gex_ayuda = StringVar(
            value=(
                "Open Interest desactivado en esta versión. "
                "Se muestran solo bases activas con bid, ask o last."
            )
        )
        # Variable de Tkinter de texto para smile fecha.
        self.var_smile_fecha = StringVar(value="HOY (vivo)")
        # Variable de Tkinter de texto para smile vencimiento.
        self.var_smile_vencimiento = StringVar(value=self.var_vencimiento.get().strip() or (self._vencimientos[0] if self._vencimientos else ""))
        # Variable de Tkinter de texto para smile info.
        self.var_smile_info = StringVar(
            value=(
                "Smile VI día: elegí HOY (vivo) o una fecha de cierre y luego el vencimiento para ver la curva "
                "de volatilidad implícita por strike."
            )
        )
        # Variable de Tkinter de texto para smile superficie vencimiento.
        self.var_smile_superficie_vencimiento = StringVar(value=self.var_smile_vencimiento.get().strip())
        # Variable de Tkinter de texto para smile superficie info.
        self.var_smile_superficie_info = StringVar(
            value=(
                "Superficie VI cierres: elegí un vencimiento para ver una línea 3D por cada fecha de cierre "
                "histórica, más la línea viva si hay mercado abierto."
            )
        )
        # Variable de Tkinter de texto para matriz bases fuente.
        self.var_matriz_bases_fuente = StringVar(value="HOY (vivo)")
        # Estado de la matriz de bases para modes.
        self._matriz_bases_modes = ("last_last", "buy_a_sell_b", "buy_b_sell_a")
        # Variable de Tkinter de texto para matriz bases mode.
        self.var_matriz_bases_mode = StringVar(value="last_last")
        # Variable de Tkinter de texto para matriz bases mode button.
        self.var_matriz_bases_mode_button = StringVar(value="Relación: Last/Last")
        # Estado de la matriz de bases para metric modes.
        self._matriz_bases_metric_modes = ("ratio", "cost", "fill_pct")
        # Variable de Tkinter de texto para matriz bases metric.
        self.var_matriz_bases_metric = StringVar(value="ratio")
        # Variable de Tkinter de texto para matriz bases metric button.
        self.var_matriz_bases_metric_button = StringVar(value="Vista: Ratios")
        # Variable de Tkinter de texto para matriz bases info.
        self.var_matriz_bases_info = StringVar(
            value=(
                "Matriz bases: elegí HOY (vivo) o una fecha de cierre para ver relaciones entre bases activas del vencimiento. "
                "Calls usa base baja / base alta. Puts usa base alta / base baja."
            )
        )
        # Colección de slots o subpestañas para registro spread.
        self.var_ratios_vista = StringVar(value="cuadro")
        self.var_ratios_tipo = StringVar(value="Call")
        self.var_ratios_base_centro = StringVar(value="")
        self.var_ratios_salto = StringVar(value="1")
        self.var_ratios_umbral_ri_bajo = StringVar(value="0.30")
        self.var_ratios_umbral_ri_alto = StringVar(value="0.50")
        self.var_ratios_umbral_rc_bajo = StringVar(value="1.50")
        self.var_ratios_umbral_rc_alto = StringVar(value="2.50")
        self.var_ratios_info = StringVar(
            value="Ratios: elegi Call o Put, una base central y el salto entre bases para ver el mapa de relaciones."
        )
        self._registro_spread_slots = tuple(range(1, 7))
