    def _bombear_tk_arranque(self, *, forzar: bool = False) -> None:
        """Permite que Tk procese eventos durante la construcción inicial pesada."""
        if not hasattr(self, "root"):
            return
        ahora_mono = time.monotonic()
        if (not forzar) and (ahora_mono - float(getattr(self, "_startup_pump_last_mono", 0.0) or 0.0) < 0.08):
            return
        self._startup_pump_last_mono = ahora_mono
        try:
            self.root.update_idletasks()
            self.root.update()
        except Exception:
            LOGGER.debug("No se pudo bombear eventos Tk durante el arranque", exc_info=True)

    def _filtrar_instrumentos_activos_configurados(self, instrumentos: list[InstrumentoClasificado]) -> list[InstrumentoClasificado]:
        """Filtra el maestro para no mantener bases inactivas ni duplicados equivalentes.

        Oculta variantes viejas cuando existe el ticker canónico actual, tanto para
        el cambio de liquidación 24hs -> CI como para el reajuste de bases de junio
        aplicado desde 2026-05-05.
        """
        tickers_activos = {
            str(getattr(inst, 'ticker', '') or '').strip().upper(): str(getattr(inst, 'ticker', '') or '').strip()
            for inst in instrumentos
            if str(getattr(inst, 'ticker', '') or '').strip()
        }
        salida: list[InstrumentoClasificado] = []
        for inst in instrumentos:
            tipo = str(getattr(inst, "tipo", "") or "")
            venc = str(getattr(inst, "vencimiento", "") or "")
            ticker = str(getattr(inst, 'ticker', '') or '').strip()
            if not ticker:
                continue
            ticker_upper = ticker.upper()
            if tipo in {"calls", "puts"}:
                if venc and not strike_activo_permitido(venc, getattr(inst, "strike", None)):
                    continue
                canonico = self._ticker_canonico_selector_liquidacion(ticker)
                if canonico and canonico.upper() != ticker_upper and canonico.upper() in tickers_activos:
                    continue
            salida.append(inst)
        return salida

    def _ticker_canonico_selector_liquidacion(self, ticker: str) -> str:
        """Normaliza tickers de selectores para cambios equivalentes del monitor.

        Reemplaza referencias previas 24hs -> CI y bases junio viejas -> bases
        junio nuevas cuando el ticker canónico activo existe en el maestro actual.
        """
        texto = ticker_liquidacion_ci_para_ui(ticker)
        if not texto:
            return ""
        activos = {
            str(getattr(inst, 'ticker', '') or '').strip().upper(): str(getattr(inst, 'ticker', '') or '').strip()
            for inst in getattr(self, 'instrumentos', [])
            if str(getattr(inst, 'ticker', '') or '').strip()
        }
        candidatos = [texto] + ticker_aliases_monitor_equivalentes(texto)
        mejor = texto
        mejor_score = None
        codigos_nuevos = tuple(JUNIO_2026_CODE_REMAP_20260505.values())
        for candidato in candidatos:
            candidato_up = str(candidato or '').strip().upper()
            if candidato_up not in activos:
                continue
            real = activos[candidato_up]
            real_up = real.upper()
            if ticker_es_liquidacion_24hs(real_up):
                continue
            score = 4
            if real_up.endswith(' - CI'):
                score -= 1
            if any(cod in real_up for cod in codigos_nuevos):
                score -= 2
            if mejor_score is None or score < mejor_score:
                mejor = real
                mejor_score = score
        return mejor

    def _normalizar_opciones_selector_liquidacion(self, opciones: list[str]) -> list[str]:
        """Reemplaza opciones 24hs por CI y elimina duplicados preservando orden."""
        salida: list[str] = []
        vistos: set[str] = set()
        for opcion in opciones or []:
            canonico = self._ticker_canonico_selector_liquidacion(opcion)
            if not canonico:
                continue
            canonico = ticker_liquidacion_ci_para_ui(canonico)
            if ticker_es_liquidacion_24hs(canonico):
                continue
            clave = canonico.upper()
            if clave in vistos:
                continue
            vistos.add(clave)
            salida.append(canonico)
        return salida

    def _programar_refresco_ui(self, delay_ms: int = 1200, forzar: bool = False, reemplazar: bool = True) -> None:
        """Programa un único refresco futuro de UI evitando acumulación de callbacks."""
        if not hasattr(self, "root"):
            return
        # Variable local para actual.
        actual = getattr(self, "_ui_refresh_after_id", None)
        if actual is not None and reemplazar:
            try:
                self.root.after_cancel(actual)
            except Exception:
                LOGGER.debug("No se pudo cancelar un refresco UI programado", exc_info=True)
            finally:
                self._ui_refresh_after_id = None
        if getattr(self, "_ui_refresh_after_id", None) is not None:
            return
        self._ui_refresh_after_id = self.root.after(delay_ms, lambda: self._refrescar_ui(forzar=forzar))

    def _cancelar_refresco_ui_programado(self) -> None:
        """Cancela el próximo refresco UI si estaba pendiente."""
        # Variable local para actual.
        actual = getattr(self, "_ui_refresh_after_id", None)
        if actual is None or not hasattr(self, "root"):
            return
        try:
            self.root.after_cancel(actual)
        except Exception:
            LOGGER.debug("No se pudo cancelar el refresco UI pendiente", exc_info=True)
        finally:
            self._ui_refresh_after_id = None

    def _programar_refresco_vivo_relaciones(self, delay_ms: int = 250, reemplazar: bool = True) -> None:
        """Programa un refresco rápido y liviano de la fila viva de relaciones."""
        if not hasattr(self, "root"):
            return
        if self._debe_diferir_refresh_pesado():
            delay_ms = max(int(delay_ms), self._restante_diferir_refresh_ms() + 120)
        actual = getattr(self, "_live_rel_refresh_after_id", None)
        if actual is not None and reemplazar:
            try:
                self.root.after_cancel(actual)
            except Exception:
                LOGGER.debug("No se pudo cancelar el refresco vivo pendiente", exc_info=True)
            finally:
                self._live_rel_refresh_after_id = None
        if getattr(self, "_live_rel_refresh_after_id", None) is not None:
            return
        self._live_rel_refresh_after_id = self.root.after(delay_ms, self._refrescar_vistas_relaciones_vivo)

    def _cancelar_refresco_vivo_relaciones_programado(self) -> None:
        """Cancela el refresco rápido de relaciones si estaba pendiente."""
        actual = getattr(self, "_live_rel_refresh_after_id", None)
        if actual is None or not hasattr(self, "root"):
            return
        try:
            self.root.after_cancel(actual)
        except Exception:
            LOGGER.debug("No se pudo cancelar el refresco vivo pendiente", exc_info=True)
        finally:
            self._live_rel_refresh_after_id = None

    def _extraer_filas_live_relaciones(self, ticker_a: str, ticker_b: str, tasa: float, referencia_tiempo: datetime) -> tuple[list[dict[str, Any]], list[dict[str, Any]], dict[str, Any]]:
        """Toma solo las filas necesarias para actualizar rápido la fila viva de relaciones."""
        filas = ESTADO.snapshot_rows()
        info = ESTADO.snapshot_info()
        tickers_objetivo = {str(ticker_a or "").strip(), str(ticker_b or "").strip()}
        subset: list[dict[str, Any]] = []
        for fila in filas:
            ticker = str(fila.get("ticker") or "").strip()
            tipo = str(fila.get("tipo") or "").strip().lower()
            if ticker in tickers_objetivo or tipo == "accion":
                subset.append(dict(fila))
        enriquecidas, _ = enriquecer_filas_analiticas(
            subset,
            self.instrumentos_por_ticker,
            tasa,
            analytics_cache=self._analytics_cache,
            referencia_tiempo=referencia_tiempo,
        )
        filas_calls = [dict(f) for f in enriquecidas if str(f.get("tipo") or "").strip().lower() == "calls"]
        filas_puts = [dict(f) for f in enriquecidas if str(f.get("tipo") or "").strip().lower() == "puts"]
        return filas_calls, filas_puts, info

    def _construir_fila_viva_tabla_rel_diaria(
        self,
        ticker_a: str,
        ticker_b: str,
        filas_calls: list[dict[str, Any]],
        filas_puts: list[dict[str, Any]],
        info: dict[str, Any],
        max_spread: Any,
    ) -> dict[str, Any] | None:
        """Construye solo la fila AHORA para la tabla diaria, sin recomputar todo el histórico."""
        if self.offline_mode or not mercado_en_horario_operativo():
            return None
        mapa_actual = {str(fila.get("ticker") or ""): fila for fila in list(filas_calls) + list(filas_puts)}
        fila_a = dict(mapa_actual.get(str(ticker_a).strip(), {}) or {})
        fila_b = dict(mapa_actual.get(str(ticker_b).strip(), {}) or {})
        fallback_valor_a = self._history_db.obtener_ultimo_valor_ticker(ticker_a) if ticker_a else None
        fallback_valor_b = self._history_db.obtener_ultimo_valor_ticker(ticker_b) if ticker_b else None
        last_a = convertir_a_numero(fila_a.get("last"))
        last_b = convertir_a_numero(fila_b.get("last"))
        usando_fallback_last = False
        if last_a is None and fallback_valor_a is not None:
            last_a = convertir_a_numero(fallback_valor_a.get("last"))
            usando_fallback_last = last_a is not None or usando_fallback_last
        if last_b is None and fallback_valor_b is not None:
            last_b = convertir_a_numero(fallback_valor_b.get("last"))
            usando_fallback_last = last_b is not None or usando_fallback_last
        if last_a is None or last_b is None:
            return None
        delta_a_ahora = fila_a.get("delta") if convertir_a_numero(fila_a.get("delta")) is not None else ((fallback_valor_a or {}).get("delta"))
        delta_b_ahora = fila_b.get("delta") if convertir_a_numero(fila_b.get("delta")) is not None else ((fallback_valor_b or {}).get("delta"))
        vega_a_ahora = fila_a.get("vega") if convertir_a_numero(fila_a.get("vega")) is not None else ((fallback_valor_a or {}).get("vega"))
        vega_b_ahora = fila_b.get("vega") if convertir_a_numero(fila_b.get("vega")) is not None else ((fallback_valor_b or {}).get("vega"))
        theta_a_ahora = fila_a.get("theta") if convertir_a_numero(fila_a.get("theta")) is not None else ((fallback_valor_a or {}).get("theta"))
        theta_b_ahora = fila_b.get("theta") if convertir_a_numero(fila_b.get("theta")) is not None else ((fallback_valor_b or {}).get("theta"))
        ask_a_ahora = fila_a.get("ask") if convertir_a_numero(fila_a.get("ask")) is not None else last_a
        bid_b_ahora = fila_b.get("bid") if convertir_a_numero(fila_b.get("bid")) is not None else last_b
        texto_rango_vivo_ab = ""
        texto_rango_vivo_spread = ""
        texto_rango_vivo_ratio_pos_1a2b = ""
        texto_rango_vivo_ratio_inv_1a2b = ""
        if not usando_fallback_last:
            last_evento_texto = str(info.get("last_event_at") or ahora_texto())
            try:
                ts_live = datetime.strptime(last_evento_texto, "%Y-%m-%d %H:%M:%S")
            except Exception:
                ts_live = ahora().replace(tzinfo=None)
            fecha_hoy = ahora().strftime("%Y-%m-%d")
            max_ab_dia, min_ab_dia = self._extremos_intradia_tabla_rel_estrategia(fecha_hoy, ticker_a, ticker_b, estrategia="ab", last_a_live=float(last_a), last_b_live=float(last_b), ts_live=ts_live)
            max_spread_dia, min_spread_dia = self._extremos_intradia_tabla_rel_estrategia(fecha_hoy, ticker_a, ticker_b, estrategia="spread", last_a_live=float(last_a), last_b_live=float(last_b), ts_live=ts_live)
            max_ratio_pos_1a2b_dia, min_ratio_pos_1a2b_dia = self._extremos_intradia_tabla_rel_estrategia(fecha_hoy, ticker_a, ticker_b, estrategia="ratio_pos_1a2b", last_a_live=float(last_a), last_b_live=float(last_b), ts_live=ts_live)
            max_ratio_inv_1a2b_dia, min_ratio_inv_1a2b_dia = self._extremos_intradia_tabla_rel_estrategia(fecha_hoy, ticker_a, ticker_b, estrategia="ratio_inv_1a2b", last_a_live=float(last_a), last_b_live=float(last_b), ts_live=ts_live)
            texto_rango_vivo_ab = self._formatear_rango_tabla_rel_ab(max_ab_dia, min_ab_dia)
            texto_rango_vivo_spread = self._formatear_rango_tabla_rel_ab(max_spread_dia, min_spread_dia)
            texto_rango_vivo_ratio_pos_1a2b = self._formatear_rango_tabla_rel_ab(max_ratio_pos_1a2b_dia, min_ratio_pos_1a2b_dia)
            texto_rango_vivo_ratio_inv_1a2b = self._formatear_rango_tabla_rel_ab(max_ratio_inv_1a2b_dia, min_ratio_inv_1a2b_dia)
        fuente_ahora = "últ. last" if usando_fallback_last else "vivo"
        return self._calcular_resumen_relacion(
            "AHORA",
            last_a,
            last_b,
            fuente_ahora,
            delta_a=delta_a_ahora,
            delta_b=delta_b_ahora,
            vega_a=vega_a_ahora,
            vega_b=vega_b_ahora,
            theta_a=theta_a_ahora,
            theta_b=theta_b_ahora,
            ask_a=ask_a_ahora,
            bid_b=bid_b_ahora,
            minmax_ab_dia=texto_rango_vivo_ab,
            minmax_spread_dia=texto_rango_vivo_spread,
            minmax_ratio_pos_1a2b_dia=texto_rango_vivo_ratio_pos_1a2b,
            minmax_ratio_inv_1a2b_dia=texto_rango_vivo_ratio_inv_1a2b,
            max_spread=max_spread,
        )

    def _refrescar_tabla_relaciones_vivo_rapido(self) -> bool:
        """Actualiza solo la fila AHORA y resúmenes de la tabla diaria sin pasar por todo el loop general."""
        if not self._requiere_refresco_rapido_tabla_rel_diaria():
            return False
        slot = self._tab_tabla_rel_activa_indice()
        ticker_a = str(self.var_tabla_rel_a.get() or "").strip()
        ticker_b = str(self.var_tabla_rel_b.get() or "").strip()
        if not ticker_a or not ticker_b:
            return False
        base_rows_actuales = [
            dict(fila)
            for fila in self._filas_base_tabla_rel(self._tabla_rel_last_rows.get(slot) or [])
            if str(fila.get("fuente") or "").strip().lower() != "vivo" and str(fila.get("fecha") or "").strip().upper() != "AHORA"
        ]
        if not base_rows_actuales:
            return False
        tasa = parsear_tasa_porcentaje(self.var_tasa.get())
        referencia_tiempo = ahora().replace(second=0, microsecond=0)
        filas_calls, filas_puts, info = self._extraer_filas_live_relaciones(ticker_a, ticker_b, tasa, referencia_tiempo)
        fila_live = self._construir_fila_viva_tabla_rel_diaria(ticker_a, ticker_b, filas_calls, filas_puts, info, self._maximo_cobro_registro_spread(ticker_a, ticker_b))
        if fila_live is None:
            return False
        salida = list(base_rows_actuales) + [fila_live]
        salida = self._enriquecer_variaciones_tabla_rel(salida, slot, modo="diaria")
        fila_promedio = self._fila_promedio_tabla_rel(salida)
        if fila_promedio is not None:
            salida.append(fila_promedio)
        fila_ema = self._fila_ema_tabla_rel(salida)
        if fila_ema is not None:
            salida.append(fila_ema)
        fila_prob_positiva = self._fila_prob_positiva_tabla_rel(salida)
        if fila_prob_positiva is not None:
            salida.append(fila_prob_positiva)
        self._tabla_rel_last_rows[slot] = [dict(f) for f in salida]
        self._cargar_tree_tabla_rel(salida)
        return True

    def _refrescar_tabla_rel_intradia_vivo_rapido(self) -> bool:
        """Actualiza solo la última fila viva intradía sin recomputar todo el loop general."""
        if not self._requiere_refresco_rapido_tabla_rel_intradia():
            return False
        slot = self.notebook_intradia_rel.index(self.notebook_intradia_rel.select()) + 1 if hasattr(self, 'notebook_intradia_rel') else 1
        widgets = self._intradia_rel_widgets.get(slot, {})
        tree = widgets.get("tree")
        if tree is None:
            return False
        fecha = str(self._intradia_vars_fecha[slot].get() or "").strip()
        ticker_a = str(self._intradia_vars_a[slot].get() or "").strip()
        ticker_b = str(self._intradia_vars_b[slot].get() or "").strip()
        if not fecha or not ticker_a or not ticker_b:
            return False
        base_rows_actuales = [dict(fila) for fila in (self._intradia_rel_last_rows.get(slot) or []) if str(fila.get("fuente") or "").strip().lower() != "vivo"]
        if not base_rows_actuales:
            return False
        tasa = parsear_tasa_porcentaje(self.var_tasa.get())
        referencia_tiempo = ahora().replace(second=0, microsecond=0)
        filas_calls, filas_puts, info = self._extraer_filas_live_relaciones(ticker_a, ticker_b, tasa, referencia_tiempo)
        fila_live = self._construir_fila_viva_tabla_rel_intradia(fecha, ticker_a, ticker_b, filas_calls, filas_puts, info, self._maximo_cobro_registro_spread(ticker_a, ticker_b))
        if fila_live is None:
            return False
        salida = self._asegurar_ultima_fila_viva_tabla_rel_intradia(base_rows_actuales, fila_live)
        salida = self._recalcular_columnas_derivadas_tabla_rel_intradia_visible(salida, slot)
        for fila in salida:
            fila.pop("_ts_obj", None)
        self._intradia_rel_last_rows[slot] = [dict(f) for f in salida]
        self._cargar_tree_tabla_rel_intradia_en(tree, salida)
        return True

    def _refrescar_vistas_relaciones_vivo(self) -> None:
        """Refresco rápido independiente para la fila viva de Tabla relaciones e intradía."""
        self._live_rel_refresh_after_id = None
        if STOP_EVENT.is_set() or getattr(self, "_closing_in_progress", False):
            return
        if self._debe_diferir_refresh_pesado():
            self._programar_refresco_vivo_relaciones(delay_ms=max(220, self._restante_diferir_refresh_ms() + 120), reemplazar=True)
            return
        if self._live_rel_refresh_running:
            self._programar_refresco_vivo_relaciones(delay_ms=220, reemplazar=False)
            return
        if self._ui_refresh_running:
            self._programar_refresco_vivo_relaciones(delay_ms=180, reemplazar=False)
            return
        self._live_rel_refresh_running = True
        try:
            tab_activa = self._tab_activa_texto()
            if tab_activa == "Tabla relaciones":
                self._refrescar_tabla_relaciones_vivo_rapido()
            elif tab_activa == "Tabla rel. intradía":
                self._refrescar_tabla_rel_intradia_vivo_rapido()
        except Exception:
            LOGGER.exception("Fallo en refresco vivo rápido de relaciones")
        finally:
            self._live_rel_refresh_running = False
        if not STOP_EVENT.is_set() and not getattr(self, "_closing_in_progress", False):
            delay_ms = 220 if self._requiere_refresco_rapido_tabla_rel_viva() else 1000
            self._programar_refresco_vivo_relaciones(delay_ms=delay_ms, reemplazar=False)

