    def _guardar_estado_ui(self) -> None:
        """Guarda en disco las combinaciones intradía elegidas para reabrirlas luego."""
        try:
            guardar_json(self._payload_estado_ui(), self._ui_state_path)
        except Exception:
            LOGGER.exception("No se pudo guardar el estado UI en %s", self._ui_state_path)

    def _leer_payload_distribucion_manual(self) -> dict[str, Any] | None:
        """Lee la distribución manual, que tiene prioridad sobre el autoguardado."""
        ruta = getattr(self, "_ui_distribution_path", None)
        if ruta is None or not ruta.exists():
            return None
        try:
            payload = json.loads(ruta.read_text(encoding="utf-8"))
        except Exception:
            LOGGER.exception("No se pudo leer la distribución manual desde %s", ruta)
            return None
        return payload if isinstance(payload, dict) else None

    def guardar_distribucion_manual(self) -> None:
        """Guarda la distribución que debe restaurarse en los próximos arranques."""
        try:
            payload = self._payload_estado_ui()
            payload["distribucion_manual"] = True
            payload["distribucion_manual_guardada_en"] = ahora_texto()
            guardar_json(payload, self._ui_distribution_path)
            self.var_estado.set(f"Estado: distribución guardada en {self._ui_distribution_path.name}")
        except Exception as exc:
            LOGGER.exception("No se pudo guardar la distribución manual")
            self.var_estado.set(f"Estado: no se pudo guardar la distribución: {exc}")

    def _programar_guardado_estado_ui(self, delay_ms: int = 220, reemplazar: bool = True) -> None:
        """Debounce del guardado de estado para no escribir disco en cada cambio de subvista."""
        if not hasattr(self, "root"):
            try:
                self._guardar_estado_ui()
            except Exception:
                LOGGER.debug("No se pudo guardar el estado UI sin root", exc_info=True)
            return
        actual = getattr(self, "_ui_state_after_id", None)
        if actual is not None and reemplazar:
            try:
                self.root.after_cancel(actual)
            except Exception:
                LOGGER.debug("No se pudo cancelar el guardado diferido de estado UI", exc_info=True)
            finally:
                self._ui_state_after_id = None
        if getattr(self, "_ui_state_after_id", None) is not None:
            return
        self._ui_state_after_id = self.root.after(delay_ms, self._ejecutar_guardado_estado_ui_programado)

    def _ejecutar_guardado_estado_ui_programado(self) -> None:
        """Ejecuta el guardado de estado diferido si seguía pendiente."""
        self._ui_state_after_id = None
        self._guardar_estado_ui()

    def _capturar_anchos_columnas_tree_tabla_rel(self, tree) -> dict[str, int]:
        """Devuelve anchos reales de una tabla de relaciones."""
        if tree is None:
            return {}
        if isinstance(tree, SheetTableAdapter):
            try:
                return {
                    str(col): int(width)
                    for col, width in tree.sync_column_widths_from_widget().items()
                    if str(col) in self.TABLA_REL_COLUMNAS and int(width) > 0
                }
            except Exception:
                LOGGER.debug("No se pudieron capturar anchos de tksheet", exc_info=True)
                return {}
        try:
            columnas = tuple(tree.cget("columns") or ())
        except Exception:
            columnas = tuple()
        anchos: dict[str, int] = {}
        for columna in columnas:
            col = str(columna)
            if col not in self.TABLA_REL_COLUMNAS:
                continue
            try:
                ancho = int(tree.column(col, "width"))
            except Exception:
                continue
            if ancho > 0:
                anchos[col] = ancho
        return anchos

    def _sincronizar_layout_tablas_relaciones_desde_widgets(self) -> None:
        """Copia a estado serializable la disposicion visual actual de relaciones."""
        for slot in self._tabla_rel_slots:
            tree_diaria = (self._tabla_rel_widgets.get(slot, {}) or {}).get("tree")
            anchos_diaria = self._capturar_anchos_columnas_tree_tabla_rel(tree_diaria)
            if anchos_diaria:
                self._tabla_rel_column_width_vars.setdefault("diaria", {}).setdefault(slot, {})
                self._tabla_rel_column_width_vars["diaria"][slot].update(anchos_diaria)
            tree_intradia = (self._intradia_rel_widgets.get(slot, {}) or {}).get("tree")
            anchos_intradia = self._capturar_anchos_columnas_tree_tabla_rel(tree_intradia)
            if anchos_intradia:
                self._tabla_rel_column_width_vars.setdefault("intradia", {}).setdefault(slot, {})
                self._tabla_rel_column_width_vars["intradia"][slot].update(anchos_intradia)

    def _normalizar_anchos_columnas_tabla_rel(self, data: Any) -> dict[str, int]:
        """Valida un mapa de anchos de columnas guardado."""
        if not isinstance(data, dict):
            return {}
        salida: dict[str, int] = {}
        for col, ancho in data.items():
            col_norm = str(col)
            if col_norm not in self.TABLA_REL_COLUMNAS:
                continue
            try:
                ancho_int = int(float(ancho))
            except Exception:
                continue
            salida[col_norm] = max(24, min(600, ancho_int))
        return salida

    def _aplicar_anchos_columnas_tabla_rel(self, tree, slot: int, modo: str) -> None:
        """Aplica anchos persistidos de columnas a una tabla de relaciones."""
        if tree is None:
            return
        modo_norm = self._normalizar_modo_tabla_rel(modo)
        anchos = self._tabla_rel_column_width_vars.get(modo_norm, {}).get(int(slot or 1), {})
        if not isinstance(anchos, dict) or not anchos:
            return
        for col, ancho in anchos.items():
            if str(col) not in self.TABLA_REL_COLUMNAS:
                continue
            try:
                tree.column(str(col), width=int(ancho))
            except Exception:
                LOGGER.debug("No se pudo aplicar ancho de columna %s", col, exc_info=True)

    def _subvista_tiene_config_guardada(self, payload: dict[str, Any], slot: int) -> bool:
        """Detecta si un slot alto tiene configuración real y no sólo defaults."""
        slot_txt = str(slot)

        def valor_significativo(valor: Any) -> bool:
            if isinstance(valor, str):
                texto = valor.strip()
                return bool(texto) and texto != f"Vista {slot}"
            if isinstance(valor, bool):
                return bool(valor)
            if isinstance(valor, (int, float)):
                return valor != 0
            if isinstance(valor, dict):
                return any(valor_significativo(v) for v in valor.values())
            if isinstance(valor, (list, tuple, set)):
                return any(valor_significativo(v) for v in valor)
            return valor is not None

        nombres = payload.get("subvista_nombres")
        if isinstance(nombres, dict) and valor_significativo(nombres.get(slot_txt, nombres.get(slot))):
            return True

        for clave in (
            "comparador_2_bases",
            "tabla_relaciones",
            "intradia",
            "backtest",
            "backtest_cobertura",
        ):
            data = payload.get(clave)
            if isinstance(data, dict) and valor_significativo(data.get(slot_txt, data.get(slot))):
                return True

        estado_por_vencimiento = payload.get("estado_por_vencimiento")
        if isinstance(estado_por_vencimiento, dict):
            for estado in estado_por_vencimiento.values():
                if not isinstance(estado, dict):
                    continue
                slots = estado.get("slots")
                if isinstance(slots, dict) and valor_significativo(slots.get(slot_txt, slots.get(slot))):
                    return True
        return False

    def _resolver_subvistas_activas_guardadas(self, payload: dict[str, Any]) -> int:
        """Restaura cantidad activa sin conservar 24 si quedó guardado sólo porque una versión lo forzaba."""
        max_subvistas = int(getattr(self, "MAX_SUBVISTAS", self.NUM_SUBVISTAS))
        default = max(1, min(int(getattr(self, "SUBVISTAS_INICIALES", 6)), max_subvistas))
        try:
            guardadas = int(payload.get("subvistas_activas") or default)
        except Exception:
            guardadas = default
        data_venc = None
        venc = str(payload.get("vencimiento_general") or payload.get("vencimiento") or "").strip()
        estados = payload.get("estado_vencimientos_ui") or payload.get("estado_por_vencimiento")
        if venc and isinstance(estados, dict):
            posible = estados.get(venc)
            if isinstance(posible, dict):
                data_venc = posible
        if isinstance(data_venc, dict):
            return self._limitar_subvistas_guardadas_por_config(data_venc, guardadas)
        return max(1, min(guardadas, max_subvistas))

    def _marcar_interaccion_vista(self, cooldown_ms: int = 180) -> None:
        """Marca un cambio de vista reciente para diferir refrescos pesados y evitar cuelgues por ráfagas."""
        ahora_mono = time.monotonic()
        self._ultima_interaccion_vista_mono = ahora_mono
        self._defer_heavy_refresh_until_mono = max(
            float(getattr(self, "_defer_heavy_refresh_until_mono", 0.0) or 0.0),
            ahora_mono + max(int(cooldown_ms), 0) / 1000.0,
        )
        self._cancelar_refresco_vivo_relaciones_programado()

    def _restante_diferir_refresh_ms(self) -> int:
        """Devuelve cuántos ms faltan para reanudar refrescos pesados tras un cambio de vista."""
        restante = float(getattr(self, "_defer_heavy_refresh_until_mono", 0.0) or 0.0) - time.monotonic()
        return int(max(restante, 0.0) * 1000)

    def _debe_diferir_refresh_pesado(self) -> bool:
        """Indica si conviene posponer refrescos pesados mientras la UI se estabiliza tras un cambio de vista."""
        return self._restante_diferir_refresh_ms() > 0 and not getattr(self, "_closing_in_progress", False)

    def _programar_refresco_subvista(self, delay_ms: int = 60, forzar: bool = False) -> None:
        """Programa un refresco rápido pero no bloqueante al cambiar de subvista."""
        if bool(getattr(self, "_startup_building_ui", False)):
            return
        delay_real = max(int(delay_ms), 120)
        self._marcar_interaccion_vista(cooldown_ms=max(delay_real, 450))
        self._programar_refresco_ui(delay_ms=delay_real, forzar=forzar, reemplazar=True)

    def _programar_hidratacion_subvista(
        self,
        notebook_attr: str,
        *,
        tab_principal: str | None = None,
        delay_refresco_ms: int = 180,
    ) -> None:
        """Construye una subvista perezosa cuando Tk quedó libre y sólo si sigue activa."""
        if bool(getattr(self, "_startup_building_ui", False)):
            return
        try:
            slot = self._slot_actual_desde_notebook_attr(notebook_attr)
        except Exception:
            slot = 1

        def ejecutar() -> None:
            if bool(getattr(self, "_closing_in_progress", False)):
                return
            if tab_principal and self._tab_activa_texto() != tab_principal:
                return
            if self._slot_actual_desde_notebook_attr(notebook_attr) != slot:
                return
            construida = self._asegurar_subvista_construida(notebook_attr, slot)
            if construida:
                if notebook_attr == "notebook_comp":
                    self._sincronizar_aliases_comp_activos()
                elif notebook_attr == "notebook_tabla_rel":
                    self._sincronizar_aliases_tabla_rel_activos()
                elif notebook_attr == "notebook_backtest":
                    self._sincronizar_aliases_backtest_activos()
                elif notebook_attr == "notebook_backtest_hedge":
                    self._sincronizar_aliases_backtest_hedge_activos()
            if (not tab_principal) or self._tab_activa_texto() == tab_principal:
                self._programar_refresco_subvista(delay_ms=delay_refresco_ms, forzar=False)

        try:
            self.root.after_idle(ejecutar)
        except Exception:
            ejecutar()

    def _al_recuperar_foco_ventana(self, _event=None) -> None:
        """Difiere refrescos pesados al volver desde otra aplicación."""
        self._marcar_interaccion_vista(cooldown_ms=1000)
        self._programar_refresco_ui(delay_ms=1000, forzar=False, reemplazar=True)

    def _al_cambiar_subvista_comp(self, _event=None) -> None:
        """Vista Comparador 2 bases eliminada — sin acción."""
        return

    def _al_cambiar_subvista_tabla_rel(self, _event=None) -> None:
        """Sincroniza y refresca en forma perezosa al cambiar de subvista de tabla relaciones."""
        if bool(getattr(self, "_hydrating_lazy_subvista", False)):
            return
        self._sincronizar_aliases_tabla_rel_activos()
        self._programar_guardado_estado_ui(delay_ms=650)
        self._programar_hidratacion_subvista("notebook_tabla_rel", tab_principal="Tabla relaciones", delay_refresco_ms=150)

