    def _cargar_estado_ui_guardado(self) -> None:
        """Restaura las combinaciones usadas en la ejecución anterior si el archivo existe."""
        distribucion_manual = self._leer_payload_distribucion_manual()
        if isinstance(distribucion_manual, dict):
            payload = distribucion_manual
        else:
            if not self._ui_state_path.exists():
                return
            try:
                # Payload temporal procesado en este bloque.
                payload = json.loads(self._ui_state_path.read_text(encoding="utf-8"))
            except Exception:
                LOGGER.exception("No se pudo leer el estado UI guardado desde %s", self._ui_state_path)
                return
            if not isinstance(payload, dict):
                return
        self._estado_ui_cargado_desde_disco = True
        mostrar_hist = payload.get("mostrar_vencimientos_historicos")
        if mostrar_hist is not None:
            self._mostrar_vencimientos_historicos.set(bool(mostrar_hist))
            self._actualizar_texto_toggle_vencimientos_historicos()
        # Variable local para vencimiento general.
        vencimiento_general = str(payload.get("vencimiento_general") or payload.get("vencimiento") or "").strip()
        if vencimiento_general:
            self._asegurar_vencimiento_en_selector(vencimiento_general)
            if self._vencimiento_seleccionable(vencimiento_general):
                self.var_vencimiento.set(vencimiento_general)
            else:
                primero_visible = self._primer_vencimiento_visible()
                if primero_visible:
                    self.var_vencimiento.set(primero_visible)
        self._cargar_estado_vencimientos_ui_desde_payload(payload)
        self._subvistas_activas = self._resolver_subvistas_activas_guardadas(payload)
        subvista_nombres = payload.get("subvista_nombres")
        if isinstance(subvista_nombres, dict):
            subvista_nombres = self._normalizar_nombres_subvistas_guardados(subvista_nombres)
            for slot in self._comp_slots:
                nombre = subvista_nombres.get(str(slot), subvista_nombres.get(slot))
                if nombre is None:
                    continue
                self._subvista_nombres[slot] = self._normalizar_nombre_subvista(str(nombre), slot)
        self._aplicar_visibilidad_subvistas()
        # Variable local para estado aplicado vencimiento.
        estado_aplicado_venc = self._restaurar_estado_vencimiento_ui(self.var_vencimiento.get().strip())
        # Variable local para estado aplicado registro vencimiento.
        estado_aplicado_registro_venc = False
        # Variable local para data vencimiento actual.
        data_venc_actual = self._estado_por_vencimiento.get(self.var_vencimiento.get().strip())
        if isinstance(data_venc_actual, dict):
            estado_aplicado_registro_venc = any(
                isinstance(data_venc_actual.get(clave), dict)
                for clave in ("registro_spread", "registro_ratio_invertido")
            )
        # Variable local para intradía.
        intradia = payload.get("intradia")
        if isinstance(intradia, dict):
            for slot in self._intradia_slots:
                # Variable local para data.
                data = intradia.get(str(slot))
                if not isinstance(data, dict):
                    continue
                # Fecha temporal usada en este cálculo.
                fecha = str(data.get("fecha") or "").strip()
                # Variable local para base A.
                base_a = str(data.get("base_a") or "").strip()
                # Variable local para base B.
                base_b = str(data.get("base_b") or "").strip()
                # Variable local para modo costo.
                modo_costo = str(data.get("modo_costo") or "").strip()
                # Variable local para fuente grafico costo.
                fuente_grafico_costo = str(data.get("fuente_grafico_costo") or data.get("modo_fuente_costo") or "").strip()
                # Variable local para modo bandas.
                modo_bandas = str(data.get("modo_bandas") or "").strip()
                if fecha:
                    self._intradia_vars_fecha[slot].set(fecha)
                if base_a and not estado_aplicado_venc:
                    self._intradia_vars_a[slot].set(base_a)
                if base_b and not estado_aplicado_venc:
                    self._intradia_vars_b[slot].set(base_b)
                if modo_costo in self._intradia_cost_modes:
                    self._intradia_cost_mode_vars[slot].set(modo_costo)
                    self._intradia_cost_mode_button_vars[slot].set(self._texto_modo_costo_comp(modo_costo))
                if fuente_grafico_costo in self._intradia_price_source_modes:
                    self._intradia_price_source_vars[slot].set(fuente_grafico_costo)
                    self._intradia_price_source_button_vars[slot].set(self._texto_fuente_grafico_comp(fuente_grafico_costo))
                if modo_bandas in self._intradia_band_modes:
                    self._intradia_band_mode_vars[slot].set(modo_bandas)
                    self._intradia_band_mode_button_vars[slot].set(self._texto_modo_bandas_intradia(modo_bandas))
        # Variable local para comparador.
        comparador = payload.get("comparador_2_bases")
        if isinstance(comparador, dict):
            for slot in self._comp_slots:
                data = comparador.get(str(slot))
                if not isinstance(data, dict):
                    continue
                base_a = str(data.get("base_a") or "").strip()
                base_b = str(data.get("base_b") or "").strip()
                modo_costo = str(data.get("modo_costo") or "").strip()
                fuente_grafico_costo = str(data.get("fuente_grafico_costo") or data.get("modo_fuente_costo") or "").strip()
                modo_bandas = str(data.get("modo_bandas") or "").strip()
                # Variable local para modo vista.
                modo_vista = str(data.get("modo_vista") or "").strip()
                # Variable local para modo escala y.
                modo_escala_y = str(data.get("modo_escala_y") or "").strip().lower()
                if base_a and not estado_aplicado_venc:
                    self._comp_vars_a[slot].set(base_a)
                if base_b and not estado_aplicado_venc:
                    self._comp_vars_b[slot].set(base_b)
                if modo_costo in self._comp_cost_modes:
                    self._comp_cost_mode_vars[slot].set(modo_costo)
                    self._comp_cost_mode_button_vars[slot].set(self._texto_modo_costo_comp(modo_costo))
                if modo_bandas in self._comp_band_modes:
                    self._comp_band_mode_vars[slot].set(modo_bandas)
                    self._comp_band_mode_button_vars[slot].set(self._texto_modo_bandas_comp(modo_bandas))
                if modo_vista in self._comp_view_modes:
                    self._comp_view_mode_vars[slot].set(modo_vista)
                    self._comp_view_mode_button_vars[slot].set(self._texto_modo_vista_comp(modo_vista))
                    self._aplicar_estado_modo_vista_comp(slot)
                if modo_escala_y in self._comp_y_scale_modes:
                    self._comp_y_scale_vars[slot].set(modo_escala_y)
                    self._comp_y_scale_button_vars[slot].set(self._texto_modo_escala_y_comp(modo_escala_y))
        # Variable local para tabla relaciones.
        tabla_rel = payload.get("tabla_relaciones")
        if isinstance(tabla_rel, dict):
            for slot in self._tabla_rel_slots:
                data = tabla_rel.get(str(slot))
                if not isinstance(data, dict):
                    continue
                base_a = str(data.get("base_a") or "").strip()
                base_b = str(data.get("base_b") or "").strip()
                # Variable local para mostrar vega.
                mostrar_vega = data.get("mostrar_vega")
                # Variable local para mostrar delta.
                mostrar_delta = data.get("mostrar_delta")
                # Variable local para mostrar delta símbolo (Δ entre hoy y rueda anterior).
                mostrar_delta_simbolo = data.get("mostrar_delta_simbolo")
                if mostrar_delta_simbolo is None:
                    mostrar_delta_simbolo = data.get("mostrar_delta")
                # Variable local para mostrar A/B base.
                mostrar_ratio_ab = data.get("mostrar_ratio_ab")
                # Variable local para mostrar relaciones hoy/ayer de las estrategias.
                mostrar_relaciones = data.get("mostrar_relaciones")
                # Variable local para mostrar delta griega de las estrategias activas.
                mostrar_delta_griega = data.get("mostrar_delta_griega")
                if mostrar_delta_griega is None:
                    mostrar_delta_griega = data.get("mostrar_delta")
                # Variable local para mostrar theta.
                mostrar_theta = data.get("mostrar_theta")
                # Variable local para mostrar ECDF de griegas agregadas.
                mostrar_ecdf_griegas = data.get("mostrar_ecdf_griegas")
                # Variable local para mostrar log-delta.
                mostrar_logdelta = data.get("mostrar_logdelta")
                # Variable local para mostrar ratios porcentuales.
                mostrar_ratio_mode = data.get("mostrar_ratio_mode")
                # Variable local para mostrar ECDF.
                mostrar_varlog_ndelta = data.get("mostrar_varlog_ndelta")
                # Variable local para mostrar ab.
                mostrar_ab = data.get("mostrar_ab")
                # Variable local para mostrar spread.
                mostrar_spread = data.get("mostrar_spread")
                # Variable local para mostrar % de llenado.
                mostrar_fill_pct = data.get("mostrar_fill_pct")
                # Variable local para mostrar ratio positivo.
                mostrar_ratio_pos = data.get("mostrar_ratio_pos")
                # Variable local para mostrar ratio negativo.
                mostrar_ratio_neg = data.get("mostrar_ratio_neg")
                # Variable local para mostrar minmax.
                mostrar_minmax = data.get("mostrar_minmax")
                # Variable local para modo de cálculo de Ln/ECDF.
                mostrar_calc_mode = data.get("calc_mode")
                # Variable local para modo de ventana del ECDF (dinámica o fija).
                ecdf_window_mode = str(data.get("ecdf_window_mode") or "").strip().lower()
                # Variable local para formato condicional ECDF diario.
                ecdf_format_diaria = str(data.get("ecdf_format_diaria") or "").strip().lower()
                # Variable local para formato condicional ECDF intradía.
                ecdf_format_intradia = str(data.get("ecdf_format_intradia") or "").strip().lower()
                # Variable local para orden columnas.
                orden_columnas = data.get("orden_columnas")
                anchos_columnas_diaria = data.get("anchos_columnas_diaria")
                anchos_columnas_intradia = data.get("anchos_columnas_intradia")
                ocultas_manuales_diaria = data.get("ocultas_manuales_diaria")
                ocultas_manuales_intradia = data.get("ocultas_manuales_intradia")
                columnas_grafico = data.get("columnas_grafico")
                x_grafico_diaria = str(data.get("x_grafico_diaria") or "").strip()
                x_grafico_intradia = str(data.get("x_grafico_intradia") or "").strip()
                ecdf_griegas_visible_diaria = data.get("ecdf_griegas_estrategia_visible_diaria")
                ecdf_griegas_visible_intradia = data.get("ecdf_griegas_estrategia_visible_intradia")
                ecdf_griegas_modo_diaria = data.get("ecdf_griegas_estrategia_modo_diaria")
                ecdf_griegas_modo_intradia = data.get("ecdf_griegas_estrategia_modo_intradia")
                if base_a and not estado_aplicado_venc:
                    self._tabla_rel_vars_a[slot].set(base_a)
                if base_b and not estado_aplicado_venc:
                    self._tabla_rel_vars_b[slot].set(base_b)
                if isinstance(orden_columnas, list):
                    # Variable local para columnas validas.
                    columnas_validas = [str(col) for col in orden_columnas if str(col) in self.TABLA_REL_COLUMNAS]
                    # Variable local para faltantes.
                    faltantes = [col for col in self.TABLA_REL_COLUMNAS if col not in columnas_validas]
                    self._tabla_rel_column_order_vars[slot] = columnas_validas + faltantes
                anchos_diaria_norm = self._normalizar_anchos_columnas_tabla_rel(anchos_columnas_diaria)
                if anchos_diaria_norm:
                    self._tabla_rel_column_width_vars.setdefault("diaria", {}).setdefault(slot, {})
                    self._tabla_rel_column_width_vars["diaria"][slot].update(anchos_diaria_norm)
                anchos_intradia_norm = self._normalizar_anchos_columnas_tabla_rel(anchos_columnas_intradia)
                if anchos_intradia_norm:
                    self._tabla_rel_column_width_vars.setdefault("intradia", {}).setdefault(slot, {})
                    self._tabla_rel_column_width_vars["intradia"][slot].update(anchos_intradia_norm)
                if isinstance(ocultas_manuales_diaria, list):
                    self._tabla_rel_manual_hidden_columns.setdefault("diaria", {}).setdefault(slot, set())
                    self._tabla_rel_manual_hidden_columns["diaria"][slot] = {str(col) for col in ocultas_manuales_diaria if str(col) in self.TABLA_REL_COLUMNAS}
                if isinstance(ocultas_manuales_intradia, list):
                    self._tabla_rel_manual_hidden_columns.setdefault("intradia", {}).setdefault(slot, set())
                    self._tabla_rel_manual_hidden_columns["intradia"][slot] = {str(col) for col in ocultas_manuales_intradia if str(col) in self.TABLA_REL_COLUMNAS}
                if isinstance(columnas_grafico, list):
                    self._tabla_rel_selected_plot_cols[slot] = [
                        str(col)
                        for col in columnas_grafico
                        if str(col) in self.TABLA_REL_COLUMNAS and self._columna_graficable_tabla_rel(str(col))
                    ]
                if x_grafico_diaria in self.TABLA_REL_COLUMNAS and self._columna_graficable_tabla_rel(x_grafico_diaria):
                    self._tabla_rel_plot_x_cols[slot] = x_grafico_diaria
                if x_grafico_intradia in self.TABLA_REL_COLUMNAS and self._columna_graficable_tabla_rel(x_grafico_intradia):
                    self._tabla_rel_intradia_plot_x_cols[slot] = x_grafico_intradia
                self._asegurar_estado_ecdf_griegas_estrategia_tabla_rel()
                if isinstance(ecdf_griegas_visible_diaria, dict):
                    for key, val in ecdf_griegas_visible_diaria.items():
                        key_n = str(key)
                        if key_n in self._tabla_rel_ecdf_griegas_strategy_keys():
                            if isinstance(val, dict):
                                for greek, visible in val.items():
                                    greek_n = str(greek).strip().lower()
                                    if greek_n in self._tabla_rel_ecdf_griegas_greek_keys():
                                        self._tabla_rel_ecdf_griegas_strategy_visible["diaria"][slot][key_n][greek_n] = bool(visible)
                            else:
                                for greek_n in self._tabla_rel_ecdf_griegas_greek_keys():
                                    self._tabla_rel_ecdf_griegas_strategy_visible["diaria"][slot][key_n][greek_n] = bool(val)
                if isinstance(ecdf_griegas_visible_intradia, dict):
                    for key, val in ecdf_griegas_visible_intradia.items():
                        key_n = str(key)
                        if key_n in self._tabla_rel_ecdf_griegas_strategy_keys():
                            if isinstance(val, dict):
                                for greek, visible in val.items():
                                    greek_n = str(greek).strip().lower()
                                    if greek_n in self._tabla_rel_ecdf_griegas_greek_keys():
                                        self._tabla_rel_ecdf_griegas_strategy_visible["intradia"][slot][key_n][greek_n] = bool(visible)
                            else:
                                for greek_n in self._tabla_rel_ecdf_griegas_greek_keys():
                                    self._tabla_rel_ecdf_griegas_strategy_visible["intradia"][slot][key_n][greek_n] = bool(val)
                if isinstance(ecdf_griegas_modo_diaria, dict):
                    for key, val in ecdf_griegas_modo_diaria.items():
                        if str(key) in self._tabla_rel_ecdf_griegas_strategy_keys():
                            self._tabla_rel_ecdf_griegas_strategy_mode["diaria"][slot][str(key)] = "relacional" if str(val).strip().lower().startswith("rel") else "directo"
                if isinstance(ecdf_griegas_modo_intradia, dict):
                    for key, val in ecdf_griegas_modo_intradia.items():
                        if str(key) in self._tabla_rel_ecdf_griegas_strategy_keys():
                            self._tabla_rel_ecdf_griegas_strategy_mode["intradia"][slot][str(key)] = "relacional" if str(val).strip().lower().startswith("rel") else "directo"
                if mostrar_vega is not None:
                    # Variable local para activo vega.
                    activo_vega = bool(mostrar_vega)
                    self._tabla_rel_show_vega_vars[slot].set(activo_vega)
                    self._tabla_rel_show_vega_button_vars[slot].set(self._texto_toggle_tabla_rel_vega(activo_vega))
                if mostrar_delta_simbolo is not None:
                    # Variable local para activo delta simbolo.
                    activo_delta_simbolo = bool(mostrar_delta_simbolo)
                    self._tabla_rel_show_delta_symbol_vars[slot].set(activo_delta_simbolo)
                    self._tabla_rel_show_delta_symbol_button_vars[slot].set(self._texto_toggle_tabla_rel_delta_symbol(activo_delta_simbolo))
                if mostrar_ratio_ab is not None:
                    activo_ratio_ab = bool(mostrar_ratio_ab)
                    self._tabla_rel_show_ratio_ab_vars[slot].set(activo_ratio_ab)
                    self._tabla_rel_show_ratio_ab_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_ab(activo_ratio_ab))
                if mostrar_relaciones is not None:
                    activo_relaciones = bool(mostrar_relaciones)
                    self._tabla_rel_show_relaciones_vars[slot].set(activo_relaciones)
                    self._tabla_rel_show_relaciones_button_vars[slot].set(self._texto_toggle_tabla_rel_relaciones(activo_relaciones))
                if mostrar_delta_griega is not None:
                    # Variable local para activo delta griega.
                    activo_delta = bool(mostrar_delta_griega)
                    self._tabla_rel_show_delta_vars[slot].set(activo_delta)
                    self._tabla_rel_show_delta_button_vars[slot].set(self._texto_toggle_tabla_rel_delta(activo_delta))
                if mostrar_theta is not None:
                    # Variable local para activo theta.
                    activo_theta = bool(mostrar_theta)
                    self._tabla_rel_show_theta_vars[slot].set(activo_theta)
                    self._tabla_rel_show_theta_button_vars[slot].set(self._texto_toggle_tabla_rel_theta(activo_theta))
                if mostrar_ecdf_griegas is not None:
                    activo_ecdf_griegas = bool(mostrar_ecdf_griegas)
                    self._tabla_rel_show_ecdf_griegas_vars[slot].set(activo_ecdf_griegas)
                    self._tabla_rel_show_ecdf_griegas_button_vars[slot].set(self._texto_toggle_tabla_rel_ecdf_griegas(activo_ecdf_griegas))
                if mostrar_logdelta is not None:
                    # Variable local para activo log-delta.
                    activo_logdelta = bool(mostrar_logdelta)
                    self._tabla_rel_show_logdelta_vars[slot].set(activo_logdelta)
                    self._tabla_rel_show_logdelta_button_vars[slot].set(self._texto_toggle_tabla_rel_logdelta(activo_logdelta))
                if mostrar_ratio_mode is not None:
                    activo_ratio_mode = bool(mostrar_ratio_mode)
                    self._tabla_rel_show_ratio_mode_vars[slot].set(activo_ratio_mode)
                    self._tabla_rel_show_ratio_mode_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_mode(activo_ratio_mode))
                if mostrar_varlog_ndelta is not None:
                    # Variable local para activo ECDF.
                    activo_varlog_ndelta = bool(mostrar_varlog_ndelta)
                    self._tabla_rel_show_varlog_ndelta_vars[slot].set(activo_varlog_ndelta)
                    self._tabla_rel_show_varlog_ndelta_button_vars[slot].set(self._texto_toggle_tabla_rel_varlog_ndelta(activo_varlog_ndelta))
                if mostrar_ab is not None:
                    # Variable local para activo ab.
                    activo_ab = bool(mostrar_ab)
                    self._tabla_rel_show_ab_vars[slot].set(activo_ab)
                    self._tabla_rel_show_ab_button_vars[slot].set(self._texto_toggle_tabla_rel_ab(activo_ab))
                if mostrar_spread is not None:
                    # Variable local para activo spread.
                    activo_spread = bool(mostrar_spread)
                    self._tabla_rel_show_spread_vars[slot].set(activo_spread)
                    self._tabla_rel_show_spread_button_vars[slot].set(self._texto_toggle_tabla_rel_spread(activo_spread))
                if mostrar_fill_pct is not None:
                    # Variable local para activo fill pct.
                    activo_fill_pct = bool(mostrar_fill_pct)
                    self._tabla_rel_show_fill_pct_vars[slot].set(activo_fill_pct)
                    self._tabla_rel_show_fill_pct_button_vars[slot].set(self._texto_toggle_tabla_rel_fill_pct(activo_fill_pct))
                if mostrar_ratio_pos is not None:
                    # Variable local para activo ratio positivo.
                    activo_ratio_pos = bool(mostrar_ratio_pos)
                    self._tabla_rel_show_ratio_pos_vars[slot].set(activo_ratio_pos)
                    self._tabla_rel_show_ratio_pos_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_pos(activo_ratio_pos))
                if mostrar_ratio_neg is not None:
                    # Variable local para activo ratio negativo.
                    activo_ratio_neg = bool(mostrar_ratio_neg)
                    self._tabla_rel_show_ratio_neg_vars[slot].set(activo_ratio_neg)
                    self._tabla_rel_show_ratio_neg_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_neg(activo_ratio_neg))
                if mostrar_minmax is not None:
                    # Variable local para activo minmax.
                    activo_minmax = bool(mostrar_minmax)
                    self._tabla_rel_show_minmax_vars[slot].set(activo_minmax)
                    self._tabla_rel_show_minmax_button_vars[slot].set(self._texto_toggle_tabla_rel_minmax(activo_minmax))
                if mostrar_calc_mode is not None:
                    modo_calc = "relacional" if str(mostrar_calc_mode).strip().lower().startswith("rel") else "directo"
                    self._tabla_rel_calc_mode_vars[slot].set(modo_calc)
                    self._tabla_rel_calc_mode_button_vars[slot].set(self._texto_toggle_tabla_rel_calc_mode(modo_calc) if hasattr(self, "_texto_toggle_tabla_rel_calc_mode") else ("Calcula: Relacional" if str(modo_calc).strip().lower().startswith("rel") else "Calcula: Directo"))
                if ecdf_window_mode in {"dinamica", "fija"}:
                    self._tabla_rel_ecdf_window_mode_vars[slot].set(ecdf_window_mode)
                    self._tabla_rel_ecdf_window_mode_button_vars[slot].set(self._texto_toggle_tabla_rel_ecdf_window_mode(ecdf_window_mode) if hasattr(self, "_texto_toggle_tabla_rel_ecdf_window_mode") else ("ECDF: Fija" if ecdf_window_mode == "fija" else "ECDF: Dinámica"))
                if ecdf_format_diaria in self._tabla_rel_ecdf_format_modes:
                    self._tabla_rel_ecdf_format_diaria_vars[slot].set(ecdf_format_diaria)
                if ecdf_format_intradia in self._tabla_rel_ecdf_format_modes:
                    self._tabla_rel_ecdf_format_intradia_vars[slot].set(ecdf_format_intradia)
                self._aplicar_estado_columnas_tabla_rel(slot)

        # Variable local para notas tabla relaciones.
        notas_tabla_rel = payload.get("notas_tabla_relaciones")
        if isinstance(notas_tabla_rel, dict):
            for modo_nota in ("diaria", "intradia"):
                notas_modo = notas_tabla_rel.get(modo_nota)
                if not isinstance(notas_modo, dict):
                    continue
                for slot in self._tabla_rel_slots:
                    texto_nota = notas_modo.get(str(slot))
                    if texto_nota is None:
                        continue
                    self._tabla_rel_notes_texts[self._clave_nota_tabla_rel(slot, modo_nota)] = str(texto_nota)

        # Variable local para tabla relaciones intradía.
        tabla_rel_intradia = payload.get("tabla_rel_intradia")
        if isinstance(tabla_rel_intradia, dict):
            slots_data = tabla_rel_intradia.get("slots")
            if isinstance(slots_data, dict):
                for slot in self._tabla_rel_slots:
                    data = slots_data.get(str(slot))
                    if not isinstance(data, dict):
                        continue
                    fecha = str(data.get("fecha") or "").strip()
                    base_a = str(data.get("base_a") or "").strip()
                    base_b = str(data.get("base_b") or "").strip()
                    intervalo = str(data.get("intervalo") or "").strip()
                    if fecha:
                        self._intradia_vars_fecha[slot].set(fecha)
                    if base_a and not estado_aplicado_venc:
                        self._intradia_vars_a[slot].set(base_a)
                    if base_b and not estado_aplicado_venc:
                        self._intradia_vars_b[slot].set(base_b)
                    if intervalo in {"Cambio", "1 min", "5 min", "10 min", "15 min", "30 min", "60 min"}:
                        self._intradia_rel_interval_vars[slot].set(intervalo)

        # Variable local para backtest.
        backtest = payload.get("backtest_intradia")
        if isinstance(backtest, dict):
            # Variable local para slots data.
            slots_data = backtest.get("slots")
            if isinstance(slots_data, dict):
                for slot in self._backtest_slots:
                    data = slots_data.get(str(slot))
                    if not isinstance(data, dict):
                        continue
                    fecha = str(data.get("fecha") or "").strip()
                    base_a = str(data.get("base_a") or "").strip()
                    base_b = str(data.get("base_b") or "").strip()
                    # Variable local para modo serie slot.
                    modo_serie_slot = str(data.get("modo_serie") or "").strip().lower()
                    if fecha:
                        self._backtest_vars_fecha[slot].set(fecha)
                    if base_a and not estado_aplicado_venc:
                        self._backtest_vars_a[slot].set(base_a)
                    if base_b and not estado_aplicado_venc:
                        self._backtest_vars_b[slot].set(base_b)
                    if modo_serie_slot in {"ratio", "cono"}:
                        self._backtest_series_mode_vars[slot].set(modo_serie_slot)
                        self._backtest_series_mode_button_vars[slot].set(self._texto_modo_serie_backtest(modo_serie_slot))
            else:
                fecha = str(backtest.get("fecha") or "").strip()
                base_a = str(backtest.get("base_a") or "").strip()
                base_b = str(backtest.get("base_b") or "").strip()
                if fecha:
                    self._backtest_vars_fecha[1].set(fecha)
                if base_a and not estado_aplicado_venc:
                    self._backtest_vars_a[1].set(base_a)
                if base_b and not estado_aplicado_venc:
                    self._backtest_vars_b[1].set(base_b)
            # Variable local para modo.
            modo = str(backtest.get("modo_ejecucion") or "").strip()
            # Variable local para modo salida.
            modo_salida = str(backtest.get("modo_salida") or backtest.get("exit_mode") or "").strip().lower()
            # Variable local para sigma.
            sigma = str(backtest.get("sigma") or "").strip()
            # Variable local para sigma refuerzo 1.
            sigma_refuerzo_1 = str(backtest.get("sigma_refuerzo_1") or backtest.get("sigma_refuerzo") or "").strip()
            # Variable local para sigma refuerzo 2.
            sigma_refuerzo_2 = str(backtest.get("sigma_refuerzo_2") or "").strip()
            # Variable local para hora inicio.
            hora_inicio = str(backtest.get("hora_inicio") or "").strip()
            # Variable local para hora cierre.
            hora_cierre = str(backtest.get("hora_cierre") or "").strip()
            modo_bandas = str(backtest.get("modo_bandas") or "").strip()
            # Variable local para sigma extrema hist.
            sigma_extrema_hist = str(backtest.get("sigma_extrema_hist") or backtest.get("extreme_sigma_mult") or "").strip()
            # Variable local para espera extrema min.
            espera_extrema_min = str(backtest.get("espera_extrema_min") or backtest.get("cooldown_extrema_min") or "").strip()
            # Variable local para max eventos extremos dia.
            max_eventos_extremos_dia = str(backtest.get("max_eventos_extremos_dia") or backtest.get("limite_extremos_dia") or "").strip()
            # Variable local para extrema habilitada.
            extrema_habilitada = backtest.get("extrema_habilitada")
            # Variable local para perdida maxima.
            perdida_maxima = str(backtest.get("perdida_maxima") or backtest.get("stop_loss_monto") or "").strip()
            # Variable local para espera perdida min.
            espera_perdida_min = str(backtest.get("espera_perdida_min") or backtest.get("cooldown_perdida_min") or "").strip()
            # Variable local para perdida habilitada.
            perdida_habilitada = backtest.get("perdida_habilitada")
            # Variable local para intervalo backtest.
            intervalo_backtest = str(backtest.get("intervalo") or backtest.get("interval") or "").strip()
            # Variable local para ticks entrada.
            ticks_entrada_bt = str(backtest.get("ticks_entrada") or backtest.get("entry_ticks") or "").strip()
            # Variable local para ticks salida.
            ticks_salida_bt = str(backtest.get("ticks_salida") or backtest.get("exit_ticks") or "").strip()
            # Variable local para shock vol habilitado.
            shock_vol_habilitado = backtest.get("shock_vol_habilitado")
            # Variable local para shock vol ventana min.
            shock_vol_ventana_min = str(backtest.get("shock_vol_ventana_min") or "").strip()
            # Variable local para shock vol múltiplo.
            shock_vol_mult = str(backtest.get("shock_vol_mult") or "").strip()
            # Variable local para shock vol espera min.
            shock_vol_espera_min = str(backtest.get("shock_vol_espera_min") or "").strip()
            # Variable local para cambio media habilitado.
            cambio_media_habilitado = backtest.get("cambio_media_habilitado")
            # Variable local para cambio media sigma.
            cambio_media_sigma = str(backtest.get("cambio_media_sigma") or "").strip()
            # Variable local para cambio media espera min.
            cambio_media_espera_min = str(backtest.get("cambio_media_espera_min") or "").strip()
            # Variable local para confirmar segundo tick raw.
            confirmar_segundo_tick_raw = backtest.get("confirmar_segundo_tick")
            # Variable local para modo serie.
            modo_serie = str(backtest.get("modo_serie") or "").strip().lower()
            if modo in {"last", "bid_ask"}:
                self.var_backtest_exec_mode.set(modo)
            elif modo == "last_exit_market":
                self.var_backtest_exec_mode.set("last")
                self.var_backtest_exit_mode.set("market")
            if modo_salida in {"last", "market"}:
                self.var_backtest_exit_mode.set(modo_salida)
            if sigma:
                self.var_backtest_sigma.set(sigma)
            if sigma_refuerzo_1:
                self.var_backtest_sigma_refuerzo_1.set(sigma_refuerzo_1)
            if sigma_refuerzo_2:
                self.var_backtest_sigma_refuerzo_2.set(sigma_refuerzo_2)
            if hora_inicio:
                self.var_backtest_hora_inicio.set(hora_inicio)
            if hora_cierre:
                self.var_backtest_hora_cierre.set(hora_cierre)
            if intervalo_backtest in BACKTEST_INTERVAL_OPTIONS:
                self.var_backtest_interval.set(intervalo_backtest)
            if ticks_entrada_bt:
                self.var_backtest_entry_ticks.set(ticks_entrada_bt)
            if ticks_salida_bt:
                self.var_backtest_exit_ticks.set(ticks_salida_bt)
            elif confirmar_segundo_tick_raw is not None and not ticks_entrada_bt:
                self.var_backtest_entry_ticks.set("2" if bool(confirmar_segundo_tick_raw) else "1")
            if modo_bandas in {"dinamica", "fija"}:
                self.var_backtest_band_mode.set(modo_bandas)
                self.var_backtest_band_mode_button.set(self._texto_modo_bandas_backtest(modo_bandas))
            if sigma_extrema_hist:
                self.var_backtest_extreme_sigma_mult.set(sigma_extrema_hist)
            if espera_extrema_min:
                self.var_backtest_extreme_wait_min.set(espera_extrema_min)
            if max_eventos_extremos_dia:
                self.var_backtest_extreme_max_events.set(max_eventos_extremos_dia)
            if perdida_maxima:
                self.var_backtest_loss_limit.set(perdida_maxima)
            if espera_perdida_min:
                self.var_backtest_loss_wait_min.set(espera_perdida_min)
            if shock_vol_ventana_min:
                self.var_backtest_volshock_window_min.set(shock_vol_ventana_min)
            if shock_vol_mult:
                self.var_backtest_volshock_mult.set(shock_vol_mult)
            if shock_vol_espera_min:
                self.var_backtest_volshock_wait_min.set(shock_vol_espera_min)
            if cambio_media_sigma:
                self.var_backtest_media_shift_sigma.set(cambio_media_sigma)
            if cambio_media_espera_min:
                self.var_backtest_media_shift_wait_min.set(cambio_media_espera_min)
            if extrema_habilitada is not None:
                self.var_backtest_extreme_enabled.set(bool(extrema_habilitada))
            if perdida_habilitada is not None:
                self.var_backtest_loss_enabled.set(bool(perdida_habilitada))
            if shock_vol_habilitado is not None:
                self.var_backtest_volshock_enabled.set(bool(shock_vol_habilitado))
            if cambio_media_habilitado is not None:
                self.var_backtest_media_shift_enabled.set(bool(cambio_media_habilitado))
            self.var_backtest_extreme_enabled_button.set(self._texto_toggle_backtest_cierre("Cierre extremo", bool(self.var_backtest_extreme_enabled.get())))
            self.var_backtest_loss_enabled_button.set(self._texto_toggle_backtest_cierre("Stop pérdida", bool(self.var_backtest_loss_enabled.get())))
            self.var_backtest_volshock_enabled_button.set(self._texto_toggle_backtest_cierre("Shock vol", bool(self.var_backtest_volshock_enabled.get())))
            self.var_backtest_media_shift_enabled_button.set(self._texto_toggle_backtest_cierre("Cambio media", bool(self.var_backtest_media_shift_enabled.get())))
            self.var_backtest_confirm_second_tick.set(bool(confirmar_segundo_tick_raw))
            self.var_backtest_confirm_second_tick_button.set(self._texto_confirmacion_entrada_backtest(bool(confirmar_segundo_tick_raw)))
            if modo_serie in {"ratio", "cono"}:
                for slot in self._backtest_slots:
                    if self._backtest_series_mode_vars[slot].get().strip().lower() not in {"ratio", "cono"}:
                        self._backtest_series_mode_vars[slot].set(modo_serie)
                        self._backtest_series_mode_button_vars[slot].set(self._texto_modo_serie_backtest(modo_serie))
            self.var_backtest_series_mode_button.set(self._texto_modo_serie_backtest(self.var_backtest_series_mode.get()))
        # Variable local para backtest cobertura.
        backtest_cobertura = payload.get("backtest_cobertura")
        if isinstance(backtest_cobertura, dict):
            slots_data = backtest_cobertura.get("slots")
            if isinstance(slots_data, dict):
                for slot in self._backtest_slots:
                    data = slots_data.get(str(slot))
                    if not isinstance(data, dict):
                        continue
                    modo_serie_slot = str(data.get("modo_serie") or "").strip().lower()
                    if modo_serie_slot in {"ratio", "cono"}:
                        self._backtest_hedge_series_mode_vars[slot].set(modo_serie_slot)
                        self._backtest_hedge_series_mode_button_vars[slot].set(self._texto_modo_serie_backtest(modo_serie_slot))
            # Variable local para modo cobertura.
            modo_cobertura = str(backtest_cobertura.get("modo_cobertura") or "").strip()
            # Variable local para modo serie cob.
            modo_serie_cob = str(backtest_cobertura.get("modo_serie") or "").strip().lower()
            if modo_cobertura in {"1a1", "precio", "delta", "vega"}:
                self.var_backtest_hedge_mode.set(modo_cobertura)
            if modo_serie_cob in {"ratio", "cono"}:
                for slot in self._backtest_slots:
                    if self._backtest_hedge_series_mode_vars[slot].get().strip().lower() not in {"ratio", "cono"}:
                        self._backtest_hedge_series_mode_vars[slot].set(modo_serie_cob)
                        self._backtest_hedge_series_mode_button_vars[slot].set(self._texto_modo_serie_backtest(modo_serie_cob))
                self.var_backtest_hedge_series_mode.set(modo_serie_cob)
                self.var_backtest_hedge_series_mode_button.set(self._texto_modo_serie_backtest(modo_serie_cob))

        # Variable local para matriz bases.
        matriz_bases = payload.get("matriz_bases")
        if isinstance(matriz_bases, dict):
            # Variable local para fuente matriz.
            fuente_matriz = str(matriz_bases.get("fuente") or "").strip()
            if fuente_matriz:
                self.var_matriz_bases_fuente.set(fuente_matriz)
            # Variable local para modo matriz.
            modo_matriz = str(matriz_bases.get("modo") or "").strip()
            if modo_matriz in self._matriz_bases_modes:
                self.var_matriz_bases_mode.set(modo_matriz)
                self.var_matriz_bases_mode_button.set(self._texto_modo_matriz_bases(modo_matriz))
            # Variable local para metrica matriz.
            metrica_matriz = str(matriz_bases.get("metrica") or "").strip()
            if metrica_matriz in self._matriz_bases_metric_modes:
                self.var_matriz_bases_metric.set(metrica_matriz)
                self.var_matriz_bases_metric_button.set(self._texto_metrica_matriz_bases(metrica_matriz))
            try:
                # Variable local para tab matriz activa.
                tab_matriz_activa = int(matriz_bases.get("tab_activa") or 1)
            except Exception:
                tab_matriz_activa = 1
            if hasattr(self, "notebook_matriz_bases") and tab_matriz_activa in {1, 2}:
                try:
                    self.notebook_matriz_bases.select(tab_matriz_activa - 1)
                except Exception:
                    LOGGER.debug("No se pudo restaurar la subpestaña de matriz bases", exc_info=True)

        # Variable local para registro spread.
        registro_spread = payload.get("registro_spread")
        if isinstance(registro_spread, dict) and not estado_aplicado_registro_venc:
            # Variable local para slots registro.
            slots_registro = registro_spread.get("slots")
            if isinstance(slots_registro, dict):
                for slot in self._registro_spread_slots:
                    data = slots_registro.get(str(slot))
                    if not isinstance(data, dict):
                        continue
                    base_a = str(data.get("base_a") or "").strip()
                    base_b = str(data.get("base_b") or "").strip()
                    # Variable local para activo.
                    activo = data.get("activo")
                    if base_a:
                        self._registro_spread_vars_a[slot].set(base_a)
                    if base_b:
                        self._registro_spread_vars_b[slot].set(base_b)
                    if activo is not None:
                        self._registro_spread_enabled_vars[slot].set(bool(activo))

        # Variable local para registro mariposa.
        registro_mariposa = payload.get("registro_mariposa")
        if isinstance(registro_mariposa, dict):
            self.var_registro_mariposa_simular_puntas.set(bool(registro_mariposa.get("simular_puntas")))
            self.var_registro_mariposa_simular_puntas_label.set(
                "Simular puntas: ON" if bool(self.var_registro_mariposa_simular_puntas.get()) else "Simular puntas: OFF"
            )
            slots_registro = registro_mariposa.get("slots")
            if isinstance(slots_registro, dict):
                for slot in self._registro_mariposa_slots:
                    data = slots_registro.get(str(slot))
                    if not isinstance(data, dict):
                        continue
                    base_a = str(data.get("base_a") or "").strip()
                    base_b = str(data.get("base_b") or "").strip()
                    # Variable local para base C.
                    base_c = str(data.get("base_c") or "").strip()
                    # Variable local para tipo.
                    tipo = self._tipo_registro_mariposa_normalizado(data.get("tipo"))
                    activo = data.get("activo")
                    if base_a:
                        self._registro_mariposa_vars_a[slot].set(base_a)
                    if base_b:
                        self._registro_mariposa_vars_b[slot].set(base_b)
                    if base_c:
                        self._registro_mariposa_vars_c[slot].set(base_c)
                    self._registro_mariposa_tipo_vars[slot].set(tipo)
                    if activo is not None:
                        self._registro_mariposa_enabled_vars[slot].set(bool(activo))

        # Variable local para registro ratio invertido.
        registro_ratio_invertido = payload.get("registro_ratio_invertido")
        if isinstance(registro_ratio_invertido, dict) and not estado_aplicado_registro_venc:
            slots_registro = registro_ratio_invertido.get("slots")
            if isinstance(slots_registro, dict):
                # Variable local para usar bases ratio inv.
                usar_bases_ratio_inv = not isinstance(registro_spread, dict)
                for slot in self._registro_ratio_inv_slots:
                    data = slots_registro.get(str(slot))
                    if not isinstance(data, dict):
                        continue
                    base_a = str(data.get("base_a") or "").strip()
                    base_b = str(data.get("base_b") or "").strip()
                    activo = data.get("activo")
                    # Variable local para coeficiente venta.
                    coef_venta = str(data.get("coef_venta") or "").strip()
                    if usar_bases_ratio_inv and base_a:
                        self._registro_ratio_inv_vars_a[slot].set(base_a)
                    if usar_bases_ratio_inv and base_b:
                        self._registro_ratio_inv_vars_b[slot].set(base_b)
                    if activo is not None:
                        self._registro_ratio_inv_enabled_vars[slot].set(bool(activo))
                    if coef_venta:
                        self._registro_ratio_inv_coef_vars[slot].set(coef_venta)

        # Variable local para backtest vencimiento.
        backtest_vencimiento = payload.get("backtest_vencimiento")
        if isinstance(backtest_vencimiento, dict):
            # Variable local para slots bt.
            slots_bt = backtest_vencimiento.get("slots")
            if isinstance(slots_bt, dict):
                # Variable local para estrategias validas.
                estrategias_validas = {texto for _clave, texto in self._backtest_venc_strategy_options}
                for slot in self._backtest_venc_slots:
                    data = slots_bt.get(str(slot))
                    if not isinstance(data, dict):
                        continue
                    base_a = str(data.get("base_a") or "").strip()
                    base_b = str(data.get("base_b") or "").strip()
                    activo = data.get("activo")
                    # Variable local para estrategia.
                    estrategia = str(data.get("estrategia") or "").strip()
                    # Variable local para coeficiente ratio.
                    coef_ratio = str(data.get("coef_ratio") or "").strip()
                    if base_a:
                        self._backtest_venc_vars_a[slot].set(base_a)
                    if base_b:
                        self._backtest_venc_vars_b[slot].set(base_b)
                    if activo is not None:
                        self._backtest_venc_enabled_vars[slot].set(bool(activo))
                    if estrategia in estrategias_validas:
                        self._backtest_venc_strategy_vars[slot].set(estrategia)
                    if coef_ratio:
                        self._backtest_venc_ratio_coef_vars[slot].set(coef_ratio)
            # Variable local para sigma bt.
            sigma_bt = str(backtest_vencimiento.get("sigma") or "").strip()
            # Variable local para sigma ref 1 bt.
            sigma_ref_1_bt = str(backtest_vencimiento.get("sigma_refuerzo_1") or "").strip()
            # Variable local para sigma ref 2 bt.
            sigma_ref_2_bt = str(backtest_vencimiento.get("sigma_refuerzo_2") or "").strip()
            # Variable local para sigma ext bt.
            sigma_ext_bt = str(backtest_vencimiento.get("sigma_extrema_hist") or "").strip()
            # Variable local para espera ext bt.
            espera_ext_bt = str(backtest_vencimiento.get("espera_extrema_dias") or "").strip()
            # Variable local para extrema habilitada bt.
            extrema_habilitada_bt = backtest_vencimiento.get("extrema_habilitada")
            # Variable local para modo bandas bt.
            modo_bandas_bt = str(backtest_vencimiento.get("modo_bandas") or "").strip().lower()
            # Variable local para anios bandas bt.
            anios_bandas_bt = str(backtest_vencimiento.get("anios_bandas") or "").strip()
            if sigma_bt:
                self.var_backtest_venc_sigma.set(sigma_bt)
            if sigma_ref_1_bt:
                self.var_backtest_venc_sigma_refuerzo_1.set(sigma_ref_1_bt)
            if sigma_ref_2_bt:
                self.var_backtest_venc_sigma_refuerzo_2.set(sigma_ref_2_bt)
            if sigma_ext_bt:
                self.var_backtest_venc_extreme_sigma_mult.set(sigma_ext_bt)
            if espera_ext_bt:
                self.var_backtest_venc_extreme_wait_days.set(espera_ext_bt)
            if extrema_habilitada_bt is not None:
                self.var_backtest_venc_extreme_enabled.set(bool(extrema_habilitada_bt))
            if modo_bandas_bt in self._backtest_venc_band_modes:
                self.var_backtest_venc_band_mode.set(modo_bandas_bt)
            try:
                # Variable local para anios bt num.
                anios_bt_num = int(float(anios_bandas_bt))
            except Exception:
                anios_bt_num = 1
            self.var_backtest_venc_band_years.set(str(max(1, min(3, anios_bt_num))))
            self.var_backtest_venc_extreme_enabled_button.set(self._texto_toggle_backtest_cierre("Cierre extremo", bool(self.var_backtest_venc_extreme_enabled.get())))
            self.var_backtest_venc_band_mode_button.set(self._texto_modo_bandas_backtest_venc(self.var_backtest_venc_band_mode.get()))

        # Variable local para smile.
        smile = payload.get("smile")
        if isinstance(smile, dict):
            # Variable local para fecha smile.
            fecha_smile = str(smile.get("fecha") or "").strip()
            # Variable local para vencimiento smile.
            venc_smile = str(smile.get("vencimiento") or "").strip()
            # Variable local para vencimiento smile superficie.
            venc_smile_superficie = str(smile.get("vencimiento_superficie") or "").strip()
            if fecha_smile:
                self.var_smile_fecha.set(fecha_smile)
            if venc_smile:
                self.var_smile_vencimiento.set(venc_smile)
            if venc_smile_superficie:
                self.var_smile_superficie_vencimiento.set(venc_smile_superficie)
            try:
                # Variable local para tab smile activa.
                tab_smile_activa = int(smile.get("tab_activa") or 1)
            except Exception:
                tab_smile_activa = 1
            if hasattr(self, "notebook_smile") and tab_smile_activa in {1, 2}:
                try:
                    self.notebook_smile.select(tab_smile_activa - 1)
                except Exception:
                    LOGGER.debug("No se pudo restaurar la subpestana de Smile VI", exc_info=True)
        self._vencimiento_general_actual = self.var_vencimiento.get().strip()

        try:
            # Variable local para activa.
            activa = int(payload.get("intradia_tab_activa") or 1)
        except Exception:
            activa = 1
        try:
            # Variable local para activa comparador.
            activa_comp = int(payload.get("comparador_tab_activa") or 1)
        except Exception:
            activa_comp = 1
        if 1 <= activa_comp <= self._subvistas_activas and hasattr(self, "notebook_comp"):
            try:
                self.notebook_comp.select(activa_comp - 1)
            except Exception:
                LOGGER.debug("No se pudo restaurar la subpestaña del comparador 2 bases", exc_info=True)
        try:
            # Variable local para activa tabla.
            activa_tabla = int(payload.get("tabla_rel_tab_activa") or 1)
        except Exception:
            activa_tabla = 1
        if 1 <= activa_tabla <= self._subvistas_activas and hasattr(self, "notebook_tabla_rel"):
            try:
                self.notebook_tabla_rel.select(activa_tabla - 1)
            except Exception:
                LOGGER.debug("No se pudo restaurar la subpestaña de tabla relaciones", exc_info=True)
        if 1 <= activa <= self._subvistas_activas and hasattr(self, "notebook_intradia"):
            try:
                self.notebook_intradia.select(activa - 1)
            except Exception:
                LOGGER.debug("No se pudo restaurar la subpestaña intradía activa", exc_info=True)
        try:
            # Variable local para activa tabla intradía.
            activa_tabla_intradia = int(((tabla_rel_intradia or {}) if isinstance(tabla_rel_intradia, dict) else {}).get("tab_activa") or 1)
        except Exception:
            activa_tabla_intradia = 1
        if 1 <= activa_tabla_intradia <= self._subvistas_activas and hasattr(self, "notebook_intradia_rel"):
            try:
                self.notebook_intradia_rel.select(activa_tabla_intradia - 1)
            except Exception:
                LOGGER.debug("No se pudo restaurar la subpestaña de tabla relaciones intradía", exc_info=True)
        try:
            # Variable local para activa backtest.
            activa_backtest = int((backtest or {}).get("tab_activa") or 1)
        except Exception:
            activa_backtest = 1
        if 1 <= activa_backtest <= self._subvistas_activas and hasattr(self, "notebook_backtest"):
            try:
                self.notebook_backtest.select(activa_backtest - 1)
            except Exception:
                LOGGER.debug("No se pudo restaurar la subpestaña de backtest intradía", exc_info=True)
        try:
            # Variable local para activa backtest hedge.
            activa_backtest_hedge = int((backtest_cobertura or {}).get("tab_activa") or 1)
        except Exception:
            activa_backtest_hedge = 1
        if 1 <= activa_backtest_hedge <= self._subvistas_activas and hasattr(self, "notebook_backtest_hedge"):
            try:
                self.notebook_backtest_hedge.select(activa_backtest_hedge - 1)
            except Exception:
                LOGGER.debug("No se pudo restaurar la subpestaña de backtest cobertura", exc_info=True)
        self._sincronizar_aliases_comp_activos()
        self._sincronizar_aliases_tabla_rel_activos()
        self._sincronizar_aliases_backtest_activos()
        self._sincronizar_aliases_backtest_hedge_activos()
        if hasattr(self, "notebook"):
            # Variable local para orden tabs.
            orden_tabs = payload.get("tab_principal_order")
            if isinstance(orden_tabs, list) and orden_tabs:
                try:
                    self._aplicar_orden_pestanas_principales([str(item) for item in orden_tabs])
                except Exception:
                    LOGGER.debug("No se pudo restaurar el orden de las pestañas principales", exc_info=True)
        # Conservamos el orden de pestañas, pero al iniciar forzamos una vista
        # liviana para que una pestaña pesada guardada no congele el arranque.
        self._restaurar_tab_principal_guardada_inicio(payload)

    def _restaurar_tab_principal_guardada_inicio(self, payload: dict[str, Any]) -> None:
        """Restaura la pestana principal guardada despues de que Tk pueda pintar."""
        if not hasattr(self, "notebook"):
            return
        try:
            indice_guardado = int(payload.get("tab_principal_activa") or 0)
        except Exception:
            indice_guardado = 0
        tab_id_guardado = str(payload.get("tab_principal_activa_id") or "").strip()

        def seleccionar() -> None:
            try:
                tabs = self.notebook.tabs()
                if not tabs:
                    return
                id_to_widget, _widget_to_id = self._mapa_pestanas_principales()
                widget_guardado = id_to_widget.get(tab_id_guardado)
                if widget_guardado is not None and str(widget_guardado) in {str(tab) for tab in tabs}:
                    self.notebook.select(widget_guardado)
                else:
                    indice = max(0, min(indice_guardado, len(tabs) - 1))
                    self.notebook.select(tabs[indice])
                self._programar_hidratacion_de_pestana_principal_activa()
            except Exception:
                LOGGER.debug("No se pudo restaurar la pestana principal guardada", exc_info=True)

        try:
            self.root.after_idle(seleccionar)
        except Exception:
            seleccionar()

    def _seleccionar_tab_principal_segura_inicio(self) -> None:
        """Arranca en la vista compacta para evitar cuelgues al restaurar una vista pesada."""
        if not hasattr(self, "notebook"):
            return
        try:
            if hasattr(self, "tab_compacta"):
                self.notebook.select(self.tab_compacta)
                return
        except Exception:
            LOGGER.debug("No se pudo seleccionar la vista compacta al iniciar", exc_info=True)
        try:
            self.notebook.select(0)
        except Exception:
            LOGGER.debug("No se pudo seleccionar la primera pestaña al iniciar", exc_info=True)

    def _al_cambiar_selector_intradia(self, slot: int) -> None:
        """Persiste y refresca una subvista intradía cuando cambia fecha o ticker."""
        self._invalidar_cache_intradia(slot)
        self._resetear_zoom_intradia(slot)
        self._guardar_estado_ui()
        self._refrescar_ui(forzar=True)

    def _ejecutar_cambio_selector_backtest(self) -> None:
        """Aplica el recálculo del backtest una vez que Tk terminó de procesar la edición actual."""
        # Variable interna para selector backtest refresh scheduled.
        self._selector_backtest_refresh_scheduled = False
        try:
            self.root.update_idletasks()
        except Exception:
            pass
        self._confirmar_config_backtest_en_edicion()
        self._invalidar_cache_backtest()
        self._resetear_zoom_backtest()
        self._resetear_zoom_backtest_hedge()
        self._guardar_estado_ui()
        self._refrescar_ui(forzar=True)

    def _al_cambiar_selector_backtest(self) -> None:
        """Persiste y refresca las vistas de backtest intradía."""
        if bool(getattr(self, "_selector_backtest_refresh_scheduled", False)):
            return
        self._selector_backtest_refresh_scheduled = True
        try:
            self.root.after_idle(self._ejecutar_cambio_selector_backtest)
        except Exception:
            self._selector_backtest_refresh_scheduled = False
            self._ejecutar_cambio_selector_backtest()

    def _al_cambiar_vencimiento_general(self) -> None:
        """Persiste el vencimiento general y restaura la selección guardada para ese vencimiento."""
        if bool(getattr(self, "_procesando_cambio_vencimiento", False)):
            return
        self._procesando_cambio_vencimiento = True
        try:
            self._aplicar_cambio_vencimiento_general()
        finally:
            self._procesando_cambio_vencimiento = False

    def _aplicar_cambio_vencimiento_general(self) -> None:
        """Aplica el cambio de vencimiento y guarda el estado de la selección actual."""
        # Variable local para vencimiento nuevo.
        venc_nuevo = self.var_vencimiento.get().strip()
        # Variable local para vencimiento anterior.
        venc_anterior = str(getattr(self, "_vencimiento_general_actual", "") or "").strip()
        if venc_anterior:
            self._guardar_estado_vencimiento_actual(venc_anterior)
        if venc_nuevo and venc_nuevo != venc_anterior:
            self._restaurar_estado_vencimiento_ui(venc_nuevo)
        self._vencimiento_general_actual = venc_nuevo
        self._resetear_zoom_smile()
        self._resetear_zoom_gex()
        self._guardar_estado_ui()
        self._refrescar_ui()

    def _al_cambiar_selector_smile(self) -> None:
        """Persiste y refresca las vistas del módulo Smile."""
        self._resetear_zoom_smile()
        self._guardar_estado_ui()
        self._refrescar_ui(forzar=True)

    def _al_cambiar_tab_smile(self, _event=None) -> None:
        """Persiste y refresca la subpestaña activa del módulo Smile."""
        self._guardar_estado_ui()
        self._refrescar_ui(forzar=True)

    def _al_cambiar_selector_comp(self, slot: int) -> None:
        """Persiste y refresca una subvista del comparador 2 bases cuando cambia una base."""
        if slot in self._comp_slots and hasattr(self, "notebook_comp"):
            try:
                self.notebook_comp.select(slot - 1)
            except Exception:
                pass
        self._sincronizar_aliases_comp_activos()
        self._guardar_estado_ui()
        self._invalidar_cache_comparador()
        self._resetear_zoom_comparador()
        self._refrescar_ui(forzar=True)

    def _al_cambiar_selector_tabla_rel(self, slot: int | None = None) -> None:
        """Persiste y refresca la tabla diaria de relaciones entre dos bases."""
        if slot in self._tabla_rel_slots and hasattr(self, "notebook_tabla_rel"):
            try:
                self.notebook_tabla_rel.select(slot - 1)
            except Exception:
                pass
        self._sincronizar_aliases_tabla_rel_activos()
        self._guardar_estado_ui()
        self._refrescar_ui(forzar=True)

    # Devuelve el texto descriptivo para toggle tabla relaciones vega.
    def _texto_toggle_tabla_rel_vega(self, activo: bool) -> str:
        return f"Vega: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_delta_symbol(self, activo: bool) -> str:
        return f"Δ: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_ratio_ab(self, activo: bool) -> str:
        return f"A/B: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_relaciones(self, activo: bool) -> str:
        return f"Relaciones: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_delta(self, activo: bool) -> str:
        return f"δ griega: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_theta(self, activo: bool) -> str:
        return f"Theta: {'ON' if bool(activo) else 'OFF'}"

    def _tabla_rel_ecdf_griegas_strategy_keys(self) -> tuple[str, str, str, str]:
        return ("bull", "spread", "ratio_pos", "ratio_neg")

    def _tabla_rel_ecdf_griegas_strategy_label(self, strategy: str) -> str:
        mapping = {
            "bull": "A+B",
            "spread": "A-B",
            "ratio_pos": "+A-2B",
            "ratio_neg": "-A+2B",
        }
        return mapping.get(str(strategy or "").strip().lower(), str(strategy or ""))

    def _tabla_rel_ecdf_griegas_greek_keys(self) -> tuple[str, str, str]:
        return ("delta", "vega", "theta")

    def _tabla_rel_ecdf_griegas_greek_label(self, greek: str) -> str:
        mapping = {
            "delta": "ECDF DELTA",
            "vega": "ECDF VEGA",
            "theta": "ECDF THETA",
        }
        return mapping.get(str(greek or "").strip().lower(), str(greek or ""))

    def _tabla_rel_ecdf_griegas_strategy_columns(self, strategy: str) -> tuple[str, str, str]:
        strategy_n = str(strategy or "").strip().lower()
        mapping = {
            "bull": ("ecdf_delta_bull", "ecdf_vega_bull", "ecdf_theta_bull"),
            "spread": ("ecdf_delta_spread", "ecdf_vega_spread", "ecdf_theta_spread"),
            "ratio_pos": ("ecdf_delta_ratio_pos_1a2b", "ecdf_vega_ratio_pos_1a2b", "ecdf_theta_ratio_pos_1a2b"),
            "ratio_neg": ("ecdf_delta_ratio_inv_1a2b", "ecdf_vega_ratio_inv_1a2b", "ecdf_theta_ratio_inv_1a2b"),
        }
        return mapping.get(strategy_n, tuple())

    def _tabla_rel_ecdf_griega_strategy_column(self, strategy: str, greek: str) -> str | None:
        greek_n = str(greek or "").strip().lower()
        columnas = self._tabla_rel_ecdf_griegas_strategy_columns(strategy)
        if len(columnas) != 3:
            return None
        idx = {"delta": 0, "vega": 1, "theta": 2}.get(greek_n)
        return columnas[idx] if idx is not None else None

    def _asegurar_estado_ecdf_griegas_estrategia_tabla_rel(self) -> None:
        keys = self._tabla_rel_ecdf_griegas_strategy_keys()
        greek_keys = self._tabla_rel_ecdf_griegas_greek_keys()
        if not hasattr(self, "_tabla_rel_ecdf_griegas_strategy_visible"):
            self._tabla_rel_ecdf_griegas_strategy_visible = {
                modo: {slot: {key: {greek: False for greek in greek_keys} for key in keys} for slot in self._tabla_rel_slots}
                for modo in ("diaria", "intradia")
            }
        if not hasattr(self, "_tabla_rel_ecdf_griegas_strategy_mode"):
            self._tabla_rel_ecdf_griegas_strategy_mode = {
                modo: {slot: {key: "directo" for key in keys} for slot in self._tabla_rel_slots}
                for modo in ("diaria", "intradia")
            }
        for modo in ("diaria", "intradia"):
            self._tabla_rel_ecdf_griegas_strategy_visible.setdefault(modo, {})
            self._tabla_rel_ecdf_griegas_strategy_mode.setdefault(modo, {})
            for slot in self._tabla_rel_slots:
                self._tabla_rel_ecdf_griegas_strategy_visible[modo].setdefault(slot, {})
                self._tabla_rel_ecdf_griegas_strategy_mode[modo].setdefault(slot, {key: "directo" for key in keys})
                for key in keys:
                    actual_visible = self._tabla_rel_ecdf_griegas_strategy_visible[modo][slot].get(key)
                    if isinstance(actual_visible, bool):
                        actual_visible = {greek: bool(actual_visible) for greek in greek_keys}
                    elif not isinstance(actual_visible, dict):
                        actual_visible = {greek: False for greek in greek_keys}
                    for greek in greek_keys:
                        actual_visible[greek] = bool(actual_visible.get(greek, False))
                    self._tabla_rel_ecdf_griegas_strategy_visible[modo][slot][key] = actual_visible
                    modo_actual = str(self._tabla_rel_ecdf_griegas_strategy_mode[modo][slot].get(key) or "directo").strip().lower()
                    self._tabla_rel_ecdf_griegas_strategy_mode[modo][slot][key] = "relacional" if modo_actual.startswith("rel") else "directo"

    def _mostrar_ecdf_griega_estrategia_tabla_rel(self, slot: int, modo: str, strategy: str, greek: str) -> bool:
        self._asegurar_estado_ecdf_griegas_estrategia_tabla_rel()
        modo_n = self._normalizar_modo_tabla_rel(modo)
        strategy_n = str(strategy or "").strip().lower()
        greek_n = str(greek or "").strip().lower()
        return bool(self._tabla_rel_ecdf_griegas_strategy_visible.get(modo_n, {}).get(int(slot or 1), {}).get(strategy_n, {}).get(greek_n, False))

    def _modo_ecdf_griegas_estrategia_tabla_rel(self, slot: int, modo: str, strategy: str) -> str:
        self._asegurar_estado_ecdf_griegas_estrategia_tabla_rel()
        modo_n = self._normalizar_modo_tabla_rel(modo)
        strategy_n = str(strategy or "").strip().lower()
        valor = str(self._tabla_rel_ecdf_griegas_strategy_mode.get(modo_n, {}).get(int(slot or 1), {}).get(strategy_n) or "directo").strip().lower()
        return "relacional" if valor.startswith("rel") else "directo"

    def _set_mostrar_ecdf_griega_estrategia_tabla_rel(self, slot: int, modo: str, strategy: str, greek: str, visible: bool) -> None:
        self._asegurar_estado_ecdf_griegas_estrategia_tabla_rel()
        modo_n = self._normalizar_modo_tabla_rel(modo)
        strategy_n = str(strategy or "").strip().lower()
        greek_n = str(greek or "").strip().lower()
        self._tabla_rel_ecdf_griegas_strategy_visible[modo_n][int(slot or 1)][strategy_n][greek_n] = bool(visible)

    def _set_modo_ecdf_griegas_estrategia_tabla_rel(self, slot: int, modo: str, strategy: str, calc_mode: str) -> None:
        self._asegurar_estado_ecdf_griegas_estrategia_tabla_rel()
        modo_n = self._normalizar_modo_tabla_rel(modo)
        strategy_n = str(strategy or "").strip().lower()
        valor = "relacional" if str(calc_mode or "").strip().lower().startswith("rel") else "directo"
        self._tabla_rel_ecdf_griegas_strategy_mode[modo_n][int(slot or 1)][strategy_n] = valor

    def _toggle_mostrar_ecdf_griega_estrategia_tabla_rel(self, slot: int, modo: str, strategy: str, greek: str) -> None:
        nuevo = not self._mostrar_ecdf_griega_estrategia_tabla_rel(slot, modo, strategy, greek)
        self._set_mostrar_ecdf_griega_estrategia_tabla_rel(slot, modo, strategy, greek, nuevo)
        columna = self._tabla_rel_ecdf_griega_strategy_column(strategy, greek)
        if columna:
            self._set_columna_oculta_manualmente_tabla_rel(slot, columna, modo, False)
        if self._normalizar_modo_tabla_rel(modo) == "intradia":
            self._aplicar_estado_columnas_tabla_rel_intradia(slot)
        else:
            self._aplicar_estado_columnas_tabla_rel(slot)
        self._guardar_estado_ui()

    def _cambiar_modo_ecdf_griegas_estrategia_tabla_rel(self, slot: int, modo: str, strategy: str, calc_mode: str) -> None:
        self._set_modo_ecdf_griegas_estrategia_tabla_rel(slot, modo, strategy, calc_mode)
        if self._normalizar_modo_tabla_rel(modo) == "intradia":
            self._aplicar_estado_columnas_tabla_rel_intradia(slot)
        else:
            self._aplicar_estado_columnas_tabla_rel(slot)
        self._guardar_estado_ui()

    def _agregar_submenu_ecdf_griegas_tabla_rel(self, menu, slot: int, modo: str) -> bool:
        """Agrega al menú contextual opciones de ECDF de griegas para todas las estrategias."""
        self._asegurar_estado_ecdf_griegas_estrategia_tabla_rel()
        modo_n = self._normalizar_modo_tabla_rel(modo)
        submenu_principal = Menu(menu, tearoff=0)
        agregado = False
        for strategy in self._tabla_rel_ecdf_griegas_strategy_keys():
            label_estrategia = self._tabla_rel_ecdf_griegas_strategy_label(strategy)
            submenu_estrategia = Menu(submenu_principal, tearoff=0)
            for greek in self._tabla_rel_ecdf_griegas_greek_keys():
                label_greek = self._tabla_rel_ecdf_griegas_greek_label(greek)
                visible = self._mostrar_ecdf_griega_estrategia_tabla_rel(slot, modo_n, strategy, greek)
                submenu_estrategia.add_checkbutton(
                    label=label_greek,
                    onvalue=True,
                    offvalue=False,
                    variable=BooleanVar(value=visible),
                    command=lambda s=slot, m=modo_n, st=strategy, g=greek: self._toggle_mostrar_ecdf_griega_estrategia_tabla_rel(s, m, st, g),
                )
            submenu_estrategia.add_separator()
            modo_var = StringVar(value=self._modo_ecdf_griegas_estrategia_tabla_rel(slot, modo_n, strategy))
            submenu_estrategia.add_radiobutton(
                label='Cálculo: Directo',
                variable=modo_var,
                value='directo',
                command=lambda s=slot, m=modo_n, st=strategy: self._cambiar_modo_ecdf_griegas_estrategia_tabla_rel(s, m, st, 'directo'),
            )
            submenu_estrategia.add_radiobutton(
                label='Cálculo: Relacional',
                variable=modo_var,
                value='relacional',
                command=lambda s=slot, m=modo_n, st=strategy: self._cambiar_modo_ecdf_griegas_estrategia_tabla_rel(s, m, st, 'relacional'),
            )
            submenu_principal.add_cascade(label=label_estrategia, menu=submenu_estrategia)
            agregado = True
        if agregado:
            menu.add_cascade(label='ECDF griegas', menu=submenu_principal)
        return agregado

    def _estrategia_ecdf_griegas_desde_columna_tabla_rel(self, columna: str) -> str | None:
        col = str(columna or "").strip()
        if not col:
            return None
        mapping = {
            "bull": "ab",
            "spread": "spread",
            "ratio_pos": "ratio_pos",
            "ratio_neg": "ratio_neg",
        }
        for strategy, group in mapping.items():
            columnas = set(self._columnas_por_grupo_tabla_rel(group)) | set(self._tabla_rel_ecdf_griegas_strategy_columns(strategy))
            if col in columnas:
                return strategy
        return None

    def _texto_toggle_tabla_rel_ecdf_griegas(self, activo: bool) -> str:
        return f"ECDF griegas: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_logdelta(self, activo: bool) -> str:
        return f"Log: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_varlog_ndelta(self, activo: bool) -> str:
        return f"ECDF: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_ratio_mode(self, activo: bool) -> str:
        return f"Modo ratio: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_ab(self, activo: bool) -> str:
        return f"A+B: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_spread(self, activo: bool) -> str:
        return f"A-B: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_fill_pct(self, activo: bool) -> str:
        return f"% llenado: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_ratio_pos(self, activo: bool) -> str:
        return f"+A-2B: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_ratio_neg(self, activo: bool) -> str:
        return f"-A+2B: {'ON' if bool(activo) else 'OFF'}"

    def _texto_toggle_tabla_rel_minmax(self, activo: bool) -> str:
        return f"MinMax: {'ON' if bool(activo) else 'OFF'}"

    def _validar_helpers_tablas_relaciones(self) -> None:
        """Verifica que los helpers críticos de tablas de relaciones existan antes de usarlos."""
        requeridos = (
            "_texto_toggle_tabla_rel_calc_mode",
            "_texto_toggle_tabla_rel_ecdf_window_mode",
            "_modo_calculo_relativo_tabla_rel",
            "_modo_ecdf_fijo_tabla_rel",
            "_toggle_tabla_rel_calc_mode",
            "_toggle_tabla_rel_ecdf_window_mode",
            "_enriquecer_probabilidades_tabla_rel",
            "_enriquecer_ln_ecdf_intradia_tabla_rel",
            "_configurar_tags_formato_ecdf_tree",
            "_tag_formato_ecdf_tabla_rel",
            "_tags_visuales_tabla_rel",
            "_actualizar_formato_ecdf_tabla_rel",
        )
        faltantes = [nombre for nombre in requeridos if not callable(getattr(self, nombre, None))]
        if faltantes:
            raise AttributeError(f"Helpers faltantes en tablas de relaciones: {', '.join(faltantes)}")

    def _texto_toggle_tabla_rel_calc_mode(self, modo: str) -> str:
        """Devuelve el texto del botón que define la fuente de cálculo del ECDF."""
        return "Calcula: Relacional" if str(modo).strip().lower().startswith("rel") else "Calcula: Directo"

    def _modo_calculo_relativo_tabla_rel(self, slot: int) -> bool:
        """Indica si la subvista usa el modo relacional para calcular el ECDF."""
        try:
            var = self._tabla_rel_calc_mode_vars.get(slot)
            valor = str(var.get() if var is not None else "directo").strip().lower()
            return valor.startswith("rel")
        except Exception:
            return False

    def _toggle_tabla_rel_calc_mode(self, slot: int) -> None:
        """Alterna el modo de cálculo del ECDF entre directo y relacional."""
        actual = "directo"
        try:
            actual = str(self._tabla_rel_calc_mode_vars[slot].get()).strip().lower()
        except Exception:
            pass
        nuevo = "directo" if actual.startswith("rel") else "relacional"
        self._tabla_rel_calc_mode_vars[slot].set(nuevo)
        self._tabla_rel_calc_mode_button_vars[slot].set(self._texto_toggle_tabla_rel_calc_mode(nuevo))
        try:
            self._guardar_estado_ui()
        except Exception:
            pass
        self._refrescar_ui(forzar=True)

    def _texto_toggle_tabla_rel_ecdf_window_mode(self, modo: str) -> str:
        """Devuelve el texto del botón que alterna entre ECDF dinámico y fijo."""
        return "ECDF: Fija" if str(modo).strip().lower().startswith("fij") else "ECDF: Dinámica"

    def _modo_ecdf_fijo_tabla_rel(self, slot: int) -> bool:
        """Indica si la subvista usa ECDF fijo por fila cerrada en vez de dinámico."""
        try:
            var = self._tabla_rel_ecdf_window_mode_vars.get(slot)
            valor = str(var.get() if var is not None else "dinamica").strip().lower()
            return valor.startswith("fij")
        except Exception:
            return False

    def _toggle_tabla_rel_ecdf_window_mode(self, slot: int) -> None:
        """Alterna el ECDF entre modo dinámico actual y modo fijo acumulado por fila."""
        actual = "dinamica"
        try:
            actual = str(self._tabla_rel_ecdf_window_mode_vars[slot].get()).strip().lower()
        except Exception:
            pass
        nuevo = "fija" if not actual.startswith("fij") else "dinamica"
        self._tabla_rel_ecdf_window_mode_vars[slot].set(nuevo)
        self._tabla_rel_ecdf_window_mode_button_vars[slot].set(self._texto_toggle_tabla_rel_ecdf_window_mode(nuevo))
        try:
            self._guardar_estado_ui()
        except Exception:
            pass
        self._refrescar_ui(forzar=True)

    def _columnas_visibles_tabla_rel(self, slot: int, modo: str = "diaria") -> list[str]:
        """Devuelve las columnas visibles agrupadas por tipo para facilitar la lectura.

        El orden deja juntas las columnas del mismo bloque lógico. Primero aparecen los
        valores base y de estrategia, luego las variaciones Δ, después Ln Δ, luego ECDF,
        luego métricas del modo ratio, después MinMax y finalmente griegas. Dentro de
        cada bloque se respeta siempre el orden: ratio A/B, A+B, A-B, +A-2B, -A+2B.
        """
        mostrar_vega = bool(self._tabla_rel_show_vega_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_delta_simbolo = bool(self._tabla_rel_show_delta_symbol_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_ratio_ab = bool(self._tabla_rel_show_ratio_ab_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_relaciones = bool(self._tabla_rel_show_relaciones_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_delta_griega = bool(self._tabla_rel_show_delta_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_theta = bool(self._tabla_rel_show_theta_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_logdelta = bool(self._tabla_rel_show_logdelta_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_varlog_ndelta = bool(self._tabla_rel_show_varlog_ndelta_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_ratio_mode = bool(self._tabla_rel_show_ratio_mode_vars.get(slot, BooleanVar(value=False)).get())
        mostrar_ab = bool(self._tabla_rel_show_ab_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_spread = bool(self._tabla_rel_show_spread_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_fill_pct = bool(self._tabla_rel_show_fill_pct_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_ratio_pos = bool(self._tabla_rel_show_ratio_pos_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_ratio_neg = bool(self._tabla_rel_show_ratio_neg_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_minmax = bool(self._tabla_rel_show_minmax_vars.get(slot, BooleanVar(value=True)).get())

        alguna_estrategia_activa = any((mostrar_ab, mostrar_spread, mostrar_ratio_pos, mostrar_ratio_neg))
        visibles: list[str] = ["fecha", "precio_a", "precio_b"]

        def agregar(col: str, condicion: bool = True) -> None:
            if condicion and col in self.TABLA_REL_COLUMNAS and col not in visibles:
                visibles.append(col)

        # 1) Valores base y de estrategias, siempre agrupados por tipo.
        agregar("pct_llenado_spread", mostrar_spread and mostrar_fill_pct)
        agregar("ratio_ab", mostrar_ratio_ab)
        agregar("costo_bull", mostrar_ab)
        agregar("a_menos_b_last", mostrar_spread)
        agregar("ratio_pos_1a2b", mostrar_ratio_pos)
        agregar("ratio_inv_1a2b", mostrar_ratio_neg)

        # 2) Cambios Δ de precio entre hoy y ayer, agrupados juntos.
        if mostrar_delta_simbolo:
            agregar("var_dia_ratio_ab", mostrar_ratio_ab)
            agregar("var_dia_bull", mostrar_ab)
            agregar("var_dia_spread", mostrar_spread)
            agregar("var_dia_ratio_pos_1a2b", mostrar_ratio_pos)
            agregar("var_dia_ratio_inv_1a2b", mostrar_ratio_neg)

        # 3) Relaciones hoy/ayer de las estrategias, agrupadas juntas.
        if mostrar_relaciones:
            agregar("rel_ratio_ab", mostrar_ratio_ab)
            agregar("rel_bull", mostrar_ab)
            agregar("rel_spread", mostrar_spread)
            agregar("rel_ratio_pos_1a2b", mostrar_ratio_pos)
            agregar("rel_ratio_inv_1a2b", mostrar_ratio_neg)

        # 4) Log de la diferencia directa entre hoy y ayer.
        if mostrar_logdelta and mostrar_delta_simbolo:
            agregar("logdelta_ratio_ab", mostrar_ratio_ab)
            agregar("logdelta_bull", mostrar_ab)
            agregar("logdelta_spread", mostrar_spread)
            agregar("logdelta_ratio_pos_1a2b", mostrar_ratio_pos)
            agregar("logdelta_ratio_inv_1a2b", mostrar_ratio_neg)

        # 5) Log de las relaciones hoy/ayer.
        if mostrar_logdelta and mostrar_relaciones:
            agregar("logratio_ratio_ab", mostrar_ratio_ab)
            agregar("logratio_bull", mostrar_ab)
            agregar("logratio_spread", mostrar_spread)
            agregar("logratio_ratio_pos_1a2b", mostrar_ratio_pos)
            agregar("logratio_ratio_inv_1a2b", mostrar_ratio_neg)

        # 6) ECDF por estrategia activa. La fuente depende del botón Calcula.
        if mostrar_varlog_ndelta:
            agregar("ecdf_ratio_ab", mostrar_ratio_ab)
            agregar("ecdf_bull", mostrar_ab)
            agregar("ecdf_spread", mostrar_spread)
            agregar("ecdf_ratio_pos_1a2b", mostrar_ratio_pos)
            agregar("ecdf_ratio_inv_1a2b", mostrar_ratio_neg)

        # 7) Bloques del modo ratio, siempre agrupados por subtipo.
        if mostrar_ratio_mode and mostrar_delta_simbolo:
            agregar("var_ratio_bull", mostrar_ab)
            agregar("var_ratio_spread", mostrar_spread)
            agregar("var_ratio_ratio_pos_1a2b", mostrar_ratio_pos)
            agregar("var_ratio_ratio_inv_1a2b", mostrar_ratio_neg)

        # 6) Min/Max, agrupados juntos.
        if mostrar_minmax:
            agregar("minmax_ab_dia", mostrar_ab)
            agregar("minmax_spread_dia", mostrar_spread)
            agregar("minmax_ratio_pos_1a2b_dia", mostrar_ratio_pos)
            agregar("minmax_ratio_inv_1a2b_dia", mostrar_ratio_neg)

        # 7) Griegas solo para las estrategias activas visibles en el momento.
        #    No se muestran ya las griegas individuales de Base A y Base B, porque el
        #    pedido funcional es que estos botones reflejen únicamente las estrategias
        #    activas de la subvista (A+B, A-B, +A-2B y -A+2B).
        if mostrar_delta_griega and alguna_estrategia_activa:
            agregar("delta_bull", mostrar_ab)
            agregar("delta_spread", mostrar_spread)
            agregar("delta_ratio_pos_1a2b", mostrar_ratio_pos)
            agregar("delta_ratio_inv_1a2b", mostrar_ratio_neg)
        if mostrar_vega and alguna_estrategia_activa:
            agregar("vega_bull", mostrar_ab)
            agregar("vega_spread", mostrar_spread)
            agregar("vega_ratio_pos_1a2b", mostrar_ratio_pos)
            agregar("vega_ratio_inv_1a2b", mostrar_ratio_neg)
        if mostrar_theta and alguna_estrategia_activa:
            agregar("theta_bull", mostrar_ab)
            agregar("theta_spread", mostrar_spread)
            agregar("theta_ratio_pos_1a2b", mostrar_ratio_pos)
            agregar("theta_ratio_inv_1a2b", mostrar_ratio_neg)
        for strategy_key, activo_estrategia in (("bull", mostrar_ab), ("spread", mostrar_spread), ("ratio_pos", mostrar_ratio_pos), ("ratio_neg", mostrar_ratio_neg)):
            if not activo_estrategia:
                continue
            for greek_key, col_ecdf_griega in zip(self._tabla_rel_ecdf_griegas_greek_keys(), self._tabla_rel_ecdf_griegas_strategy_columns(strategy_key)):
                if self._mostrar_ecdf_griega_estrategia_tabla_rel(slot, modo, strategy_key, greek_key):
                    agregar(col_ecdf_griega)

        agregar("fuente")
        ocultas_manuales = self._obtener_columnas_ocultas_manualmente_tabla_rel(slot, modo)
        if ocultas_manuales:
            visibles = [col for col in visibles if col not in ocultas_manuales]
        return visibles

    def _normalizar_modo_tabla_rel(self, modo: str) -> str:
        """Normaliza el modo usado para ocultamiento manual de columnas."""
        return "intradia" if str(modo or "").strip().lower() == "intradia" else "diaria"

    def _obtener_columnas_ocultas_manualmente_tabla_rel(self, slot: int, modo: str) -> set[str]:
        """Devuelve el conjunto de columnas ocultas manualmente en una subvista."""
        modo_norm = self._normalizar_modo_tabla_rel(modo)
        return set(self._tabla_rel_manual_hidden_columns.get(modo_norm, {}).get(int(slot or 1), set()))

    def _set_columna_oculta_manualmente_tabla_rel(self, slot: int, columna: str, modo: str, oculta: bool) -> None:
        """Marca o desmarca una columna como ocultada manualmente en una subvista."""
        col = str(columna or "").strip()
        if col not in self.TABLA_REL_COLUMNAS:
            return
        modo_norm = self._normalizar_modo_tabla_rel(modo)
        self._tabla_rel_manual_hidden_columns.setdefault(modo_norm, {}).setdefault(int(slot or 1), set())
        ocultas = self._tabla_rel_manual_hidden_columns[modo_norm][int(slot or 1)]
        if oculta:
            ocultas.add(col)
        else:
            ocultas.discard(col)

    def _columnas_por_grupo_tabla_rel(self, grupo: str) -> set[str]:
        """Lista las columnas afectadas por cada botón de visibilidad."""
        grupo_norm = str(grupo or "").strip().lower()
        mapa = {
            "vega": {"vega_a", "vega_b", "vega_bull", "vega_spread", "vega_ratio_pos_1a2b", "vega_ratio_inv_1a2b"},
            "delta_symbol": {"var_dia_ratio_ab", "var_dia_bull", "var_dia_spread", "var_dia_ratio_pos_1a2b", "var_dia_ratio_inv_1a2b"},
            "ratio_ab": {"ratio_ab", "var_dia_ratio_ab", "rel_ratio_ab", "logdelta_ratio_ab", "logratio_ratio_ab", "ecdf_ratio_ab"},
            "relaciones": {"rel_ratio_ab", "rel_bull", "rel_spread", "rel_ratio_pos_1a2b", "rel_ratio_inv_1a2b"},
            "delta": {"delta_a", "delta_b", "delta_bull", "delta_spread", "delta_ratio_pos_1a2b", "delta_ratio_inv_1a2b"},
            "theta": {"theta_bull", "theta_spread", "theta_ratio_pos_1a2b", "theta_ratio_inv_1a2b"},
            "logdelta": {"logdelta_ratio_ab", "logdelta_bull", "logdelta_spread", "logdelta_ratio_pos_1a2b", "logdelta_ratio_inv_1a2b", "logratio_ratio_ab", "logratio_bull", "logratio_spread", "logratio_ratio_pos_1a2b", "logratio_ratio_inv_1a2b"},
            "varlog_ndelta": {"ecdf_ratio_ab", "ecdf_bull", "ecdf_spread", "ecdf_ratio_pos_1a2b", "ecdf_ratio_inv_1a2b"},
            "ratio_mode": {"var_ratio_bull", "var_ratio_spread", "var_ratio_ratio_pos_1a2b", "var_ratio_ratio_inv_1a2b"},
            "ab": {"costo_bull", "var_dia_bull", "rel_bull", "logdelta_bull", "logratio_bull", "ecdf_bull", "var_ratio_bull", "minmax_ab_dia", "delta_bull", "vega_bull", "theta_bull", "ecdf_delta_bull", "ecdf_vega_bull", "ecdf_theta_bull"},
            "spread": {"a_menos_b_last", "pct_llenado_spread", "var_dia_spread", "rel_spread", "logdelta_spread", "logratio_spread", "ecdf_spread", "var_ratio_spread", "minmax_spread_dia", "delta_spread", "vega_spread", "theta_spread", "ecdf_delta_spread", "ecdf_vega_spread", "ecdf_theta_spread"},
            "fill_pct": {"pct_llenado_spread"},
            "ratio_pos": {"ratio_pos_1a2b", "var_dia_ratio_pos_1a2b", "rel_ratio_pos_1a2b", "logdelta_ratio_pos_1a2b", "logratio_ratio_pos_1a2b", "ecdf_ratio_pos_1a2b", "var_ratio_ratio_pos_1a2b", "minmax_ratio_pos_1a2b_dia", "delta_ratio_pos_1a2b", "vega_ratio_pos_1a2b", "theta_ratio_pos_1a2b", "ecdf_delta_ratio_pos_1a2b", "ecdf_vega_ratio_pos_1a2b", "ecdf_theta_ratio_pos_1a2b"},
            "ratio_neg": {"ratio_inv_1a2b", "var_dia_ratio_inv_1a2b", "rel_ratio_inv_1a2b", "logdelta_ratio_inv_1a2b", "logratio_ratio_inv_1a2b", "ecdf_ratio_inv_1a2b", "var_ratio_ratio_inv_1a2b", "minmax_ratio_inv_1a2b_dia", "delta_ratio_inv_1a2b", "vega_ratio_inv_1a2b", "theta_ratio_inv_1a2b", "ecdf_delta_ratio_inv_1a2b", "ecdf_vega_ratio_inv_1a2b", "ecdf_theta_ratio_inv_1a2b"},
            "minmax": {"minmax_ab_dia", "minmax_spread_dia", "minmax_ratio_pos_1a2b_dia", "minmax_ratio_inv_1a2b_dia"},
        }
        return {col for col in mapa.get(grupo_norm, set()) if col in self.TABLA_REL_COLUMNAS}

    def _resetear_ocultamiento_manual_tabla_rel(self, slot: int, grupo: str | None = None) -> None:
        """Limpia el ocultamiento manual de una subvista, total o por grupo de botón."""
        columnas_objetivo = self._columnas_por_grupo_tabla_rel(grupo) if grupo else set(self.TABLA_REL_COLUMNAS)
        for modo_norm in ("diaria", "intradia"):
            ocultas = self._tabla_rel_manual_hidden_columns.setdefault(modo_norm, {}).setdefault(int(slot or 1), set())
            if grupo:
                ocultas.difference_update(columnas_objetivo)
            else:
                ocultas.clear()

    def _toggle_ocultamiento_manual_columna_tabla_rel(self, slot: int, columna: str, modo: str) -> None:
        """Alterna el ocultamiento manual de una columna en la subvista indicada."""
        col = str(columna or "").strip()
        if col not in self.TABLA_REL_COLUMNAS:
            return
        modo_norm = self._normalizar_modo_tabla_rel(modo)
        ocultas = self._obtener_columnas_ocultas_manualmente_tabla_rel(slot, modo_norm)
        self._set_columna_oculta_manualmente_tabla_rel(slot, col, modo_norm, col not in ocultas)
        if modo_norm == "intradia":
            self._aplicar_estado_columnas_tabla_rel_intradia(slot)
        else:
            self._aplicar_estado_columnas_tabla_rel(slot)
        self._guardar_estado_ui()

    def _exportar_distribucion_columnas_tabla_rel(self, slot: int, modo: str) -> dict[str, Any]:
        """Serializa la distribución visible de columnas de la vista actual."""
        modo_norm = self._normalizar_modo_tabla_rel(modo)
        self._sincronizar_layout_tablas_relaciones_desde_widgets()
        self._asegurar_estado_ecdf_griegas_estrategia_tabla_rel()
        return {
            "modo": modo_norm,
            "orden_columnas": list(self._tabla_rel_column_order_vars.get(slot, list(self.TABLA_REL_COLUMNAS))),
            "anchos_columnas": dict(self._tabla_rel_column_width_vars.get(modo_norm, {}).get(slot, {})),
            "ocultas_manuales": sorted(self._obtener_columnas_ocultas_manualmente_tabla_rel(slot, modo_norm)),
            "grupos": {
                "vega": bool(self._tabla_rel_show_vega_vars[slot].get()),
                "delta_symbol": bool(self._tabla_rel_show_delta_symbol_vars[slot].get()),
                "ratio_ab": bool(self._tabla_rel_show_ratio_ab_vars[slot].get()),
                "relaciones": bool(self._tabla_rel_show_relaciones_vars[slot].get()),
                "delta": bool(self._tabla_rel_show_delta_vars[slot].get()),
                "theta": bool(self._tabla_rel_show_theta_vars[slot].get()),
                "ecdf_griegas": bool(self._tabla_rel_show_ecdf_griegas_vars[slot].get()),
                "logdelta": bool(self._tabla_rel_show_logdelta_vars[slot].get()),
                "varlog_ndelta": bool(self._tabla_rel_show_varlog_ndelta_vars[slot].get()),
                "ratio_mode": bool(self._tabla_rel_show_ratio_mode_vars[slot].get()),
                "ab": bool(self._tabla_rel_show_ab_vars[slot].get()),
                "spread": bool(self._tabla_rel_show_spread_vars[slot].get()),
                "fill_pct": bool(self._tabla_rel_show_fill_pct_vars[slot].get()),
                "ratio_pos": bool(self._tabla_rel_show_ratio_pos_vars[slot].get()),
                "ratio_neg": bool(self._tabla_rel_show_ratio_neg_vars[slot].get()),
                "minmax": bool(self._tabla_rel_show_minmax_vars[slot].get()),
            },
            "ecdf_griegas_visible": deepcopy(self._tabla_rel_ecdf_griegas_strategy_visible.get(modo_norm, {}).get(slot, {})),
            "ecdf_griegas_modo": dict(self._tabla_rel_ecdf_griegas_strategy_mode.get(modo_norm, {}).get(slot, {})),
        }

    def _copiar_distribucion_columnas_tabla_rel(self, slot: int, modo: str) -> None:
        """Copia la distribución actual de columnas para pegarla en otra subvista."""
        self._tabla_rel_column_layout_clipboard = self._exportar_distribucion_columnas_tabla_rel(slot, modo)
        modo_norm = self._normalizar_modo_tabla_rel(modo)
        self.var_estado.set(f"Estado: distribución de columnas copiada ({modo_norm})")

    def _pegar_distribucion_columnas_tabla_rel(self, slot: int, modo: str) -> None:
        """Pega sobre la subvista actual la distribución de columnas copiada."""
        payload = getattr(self, '_tabla_rel_column_layout_clipboard', None)
        if not isinstance(payload, dict):
            try:
                messagebox.showinfo('Columnas', 'Primero copiá una distribución de columnas desde otra subvista.')
            except Exception:
                pass
            return
        modo_norm = self._normalizar_modo_tabla_rel(modo)
        grupos = payload.get('grupos') if isinstance(payload.get('grupos'), dict) else {}
        self._tabla_rel_show_vega_vars[slot].set(bool(grupos.get('vega', self._tabla_rel_show_vega_vars[slot].get())))
        self._tabla_rel_show_vega_button_vars[slot].set(self._texto_toggle_tabla_rel_vega(bool(self._tabla_rel_show_vega_vars[slot].get())))
        self._tabla_rel_show_delta_symbol_vars[slot].set(bool(grupos.get('delta_symbol', self._tabla_rel_show_delta_symbol_vars[slot].get())))
        self._tabla_rel_show_delta_symbol_button_vars[slot].set(self._texto_toggle_tabla_rel_delta_symbol(bool(self._tabla_rel_show_delta_symbol_vars[slot].get())))
        self._tabla_rel_show_ratio_ab_vars[slot].set(bool(grupos.get('ratio_ab', self._tabla_rel_show_ratio_ab_vars[slot].get())))
        self._tabla_rel_show_ratio_ab_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_ab(bool(self._tabla_rel_show_ratio_ab_vars[slot].get())))
        self._tabla_rel_show_relaciones_vars[slot].set(bool(grupos.get('relaciones', self._tabla_rel_show_relaciones_vars[slot].get())))
        self._tabla_rel_show_relaciones_button_vars[slot].set(self._texto_toggle_tabla_rel_relaciones(bool(self._tabla_rel_show_relaciones_vars[slot].get())))
        self._tabla_rel_show_delta_vars[slot].set(bool(grupos.get('delta', self._tabla_rel_show_delta_vars[slot].get())))
        self._tabla_rel_show_delta_button_vars[slot].set(self._texto_toggle_tabla_rel_delta(bool(self._tabla_rel_show_delta_vars[slot].get())))
        self._tabla_rel_show_theta_vars[slot].set(bool(grupos.get('theta', self._tabla_rel_show_theta_vars[slot].get())))
        self._tabla_rel_show_theta_button_vars[slot].set(self._texto_toggle_tabla_rel_theta(bool(self._tabla_rel_show_theta_vars[slot].get())))
        self._tabla_rel_show_ecdf_griegas_vars[slot].set(bool(grupos.get('ecdf_griegas', self._tabla_rel_show_ecdf_griegas_vars[slot].get())))
        self._tabla_rel_show_ecdf_griegas_button_vars[slot].set(self._texto_toggle_tabla_rel_ecdf_griegas(bool(self._tabla_rel_show_ecdf_griegas_vars[slot].get())))
        self._tabla_rel_show_logdelta_vars[slot].set(bool(grupos.get('logdelta', self._tabla_rel_show_logdelta_vars[slot].get())))
        self._tabla_rel_show_logdelta_button_vars[slot].set(self._texto_toggle_tabla_rel_logdelta(bool(self._tabla_rel_show_logdelta_vars[slot].get())))
        self._tabla_rel_show_varlog_ndelta_vars[slot].set(bool(grupos.get('varlog_ndelta', self._tabla_rel_show_varlog_ndelta_vars[slot].get())))
        self._tabla_rel_show_varlog_ndelta_button_vars[slot].set(self._texto_toggle_tabla_rel_varlog_ndelta(bool(self._tabla_rel_show_varlog_ndelta_vars[slot].get())))
        self._tabla_rel_show_ratio_mode_vars[slot].set(bool(grupos.get('ratio_mode', self._tabla_rel_show_ratio_mode_vars[slot].get())))
        self._tabla_rel_show_ratio_mode_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_mode(bool(self._tabla_rel_show_ratio_mode_vars[slot].get())))
        self._tabla_rel_show_ab_vars[slot].set(bool(grupos.get('ab', self._tabla_rel_show_ab_vars[slot].get())))
        self._tabla_rel_show_ab_button_vars[slot].set(self._texto_toggle_tabla_rel_ab(bool(self._tabla_rel_show_ab_vars[slot].get())))
        self._tabla_rel_show_spread_vars[slot].set(bool(grupos.get('spread', self._tabla_rel_show_spread_vars[slot].get())))
        self._tabla_rel_show_spread_button_vars[slot].set(self._texto_toggle_tabla_rel_spread(bool(self._tabla_rel_show_spread_vars[slot].get())))
        self._tabla_rel_show_fill_pct_vars[slot].set(bool(grupos.get('fill_pct', self._tabla_rel_show_fill_pct_vars[slot].get())))
        self._tabla_rel_show_fill_pct_button_vars[slot].set(self._texto_toggle_tabla_rel_fill_pct(bool(self._tabla_rel_show_fill_pct_vars[slot].get())))
        self._tabla_rel_show_ratio_pos_vars[slot].set(bool(grupos.get('ratio_pos', self._tabla_rel_show_ratio_pos_vars[slot].get())))
        self._tabla_rel_show_ratio_pos_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_pos(bool(self._tabla_rel_show_ratio_pos_vars[slot].get())))
        self._tabla_rel_show_ratio_neg_vars[slot].set(bool(grupos.get('ratio_neg', self._tabla_rel_show_ratio_neg_vars[slot].get())))
        self._tabla_rel_show_ratio_neg_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_neg(bool(self._tabla_rel_show_ratio_neg_vars[slot].get())))
        self._tabla_rel_show_minmax_vars[slot].set(bool(grupos.get('minmax', self._tabla_rel_show_minmax_vars[slot].get())))
        self._tabla_rel_show_minmax_button_vars[slot].set(self._texto_toggle_tabla_rel_minmax(bool(self._tabla_rel_show_minmax_vars[slot].get())))
        columnas = [str(col) for col in payload.get('orden_columnas', []) if str(col) in self.TABLA_REL_COLUMNAS]
        if columnas:
            faltantes = [col for col in self.TABLA_REL_COLUMNAS if col not in columnas]
            self._tabla_rel_column_order_vars[slot] = columnas + faltantes
        anchos_payload = self._normalizar_anchos_columnas_tabla_rel(payload.get('anchos_columnas'))
        if anchos_payload:
            self._tabla_rel_column_width_vars.setdefault(modo_norm, {}).setdefault(slot, {})
            self._tabla_rel_column_width_vars[modo_norm][slot].update(anchos_payload)
        ocultas = {str(col) for col in payload.get('ocultas_manuales', []) if str(col) in self.TABLA_REL_COLUMNAS}
        self._tabla_rel_manual_hidden_columns.setdefault(modo_norm, {}).setdefault(slot, set())
        self._tabla_rel_manual_hidden_columns[modo_norm][slot] = ocultas
        self._asegurar_estado_ecdf_griegas_estrategia_tabla_rel()
        visibles_ecdf = payload.get('ecdf_griegas_visible') if isinstance(payload.get('ecdf_griegas_visible'), dict) else {}
        for strategy in self._tabla_rel_ecdf_griegas_strategy_keys():
            for greek in self._tabla_rel_ecdf_griegas_greek_keys():
                visible = bool(((visibles_ecdf.get(strategy) or {}) if isinstance(visibles_ecdf.get(strategy), dict) else {}).get(greek, False))
                self._tabla_rel_ecdf_griegas_strategy_visible[modo_norm][slot][strategy][greek] = visible
        modos_ecdf = payload.get('ecdf_griegas_modo') if isinstance(payload.get('ecdf_griegas_modo'), dict) else {}
        for strategy in self._tabla_rel_ecdf_griegas_strategy_keys():
            modo_calc = str(modos_ecdf.get(strategy) or 'directo').strip().lower()
            self._tabla_rel_ecdf_griegas_strategy_mode[modo_norm][slot][strategy] = 'relacional' if modo_calc.startswith('rel') else 'directo'
        if modo_norm == 'intradia':
            self._aplicar_estado_columnas_tabla_rel_intradia(slot)
        else:
            self._aplicar_estado_columnas_tabla_rel(slot)
        self._guardar_estado_ui()
        self.var_estado.set(f"Estado: distribución de columnas pegada en subvista {slot} ({modo_norm})")

    def _aplicar_estado_columnas_tabla_rel(self, slot: int) -> None:
        """Muestra/oculta vega y respeta el orden manual de columnas en la subvista indicada."""
        # Variable local para widgets.
        widgets = self._tabla_rel_widgets.get(slot, {})
        # Variable local para tree.
        tree = widgets.get("tree")
        if tree is None:
            return
        # Variable local para visibles.
        visibles = self._columnas_visibles_tabla_rel(slot, modo="diaria")
        if isinstance(tree, SheetTableAdapter):
            tree.begin_bulk_update()
        try:
            try:
                tree.configure(displaycolumns=tuple(visibles))
            except Exception:
                LOGGER.debug("No se pudo aplicar el estado de columnas de Tabla relaciones", exc_info=True)
            self._aplicar_anchos_columnas_tabla_rel(tree, slot, "diaria")
            # Variable local para seleccionadas.
            seleccionadas = [col for col in self._tabla_rel_selected_plot_cols.get(slot, []) if col in visibles and self._columna_graficable_tabla_rel(col)]
            self._tabla_rel_selected_plot_cols[slot] = seleccionadas
            self._actualizar_headings_tree(tree)
        finally:
            if isinstance(tree, SheetTableAdapter):
                tree.end_bulk_update(refresh=True)

    def _registrar_tree_reordenable_tabla_rel(self, tree, slot: int) -> None:
        """Habilita drag and drop sobre encabezados para reordenar columnas."""
        self._tabla_rel_tree_slot_by_key[self._tree_sort_key(tree)] = slot
        tree.bind("<ButtonPress-1>", lambda e, t=tree, s=slot: self._on_tabla_rel_heading_press(e, t, s), add="+")
        tree.bind("<B1-Motion>", lambda e, t=tree, s=slot: self._on_tabla_rel_heading_drag(e, t, s), add="+")
        tree.bind("<ButtonRelease-1>", lambda e, t=tree, s=slot: self._on_tabla_rel_heading_release(e, t, s), add="+")
        tree.bind("<Control-ButtonPress-1>", lambda e, t=tree, s=slot: self._on_tabla_rel_heading_ctrl_select(e, t, s), add="+")
        tree.bind("<Button-3>", lambda e, t=tree, s=slot: self._on_tabla_rel_heading_right_click(e, t, s), add="+")

    # Reinicia el estado de drag tabla relaciones columnas.
    def _resetear_drag_tabla_rel_columnas(self) -> None:
        self._drag_tabla_rel_column_tree = None
        self._drag_tabla_rel_column_slot = None
        self._drag_tabla_rel_column_name = None
        self._drag_tabla_rel_column_start_xy = None
        self._drag_tabla_rel_column_moved = False

    # Identifica r columna visible tabla relaciones.
    def _identificar_columna_visible_tabla_rel(self, tree, slot: int, x: int) -> str | None:
        if tree.identify_region(x, 4) != "heading":
            return None
        # Variable local para identificador.
        identificador = str(tree.identify_column(x) or "")
        if not identificador.startswith("#"):
            return None
        try:
            # Variable local para idx.
            idx = int(identificador[1:]) - 1
        except Exception:
            return None
        # Variable local para visibles.
        visibles = list(getattr(tree, '_displaycolumns', []) or []) if isinstance(tree, SheetTableAdapter) else self._columnas_visibles_tabla_rel(slot)
        if not visibles:
            visibles = self._columnas_visibles_tabla_rel(slot)
        if 0 <= idx < len(visibles):
            return visibles[idx]
        return None

    # Reordena o mueve columna tabla relaciones.
    def _mover_columna_tabla_rel(self, slot: int, source_col: str, target_col: str) -> bool:
        if source_col == target_col:
            return False
        # Variable local para orden.
        orden = list(self._tabla_rel_column_order_vars.get(slot, list(self.TABLA_REL_COLUMNAS)))
        orden = [col for col in orden if col in self.TABLA_REL_COLUMNAS]
        for col in self.TABLA_REL_COLUMNAS:
            if col not in orden:
                orden.append(col)
        if source_col not in orden or target_col not in orden:
            return False
        # Variable local para origen.
        origen = orden.index(source_col)
        # Variable local para destino.
        destino = orden.index(target_col)
        # Variable local para col.
        col = orden.pop(origen)
        if origen < destino:
            destino -= 1
        orden.insert(destino, col)
        self._tabla_rel_column_order_vars[slot] = orden
        self._aplicar_estado_columnas_tabla_rel(slot)
        return True

    # Maneja el evento tabla relaciones heading press.
    def _on_tabla_rel_heading_press(self, event, tree, slot: int):
        if tree.identify_region(event.x, event.y) != "heading":
            self._resetear_drag_tabla_rel_columnas()
            return None
        # Variable local para columna.
        columna = self._identificar_columna_visible_tabla_rel(tree, slot, int(event.x))
        if not columna:
            self._resetear_drag_tabla_rel_columnas()
            return None
        self._drag_tabla_rel_column_tree = tree
        self._drag_tabla_rel_column_slot = slot
        self._drag_tabla_rel_column_name = columna
        self._drag_tabla_rel_column_start_xy = (int(event.x), int(event.y))
        self._drag_tabla_rel_column_moved = False
        return None

    # Maneja el evento tabla relaciones heading drag.
    def _on_tabla_rel_heading_drag(self, event, tree, slot: int):
        if self._drag_tabla_rel_column_tree is not tree or self._drag_tabla_rel_column_slot != slot:
            return None
        if self._drag_tabla_rel_column_name is None or self._drag_tabla_rel_column_start_xy is None:
            return None
        # Variable local para dx.
        dx = abs(int(event.x) - int(self._drag_tabla_rel_column_start_xy[0]))
        # Variable local para dy.
        dy = abs(int(event.y) - int(self._drag_tabla_rel_column_start_xy[1]))
        if not self._drag_tabla_rel_column_moved and max(dx, dy) < 8:
            return None
        # Variable local para target col.
        target_col = self._identificar_columna_visible_tabla_rel(tree, slot, int(event.x))
        if not target_col or target_col == self._drag_tabla_rel_column_name:
            return None
        if self._mover_columna_tabla_rel(slot, self._drag_tabla_rel_column_name, target_col):
            self._drag_tabla_rel_column_name = target_col
            self._drag_tabla_rel_column_moved = True
        return "break"

    # Maneja el evento tabla relaciones heading release.
    def _on_tabla_rel_heading_release(self, event, tree, slot: int):
        if self._drag_tabla_rel_column_tree is not tree or self._drag_tabla_rel_column_slot != slot:
            self._resetear_drag_tabla_rel_columnas()
            return None
        # Variable local para movio.
        movio = bool(self._drag_tabla_rel_column_moved)
        self._resetear_drag_tabla_rel_columnas()
        if movio:
            self._guardar_estado_ui()
            return "break"
        if getattr(event, 'state', 0) & 0x0004:
            return "break"
        if hasattr(tree, 'invoke_heading_command'):
            try:
                tree.invoke_heading_command(int(event.x))
                return "break"
            except Exception:
                LOGGER.exception('No se pudo ejecutar el orden de encabezado sobre tksheet')
                return None
        return None

    # Devuelve información auxiliar sobre la columna graficable tabla relaciones.
    def _columna_graficable_tabla_rel(self, columna: str) -> bool:
        return str(columna or "") not in {"", "fecha", "fuente"}

    # Alterna el estado de seleccion columna tabla relaciones plot.
    def _toggle_seleccion_columna_tabla_rel_plot(self, slot: int, columna: str) -> None:
        if not self._columna_graficable_tabla_rel(columna):
            return
        # Variable local para seleccionadas.
        seleccionadas = list(self._tabla_rel_selected_plot_cols.get(slot, []))
        if columna in seleccionadas:
            seleccionadas.remove(columna)
        else:
            seleccionadas.append(columna)
        self._tabla_rel_selected_plot_cols[slot] = seleccionadas
        for widgets in (self._tabla_rel_widgets.get(slot) or {}, self._intradia_rel_widgets.get(slot) or {}):
            tree = widgets.get("tree")
            if tree is not None:
                self._actualizar_headings_tree(tree)
        popup = self._tabla_rel_plot_windows.get(slot)
        if popup and popup.get("window") is not None and seleccionadas:
            popup["cols"] = list(seleccionadas)
            self._refrescar_popup_grafico_tabla_rel(slot)
        popup_intradia = self._tabla_rel_intradia_plot_windows.get(slot)
        if popup_intradia and popup_intradia.get("window") is not None and seleccionadas:
            popup_intradia["cols"] = list(seleccionadas)
            self._refrescar_popup_grafico_tabla_rel_intradia(slot)

    # Limpia el estado asociado a seleccion columnas tabla relaciones plot.
    def _limpiar_seleccion_columnas_tabla_rel_plot(self, slot: int) -> None:
        self._tabla_rel_selected_plot_cols[slot] = []
        for widgets in (self._tabla_rel_widgets.get(slot) or {}, self._intradia_rel_widgets.get(slot) or {}):
            tree = widgets.get("tree")
            if tree is not None:
                self._actualizar_headings_tree(tree)

    # Maneja el evento tabla relaciones heading ctrl select.
    def _on_tabla_rel_heading_ctrl_select(self, event, tree, slot: int):
        if tree.identify_region(event.x, event.y) != "heading":
            return None
        # Variable local para columna.
        columna = self._identificar_columna_visible_tabla_rel(tree, slot, int(event.x))
        if not columna:
            return None
        self._toggle_seleccion_columna_tabla_rel_plot(slot, columna)
        return "break"

    # Maneja el evento tabla relaciones heading right click.
    def _on_tabla_rel_heading_right_click(self, event, tree, slot: int):
        if tree.identify_region(event.x, event.y) != "heading":
            return None
        # Variable local para columna.
        columna = self._identificar_columna_visible_tabla_rel(tree, slot, int(event.x))
        # Variable local para menu.
        menu = Menu(tree, tearoff=0)
        # Variable local para seleccionadas.
        seleccionadas = list(self._tabla_rel_selected_plot_cols.get(slot, []))
        textos = self._tree_heading_texts.get(self._tree_sort_key(tree), {})
        if columna:
            etiqueta_col = textos.get(columna, columna)
            menu.add_command(label=f"Ocultar columna: {etiqueta_col}", command=lambda s=slot, c=columna: self._toggle_ocultamiento_manual_columna_tabla_rel(s, c, 'diaria'))
            if self._columna_graficable_tabla_rel(columna):
                accion = "Quitar" if columna in seleccionadas else "Seleccionar"
                menu.add_command(label=f"{accion} columna: {etiqueta_col}", command=lambda s=slot, c=columna: self._toggle_seleccion_columna_tabla_rel_plot(s, c))
            menu.add_separator()
        ocultas = sorted(self._obtener_columnas_ocultas_manualmente_tabla_rel(slot, 'diaria'))
        if ocultas:
            submenu = Menu(menu, tearoff=0)
            for col_oculta in ocultas:
                etiqueta_oculta = textos.get(col_oculta, col_oculta)
                submenu.add_command(label=etiqueta_oculta, command=lambda s=slot, c=col_oculta: self._toggle_ocultamiento_manual_columna_tabla_rel(s, c, 'diaria'))
            menu.add_cascade(label="Mostrar columna oculta", menu=submenu)
            menu.add_separator()
        if self._agregar_submenu_ecdf_griegas_tabla_rel(menu, slot, 'diaria'):
            menu.add_separator()
        menu.add_command(label="Copiar distribución visible", command=lambda s=slot: self._copiar_distribucion_columnas_tabla_rel(s, 'diaria'))
        menu.add_command(label="Pegar distribución visible", command=lambda s=slot: self._pegar_distribucion_columnas_tabla_rel(s, 'diaria'), state=("normal" if getattr(self, '_tabla_rel_column_layout_clipboard', None) else "disabled"))
        menu.add_separator()
        # Variable local para puede graficar.
        puede_graficar = len(seleccionadas) >= 1
        if puede_graficar:
            if len(seleccionadas) == 1:
                # Variable local para label graf.
                label_graf = f"Graficar: {textos.get(seleccionadas[0], seleccionadas[0])}"
            elif len(seleccionadas) == 2:
                a, b = seleccionadas
                label_graf = f"Graficar: {textos.get(a, a)} vs {textos.get(b, b)}"
            else:
                label_graf = f"Graficar {len(seleccionadas)} columnas seleccionadas"
            menu.add_command(label=label_graf, command=lambda s=slot: self._abrir_popup_grafico_tabla_rel(s))
        else:
            menu.add_command(label="Graficar columnas seleccionadas", state="disabled")
        menu.add_command(label="Limpiar selección", command=lambda s=slot: self._limpiar_seleccion_columnas_tabla_rel_plot(s))
        menu.add_separator()
        menu.add_command(label="Tip: botón resetea ocultas del grupo", state="disabled")
        try:
            menu.tk_popup(event.x_root, event.y_root)
        finally:
            try:
                menu.grab_release()
            except Exception:
                pass
        return "break"


    def _identificar_columna_visible_tabla_rel_intradia(self, tree, slot: int, x: int, event=None) -> str | None:
        """Identifica la columna visible de la tabla de relaciones intradía."""
        if event is None and tree.identify_region(x, 4) != "heading":
            return None
        if event is not None and tree.identify_region(event.x, event.y) != "heading":
            return None
        if isinstance(tree, SheetTableAdapter) and event is not None and hasattr(tree, 'identify_column_from_event'):
            identificador = str(tree.identify_column_from_event(event) or "")
        else:
            identificador = str(tree.identify_column(x) or "")
        if not identificador.startswith("#"):
            return None
        try:
            idx = int(identificador[1:]) - 1
        except Exception:
            return None
        visibles = list(getattr(tree, '_displaycolumns', []) or []) if isinstance(tree, SheetTableAdapter) else self._columnas_visibles_tabla_rel_intradia(slot)
        if not visibles:
            visibles = self._columnas_visibles_tabla_rel_intradia(slot)
        if 0 <= idx < len(visibles):
            return visibles[idx]
        return None

    def _on_tabla_rel_intradia_heading_ctrl_select(self, event, tree, slot: int):
        if tree.identify_region(event.x, event.y) != "heading":
            return None
        columna = self._identificar_columna_visible_tabla_rel_intradia(tree, slot, int(event.x), event=event)
        if not columna:
            return None
        self._toggle_seleccion_columna_tabla_rel_plot(slot, columna)
        return "break"

    def _on_tabla_rel_intradia_heading_right_click(self, event, tree, slot: int):
        if tree.identify_region(event.x, event.y) != "heading":
            return None
        columna = self._identificar_columna_visible_tabla_rel_intradia(tree, slot, int(event.x), event=event)
        menu = Menu(tree, tearoff=0)
        seleccionadas = list(self._tabla_rel_selected_plot_cols.get(slot, []))
        textos = self._tree_heading_texts.get(self._tree_sort_key(tree), {})
        if columna:
            etiqueta_col = textos.get(columna, columna)
            menu.add_command(label=f"Ocultar columna: {etiqueta_col}", command=lambda s=slot, c=columna: self._toggle_ocultamiento_manual_columna_tabla_rel(s, c, 'intradia'))
            if self._columna_graficable_tabla_rel(columna):
                accion = "Quitar" if columna in seleccionadas else "Seleccionar"
                menu.add_command(label=f"{accion} columna: {etiqueta_col}", command=lambda s=slot, c=columna: self._toggle_seleccion_columna_tabla_rel_plot(s, c))
            menu.add_separator()
        ocultas = sorted(self._obtener_columnas_ocultas_manualmente_tabla_rel(slot, 'intradia'))
        if ocultas:
            submenu = Menu(menu, tearoff=0)
            for col_oculta in ocultas:
                etiqueta_oculta = textos.get(col_oculta, col_oculta)
                submenu.add_command(label=etiqueta_oculta, command=lambda s=slot, c=col_oculta: self._toggle_ocultamiento_manual_columna_tabla_rel(s, c, 'intradia'))
            menu.add_cascade(label="Mostrar columna oculta", menu=submenu)
            menu.add_separator()
        if self._agregar_submenu_ecdf_griegas_tabla_rel(menu, slot, 'intradia'):
            menu.add_separator()
        menu.add_command(label="Copiar distribución visible", command=lambda s=slot: self._copiar_distribucion_columnas_tabla_rel(s, 'intradia'))
        menu.add_command(label="Pegar distribución visible", command=lambda s=slot: self._pegar_distribucion_columnas_tabla_rel(s, 'intradia'), state=("normal" if getattr(self, '_tabla_rel_column_layout_clipboard', None) else "disabled"))
        menu.add_separator()
        if seleccionadas:
            if len(seleccionadas) == 1:
                label_graf = f"Graficar: {textos.get(seleccionadas[0], seleccionadas[0])}"
            elif len(seleccionadas) == 2:
                a, b = seleccionadas[:2]
                label_graf = f"Graficar: {textos.get(a, a)} vs {textos.get(b, b)}"
            else:
                label_graf = f"Graficar {len(seleccionadas)} columnas seleccionadas"
            menu.add_command(label=label_graf, command=lambda s=slot: self._abrir_popup_grafico_tabla_rel_intradia(s))
        else:
            menu.add_command(label="Graficar columnas seleccionadas", state="disabled")
        menu.add_command(label="Limpiar selección", command=lambda s=slot: self._limpiar_seleccion_columnas_tabla_rel_plot(s))
        menu.add_separator()
        menu.add_command(label="Tip: botón resetea ocultas del grupo", state="disabled")
        try:
            menu.tk_popup(event.x_root, event.y_root)
        finally:
            try:
                menu.grab_release()
            except Exception:
                pass
        return "break"

    def _cerrar_popup_grafico_tabla_rel_intradia(self, slot: int) -> None:
        popup = self._tabla_rel_intradia_plot_windows.pop(slot, None)
        if not popup:
            return
        ventana = popup.get("window")
        try:
            if ventana is not None and ventana.winfo_exists():
                ventana.destroy()
        except Exception:
            pass

    def _toggle_escala_popup_tabla_rel_intradia(self, slot: int) -> None:
        popup = self._tabla_rel_intradia_plot_windows.get(slot)
        if not popup:
            return
        var = popup.get("scale_var")
        if var is None:
            return
        actual = str(var.get() or "compartida").strip().lower()
        nuevo = "separada" if actual != "separada" else "compartida"
        var.set(nuevo)
        btn_var = popup.get("scale_button_var")
        if btn_var is not None:
            btn_var.set(self._texto_escala_popup_tabla_rel(nuevo))
        self._refrescar_popup_grafico_tabla_rel_intradia(slot)

    def _set_x_popup_tabla_rel_intradia(self, slot: int, columna: str | None) -> None:
        popup = self._tabla_rel_intradia_plot_windows.get(slot)
        columna_norm = str(columna).strip() if columna else None
        if columna_norm and not self._columna_graficable_tabla_rel(columna_norm):
            columna_norm = None
        self._tabla_rel_intradia_plot_x_cols[slot] = columna_norm
        if popup:
            mapping = popup.get("x_display_to_col") or {}
            x_var = popup.get("x_var")
            if x_var is not None:
                if columna_norm is None:
                    x_var.set("Hora")
                else:
                    for display, col in mapping.items():
                        if col == columna_norm:
                            x_var.set(display)
                            break
        tree = (self._intradia_rel_widgets.get(slot) or {}).get("tree")
        if tree is not None:
            self._actualizar_headings_tree(tree)
        self._refrescar_popup_grafico_tabla_rel_intradia(slot)

    def _on_change_x_popup_tabla_rel_intradia(self, slot: int) -> None:
        popup = self._tabla_rel_intradia_plot_windows.get(slot)
        if not popup:
            return
        x_var = popup.get("x_var")
        mapping = popup.get("x_display_to_col") or {}
        display = str(x_var.get() or "Hora").strip() if x_var is not None else "Hora"
        self._set_x_popup_tabla_rel_intradia(slot, mapping.get(display))

    def _abrir_popup_grafico_tabla_rel_intradia(self, slot: int) -> None:
        seleccionadas = list(self._tabla_rel_selected_plot_cols.get(slot, []))
        if not seleccionadas:
            messagebox.showinfo("Tabla relaciones intradía", "Seleccioná una o más columnas con Ctrl+clic sobre los encabezados.")
            return
        popup = self._tabla_rel_intradia_plot_windows.get(slot)
        ventana = popup.get("window") if popup else None
        if ventana is None or not ventana.winfo_exists():
            ventana = Toplevel(self.root)
            ventana.title(f"Tabla relaciones intradía | Vista {slot}")
            ventana.geometry("1120x560")
            frame = ttk.Frame(ventana, padding=6)
            frame.pack(fill=BOTH, expand=True)
            frame_controls = ttk.Frame(frame)
            frame_controls.pack(fill=X, pady=(0, 6))
            ttk.Label(frame_controls, text="Eje X:").pack(side=LEFT)
            x_var = StringVar(value="Hora")
            combo_x = ttk.Combobox(frame_controls, textvariable=x_var, state="readonly", width=26)
            combo_x.pack(side=LEFT, padx=(6, 8))
            scale_button_var = StringVar(value=self._texto_escala_popup_tabla_rel("compartida"))
            ttk.Button(frame_controls, textvariable=scale_button_var, command=lambda s=slot: self._toggle_escala_popup_tabla_rel_intradia(s)).pack(side=LEFT)
            ttk.Label(frame_controls, text="(Usá una columna como X para comparar escalas distintas)").pack(side=LEFT, padx=(10, 0))
            fig = Figure(figsize=(10.4, 4.9), dpi=100)
            ax = fig.add_subplot(111)
            fig.subplots_adjust(top=0.90, bottom=0.18, left=0.08, right=0.92)
            canvas = FigureCanvasTkAgg(fig, master=frame)
            canvas.get_tk_widget().pack(fill=BOTH, expand=True)
            popup = {
                "window": ventana,
                "fig": fig,
                "ax": ax,
                "canvas": canvas,
                "cols": list(seleccionadas),
                "x_var": x_var,
                "x_combo": combo_x,
                "x_display_to_col": {"Hora": None},
                "scale_var": StringVar(value="compartida"),
                "scale_button_var": scale_button_var,
            }
            combo_x.bind("<<ComboboxSelected>>", lambda _e, s=slot: self._on_change_x_popup_tabla_rel_intradia(s))
            self._tabla_rel_intradia_plot_windows[slot] = popup
            ventana.protocol("WM_DELETE_WINDOW", lambda s=slot: self._cerrar_popup_grafico_tabla_rel_intradia(s))
        else:
            popup["cols"] = list(seleccionadas)
            try:
                ventana.deiconify()
                ventana.lift()
                ventana.focus_force()
            except Exception:
                pass
        self._refrescar_popup_grafico_tabla_rel_intradia(slot)

    def _refrescar_popup_grafico_tabla_rel_intradia(self, slot: int) -> None:
        popup = self._tabla_rel_intradia_plot_windows.get(slot)
        if not popup:
            return
        ventana = popup.get("window")
        if ventana is None or not ventana.winfo_exists():
            self._tabla_rel_intradia_plot_windows.pop(slot, None)
            return
        cols = [col for col in (popup.get("cols") or self._tabla_rel_selected_plot_cols.get(slot, [])) if self._columna_graficable_tabla_rel(col)]
        if not cols:
            return
        popup["cols"] = list(cols)
        tree = (self._intradia_rel_widgets.get(slot) or {}).get("tree")
        textos = self._tree_heading_texts.get(self._tree_sort_key(tree), {}) if tree is not None else {}
        display_to_col = {"Hora": None}
        for col in cols:
            display = textos.get(col, col)
            base = display
            idx = 2
            while display in display_to_col:
                display = f"{base} ({idx})"
                idx += 1
            display_to_col[display] = col
        popup["x_display_to_col"] = display_to_col
        combo_x = popup.get("x_combo")
        x_var = popup.get("x_var")
        if combo_x is not None:
            combo_x.configure(values=list(display_to_col.keys()))
        x_col = self._tabla_rel_intradia_plot_x_cols.get(slot)
        if x_col not in cols:
            x_col = None
            self._tabla_rel_intradia_plot_x_cols[slot] = None
        if x_var is not None:
            if x_col is None:
                x_var.set("Hora")
            else:
                for display, col in display_to_col.items():
                    if col == x_col:
                        x_var.set(display)
                        break
        y_cols = [col for col in cols if col != x_col]
        fig = popup.get("fig")
        canvas = popup.get("canvas")
        fig.clf()
        base_ax = fig.add_subplot(111)
        popup["ax"] = base_ax
        filas = list(self._intradia_rel_last_rows.get(slot, []))
        filas_plot = []
        for fila in filas:
            fecha = str(fila.get("fecha") or "")
            if x_col is None:
                x_val = fecha
            else:
                x_val = convertir_a_numero(fila.get(x_col))
                if x_val is None:
                    continue
                x_val = float(x_val)
            y_vals = {col: convertir_a_numero(fila.get(col)) for col in y_cols}
            if all(valor is None for valor in y_vals.values()):
                continue
            filas_plot.append((fecha, x_val, y_vals))
        if not y_cols:
            base_ax.text(0.5, 0.5, "Seleccioná al menos una columna Y adicional", ha="center", va="center", transform=base_ax.transAxes)
            base_ax.set_axis_off()
            canvas.draw_idle()
            return
        if not filas_plot:
            base_ax.text(0.5, 0.5, "Sin datos para graficar", ha="center", va="center", transform=base_ax.transAxes)
            base_ax.set_axis_off()
            canvas.draw_idle()
            return
        etiquetas = [textos.get(col, col) for col in y_cols]
        modo_escala = str((popup.get("scale_var").get() if popup.get("scale_var") is not None else "compartida") or "compartida").strip().lower()
        if x_col is None:
            x_points = list(range(len(filas_plot)))
            x_labels = [item[0] for item in filas_plot]
            x_label = "Hora"
            usar_xticklabels = True
        else:
            x_points = [item[1] for item in filas_plot]
            x_labels = None
            x_label = textos.get(x_col, x_col)
            usar_xticklabels = False
        palette = list(matplotlib.rcParams.get("axes.prop_cycle").by_key().get("color", [])) if matplotlib.rcParams.get("axes.prop_cycle") is not None else []
        if not palette:
            palette = ["tab:blue", "tab:orange", "tab:green", "tab:red", "tab:purple", "tab:brown", "tab:pink", "tab:gray", "tab:olive", "tab:cyan"]
        axes = [base_ax]
        if modo_escala == "separada" and len(y_cols) > 1:
            for idx_col, col in enumerate(y_cols):
                ax = base_ax if idx_col == 0 else base_ax.twinx()
                if idx_col >= 2:
                    ax.spines["right"].set_position(("axes", 1.0 + 0.08 * (idx_col - 1)))
                axes.append(ax) if ax is not base_ax else None
                ys = [item[2].get(col) for item in filas_plot]
                puntos = [(xp, yv) for xp, yv in zip(x_points, ys) if yv is not None]
                if not puntos:
                    continue
                xs_plot = [p[0] for p in puntos]
                ys_plot = [float(p[1]) for p in puntos]
                color = palette[idx_col % len(palette)]
                ax.plot(xs_plot, ys_plot, marker="o", linewidth=1.5, markersize=3.5, color=color, label=etiquetas[idx_col])
                ax.set_ylabel(etiquetas[idx_col], color=color)
                try:
                    ax.tick_params(axis="y", colors=color)
                except Exception:
                    pass
            base_ax.set_xlabel(x_label)
            if usar_xticklabels:
                paso = max(1, len(x_points) // 12)
                base_ax.set_xticks(x_points[::paso])
                base_ax.set_xticklabels(x_labels[::paso], rotation=45, ha="right")
            base_ax.grid(True, axis="y", alpha=0.25)
        else:
            for idx_col, col in enumerate(y_cols):
                ys = [item[2].get(col) for item in filas_plot]
                puntos = [(xp, yv) for xp, yv in zip(x_points, ys) if yv is not None]
                if not puntos:
                    continue
                xs_plot = [p[0] for p in puntos]
                ys_plot = [float(p[1]) for p in puntos]
                color = palette[idx_col % len(palette)]
                base_ax.plot(xs_plot, ys_plot, marker="o", linewidth=1.6, markersize=3.5, color=color, label=etiquetas[idx_col])
            base_ax.set_xlabel(x_label)
            base_ax.set_ylabel("Valor")
            if usar_xticklabels:
                paso = max(1, len(x_points) // 12)
                base_ax.set_xticks(x_points[::paso])
                base_ax.set_xticklabels(x_labels[::paso], rotation=45, ha="right")
            base_ax.grid(True, alpha=0.25)
            if len(y_cols) >= 1:
                base_ax.legend(loc="best")
        fig.tight_layout()
        canvas.draw_idle()

    # Cierra o libera popup grafico tabla relaciones.
    def _cerrar_popup_grafico_tabla_rel(self, slot: int) -> None:
        # Variable local para popup.
        popup = self._tabla_rel_plot_windows.pop(slot, None)
        if not popup:
            return
        # Variable local para ventana.
        ventana = popup.get("window")
        try:
            if ventana is not None and ventana.winfo_exists():
                ventana.destroy()
        except Exception:
            pass

    # Devuelve el texto descriptivo para escala popup tabla relaciones.
    def _texto_escala_popup_tabla_rel(self, modo: str) -> str:
        return "Escala: Separada" if str(modo or "").strip().lower() == "separada" else "Escala: Compartida"

    # Alterna el estado de escala popup tabla relaciones.
    def _toggle_escala_popup_tabla_rel(self, slot: int) -> None:
        # Variable local para popup.
        popup = self._tabla_rel_plot_windows.get(slot)
        if not popup:
            return
        # Variable local para var.
        var = popup.get("scale_var")
        if var is None:
            return
        # Variable local para actual.
        actual = str(var.get() or "compartida").strip().lower()
        # Variable local para nuevo.
        nuevo = "separada" if actual != "separada" else "compartida"
        var.set(nuevo)
        # Variable local para btn var.
        btn_var = popup.get("scale_button_var")
        if btn_var is not None:
            btn_var.set(self._texto_escala_popup_tabla_rel(nuevo))
        self._refrescar_popup_grafico_tabla_rel(slot)

    # Actualiza explícitamente x popup tabla relaciones.
    def _set_x_popup_tabla_rel(self, slot: int, columna: str | None) -> None:
        # Variable local para popup.
        popup = self._tabla_rel_plot_windows.get(slot)
        # Variable local para columna norm.
        columna_norm = str(columna).strip() if columna else None
        if columna_norm and not self._columna_graficable_tabla_rel(columna_norm):
            columna_norm = None
        self._tabla_rel_plot_x_cols[slot] = columna_norm
        if popup:
            # Variable local para mapping.
            mapping = popup.get("x_display_to_col") or {}
            # Variable local para x var.
            x_var = popup.get("x_var")
            if x_var is not None:
                if columna_norm is None:
                    x_var.set("Fecha")
                else:
                    for display, col in mapping.items():
                        if col == columna_norm:
                            x_var.set(display)
                            break
        # Variable local para widgets.
        widgets = self._tabla_rel_widgets.get(slot) or {}
        # Variable local para tree.
        tree = widgets.get("tree")
        if tree is not None:
            self._actualizar_headings_tree(tree)
        self._refrescar_popup_grafico_tabla_rel(slot)

    # Maneja el evento change x popup tabla relaciones.
    def _on_change_x_popup_tabla_rel(self, slot: int) -> None:
        # Variable local para popup.
        popup = self._tabla_rel_plot_windows.get(slot)
        if not popup:
            return
        # Variable local para x var.
        x_var = popup.get("x_var")
        # Variable local para mapping.
        mapping = popup.get("x_display_to_col") or {}
        # Variable local para display.
        display = str(x_var.get() or "Fecha").strip() if x_var is not None else "Fecha"
        self._set_x_popup_tabla_rel(slot, mapping.get(display))

