    # Función auxiliar para refrescar popup grafico tabla relaciones.
    def _refrescar_popup_grafico_tabla_rel(self, slot: int) -> None:
        # Variable local para popup.
        popup = self._tabla_rel_plot_windows.get(slot)
        if not popup:
            return
        # Variable local para ventana.
        ventana = popup.get("window")
        if ventana is None or not ventana.winfo_exists():
            self._tabla_rel_plot_windows.pop(slot, None)
            return
        # Variable local para cols.
        cols = [col for col in (popup.get("cols") or self._tabla_rel_selected_plot_cols.get(slot, [])) if self._columna_graficable_tabla_rel(col)]
        if not cols:
            return
        popup["cols"] = list(cols)
        # Variable local para tree.
        tree = (self._tabla_rel_widgets.get(slot) or {}).get("tree")
        # Colección temporal de textos usada para normalizar información.
        textos = self._tree_heading_texts.get(self._tree_sort_key(tree), {}) if tree is not None else {}
        # Variable local para display to col.
        display_to_col = {"Fecha": None}
        for col in cols:
            # Variable local para display.
            display = textos.get(col, col)
            # Variable local para base.
            base = display
            # Variable local para idx.
            idx = 2
            while display in display_to_col:
                display = f"{base} ({idx})"
                idx += 1
            display_to_col[display] = col
        popup["x_display_to_col"] = display_to_col
        # Variable local para combo x.
        combo_x = popup.get("x_combo")
        # Variable local para x var.
        x_var = popup.get("x_var")
        if combo_x is not None:
            combo_x.configure(values=list(display_to_col.keys()))
        # Variable local para x col.
        x_col = self._tabla_rel_plot_x_cols.get(slot)
        if x_col not in cols:
            x_col = None
            self._tabla_rel_plot_x_cols[slot] = None
        if x_var is not None:
            if x_col is None:
                x_var.set("Fecha")
            else:
                for display, col in display_to_col.items():
                    if col == x_col:
                        x_var.set(display)
                        break
        # Variable local para y cols.
        y_cols = [col for col in cols if col != x_col]
        # Variable local para fig.
        fig = popup.get("fig")
        # Variable local para canvas.
        canvas = popup.get("canvas")
        fig.clf()
        # Variable local para base ax.
        base_ax = fig.add_subplot(111)
        popup["ax"] = base_ax
        # Filas temporales recuperadas o construidas en este paso.
        filas = list(self._tabla_rel_last_rows.get(slot, []))
        # Variable local para filas plot.
        filas_plot = []
        for fila in filas:
            # Fecha temporal usada en este cálculo.
            fecha = str(fila.get("fecha") or "")
            if fecha in {"PROMEDIO", "MEDIA EXP", "Z-SCORE"}:
                continue
            if x_col is None:
                # Variable local para x val.
                x_val = fecha
            else:
                x_val = convertir_a_numero(fila.get(x_col))
                if x_val is None:
                    continue
                x_val = float(x_val)
            # Variable local para y vals.
            y_vals = {col: convertir_a_numero(fila.get(col)) for col in y_cols}
            if all(valor is None for valor in y_vals.values()):
                continue
            filas_plot.append((fecha, x_val, y_vals))
        if not y_cols:
            base_ax.text(0.5, 0.5, "Seleccioná al menos una columna Y adicional", ha="center", va="center", transform=base_ax.transAxes)
            base_ax.set_axis_off()
            canvas.draw_idle()
            return
        if not filas_plot:
            base_ax.text(0.5, 0.5, "Sin datos para graficar", ha="center", va="center", transform=base_ax.transAxes)
            base_ax.set_axis_off()
            canvas.draw_idle()
            return
        # Variable local para etiquetas.
        etiquetas = [textos.get(col, col) for col in y_cols]
        # Variable local para modo escala.
        modo_escala = str((popup.get("scale_var").get() if popup.get("scale_var") is not None else "compartida") or "compartida").strip().lower()
        if x_col is None:
            # Variable local para x points.
            x_points = list(range(len(filas_plot)))
            # Variable local para x labels.
            x_labels = [item[0] for item in filas_plot]
            # Variable local para x label.
            x_label = "Fecha"
            # Variable local para usar xticklabels.
            usar_xticklabels = True
        else:
            x_points = [float(item[1]) for item in filas_plot]
            x_labels = None
            x_label = textos.get(x_col, x_col)
            usar_xticklabels = False

        # Variable local para axes.
        axes = []
        if modo_escala == "separada" and len(y_cols) > 1:
            # Variable local para left offset.
            left_offset = 0
            # Variable local para right offset.
            right_offset = 0
            for idx, col in enumerate(y_cols):
                if idx == 0:
                    # Variable local para ax col.
                    ax_col = base_ax
                    ax_col.yaxis.set_label_position("left")
                    ax_col.yaxis.tick_left()
                else:
                    ax_col = base_ax.twinx()
                    if idx % 2 == 1:
                        right_offset += 1
                        ax_col.yaxis.set_label_position("right")
                        ax_col.yaxis.tick_right()
                        ax_col.spines["right"].set_position(("axes", 1.0 + 0.08 * (right_offset - 1)))
                    else:
                        left_offset += 1
                        ax_col.yaxis.set_label_position("left")
                        ax_col.yaxis.tick_left()
                        ax_col.spines["left"].set_position(("axes", -0.08 * left_offset))
                        ax_col.spines["left"].set_visible(True)
                        ax_col.spines["right"].set_visible(False)
                axes.append((col, ax_col, etiquetas[idx]))
            fig.subplots_adjust(top=0.90, bottom=0.18, left=0.10 + 0.04 * left_offset, right=0.90 - 0.04 * max(0, right_offset - 1))
        else:
            axes = [(col, base_ax, etiquetas[idx]) for idx, col in enumerate(y_cols)]
            fig.subplots_adjust(top=0.90, bottom=0.18, left=0.08, right=0.92)

        # Variable local para handles.
        handles = []
        # Variable local para labels legend.
        labels_legend = []
        # Variable local para palette.
        palette = []
        try:
            # Variable local para prop cycle.
            prop_cycle = matplotlib.rcParams.get("axes.prop_cycle")
            if prop_cycle is not None:
                palette = list(prop_cycle.by_key().get("color", []))
        except Exception:
            palette = []
        if not palette:
            palette = ["tab:blue", "tab:orange", "tab:green", "tab:red", "tab:purple", "tab:brown"]
        for idx_axis, (col, ax_col, etiqueta) in enumerate(axes):
            # Variable local para ys.
            ys = []
            # Variable local para xs valid.
            xs_valid = []
            for idx_row, item in enumerate(filas_plot):
                # Valor temporal usado en este cálculo.
                valor = item[2].get(col)
                if valor is None:
                    continue
                xs_valid.append(x_points[idx_row])
                ys.append(float(valor))
            if not xs_valid:
                continue
            # Variable local para color serie.
            color_serie = palette[idx_axis % len(palette)] if modo_escala == "separada" and len(y_cols) > 1 else None
            line_kwargs = {"marker": "o", "markersize": 3, "linewidth": 1.6, "label": etiqueta}
            if color_serie is not None:
                line_kwargs["color"] = color_serie
            line, = ax_col.plot(xs_valid, ys, **line_kwargs)
            handles.append(line)
            labels_legend.append(etiqueta)
            if modo_escala == "separada" and len(y_cols) > 1:
                ax_col.set_ylabel(etiqueta)
                try:
                    ax_col.tick_params(axis='y', colors=line.get_color())
                    ax_col.yaxis.label.set_color(line.get_color())
                    if ax_col is not base_ax:
                        if ax_col.yaxis.get_label_position() == "right":
                            ax_col.spines["right"].set_color(line.get_color())
                        else:
                            ax_col.spines["left"].set_color(line.get_color())
                except Exception:
                    pass
        # Variable local para titulo.
        titulo = etiquetas[0] if len(etiquetas) == 1 and x_col is None else f"Comparación de {len(y_cols)} columna(s)"
        base_ax.set_title(titulo)
        base_ax.set_xlabel(x_label)
        if modo_escala != "separada" or len(y_cols) <= 1:
            base_ax.set_ylabel("Valor")
        if usar_xticklabels:
            # Variable local para paso.
            paso = max(1, len(x_labels) // 10)
            base_ax.set_xticks(x_points[::paso])
            base_ax.set_xticklabels(x_labels[::paso], rotation=45, ha="right")
        else:
            base_ax.tick_params(axis='x', rotation=0)
        base_ax.grid(True, alpha=0.25)
        if handles:
            base_ax.legend(handles, labels_legend, loc="best", fontsize=8)
        fig.tight_layout()
        canvas.draw_idle()

    def _aplicar_visibilidad_tabla_rel(self, slot: int, grupo: str, activo: bool) -> None:
        """Aplica la visibilidad de un grupo solo sobre la subvista indicada."""
        grupo = str(grupo or "").strip().lower()
        self._resetear_ocultamiento_manual_tabla_rel(slot, grupo)
        if grupo == "vega":
            self._tabla_rel_show_vega_vars[slot].set(bool(activo))
            self._tabla_rel_show_vega_button_vars[slot].set(self._texto_toggle_tabla_rel_vega(activo))
        elif grupo == "delta_symbol":
            self._tabla_rel_show_delta_symbol_vars[slot].set(bool(activo))
            self._tabla_rel_show_delta_symbol_button_vars[slot].set(self._texto_toggle_tabla_rel_delta_symbol(activo))
        elif grupo == "ratio_ab":
            self._tabla_rel_show_ratio_ab_vars[slot].set(bool(activo))
            self._tabla_rel_show_ratio_ab_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_ab(activo))
        elif grupo == "relaciones":
            self._tabla_rel_show_relaciones_vars[slot].set(bool(activo))
            self._tabla_rel_show_relaciones_button_vars[slot].set(self._texto_toggle_tabla_rel_relaciones(activo))
        elif grupo == "delta":
            self._tabla_rel_show_delta_vars[slot].set(bool(activo))
            self._tabla_rel_show_delta_button_vars[slot].set(self._texto_toggle_tabla_rel_delta(activo))
        elif grupo == "theta":
            self._tabla_rel_show_theta_vars[slot].set(bool(activo))
            self._tabla_rel_show_theta_button_vars[slot].set(self._texto_toggle_tabla_rel_theta(activo))
        elif grupo == "ecdf_griegas":
            self._tabla_rel_show_ecdf_griegas_vars[slot].set(bool(activo))
            self._tabla_rel_show_ecdf_griegas_button_vars[slot].set(self._texto_toggle_tabla_rel_ecdf_griegas(activo))
        elif grupo == "logdelta":
            self._tabla_rel_show_logdelta_vars[slot].set(bool(activo))
            self._tabla_rel_show_logdelta_button_vars[slot].set(self._texto_toggle_tabla_rel_logdelta(activo))
        elif grupo == "varlog_ndelta":
            self._tabla_rel_show_varlog_ndelta_vars[slot].set(bool(activo))
            self._tabla_rel_show_varlog_ndelta_button_vars[slot].set(self._texto_toggle_tabla_rel_varlog_ndelta(activo))
        elif grupo == "ab":
            self._tabla_rel_show_ab_vars[slot].set(bool(activo))
            self._tabla_rel_show_ab_button_vars[slot].set(self._texto_toggle_tabla_rel_ab(activo))
        elif grupo == "spread":
            self._tabla_rel_show_spread_vars[slot].set(bool(activo))
            self._tabla_rel_show_spread_button_vars[slot].set(self._texto_toggle_tabla_rel_spread(activo))
        elif grupo == "fill_pct":
            self._tabla_rel_show_fill_pct_vars[slot].set(bool(activo))
            self._tabla_rel_show_fill_pct_button_vars[slot].set(self._texto_toggle_tabla_rel_fill_pct(activo))
        elif grupo == "ratio_pos":
            self._tabla_rel_show_ratio_pos_vars[slot].set(bool(activo))
            self._tabla_rel_show_ratio_pos_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_pos(activo))
        elif grupo == "ratio_neg":
            self._tabla_rel_show_ratio_neg_vars[slot].set(bool(activo))
            self._tabla_rel_show_ratio_neg_button_vars[slot].set(self._texto_toggle_tabla_rel_ratio_neg(activo))
        elif grupo == "minmax":
            self._tabla_rel_show_minmax_vars[slot].set(bool(activo))
            self._tabla_rel_show_minmax_button_vars[slot].set(self._texto_toggle_tabla_rel_minmax(activo))
        self._aplicar_estado_columnas_tabla_rel(slot)

