    def _toggle_comp_price_source(self, slot: int) -> None:
        # Variable local para actual.
        actual = self._comp_price_source_vars.get(slot, StringVar(value="bid_ask")).get().strip() or "bid_ask"
        try:
            # Variable local para idx.
            idx = self._comp_price_source_modes.index(actual)
        except ValueError:
            idx = 0
        # Variable local para nuevo.
        nuevo = self._comp_price_source_modes[(idx + 1) % len(self._comp_price_source_modes)]
        self._comp_price_source_vars[slot].set(nuevo)
        self._comp_price_source_button_vars[slot].set(self._texto_fuente_grafico_comp(nuevo))
        if slot in self._comp_slots and hasattr(self, "notebook_comp"):
            try:
                self.notebook_comp.select(slot - 1)
            except Exception:
                pass
        self._guardar_estado_ui()
        self._resetear_zoom_comparador()
        self._refrescar_ui(forzar=True)

