    # Función auxiliar para aplicar estado modo vista comparador.
    def _aplicar_estado_modo_vista_comp(self, slot: int) -> None:
        # Variable local para modo.
        modo = self._comp_view_mode_vars.get(slot, StringVar(value="ratio")).get().strip() or "ratio"
        # Variable local para widgets.
        widgets = self._comp_widgets.get(slot, {})
        # Variable local para btn costo.
        btn_costo = widgets.get("btn_costo")
        if btn_costo is not None:
            try:
                btn_costo.configure(state=("disabled" if modo == "estrategia" else "normal"))
            except Exception:
                LOGGER.debug("No se pudo actualizar el estado del botón de costo del comparador", exc_info=True)

