    def _texto_columnas_senal_backtest(self, modo: str) -> tuple[str, str]:
        """Devuelve los encabezados correctos para la señal usada por el backtest."""
        # Variable local para modo norm.
        modo_norm = str(modo or "").strip().lower()
        if modo_norm == "cono":
            return "Cono ent.", "Cono sal."
        return "Ratio ent.", "Ratio sal."

    def _precision_senal_backtest(self, modo: str) -> int:
        """Define cuántos decimales mostrar según el tipo de señal visible."""
        return 4 if str(modo or "").strip().lower() == "ratio" else 2

    def _actualizar_headings_tree_backtest(self, tree, modo: str) -> None:
        """Actualiza los títulos de Entrada/Salida de señal sin tocar otras columnas."""
        if tree is None:
            return
        # Variable local para key.
        key = self._tree_sort_key(tree)
        # Colección temporal de textos usada para normalizar información.
        textos = dict(self._tree_heading_texts.get(key, {}))
        if not textos:
            return
        texto_entrada, texto_salida = self._texto_columnas_senal_backtest(modo)
        textos["ratio_entrada"] = texto_entrada
        textos["ratio_salida"] = texto_salida
        self._tree_heading_texts[key] = textos
        self._actualizar_headings_tree(tree)

