    # Función auxiliar para obtener backtest vencimiento band years.
    def _obtener_backtest_venc_band_years(self) -> int:
        try:
            # Variable local para anios.
            anios = int(float(str(self.var_backtest_venc_band_years.get()).replace(",", ".").strip() or "1"))
        except Exception:
            anios = 1
        anios = max(1, min(3, anios))
        # Texto temporal usado para armar o normalizar información.
        texto = str(anios)
        if self.var_backtest_venc_band_years.get().strip() != texto:
            self.var_backtest_venc_band_years.set(texto)
        return anios

    def _obtener_tasa_desde_ui(self) -> float:
        """Lee la tasa anual desde la UI y devuelve un decimal seguro."""
        try:
            return parsear_tasa_porcentaje(self.var_tasa.get())
        except Exception:
            LOGGER.exception("No se pudo leer la tasa desde la UI")
            self.var_tasa.set("25.0")
            return 0.25

    def _tk_report_callback_exception(self, exc, val, tb) -> None:
        """Registra excepciones de Tkinter antes de que cierren la app sin contexto."""
        LOGGER.error("Excepción en callback Tkinter", exc_info=(exc, val, tb))
        try:
            self.var_estado.set(f"Estado: excepción Tkinter: {val}")
        except Exception:
            pass

    def _emitir_heartbeat_log(self) -> None:
        """Emite un log periódico de salud de la aplicación para depuración."""
        self._heartbeat_after_id = None
        try:
            # Estructura temporal con metadatos o información auxiliar.
            info = ESTADO.snapshot_info()
            LOGGER.info(
                "Heartbeat | tab=%s | last_event=%s | status=%s | error=%s | instrumentos=%s | comp=%s/%s | intradia=%s",
                self._tab_activa_texto(),
                info.get("last_event_at") or "sin ticks",
                info.get("status") or "",
                info.get("error") or "",
                info.get("count") or 0,
                self.var_comp_a.get().strip() or "-",
                self.var_comp_b.get().strip() or "-",
                self._intradia_vars_fecha.get(self._tab_intradia_activa_indice(), self._intradia_vars_fecha[1]).get().strip() or "-",
            )
            if (
                not self.offline_mode
                and LAST_WS_ENVIRONMENT is not None
                and mercado_en_horario_operativo()
                and not _ws_esta_conectado(LAST_WS_ENVIRONMENT)
            ):
                _auto_reconectar_websocket_async("heartbeat", "WS desconectado detectado en heartbeat")
        except Exception:
            LOGGER.exception("Fallo emitiendo heartbeat")
        finally:
            if not STOP_EVENT.is_set() and not getattr(self, "_closing_in_progress", False):
                self._heartbeat_after_id = self.root.after(15000, self._emitir_heartbeat_log)

    def _invalidar_cache_comparador(self) -> None:
        """Fuerza a recargar datos históricos del comparador en el próximo refresco."""
        self._comparador_cache_pair = None
        self._comparador_cache_loaded_at = 0.0
        self._comparador_series_cache = {}
        self._comparador_strategy_cache_pair = None
        self._comparador_strategy_cache_loaded_at = 0.0
        self._comparador_strategy_series_cache = {}
        self._comparador_range_cache_pair = None
        self._comparador_range_cache_loaded_at = 0.0
        self._comparador_range_series_cache = {}
        self._comparador_live_signature = None
        self._comparador_last_render_at = 0.0
        self._comparador_intradia_cache_key = None
        self._comparador_intradia_cache_loaded_at = 0.0
        self._comparador_intradia_series_cache = {}

    def _invalidar_cache_intradia(self, slot: int | None = None) -> None:
        """Fuerza a recargar datos intradía en el próximo refresco."""
        # Variable local para slots.
        slots = (slot,) if slot in self._intradia_slots else self._intradia_slots
        for slot_id in slots:
            self._intradia_cache_key[slot_id] = None
            self._intradia_cache_loaded_at[slot_id] = 0.0
            self._intradia_series_cache[slot_id] = {}
            self._intradia_live_signature[slot_id] = None
            self._intradia_last_render_at[slot_id] = 0.0

    def _invalidar_cache_backtest(self) -> None:
        """Fuerza a recalcular las vistas de backtest intradía en el próximo refresco."""
        self._backtest_cache_key = None
        self._backtest_cache_result = None
        self._backtest_render_signature = {slot: None for slot in self._backtest_slots}
        self._backtest_hedge_cache_key = None
        self._backtest_hedge_cache_result = None
        self._backtest_hedge_render_signature = {slot: None for slot in self._backtest_slots}

    def _invalidar_cache_backtest_hedge(self) -> None:
        """Fuerza a recalcular el backtest con cobertura en el próximo refresco."""
        self._backtest_hedge_cache_key = None
        self._backtest_hedge_cache_result = None
        self._backtest_hedge_render_signature = {slot: None for slot in self._backtest_slots}

    def _resetear_vistas(self, keys: Iterable[str]) -> None:
        """Limpia el zoom manual de un conjunto de ejes para volver al autoajuste."""
        for key in keys:
            # Variable local para estado.
            estado = self._axes_view_state.setdefault(key, {})
            estado["manual"] = False
            estado["xlim"] = None
            estado["ylim"] = None

    def _resetear_zoom_comparador(self) -> None:
        """Reinicia el zoom manual del comparador histórico."""
        # Conjunto temporal de claves usadas para indexar o matchear datos.
        claves = []
        for slot in self._comp_slots:
            claves.extend((f"comp{slot}_costos", f"comp{slot}_precio", f"comp{slot}_delta", f"comp{slot}_vega", f"comp{slot}_gamma"))
        self._resetear_vistas(tuple(claves))

    def _resetear_zoom_intradia(self, slot: int | None = None) -> None:
        """Reinicia el zoom manual del comparador intradía."""
        if slot in self._intradia_slots:
            # Variable local para keys.
            keys = (
                f"intradia{slot}_costo",
                f"intradia{slot}_precio",
                f"intradia{slot}_delta",
                f"intradia{slot}_vega",
                f"intradia{slot}_gamma",
            )
        else:
            keys = tuple(
                key
                for slot_id in self._intradia_slots
                for key in (
                    f"intradia{slot_id}_costo",
                    f"intradia{slot_id}_precio",
                    f"intradia{slot_id}_delta",
                    f"intradia{slot_id}_vega",
                    f"intradia{slot_id}_gamma",
                )
            )
        self._resetear_vistas(keys)

    def _resetear_zoom_backtest(self) -> None:
        """Reinicia el zoom manual de los gráficos del backtest intradía."""
        self._resetear_vistas(("backtest_ratio", "backtest_pnl"))

    def _resetear_zoom_backtest_hedge(self) -> None:
        """Reinicia el zoom manual de los gráficos del backtest con cobertura."""
        self._resetear_vistas(("backtest_hedge_ratio", "backtest_hedge_pnl"))

    def _resetear_zoom_smile(self) -> None:
        """Reinicia el zoom manual de las vistas Smile."""
        self._resetear_vistas(("smile_dia",))

    def _resetear_zoom_gex(self) -> None:
        """Reinicia el zoom manual del gráfico de GEX."""
        self._resetear_vistas(("gex",))

    def _registrar_canvas_interactivo(self, canvas, toolbar, axes_map: dict[str, Any]) -> None:
        """Conecta zoom con rueda y paneo con arrastre para un conjunto de ejes."""
        self._canvas_toolbar_by_id[id(canvas)] = toolbar
        for key, ax in axes_map.items():
            self._axes_by_key[key] = ax
            self._axis_key_by_id[id(ax)] = key
            self._axes_view_state.setdefault(key, {"manual": False, "xlim": None, "ylim": None})
        canvas.mpl_connect("scroll_event", self._on_scroll_zoom)
        canvas.mpl_connect("button_press_event", self._on_press_pan)
        canvas.mpl_connect("button_release_event", self._on_release_pan)
        canvas.mpl_connect("motion_notify_event", self._on_motion_pan)
        canvas.mpl_connect("draw_event", self._on_draw_capture_view)

    def _compactar_toolbar(self, toolbar: Any) -> None:
        """Reduce el espacio vertical ocupado por la toolbar de Matplotlib."""
        if toolbar is None:
            return
        try:
            toolbar.config(borderwidth=0, highlightthickness=0)
        except Exception:
            pass
        try:
            # Variable local para message label.
            message_label = getattr(toolbar, "_message_label", None)
            if message_label is not None:
                try:
                    message_label.pack_forget()
                except Exception:
                    pass
                try:
                    message_label.destroy()
                except Exception:
                    pass
                try:
                    toolbar._message_label = None
                except Exception:
                    pass
        except Exception:
            pass
        for child in list(getattr(toolbar, 'winfo_children', lambda: [])()):
            try:
                child.pack_configure(padx=0, pady=0, ipadx=0, ipady=0)
            except Exception:
                pass
            try:
                child.configure(borderwidth=0, highlightthickness=0, padx=0, pady=0)
            except Exception:
                pass
            try:
                if child.winfo_class() in {"Button", "Checkbutton"}:
                    child.configure(takefocus=0)
            except Exception:
                pass
        try:
            toolbar.update_idletasks()
        except Exception:
            pass

    def _toolbar_modo_activo(self, canvas) -> bool:
        """Indica si la toolbar estándar de matplotlib está en modo pan/zoom."""
        # Variable local para toolbar.
        toolbar = self._canvas_toolbar_by_id.get(id(canvas))
        return bool(getattr(toolbar, "mode", ""))

    def _guardar_vista_manual(self, key: str, ax) -> None:
        """Persiste el estado de zoom/pan manual del eje indicado."""
        # Variable local para estado.
        estado = self._axes_view_state.setdefault(key, {})
        estado["manual"] = True
        estado["xlim"] = tuple(ax.get_xlim())
        estado["ylim"] = tuple(ax.get_ylim())

    def _capturar_vistas(self, keys: Iterable[str]) -> None:
        """Toma una fotografía del zoom manual antes de redibujar los gráficos."""
        for key in keys:
            # Variable local para estado.
            estado = self._axes_view_state.get(key) or {}
            # Variable local para ax.
            ax = self._axes_by_key.get(key)
            if estado.get("manual") and ax is not None:
                try:
                    estado["xlim"] = tuple(ax.get_xlim())
                    estado["ylim"] = tuple(ax.get_ylim())
                except Exception:
                    LOGGER.debug("No se pudo capturar la vista del eje %s", key, exc_info=True)

    def _restaurar_vistas(self, keys: Iterable[str]) -> None:
        """Restaura el zoom manual luego de redibujar, sin molestar al usuario."""
        for key in keys:
            # Variable local para estado.
            estado = self._axes_view_state.get(key) or {}
            # Variable local para ax.
            ax = self._axes_by_key.get(key)
            if not estado.get("manual") or ax is None:
                continue
            # Variable local para xlim.
            xlim = estado.get("xlim")
            # Variable local para ylim.
            ylim = estado.get("ylim")
            try:
                if xlim is not None:
                    ax.set_xlim(xlim)
                if ylim is not None:
                    ax.set_ylim(ylim)
            except Exception:
                LOGGER.debug("No se pudo restaurar la vista del eje %s", key, exc_info=True)

    def _on_draw_capture_view(self, event) -> None:
        """Guarda la vista elegida con la toolbar luego del redibujado real del canvas."""
        # Variable local para canvas.
        canvas = getattr(event, "canvas", None)
        if canvas is None:
            return
        # Variable local para canvas id.
        canvas_id = id(canvas)
        if canvas_id not in self._pending_toolbar_capture_canvases:
            return
        self._pending_toolbar_capture_canvases.discard(canvas_id)
        try:
            for ax in getattr(getattr(canvas, "figure", None), "axes", []) or []:
                # Variable local para key.
                key = self._axis_key_by_id.get(id(ax))
                if key:
                    self._guardar_vista_manual(key, ax)
        except Exception:
            LOGGER.debug("No se pudo capturar la vista luego de usar la toolbar", exc_info=True)

    def _on_scroll_zoom(self, event) -> None:
        """Aplica zoom con la rueda del mouse centrado en el cursor."""
        # Variable local para ax.
        ax = getattr(event, "inaxes", None)
        if ax is None or self._toolbar_modo_activo(event.canvas):
            return
        # Variable local para key.
        key = self._axis_key_by_id.get(id(ax))
        if not key or event.xdata is None or event.ydata is None:
            return
        # Variable local para cur xlim.
        cur_xlim = ax.get_xlim()
        # Variable local para cur ylim.
        cur_ylim = ax.get_ylim()
        x0, x1 = cur_xlim
        y0, y1 = cur_ylim
        if x0 == x1 or y0 == y1:
            return
        # Variable local para factor.
        factor = 1 / 1.2 if event.button == "up" else 1.2
        # Variable local para nuevo ancho.
        nuevo_ancho = (x1 - x0) * factor
        # Variable local para nuevo alto.
        nuevo_alto = (y1 - y0) * factor
        # Variable local para relx.
        relx = (x1 - event.xdata) / (x1 - x0)
        # Variable local para rely.
        rely = (y1 - event.ydata) / (y1 - y0)
        ax.set_xlim(event.xdata - nuevo_ancho * (1 - relx), event.xdata + nuevo_ancho * relx)
        ax.set_ylim(event.ydata - nuevo_alto * (1 - rely), event.ydata + nuevo_alto * rely)
        self._guardar_vista_manual(key, ax)
        event.canvas.draw_idle()

    def _on_press_pan(self, event) -> None:
        """Inicia paneo por arrastre y permite doble clic para resetear zoom."""
        # Variable local para ax.
        ax = getattr(event, "inaxes", None)
        if ax is None or self._toolbar_modo_activo(event.canvas):
            return
        # Variable local para key.
        key = self._axis_key_by_id.get(id(ax))
        if not key:
            return
        if getattr(event, "dblclick", False):
            self._resetear_vistas((key,))
            try:
                ax.relim()
                ax.autoscale_view()
            except Exception:
                LOGGER.debug("No se pudo resetear el zoom del eje %s", key, exc_info=True)
            event.canvas.draw_idle()
            return
        if event.button != 1 or event.xdata is None or event.ydata is None:
            return
        self._drag_pan_state = {
            "canvas": event.canvas,
            "ax": ax,
            "key": key,
            "xdata": event.xdata,
            "ydata": event.ydata,
            "xlim": tuple(ax.get_xlim()),
            "ylim": tuple(ax.get_ylim()),
        }

    def _on_motion_pan(self, event) -> None:
        """Panea el gráfico moviendo el mouse con el botón izquierdo presionado."""
        # Variable local para estado.
        estado = self._drag_pan_state
        if not estado or event.canvas is not estado.get("canvas"):
            return
        # Variable local para ax.
        ax = estado.get("ax")
        if ax is None or event.inaxes is not ax or event.xdata is None or event.ydata is None:
            return
        # Variable local para dx.
        dx = event.xdata - estado["xdata"]
        # Variable local para dy.
        dy = event.ydata - estado["ydata"]
        # Variable local para xlim.
        xlim = estado["xlim"]
        # Variable local para ylim.
        ylim = estado["ylim"]
        ax.set_xlim(xlim[0] - dx, xlim[1] - dx)
        ax.set_ylim(ylim[0] - dy, ylim[1] - dy)
        self._guardar_vista_manual(estado["key"], ax)
        event.canvas.draw_idle()

    def _on_release_pan(self, event) -> None:
        """Termina el paneo y guarda la vista final para futuros refrescos."""
        if self._toolbar_modo_activo(event.canvas):
            try:
                self._pending_toolbar_capture_canvases.add(id(event.canvas))
                event.canvas.draw_idle()
            except Exception:
                LOGGER.debug("No se pudo programar la captura de vista usando la toolbar", exc_info=True)
            finally:
                self._drag_pan_state = None
            return

        # Variable local para estado.
        estado = self._drag_pan_state
        if not estado:
            return
        try:
            # Variable local para ax.
            ax = estado.get("ax")
            # Variable local para key.
            key = estado.get("key")
            if ax is not None and key:
                self._guardar_vista_manual(key, ax)
        finally:
            self._drag_pan_state = None

    def _obtener_series_cache_comparador(self, ticker_a: str, ticker_b: str) -> dict[str, list[tuple[datetime, float]]]:
        """Devuelve las series de cierres del comparador usando caché en memoria.

        El TTL se mantiene corto para que el comparador incorpore rápido el cierre oficial
        recién guardado del día, sin esperar demasiado a que venza el caché.
        """
        # Clave temporal usada para indexar o matchear datos.
        clave = (ticker_a, ticker_b)
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if (
            self._comparador_cache_pair != clave
            or not self._comparador_series_cache
            or (ahora_ts - self._comparador_cache_loaded_at) > ttl_cache
        ):
            self._comparador_series_cache = self._history_db.obtener_series_cierres_multiples(
                ticker_a,
                ticker_b,
                campos=("last", "delta", "vega", "gamma"),
            )
            self._comparador_cache_pair = clave
            self._comparador_cache_loaded_at = ahora_ts
        return self._comparador_series_cache

    def _obtener_series_cache_comparador_estrategia(self, ticker_a: str, ticker_b: str) -> dict[str, list[tuple[datetime, float]]]:
        """Devuelve las series históricas del comparador pensadas como estrategia conjunta."""
        # Clave temporal usada para indexar o matchear datos.
        clave = (ticker_a, ticker_b)
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if (
            self._comparador_strategy_cache_pair != clave
            or not self._comparador_strategy_series_cache
            or (ahora_ts - self._comparador_strategy_cache_loaded_at) > ttl_cache
        ):
            self._comparador_strategy_series_cache = self._history_db.obtener_series_cierres_estrategia(ticker_a, ticker_b)
            self._comparador_strategy_cache_pair = clave
            self._comparador_strategy_cache_loaded_at = ahora_ts
        return self._comparador_strategy_series_cache

    def _obtener_rangos_cache_comparador(self, ticker_a: str, ticker_b: str) -> dict[str, list[tuple[datetime, float, float]]]:
        """Devuelve mínimos y máximos intradía diarios del comparador usando caché en memoria."""
        # Clave temporal usada para indexar o matchear datos.
        clave = (ticker_a, ticker_b)
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if (
            self._comparador_range_cache_pair != clave
            or not self._comparador_range_series_cache
            or (ahora_ts - self._comparador_range_cache_loaded_at) > ttl_cache
        ):
            self._comparador_range_series_cache = self._history_db.obtener_rangos_diarios_comparador(ticker_a, ticker_b)
            self._comparador_range_cache_pair = clave
            self._comparador_range_cache_loaded_at = ahora_ts
        return self._comparador_range_series_cache

    def _obtener_series_cache_comparador_intradia(self, fecha: str, ticker_a: str, ticker_b: str) -> dict[str, list[tuple[datetime, float]]]:
        """Devuelve las series intradía del comparador usando caché de un minuto."""
        # Clave temporal usada para indexar o matchear datos.
        clave = (str(fecha or ""), str(ticker_a or ""), str(ticker_b or ""))
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        if (
            self._comparador_intradia_cache_key != clave
            or not self._comparador_intradia_series_cache
            or (ahora_ts - self._comparador_intradia_cache_loaded_at) > 60.0
        ):
            self._comparador_intradia_series_cache = self._history_db.obtener_series_intradia_paquete(
                fecha,
                ticker_a,
                ticker_b,
                hora_desde=BACKTEST_SESSION_START_TIME,
                hora_hasta=BACKTEST_SESSION_END_TIME,
            )
            self._comparador_intradia_cache_key = clave
            self._comparador_intradia_cache_loaded_at = ahora_ts
        return self._comparador_intradia_series_cache

    def _extremos_intradia_ab_comparador(
        self,
        fecha: str,
        ticker_a: str,
        ticker_b: str,
        *,
        last_a_live: float | None = None,
        last_b_live: float | None = None,
        ts_live: datetime | None = None,
    ) -> tuple[float | None, float | None]:
        """Devuelve máximo y mínimo intradía de A+B para la rueda visible del comparador."""
        if not fecha or not ticker_a or not ticker_b:
            return None, None
        # Colección temporal de valores usada en este cálculo.
        valores: list[float] = []
        try:
            # Colección de series construidas en este bloque.
            series = self._obtener_series_cache_comparador_intradia(fecha, ticker_a, ticker_b)
            for _ts, valor in list(series.get("costo_last") or []):
                # Número temporal calculado en este bloque.
                numero = convertir_a_numero(valor)
                if numero is not None:
                    valores.append(float(numero))
        except Exception:
            LOGGER.debug("No se pudieron leer extremos intradía del comparador", exc_info=True)
        if (
            ts_live is not None
            and isinstance(ts_live, datetime)
            and ts_live.strftime("%Y-%m-%d") == str(fecha)
            and last_a_live is not None
            and last_b_live is not None
        ):
            try:
                valores.append(float(last_a_live) + float(last_b_live))
            except Exception:
                pass
        if not valores:
            return None, None
        return max(valores), min(valores)

    def _formatear_rango_comp_ab(self, maximo: Any, minimo: Any) -> str:
        """Formatea el rango intradía de A+B como (max:min)."""
        # Variable local para vmax.
        vmax = convertir_a_numero(maximo)
        # Variable local para vmin.
        vmin = convertir_a_numero(minimo)
        if vmax is None or vmin is None:
            return ""
        try:
            return f"({float(vmax):.2f}:{float(vmin):.2f})"
        except Exception:
            return ""

    def _formatear_rango_tabla_rel_ab(self, maximo: Any, minimo: Any) -> str:
        """Formatea el rango intradía de A+B para Tabla relaciones como (max - min)."""
        # Variable local para vmax.
        vmax = convertir_a_numero(maximo)
        # Variable local para vmin.
        vmin = convertir_a_numero(minimo)
        if vmax is None or vmin is None:
            return ""
        try:
            return f"({float(vmax):.2f} - {float(vmin):.2f})"
        except Exception:
            return ""

    def _extremos_intradia_tabla_rel_estrategia(
        self,
        fecha: str,
        ticker_a: str,
        ticker_b: str,
        *,
        estrategia: str,
        last_a_live: float | None = None,
        last_b_live: float | None = None,
        ts_live: datetime | None = None,
    ) -> tuple[float | None, float | None]:
        """Devuelve máximo y mínimo intradía de una estrategia de Tabla relaciones."""
        if not fecha or not ticker_a or not ticker_b:
            return None, None
        # Colección temporal de valores usada en este cálculo.
        valores: list[float] = []
        try:
            # Filas temporales recuperadas o construidas en este paso.
            filas = self._history_db.obtener_filas_intradia_par(
                fecha,
                ticker_a,
                ticker_b,
                hora_desde=BACKTEST_SESSION_START_TIME,
                hora_hasta=BACKTEST_SESSION_END_TIME,
            )
            for fila in filas:
                # Variable local para A last.
                a_last = convertir_a_numero(fila.get("a_last"))
                # Variable local para B last.
                b_last = convertir_a_numero(fila.get("b_last"))
                if a_last is None or b_last is None:
                    continue
                if estrategia == "ab":
                    # Valor temporal usado en este cálculo.
                    valor = float(a_last) + float(b_last)
                elif estrategia == "spread":
                    valor = float(a_last) - float(b_last)
                elif estrategia == "ratio_pos_1a2b":
                    valor = float(a_last) - 2.0 * float(b_last)
                elif estrategia == "ratio_inv_1a2b":
                    valor = -float(a_last) + 2.0 * float(b_last)
                else:
                    continue
                valores.append(valor)
        except Exception:
            LOGGER.debug("No se pudieron leer extremos intradía de Tabla relaciones", exc_info=True)
        if (
            ts_live is not None
            and isinstance(ts_live, datetime)
            and ts_live.strftime("%Y-%m-%d") == str(fecha)
            and last_a_live is not None
            and last_b_live is not None
        ):
            try:
                if estrategia == "ab":
                    valores.append(float(last_a_live) + float(last_b_live))
                elif estrategia == "spread":
                    valores.append(float(last_a_live) - float(last_b_live))
                elif estrategia == "ratio_pos_1a2b":
                    valores.append(float(last_a_live) - 2.0 * float(last_b_live))
                elif estrategia == "ratio_inv_1a2b":
                    valores.append(-float(last_a_live) + 2.0 * float(last_b_live))
            except Exception:
                pass
        if not valores:
            return None, None
        return max(valores), min(valores)

    def _rango_diario_a_puntos_categoricos(
        self,
        serie: list[tuple[datetime, float, float]],
        mapa_pos: dict[Any, int],
    ) -> tuple[list[tuple[float, float]], list[tuple[float, float]]]:
        """Convierte mínimos y máximos diarios a puntos para un eje categórico."""
        # Variable local para puntos inf.
        puntos_inf: list[tuple[float, float]] = []
        # Variable local para puntos sup.
        puntos_sup: list[tuple[float, float]] = []
        # Variable local para vistos.
        vistos: set[Any] = set()
        for ts, valor_min, valor_max in sorted(serie, key=lambda item: item[0]):
            # Fecha temporal usada en este cálculo.
            fecha = ts.date()
            # Variable local para pos.
            pos = mapa_pos.get(fecha)
            if pos is None or fecha in vistos:
                continue
            try:
                puntos_inf.append((float(pos), float(valor_min)))
                puntos_sup.append((float(pos), float(valor_max)))
                vistos.add(fecha)
            except Exception:
                continue
        return puntos_inf, puntos_sup

    def _obtener_series_cache_intradia(self, slot: int, fecha: str, ticker_a: str, ticker_b: str) -> dict[str, list[tuple[datetime, float]]]:
        """Devuelve las series intradía por minuto usando caché en memoria."""
        # Clave temporal usada para indexar o matchear datos.
        clave = (fecha, ticker_a, ticker_b)
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        if (
            self._intradia_cache_key.get(slot) != clave
            or not self._intradia_series_cache.get(slot)
            or (ahora_ts - self._intradia_cache_loaded_at.get(slot, 0.0)) > 60.0
        ):
            self._intradia_series_cache[slot] = self._history_db.obtener_series_intradia_paquete(
                fecha,
                ticker_a,
                ticker_b,
                hora_desde="10:30",
                hora_hasta="17:00",
            )
            self._intradia_cache_key[slot] = clave
            self._intradia_cache_loaded_at[slot] = ahora_ts
        return self._intradia_series_cache.get(slot, {})

    def _firma_live_comparador(
        self,
        ticker_a: str,
        ticker_b: str,
        fila_a: dict[str, Any],
        fila_b: dict[str, Any],
        info: dict[str, Any],
    ) -> tuple[Any, ...]:
        """Construye una firma liviana para evitar redibujos innecesarios del comparador."""
        # Variable local para firma.
        firma: list[Any] = [ticker_a, ticker_b, info.get("last_event_at") or ""]
        for fila in (fila_a, fila_b):
            for campo in ("last", "delta", "vega", "gamma"):
                # Valor temporal usado en este cálculo.
                valor = convertir_a_numero(fila.get(campo))
                firma.append(round(float(valor), 6) if valor is not None else None)
        return tuple(firma)

    def _construir_eje_comparador(
        self,
        series_historicas: dict[str, list[tuple[datetime, float]]],
        ts_live: datetime | None,
        limite_habiles: int = 30,
    ) -> tuple[list[Any], dict[Any, int], list[str], int | None]:
        """Construye un eje X categórico por días hábiles consecutivos.

        A diferencia de una escala temporal normal, este eje no deja huecos por fines de
        semana. Además, siempre arma una ventana de trabajo con días hábiles consecutivos
        dentro de los últimos `limite_habiles` días calendario de referencia, aunque haya
        días sin cierres guardados.

        Devuelve:
        - fechas_base: días hábiles visibles en orden secuencial
        - mapa_pos: fecha -> posición secuencial
        - etiquetas_x: etiquetas del eje X
        - pos_live_extra: posición extra para el punto vivo cuando ya existe un cierre
          oficial del mismo día y conviene mostrar ambos.
        """
        from datetime import timedelta

        # Variable local para limite dias.
        limite_dias = max(int(limite_habiles or 30), 1)
        # Variable local para fechas con datos.
        fechas_con_datos: set[Any] = set()
        for serie in series_historicas.values():
            for ts, _ in serie:
                if isinstance(ts, datetime) and ts.weekday() < 5:
                    fechas_con_datos.add(ts.date())

        # Variable local para fecha referencia.
        fecha_referencia = None
        if fechas_con_datos:
            fecha_referencia = max(fechas_con_datos)
        if ts_live is not None and ts_live.weekday() < 5:
            # Variable local para fecha live.
            fecha_live = ts_live.date()
            if fecha_referencia is None or fecha_live > fecha_referencia:
                fecha_referencia = fecha_live
        if fecha_referencia is None:
            # Variable local para hoy.
            hoy = ahora().date()
            while hoy.weekday() >= 5:
                hoy -= timedelta(days=1)
            fecha_referencia = hoy

        # Variable local para fecha inicio.
        fecha_inicio = fecha_referencia - timedelta(days=limite_dias - 1)
        # Variable local para fechas base.
        fechas_base: list[Any] = []
        # Variable local para cursor.
        cursor = fecha_inicio
        while cursor <= fecha_referencia:
            if cursor.weekday() < 5:
                fechas_base.append(cursor)
            cursor += timedelta(days=1)

        if not fechas_base:
            fechas_base = [fecha_referencia]

        # Variable local para mapa pos.
        mapa_pos = {fecha: idx for idx, fecha in enumerate(fechas_base)}
        # Variable local para etiquetas x.
        etiquetas_x = [fecha.strftime("%d-%m") for fecha in fechas_base]

        # Variable local para pos live extra.
        pos_live_extra: int | None = None
        if ts_live is not None and ts_live.weekday() < 5 and fechas_base:
            # Registro temporal o último valor usado para ultima fecha.
            ultima_fecha = fechas_base[-1]
            # Variable local para hay cierre mismo dia.
            hay_cierre_mismo_dia = any(
                any(ts.date() == ultima_fecha for ts, _ in serie)
                for serie in series_historicas.values()
            )
            if ts_live.date() == ultima_fecha and hay_cierre_mismo_dia:
                pos_live_extra = len(fechas_base)
                etiquetas_x = list(etiquetas_x) + [f"{ts_live.strftime('%d-%m')} vivo"]
            elif ts_live.date() not in mapa_pos:
                pos_live_extra = len(fechas_base)
                etiquetas_x = list(etiquetas_x) + [f"{ts_live.strftime('%d-%m')} vivo"]

        return fechas_base, mapa_pos, etiquetas_x, pos_live_extra

    def _compactar_etiquetas_eje_categorico(
        self,
        etiquetas_x: list[str],
        max_etiquetas: int = 16,
    ) -> list[str]:
        """Reduce etiquetas del eje X sin mover los puntos para evitar amontonamiento."""
        # Variable local para etiquetas.
        etiquetas = list(etiquetas_x or [])
        # Variable local para cantidad.
        cantidad = len(etiquetas)
        # Variable local para limite.
        limite = max(int(max_etiquetas or 0), 2)
        if cantidad <= limite:
            return etiquetas
        # Variable local para paso.
        paso = max(1, math.ceil(cantidad / float(limite)))
        # Variable local para compactas.
        compactas: list[str] = []
        for idx, etiqueta in enumerate(etiquetas):
            if idx == 0 or idx == cantidad - 1 or (idx % paso) == 0:
                compactas.append(etiqueta)
            else:
                compactas.append("")
        return compactas

    def _construir_eje_categorico_por_datos(
        self,
        series_historicas: dict[str, list[tuple[datetime, float]]],
        ts_live: datetime | None,
    ) -> tuple[list[Any], dict[Any, int], list[str], int | None]:
        """Construye un eje X compacto usando solo fechas con datos reales.

        Se usa en vistas donde conviene centrar el dibujo en las ruedas efectivamente
        disponibles para los pares activos, evitando ventanas amplias con huecos vacíos.
        """
        # Variable local para fechas con datos.
        fechas_con_datos: list[Any] = sorted(
            {
                ts.date()
                for serie in series_historicas.values()
                for ts, _ in serie
                if isinstance(ts, datetime) and ts.weekday() < 5
            }
        )

        if not fechas_con_datos:
            # Variable local para fecha base.
            fecha_base = None
            if ts_live is not None and ts_live.weekday() < 5:
                fecha_base = ts_live.date()
            if fecha_base is None:
                fecha_base = ahora().date()
                while fecha_base.weekday() >= 5:
                    fecha_base -= timedelta(days=1)
            fechas_con_datos = [fecha_base]

        # Variable local para mapa pos.
        mapa_pos = {fecha: idx for idx, fecha in enumerate(fechas_con_datos)}
        # Variable local para etiquetas x.
        etiquetas_x = [fecha.strftime("%d-%m") for fecha in fechas_con_datos]

        # Variable local para pos live extra.
        pos_live_extra: int | None = None
        if ts_live is not None and ts_live.weekday() < 5:
            # Variable local para fecha live.
            fecha_live = ts_live.date()
            # Variable local para hay cierre mismo dia.
            hay_cierre_mismo_dia = fecha_live in mapa_pos
            if hay_cierre_mismo_dia:
                pos_live_extra = len(fechas_con_datos)
                etiquetas_x = list(etiquetas_x) + [f"{ts_live.strftime('%d-%m')} vivo"]
            elif fecha_live not in mapa_pos:
                pos_live_extra = len(fechas_con_datos)
                etiquetas_x = list(etiquetas_x) + [f"{ts_live.strftime('%d-%m')} vivo"]

        etiquetas_x = self._compactar_etiquetas_eje_categorico(etiquetas_x)
        return fechas_con_datos, mapa_pos, etiquetas_x, pos_live_extra

    def _serie_a_puntos_categoricos(
        self,
        serie: list[tuple[datetime, float]],
        mapa_pos: dict[Any, int],
        *,
        ratio_live: float | None,
        ts_live: datetime | None,
        pos_live_extra: int | None,
    ) -> list[tuple[float, float]]:
        """Convierte una serie histórica en puntos para un eje X categórico."""
        # Variable local para puntos.
        puntos: list[tuple[float, float]] = []
        # Variable local para vistos.
        vistos: set[Any] = set()
        for ts, valor in sorted(serie, key=lambda item: item[0]):
            # Fecha temporal usada en este cálculo.
            fecha = ts.date()
            # Variable local para pos.
            pos = mapa_pos.get(fecha)
            if pos is None or fecha in vistos:
                continue
            puntos.append((float(pos), float(valor)))
            vistos.add(fecha)
        if ratio_live is not None and ts_live is not None and ts_live.weekday() < 5:
            # Variable local para fecha live.
            fecha_live = ts_live.date()
            if pos_live_extra is not None:
                puntos.append((float(pos_live_extra), float(ratio_live)))
            else:
                pos = mapa_pos.get(fecha_live)
                if pos is not None:
                    # Variable local para reemplazado.
                    reemplazado = False
                    for idx, (x, _) in enumerate(puntos):
                        if int(round(x)) == pos:
                            puntos[idx] = (float(pos), float(ratio_live))
                            reemplazado = True
                            break
                    if not reemplazado:
                        puntos.append((float(pos), float(ratio_live)))
        puntos.sort(key=lambda item: item[0])
        return puntos

    def _aplicar_eje_categorico_comparador(self, ax, etiquetas_x: list[str]) -> None:
        """Configura el eje X del comparador como secuencial, sin huecos de fin de semana."""
        if not etiquetas_x:
            return
        # Variable local para posiciones.
        posiciones = list(range(len(etiquetas_x)))
        ax.set_xlim(-0.5, max(posiciones) + 0.5)
        ax.set_xticks(posiciones)
        ax.set_xticklabels(etiquetas_x, rotation=45, ha="right", fontsize=8)

    def _construir_limites_intradia(
        self,
        fecha: str,
        hora_inicio: str = BACKTEST_SESSION_START_TIME,
        hora_fin: str = BACKTEST_SESSION_END_TIME,
    ) -> tuple[datetime | None, datetime | None]:
        """Devuelve el rango horario intradía visible para una fecha dada."""
        try:
            # Variable local para inicio txt.
            inicio_txt = self._normalizar_hora_backtest_texto(hora_inicio, BACKTEST_SESSION_START_TIME)
            # Variable local para fin txt.
            fin_txt = self._normalizar_hora_backtest_texto(hora_fin, BACKTEST_SESSION_END_TIME)
            # Variable local para inicio.
            inicio = datetime.strptime(f"{fecha} {inicio_txt}:00", "%Y-%m-%d %H:%M:%S")
            # Variable local para fin.
            fin = datetime.strptime(f"{fecha} {fin_txt}:00", "%Y-%m-%d %H:%M:%S")
        except Exception:
            return None, None
        if fin <= inicio:
            fin = inicio + timedelta(minutes=15)
        return inicio, fin

    def _filtrar_puntos_intradia(
        self,
        serie: list[tuple[datetime, float]],
        inicio: datetime,
        fin: datetime,
        *,
        ratio_live: float | None,
        ts_live: datetime | None,
        incluir_live: bool,
    ) -> list[tuple[datetime, float]]:
        """Combina la serie histórica por minuto con el último punto vivo cuando corresponde."""
        # Variable local para puntos.
        puntos = [(ts, float(valor)) for ts, valor in serie if inicio <= ts <= fin]
        if incluir_live and ratio_live is not None and ts_live is not None and inicio <= ts_live <= fin:
            puntos.append((ts_live, float(ratio_live)))
        puntos.sort(key=lambda item: item[0])
        return puntos

    def _aplicar_eje_intradia(self, ax, inicio: datetime, fin: datetime) -> None:
        """Configura el eje intradía entre 10:30 y 17:00 con marcas cada 30 minutos."""
        if not isinstance(inicio, datetime) or not isinstance(fin, datetime):
            return
        if fin <= inicio:
            # Variable local para margen.
            margen = timedelta(minutes=15)
            # Variable local para inicio.
            inicio = inicio - margen
            # Variable local para fin.
            fin = fin + margen
        ax.set_xlim(inicio, fin)
        ax.xaxis.set_major_locator(mdates.MinuteLocator(interval=30))
        ax.xaxis.set_major_formatter(mdates.DateFormatter("%H:%M"))
        for label in ax.get_xticklabels():
            label.set_rotation(45)
            label.set_horizontalalignment("right")
            label.set_fontsize(8)
    def _configurar_estilo_tablas(self) -> None:
        """Ajusta el estilo visual de las grillas para que sean más legibles."""
        # Variable local para style.
        style = ttk.Style(self.root)
        try:
            if "vista" in style.theme_names():
                style.theme_use("vista")
        except Exception:
            pass
        style.configure("Treeview", rowheight=24)
        style.configure("Treeview.Heading", padding=(8, 6))

    def _crear_treeview_con_scrollbars(self, parent, columns: tuple[str, ...], height: int):
        """Crea un Treeview con scroll vertical y horizontal dentro del parent indicado."""
        # Variable local para frame.
        frame = ttk.Frame(parent)
        frame.pack(fill=BOTH, expand=True)
        frame.columnconfigure(0, weight=1)
        frame.rowconfigure(0, weight=1)
        # Variable local para tree.
        tree = ttk.Treeview(frame, columns=columns, show="headings", height=height, selectmode="extended")
        # Variable local para vsb.
        vsb = ttk.Scrollbar(frame, orient=VERTICAL, command=tree.yview)
        # Variable local para hsb.
        hsb = ttk.Scrollbar(frame, orient="horizontal", command=tree.xview)
        tree.configure(yscrollcommand=vsb.set, xscrollcommand=hsb.set)
        tree.grid(row=0, column=0, sticky="nsew")
        vsb.grid(row=0, column=1, sticky="ns")
        hsb.grid(row=1, column=0, sticky="ew")
        return tree

    # Función auxiliar para tree sort key.
    def _tree_sort_key(self, tree) -> str:
        return str(id(tree))

    def _registrar_tree_ordenable(self, tree, textos: dict[str, str]) -> None:
        """Registra encabezados clickeables y recuerda el texto base de cada columna."""
        # Variable local para key.
        key = self._tree_sort_key(tree)
        self._tree_heading_texts[key] = dict(textos)
        self._actualizar_headings_tree(tree)

    def _actualizar_headings_tree(self, tree) -> None:
        """Refresca los títulos de columnas agregando la flecha de orden cuando aplica."""
        # Variable local para key.
        key = self._tree_sort_key(tree)
        # Colección temporal de textos usada para normalizar información.
        textos = self._tree_heading_texts.get(key, {})
        columna_orden, descendente = self._tree_sort_state.get(key, ("", False))
        # Variable local para slot tabla relaciones.
        slot_tabla_rel = self._tabla_rel_tree_slot_by_key.get(key)
        # Variable local para seleccionadas.
        seleccionadas = set(self._tabla_rel_selected_plot_cols.get(slot_tabla_rel, [])) if slot_tabla_rel is not None else set()
        # Variable local para x col.
        x_col = self._tabla_rel_plot_x_cols.get(slot_tabla_rel) if slot_tabla_rel is not None else None
        if isinstance(tree, SheetTableAdapter):
            tree.begin_bulk_update()
        try:
            for columna, texto in textos.items():
                # Variable local para sufijo.
                sufijo = ""
                if columna == columna_orden:
                    sufijo = " ▼" if descendente else " ▲"
                # Variable local para marcadores.
                marcadores = ""
                if columna == x_col:
                    marcadores += "X "
                if columna in seleccionadas:
                    marcadores += "● "
                tree.heading(
                    columna,
                    text=f"{marcadores}{texto}{sufijo}",
                    command=lambda c=columna, t=tree: self._alternar_orden_tree(t, c),
                )
        finally:
            if isinstance(tree, SheetTableAdapter):
                tree.end_bulk_update(refresh=True)

    def _parsear_valor_orden_tree(self, valor: Any) -> tuple[int, Any]:
        """Convierte el valor visible de una celda en una clave robusta de ordenamiento."""
        if valor is None:
            return (2, "")
        # Texto temporal usado para armar o normalizar información.
        texto = str(valor).strip()
        if not texto:
            return (2, "")
        if texto in {"☐", "☑"}:
            return (0, 1 if texto == "☑" else 0)
        # Variable local para candidato.
        candidato = texto.replace("%", "").replace(",", "")
        try:
            return (0, float(candidato))
        except Exception:
            return (1, normalizar_texto(texto))

    def _ordenar_tree_en_memoria(self, tree, columna: str, descendente: bool) -> None:
        """Ordena un Treeview ya cargado sin reconstruir la tabla desde cero."""
        # Variable local para columnas.
        columnas = tuple(tree.cget("columns"))
        if columna not in columnas:
            return
        # Variable local para idx.
        idx = columnas.index(columna)
        # Variable local para seleccion.
        seleccion = tuple(tree.selection())
        # Variable local para foco.
        foco = tree.focus()
        # Variable local para filas con valor.
        filas_con_valor: list[tuple[tuple[int, Any], int, str]] = []
        # Variable local para filas vacias.
        filas_vacias: list[tuple[int, str]] = []
        # Variable local para filas fijas final.
        filas_fijas_final: list[tuple[int, str]] = []
        for posicion, item_id in enumerate(tree.get_children("")):
            # Variable local para tags.
            tags = set(tree.item(item_id, "tags") or ())
            if "resumen_final" in tags:
                filas_fijas_final.append((posicion, item_id))
                continue
            # Colección temporal de valores usada en este cálculo.
            valores = tree.item(item_id, "values") or ()
            # Valor temporal usado en este cálculo.
            valor = valores[idx] if idx < len(valores) else ""
            # Clave temporal usada para indexar o matchear datos.
            clave = self._parsear_valor_orden_tree(valor)
            if clave[0] == 2:
                filas_vacias.append((posicion, item_id))
            else:
                filas_con_valor.append((clave, posicion, item_id))
        filas_con_valor.sort(key=lambda item: (item[0][0], item[0][1], item[1]), reverse=descendente)
        # Variable local para orden final.
        orden_final = [item_id for _, _, item_id in filas_con_valor] + [item_id for _, item_id in filas_vacias] + [item_id for _, item_id in filas_fijas_final]
        if isinstance(tree, SheetTableAdapter):
            tree.begin_bulk_update()
        try:
            for nuevo_indice, item_id in enumerate(orden_final):
                tree.move(item_id, "", nuevo_indice)
            self._retag_tree_tras_orden(tree)
            if seleccion:
                tree.selection_set(tuple(item_id for item_id in seleccion if tree.exists(item_id)))
            if foco and tree.exists(foco):
                tree.focus(foco)
                tree.see(foco)
            self._tree_sort_state[self._tree_sort_key(tree)] = (columna, descendente)
            self._actualizar_headings_tree(tree)
        finally:
            if isinstance(tree, SheetTableAdapter):
                tree.end_bulk_update(refresh=True)

    def _retag_tree_tras_orden(self, tree) -> None:
        """Reaplica bandas visuales luego de ordenar para que no queden corridas."""
        for idx, item_id in enumerate(tree.get_children("")):
            # Variable local para tags.
            tags = list(tree.item(item_id, "tags") or ())
            # Variable local para base.
            base = [tag for tag in tags if tag not in {"par", "impar", "live_par", "live_impar"}]
            # Variable local para es live.
            es_live = "live_par" in tags or "live_impar" in tags
            # Variable local para es resumen final.
            es_resumen_final = "resumen_final" in base
            if es_resumen_final:
                pass
            elif es_live:
                base.append("live_par" if idx % 2 == 0 else "live_impar")
            elif tree in {getattr(self, "tree_gex", None), getattr(self, "tree_ratios", None), getattr(self, "tree_comp", None), getattr(self, "tree_tabla_rel", None), getattr(self, "tree_backtest", None)}:
                base.append("par" if idx % 2 == 0 else "impar")
            elif idx % 2 == 0 and any(tag in {"accion", "calls", "puts", "futuros", "sin_clasificar"} for tag in base):
                base.append("par")
            tree.item(item_id, tags=tuple(base))

    def _alternar_orden_tree(self, tree, columna: str) -> None:
        """Alterna ascendente/descendente para la columna clickeada."""
        # Variable local para key.
        key = self._tree_sort_key(tree)
        # Variable local para actual.
        actual = self._tree_sort_state.get(key)
        # Variable local para descendente.
        descendente = False
        if actual and actual[0] == columna:
            descendente = not actual[1]
        self._ordenar_tree_en_memoria(tree, columna, descendente)

    def _reaplicar_orden_tree(self, tree) -> None:
        """Reaplica el orden actual después de recargar la tabla."""
        # Variable local para key.
        key = self._tree_sort_key(tree)
        # Variable local para estado.
        estado = self._tree_sort_state.get(key)
        if estado:
            self._ordenar_tree_en_memoria(tree, estado[0], estado[1])
        else:
            self._actualizar_headings_tree(tree)

