    def _estado_opcion_compacta(self, fila: dict[str, Any] | None, tipo: str, spot: float | None, strike_atm: float | None) -> str:
        """Devuelve ITM, ATM u OTM para la grilla compacta."""
        if not fila:
            return ""
        strike = convertir_a_numero(fila.get("strike"))
        if strike is None:
            return ""
        if strike_atm is not None and abs(float(strike) - float(strike_atm)) < 0.0001:
            return "ATM"
        if spot is None:
            return ""
        if tipo == "calls":
            return "ITM" if float(strike) < float(spot) else "OTM"
        return "ITM" if float(strike) > float(spot) else "OTM"

    def _calcular_chg_compacto(self, fila: dict[str, Any] | None) -> float | None:
        """Calcula un cambio simple si la fila trae referencia previa."""
        if not fila:
            return None
        actual = convertir_a_numero(fila.get("last"))
        for clave in ("var_dia", "chg", "change", "variacion", "var_abs"):
            valor = convertir_a_numero(fila.get(clave))
            if valor is not None:
                return float(valor)
        previo = convertir_a_numero(fila.get("last_anterior") or fila.get("cierre_anterior") or fila.get("previous_close"))
        if actual is not None and previo is not None:
            return float(actual) - float(previo)
        return None

    def _formatear_compacto(self, clave: str, valor: Any) -> str:
        """Formatea celdas de la vista compacta."""
        if valor is None:
            return ""
        numero = convertir_a_numero(valor)
        if numero is None:
            return str(valor)
        if clave in {"call_delta", "put_delta", "call_vega", "put_vega", "call_theta", "put_theta"}:
            return f"{float(numero):.3f}"
        if clave in {"call_iv", "put_iv"}:
            return f"{float(numero):.2f}"
        if clave in {"call_chg", "put_chg"}:
            return f"{float(numero):+.2f}"
        if clave == "strike":
            flotante = float(numero)
            return f"{int(flotante)}" if flotante.is_integer() else f"{flotante:.2f}"
        return f"{float(numero):.2f}"

    def _construir_filas_compactas_opciones(
        self,
        filas_calls: list[dict[str, Any]],
        filas_puts: list[dict[str, Any]],
        spot: float | None,
    ) -> list[dict[str, Any]]:
        """Une calls y puts por strike para mostrarlas en una sola tabla."""
        calls_por_strike: dict[float, dict[str, Any]] = {}
        puts_por_strike: dict[float, dict[str, Any]] = {}
        for fila in filas_calls:
            strike = convertir_a_numero(fila.get("strike"))
            if strike is not None:
                calls_por_strike[round(float(strike), 4)] = fila
        for fila in filas_puts:
            strike = convertir_a_numero(fila.get("strike"))
            if strike is not None:
                puts_por_strike[round(float(strike), 4)] = fila
        strikes = sorted(set(calls_por_strike) | set(puts_por_strike))
        strike_atm = min(strikes, key=lambda item: abs(item - float(spot))) if strikes and spot is not None else None
        filas: list[dict[str, Any]] = []
        for strike in strikes:
            call = calls_por_strike.get(strike)
            put = puts_por_strike.get(strike)
            filas.append(
                {
                    "call_estado": self._estado_opcion_compacta(call, "calls", spot, strike_atm),
                    "call_delta": call.get("delta") if call else None,
                    "call_vega": call.get("vega") if call else None,
                    "call_theta": call.get("theta") if call else None,
                    "call_bid": call.get("bid") if call else None,
                    "call_ask": call.get("ask") if call else None,
                    "call_last": call.get("last") if call else None,
                    "call_chg": self._calcular_chg_compacto(call),
                    "call_iv": call.get("iv") if call else None,
                    "strike": strike,
                    "put_iv": put.get("iv") if put else None,
                    "put_chg": self._calcular_chg_compacto(put),
                    "put_last": put.get("last") if put else None,
                    "put_ask": put.get("ask") if put else None,
                    "put_bid": put.get("bid") if put else None,
                    "put_theta": put.get("theta") if put else None,
                    "put_vega": put.get("vega") if put else None,
                    "put_delta": put.get("delta") if put else None,
                    "put_estado": self._estado_opcion_compacta(put, "puts", spot, strike_atm),
                    "call_ticker": call.get("ticker") if call else "",
                    "put_ticker": put.get("ticker") if put else "",
                }
            )
        return filas

    def _cargar_tree_compact_top(self, filas_acciones: list[dict[str, Any]], filas_futuros: list[dict[str, Any]]) -> None:
        """Carga Galicia CI/24 hs y los futuros disponibles."""
        tree = self.tree_compact_top
        tree.delete(*tree.get_children())
        filas = list(filas_acciones) + list(filas_futuros)
        filas.sort(
            key=lambda fila: (
                0 if str(fila.get("tipo") or "") == "accion" else 1,
                str(fila.get("vencimiento") or ""),
                str(fila.get("ticker") or ""),
            )
        )
        for idx, fila in enumerate(filas):
            valores = [self._formatear_valor(col, fila.get(col)) for col in self.COMPACT_TOP_COLUMNS]
            tags = ["compact_accion" if str(fila.get("tipo") or "") == "accion" else "compact_futuro"]
            if idx % 2:
                tags.append("impar")
            tree.insert("", END, iid=f"compact_top_{idx}", values=valores, tags=tuple(tags))
        self._reaplicar_orden_tree(tree)

    def _cargar_tree_compact_options(self, filas: list[dict[str, Any]]) -> None:
        """Carga la tabla unificada de opciones."""
        tree = self.tree_compact_options
        ticker_call = self._selected_call_ticker
        ticker_put = self._selected_put_ticker
        tree.delete(*tree.get_children())
        iid_objetivo = None
        for idx, fila in enumerate(filas):
            valores = [self._formatear_compacto(col, fila.get(col)) for col in self.COMPACT_OPTIONS_COLUMNS]
            tags: list[str] = []
            if fila.get("call_estado") == "ATM" or fila.get("put_estado") == "ATM":
                tags.append("compact_atm")
            elif fila.get("call_estado") == "ITM":
                tags.append("compact_call_itm")
            elif fila.get("put_estado") == "ITM":
                tags.append("compact_put_itm")
            elif idx % 2:
                tags.append("impar")
            iid = f"compact_options_{idx}"
            tree.insert("", END, iid=iid, values=valores, tags=tuple(tags))
            if ticker_call and fila.get("call_ticker") == ticker_call:
                iid_objetivo = iid
            elif ticker_put and fila.get("put_ticker") == ticker_put:
                iid_objetivo = iid
        self._reaplicar_orden_tree(tree)
        if iid_objetivo is not None:
            tree.selection_set(iid_objetivo)
            tree.focus(iid_objetivo)

    def _refrescar_vista_compacta(
        self,
        filas_calls: list[dict[str, Any]],
        filas_puts: list[dict[str, Any]],
        filas_acciones: list[dict[str, Any]],
        filas_futuros: list[dict[str, Any]],
        spot: float | None,
    ) -> None:
        """Actualiza la vista compacta de mercado."""
        self._cargar_tree_compact_top(filas_acciones, filas_futuros)
        filas_opciones = self._construir_filas_compactas_opciones(filas_calls, filas_puts, spot)
        self._cargar_tree_compact_options(filas_opciones)

