    def _row_key_tabla_rel(self, fila: dict[str, Any], modo: str) -> str:
        """Construye una clave estable de fila para persistir la selección entre refrescos."""
        fecha = str(fila.get("fecha") or "").strip()
        fuente = str(fila.get("fuente") or "").strip().lower()
        if str(modo) == "intradia":
            if fuente == "cambio" or fuente.startswith("vivo"):
                return f"{fecha}|{fuente}"
            return fecha
        if fuente.startswith("vivo") or fuente in {"promedio", "ema", "prob_positiva"}:
            return f"{fecha}|{fuente}"
        return fecha

    def _persistir_seleccion_filas_tabla_rel(self, tree, slot: int, modo: str) -> None:
        """Guarda la selección actual de filas usando claves de datos en lugar de iids volátiles."""
        try:
            if str(modo) == "intradia":
                filas = list(self._intradia_rel_last_rows.get(slot, []) or [])
                prefijo = "tabla_rel_intradia_"
                destino = self._intradia_rel_selected_row_keys
            else:
                filas = list(self._tabla_rel_last_rows.get(slot, []) or [])
                prefijo = "tabla_rel_"
                destino = self._tabla_rel_selected_row_keys
            claves = []
            for item in tree.selection():
                if not str(item).startswith(prefijo):
                    continue
                try:
                    idx = int(str(item).replace(prefijo, "", 1))
                except Exception:
                    continue
                if 0 <= idx < len(filas):
                    clave = self._row_key_tabla_rel(filas[idx], modo)
                    if clave and clave not in claves:
                        claves.append(clave)
            destino[slot] = claves[:2]
        except Exception:
            LOGGER.exception("No se pudo persistir la selección de filas en Tabla relaciones")

    def _reaplicar_seleccion_filas_tabla_rel(self, tree, filas: list[dict[str, Any]], slot: int, modo: str) -> None:
        """Restaura la selección persistida luego de reconstruir la tabla."""
        try:
            claves_obj = list((self._intradia_rel_selected_row_keys if str(modo) == "intradia" else self._tabla_rel_selected_row_keys).get(slot, []) or [])
            if not claves_obj:
                return
            prefijo = "tabla_rel_intradia_" if str(modo) == "intradia" else "tabla_rel_"
            seleccion = []
            for idx, fila in enumerate(filas):
                clave = self._row_key_tabla_rel(fila, modo)
                if clave in claves_obj:
                    iid = f"{prefijo}{idx}"
                    if tree.exists(iid):
                        seleccion.append(iid)
            if seleccion:
                tree.selection_set(tuple(seleccion[:2]))
                try:
                    tree.focus(seleccion[0])
                    tree.see(seleccion[0])
                except Exception:
                    pass
        except Exception:
            LOGGER.exception("No se pudo restaurar la selección de filas en Tabla relaciones")

    def _construir_registros_tabla_rel_cache(
        self,
        filas: list[dict[str, Any]],
        slot: int,
        modo: str,
    ) -> list[dict[str, Any]]:
        """Construye registros formateados para SheetTableAdapter reutilizando un caché por subvista."""
        modo_norm = 'intradia' if str(modo).strip().lower() == 'intradia' else 'diaria'
        clave_cache = (int(slot or 1), modo_norm)
        firma = tuple(
            (
                str(fila.get('fecha') or ''),
                str(fila.get('fuente') or ''),
                tuple((col, fila.get(col)) for col in self.TABLA_REL_COLUMNAS),
            )
            for fila in filas
        )
        cache = self._tabla_rel_render_cache.get(clave_cache) or {}
        if cache.get('signature') == firma:
            return [
                {
                    'iid': str(reg.get('iid') or ''),
                    'values': tuple(reg.get('values') or ()),
                    'tags': tuple(reg.get('tags') or ()),
                    'raw': dict(reg.get('raw') or {}),
                }
                for reg in list(cache.get('rows') or [])
            ]
        registros: list[dict[str, Any]] = []
        for idx, fila in enumerate(filas):
            valores = [
                self._formatear_valor_tabla_rel(col, fila.get(col), slot=slot, modo=modo_norm)
                for col in self.TABLA_REL_COLUMNAS
            ]
            tags = self._tags_visuales_tabla_rel(idx, fila, slot, modo_norm)
            prefijo = 'tabla_rel_intradia' if modo_norm == 'intradia' else 'tabla_rel'
            registros.append({
                'iid': f'{prefijo}_{idx}',
                'values': tuple(valores),
                'tags': tuple(tags),
                'raw': dict(fila),
            })
        self._tabla_rel_render_cache[clave_cache] = {
            'signature': firma,
            'rows': [
                {
                    'iid': reg['iid'],
                    'values': tuple(reg['values']),
                    'tags': tuple(reg['tags']),
                    'raw': dict(reg['raw']),
                }
                for reg in registros
            ],
        }
        return registros

    def _cargar_tree_tabla_rel_intradia_en(self, tree, filas: list[dict[str, Any]]) -> None:
        """Carga la tabla intradía de relaciones en el árbol indicado."""
        slot = None
        try:
            slot = self._tree_tabla_rel_slot_by_key.get(self._tree_sort_key(tree))
            if slot is None:
                for slot_candidato, widgets in self._intradia_rel_widgets.items():
                    if widgets.get("tree") is tree:
                        slot = int(slot_candidato)
                        self._tree_tabla_rel_slot_by_key[self._tree_sort_key(tree)] = slot
                        break
            if slot is not None:
                self._persistir_seleccion_filas_tabla_rel(tree, int(slot), "intradia")
        except Exception:
            LOGGER.exception("No se pudo persistir la selección previa de intradía")
        if isinstance(tree, SheetTableAdapter):
            registros = []
            for idx, fila in enumerate(filas):
                valores = [self._formatear_valor_tabla_rel(col, fila.get(col), slot=int(slot or 1), modo='intradia') for col in self.TABLA_REL_INTRADIA_COLUMNAS]
                tags = self._tags_visuales_tabla_rel(idx, fila, int(slot or 1), 'intradia')
                registros.append({'iid': f'tabla_rel_intradia_{idx}', 'values': tuple(valores), 'tags': tuple(tags), 'raw': dict(fila)})
            tree.set_context(self, int(slot or 1), 'intradia')
            tree.load_rows(registros)
        else:
            tree.delete(*tree.get_children())
            for idx, fila in enumerate(filas):
                valores = [self._formatear_valor_tabla_rel(col, fila.get(col), slot=int(slot or 1), modo="intradia") for col in self.TABLA_REL_INTRADIA_COLUMNAS]
                tags = self._tags_visuales_tabla_rel(idx, fila, int(slot or 1), "intradia")
                tree.insert("", END, iid=f"tabla_rel_intradia_{idx}", values=valores, tags=tuple(tags))
        self._reaplicar_orden_tree(tree)
        if slot is not None:
            self._reaplicar_seleccion_filas_tabla_rel(tree, filas, int(slot), "intradia")

    def _seleccionar_fila_tabla_rel(self, tree, item: str, slot: int, modo: str) -> None:
        """Selecciona una fila y persiste el cambio para diaria o intradía."""
        item = str(item or '').strip()
        if not item:
            return
        seleccion = list(tree.selection())
        if item not in seleccion:
            if len(seleccion) >= 2:
                return
            tree.selection_add(item)
        try:
            tree.focus(item)
            tree.see(item)
        except Exception:
            pass
        self._persistir_seleccion_filas_tabla_rel(tree, slot, modo)

    def _deseleccionar_fila_tabla_rel(self, tree, item: str, slot: int, modo: str) -> None:
        """Quita una fila de la selección y persiste el cambio para diaria o intradía."""
        item = str(item or '').strip()
        if not item:
            return
        tree.selection_remove(item)
        self._persistir_seleccion_filas_tabla_rel(tree, slot, modo)

    def _limpiar_seleccion_filas_tabla_rel(self, tree, slot: int, modo: str) -> None:
        """Limpia la selección de filas y actualiza la persistencia asociada a la vista."""
        try:
            tree.selection_remove(*tree.selection())
        except Exception:
            pass
        self._persistir_seleccion_filas_tabla_rel(tree, slot, modo)

    def _label_grafico_columnas_tabla_rel(self, tree, slot: int) -> str:
        """Devuelve el texto del menú para graficar las columnas seleccionadas."""
        seleccionadas = [col for col in self._tabla_rel_selected_plot_cols.get(slot, []) if self._columna_graficable_tabla_rel(col)]
        textos = self._tree_heading_texts.get(self._tree_sort_key(tree), {})
        if not seleccionadas:
            return "Graficar columnas seleccionadas"
        if len(seleccionadas) == 1:
            return f"Graficar: {textos.get(seleccionadas[0], seleccionadas[0])}"
        if len(seleccionadas) == 2:
            a, b = seleccionadas[:2]
            return f"Graficar: {textos.get(a, a)} vs {textos.get(b, b)}"
        return f"Graficar {len(seleccionadas)} columnas seleccionadas"

    def _on_tabla_rel_row_ctrl_select(self, event, tree, slot: int, modo: str):
        """Alterna la selección de una fila con Ctrl+clic, igual que el graficador de columnas."""
        try:
            if getattr(tree, 'identify_region', None) is not None and tree.identify_region(event.x, event.y) == "heading":
                return None
            item = tree.identify_row_from_event(event) if hasattr(tree, 'identify_row_from_event') else tree.identify_row(event.y)
            if not item:
                return None
            seleccion = list(tree.selection())
            if item in seleccion:
                self._deseleccionar_fila_tabla_rel(tree, item, slot, modo)
            else:
                if len(seleccion) >= 2:
                    item_a_remover = seleccion[-1]
                    if item_a_remover and item_a_remover != item:
                        self._deseleccionar_fila_tabla_rel(tree, item_a_remover, slot, modo)
                        seleccion = list(tree.selection())
                self._seleccionar_fila_tabla_rel(tree, item, slot, modo)
            return "break"
        except Exception:
            LOGGER.exception("No se pudo alternar la selección de filas en Tabla relaciones")
            return None

    def _on_tabla_rel_row_right_click(self, event, tree, slot: int, modo: str) -> None:
        """Muestra un menú contextual para seleccionar filas, calcular P/L, graficar columnas y abrir notas de la vista."""
        try:
            if getattr(tree, 'identify_region', None) is not None and tree.identify_region(event.x, event.y) == "heading":
                return None
            item = tree.identify_row_from_event(event) if hasattr(tree, 'identify_row_from_event') else tree.identify_row(event.y)
            if item:
                try:
                    tree.focus(item)
                    tree.see(item)
                except Exception:
                    pass
            seleccion = list(tree.selection())
            if item and item not in seleccion and len(seleccion) < 2:
                self._seleccionar_fila_tabla_rel(tree, item, slot, modo)
                seleccion = list(tree.selection())
            self._persistir_seleccion_filas_tabla_rel(tree, slot, modo)
            menu = Menu(tree, tearoff=0)
            if item:
                if item in seleccion:
                    menu.add_command(label="Quitar fila seleccionada", command=lambda t=tree, i=item, s=slot, m=modo: self._deseleccionar_fila_tabla_rel(t, i, s, m))
                else:
                    estado = "normal" if len(seleccion) < 2 else "disabled"
                    menu.add_command(label="Seleccionar fila", state=estado, command=lambda t=tree, i=item, s=slot, m=modo: self._seleccionar_fila_tabla_rel(t, i, s, m))
                menu.add_separator()
            if len(seleccion) == 2:
                menu.add_command(label="Calcular P/L entre filas seleccionadas", command=lambda s=slot, m=modo: self._abrir_popup_pnl_tabla_rel(s, m))
            else:
                menu.add_command(label="Calcular P/L entre filas seleccionadas", state="disabled")
            columnas_seleccionadas = [col for col in self._tabla_rel_selected_plot_cols.get(slot, []) if self._columna_graficable_tabla_rel(col)]
            if columnas_seleccionadas:
                if str(modo) == "intradia":
                    menu.add_command(label=self._label_grafico_columnas_tabla_rel(tree, slot), command=lambda s=slot: self._abrir_popup_grafico_tabla_rel_intradia(s))
                else:
                    menu.add_command(label=self._label_grafico_columnas_tabla_rel(tree, slot), command=lambda s=slot: self._abrir_popup_grafico_tabla_rel(s))
            else:
                menu.add_command(label="Graficar columnas seleccionadas", state="disabled")
            menu.add_command(label="Abrir notas de esta vista", command=lambda s=slot, m=modo: self._abrir_popup_notas_tabla_rel(s, m))
            submenu_ecdf = Menu(menu, tearoff=0)
            var_formato = self._var_formato_ecdf_tabla_rel(slot, modo)
            for valor in self._tabla_rel_ecdf_format_modes:
                submenu_ecdf.add_radiobutton(
                    label=self._texto_formato_ecdf_tabla_rel(valor),
                    value=valor,
                    variable=var_formato,
                    command=lambda s=slot, m=modo, v=valor, t=tree: self._actualizar_formato_ecdf_tabla_rel(t, s, m, v),
                )
            menu.add_cascade(label="Formato condicional ECDF", menu=submenu_ecdf)
            estado_limpiar = "normal" if seleccion else "disabled"
            menu.add_command(label="Limpiar selección", state=estado_limpiar, command=lambda t=tree, s=slot, m=modo: self._limpiar_seleccion_filas_tabla_rel(t, s, m))
            menu.add_separator()
            menu.add_command(label="Tip: Ctrl+clic para marcar hasta 2 filas", state="disabled")
            menu.add_command(label="Tip: Ctrl+clic en encabezados para preparar un gráfico", state="disabled")
            menu.add_command(label="Tip: el formato ECDF marca cada columna ECDF visible de forma individual", state="disabled")
            menu.add_command(label="Tip: las notas se guardan al cerrar o al usar Guardar", state="disabled")
            try:
                menu.tk_popup(event.x_root, event.y_root)
            finally:
                try:
                    menu.grab_release()
                except Exception:
                    pass
            return "break"
        except Exception:
            LOGGER.exception("No se pudo abrir el menú de filas de Tabla relaciones")
            return None

    def _modo_formato_ecdf_tabla_rel(self, modo: str) -> str:
        """Normaliza el modo de formato condicional ECDF para diaria o intradía."""
        return "intradia" if str(modo or "").strip().lower() == "intradia" else "diaria"

    def _var_formato_ecdf_tabla_rel(self, slot: int, modo: str):
        """Devuelve la variable persistente del formato condicional ECDF para la subvista."""
        slot = int(slot or 1)
        modo_norm = self._modo_formato_ecdf_tabla_rel(modo)
        if modo_norm == "intradia":
            return self._tabla_rel_ecdf_format_intradia_vars[slot]
        return self._tabla_rel_ecdf_format_diaria_vars[slot]

    def _texto_formato_ecdf_tabla_rel(self, valor: str) -> str:
        """Convierte la clave interna del formato ECDF en un texto legible para el menú."""
        valor_norm = str(valor or "").strip().lower()
        if valor_norm == "gradient":
            return "Degradé rojo↔verde"
        if valor_norm == "extremos20":
            return "Extremos 20%"
        return "Off"

    def _usar_sheet_tabla_rel_slot(self, slot: int | None, modo: str | None) -> bool:
        """Indica si la subvista de tabla relaciones usa tksheet en lugar de Treeview."""
        try:
            slot_norm = int(slot or 1)
        except Exception:
            slot_norm = 1
        modo_norm = self._modo_formato_ecdf_tabla_rel(modo or 'diaria')
        widgets = self._intradia_rel_widgets.get(slot_norm, {}) if modo_norm == 'intradia' else self._tabla_rel_widgets.get(slot_norm, {})
        return isinstance(widgets.get('tree'), SheetTableAdapter)

    def _interpolar_color_hex(self, color_a: tuple[int, int, int], color_b: tuple[int, int, int], t: float) -> str:
        """Interpola linealmente entre dos colores RGB y devuelve un color hex."""
        t_norm = max(0.0, min(1.0, float(t)))
        r = int(round(color_a[0] + (color_b[0] - color_a[0]) * t_norm))
        g = int(round(color_a[1] + (color_b[1] - color_a[1]) * t_norm))
        b = int(round(color_a[2] + (color_b[2] - color_a[2]) * t_norm))
        return f'#{r:02x}{g:02x}{b:02x}'

    def _color_formato_ecdf_tabla_rel(self, columna: str, fila: dict[str, Any], slot: int | None, modo: str | None) -> tuple[str | None, str | None]:
        """Devuelve el color de fondo/texto para una celda ECDF cuando la tabla usa tksheet."""
        try:
            if not str(columna or '').startswith(('ecdf_', 'ecdfratio_')):
                return None, None
            if slot is None:
                return None, None
            modo_norm = self._modo_formato_ecdf_tabla_rel(modo or 'diaria')
            formato = str(self._var_formato_ecdf_tabla_rel(int(slot or 1), modo_norm).get()).strip().lower()
            if formato not in self._tabla_rel_ecdf_format_modes or formato == 'off':
                return None, None
            valor_num = convertir_a_numero((fila or {}).get(columna))
            if valor_num is None:
                return None, None
            valor_f = float(valor_num)
            if not math.isfinite(valor_f):
                return None, None
            if valor_f > 1.0 and valor_f <= 100.0:
                valor_f = valor_f / 100.0
            valor_f = max(0.0, min(1.0, valor_f))
            if formato == 'gradient':
                rojo = (244, 204, 204)
                amarillo = (255, 242, 204)
                verde = (217, 234, 211)
                if valor_f <= 0.5:
                    bg = self._interpolar_color_hex(rojo, amarillo, valor_f / 0.5)
                else:
                    bg = self._interpolar_color_hex(amarillo, verde, (valor_f - 0.5) / 0.5)
                return bg, '#111111'
            if formato == 'extremos20':
                if valor_f <= 0.20:
                    intensidad = 1.0 - (valor_f / 0.20)
                    bg = self._interpolar_color_hex((252, 232, 230), (234, 153, 153), intensidad)
                    return bg, '#111111'
                if valor_f >= 0.80:
                    intensidad = (valor_f - 0.80) / 0.20
                    bg = self._interpolar_color_hex((217, 234, 211), (147, 196, 125), intensidad)
                    return bg, '#111111'
            return None, None
        except Exception:
            LOGGER.exception('No se pudo calcular el color condicional ECDF para tksheet')
            return None, None

    def _columnas_ecdf_visibles_tabla_rel(self, slot: int, modo: str) -> list[str]:
        """Lista las columnas ECDF visibles que participan del formato condicional."""
        slot = int(slot or 1)
        modo_norm = self._modo_formato_ecdf_tabla_rel(modo)
        if modo_norm == "intradia":
            visibles = self._columnas_visibles_tabla_rel_intradia(slot)
        else:
            visibles = self._columnas_visibles_tabla_rel(slot)
        return [
            columna
            for columna in visibles
            if columna.startswith("ecdf_") or columna.startswith("ecdfratio_")
        ]

    def _configurar_tags_formato_ecdf_tree(self, tree) -> None:
        """Mantiene compatibilidad con versiones previas del formato ECDF."""
        return

    def _tag_formato_ecdf_tabla_rel(self, fila: dict[str, Any], slot: int, modo: str) -> str | None:
        """Compatibilidad: el formato ECDF ahora se aplica por celda, no por fila."""
        return None

    def _prefijo_ecdf_celda_tabla_rel(self, columna: str, valor: Any, slot: int | None, modo: str | None) -> str:
        """Devuelve un prefijo visual individual para cada columna ECDF visible.

        ttk.Treeview no permite colorear celdas individuales de forma nativa. Para
        mantener la tabla actual y aun así distinguir cada columna ECDF por separado,
        se antepone un marcador visual dentro del texto de la celda.
        """
        try:
            if not columna.startswith(("ecdf_", "ecdfratio_")):
                return ""
            if slot is None:
                return ""
            modo_norm = self._modo_formato_ecdf_tabla_rel(modo or "diaria")
            if self._usar_sheet_tabla_rel_slot(int(slot or 1), modo_norm):
                return ""
            formato = str(self._var_formato_ecdf_tabla_rel(int(slot or 1), modo_norm).get()).strip().lower()
            if formato not in self._tabla_rel_ecdf_format_modes or formato == "off":
                return ""
            valor_num = convertir_a_numero(valor)
            if valor_num is None:
                return ""
            valor_f = float(valor_num)
            if not math.isfinite(valor_f):
                return ""
            valor_f = max(0.0, min(1.0, valor_f))
            if formato == "gradient":
                if valor_f <= 0.10:
                    return "🟥 "
                if valor_f <= 0.25:
                    return "🟧 "
                if valor_f <= 0.40:
                    return "🟨 "
                if valor_f < 0.60:
                    return "▫ "
                if valor_f < 0.75:
                    return "🟨 "
                if valor_f < 0.90:
                    return "🟩 "
                return "🟢 "
            if formato == "extremos20":
                if valor_f <= 0.20:
                    intensidad = int(math.ceil((0.20 - valor_f) / 0.04))
                    intensidad = max(1, min(5, intensidad))
                    rep = 1 if intensidad <= 2 else (2 if intensidad <= 4 else 3)
                    return ("🟥" * rep) + " "
                if valor_f >= 0.80:
                    intensidad = int(math.ceil((valor_f - 0.80) / 0.04))
                    intensidad = max(1, min(5, intensidad))
                    rep = 1 if intensidad <= 2 else (2 if intensidad <= 4 else 3)
                    return ("🟩" * rep) + " "
            return ""
        except Exception:
            LOGGER.exception("No se pudo calcular el prefijo ECDF de celda")
            return ""

    def _actualizar_formato_ecdf_tabla_rel(self, tree, slot: int, modo: str, valor: str) -> None:
        """Aplica un modo de formato ECDF, lo persiste y repinta la tabla correspondiente."""
        try:
            modo_norm = self._modo_formato_ecdf_tabla_rel(modo)
            valor_norm = str(valor or "off").strip().lower()
            if valor_norm not in self._tabla_rel_ecdf_format_modes:
                valor_norm = "off"
            self._var_formato_ecdf_tabla_rel(int(slot or 1), modo_norm).set(valor_norm)
            self._guardar_estado_ui()
            self._configurar_tags_formato_ecdf_tree(tree)
            if modo_norm == "intradia":
                filas = list(self._intradia_rel_last_rows.get(int(slot or 1), []) or [])
                if tree is not None:
                    self._cargar_tree_tabla_rel_intradia_en(tree, filas)
            else:
                filas = list(self._tabla_rel_last_rows.get(int(slot or 1), []) or [])
                if tree is not None:
                    self._cargar_tree_tabla_rel_en(tree, filas, int(slot or 1))
        except Exception:
            LOGGER.exception("No se pudo actualizar el formato condicional ECDF")

    def _modo_nota_tabla_rel(self, modo: str) -> str:
        """Normaliza el modo usado por las notas de Tabla relaciones."""
        return "intradia" if str(modo or "").strip().lower() == "intradia" else "diaria"

    def _clave_nota_tabla_rel(self, slot: int, modo: str) -> str:
        """Construye la clave persistente para las notas de una subvista."""
        return f"{self._modo_nota_tabla_rel(modo)}_{int(slot)}"

    def _texto_nota_tabla_rel(self, slot: int, modo: str) -> str:
        """Devuelve el texto persistido de la nota de una subvista."""
        return str(self._tabla_rel_notes_texts.get(self._clave_nota_tabla_rel(slot, modo), ""))

    def _guardar_nota_tabla_rel(self, slot: int, modo: str, text_widget=None, status_var=None) -> None:
        """Guarda en disco la nota de la subvista actual."""
        clave = self._clave_nota_tabla_rel(slot, modo)
        texto = self._texto_nota_tabla_rel(slot, modo)
        if text_widget is not None:
            try:
                texto = text_widget.get("1.0", "end-1c")
            except Exception:
                texto = self._texto_nota_tabla_rel(slot, modo)
        self._tabla_rel_notes_texts[clave] = str(texto)
        if status_var is not None:
            try:
                status_var.set(f"Notas guardadas: {ahora_texto()}")
            except Exception:
                pass
        self._guardar_estado_ui()

    def _cerrar_popup_notas_tabla_rel(self, slot: int, modo: str) -> None:
        """Cierra la ventana de notas guardando su contenido actual."""
        clave = self._clave_nota_tabla_rel(slot, modo)
        popup = self._tabla_rel_notes_windows.pop(clave, None)
        if not popup:
            return
        text_widget = popup.get("text")
        status_var = popup.get("status_var")
        try:
            self._guardar_nota_tabla_rel(slot, modo, text_widget=text_widget, status_var=status_var)
        except Exception:
            LOGGER.exception("No se pudo guardar la nota antes de cerrar")
        ventana = popup.get("window")
        if ventana is not None:
            try:
                ventana.destroy()
            except Exception:
                pass

    def _abrir_popup_notas_tabla_rel(self, slot: int, modo: str) -> None:
        """Abre una ventana emergente para tomar notas persistentes de la subvista."""
        modo_nota = self._modo_nota_tabla_rel(modo)
        clave = self._clave_nota_tabla_rel(slot, modo_nota)
        existente = self._tabla_rel_notes_windows.get(clave, {})
        ventana = existente.get("window")
        if ventana is None or not ventana.winfo_exists():
            ventana = Toplevel(self.root)
            ventana.title(f"Notas - Tabla relaciones {'intradía' if modo_nota == 'intradia' else 'diaria'} - Vista {slot}")
            ventana.geometry("760x420")
            frame = ttk.Frame(ventana, padding=8)
            frame.pack(fill=BOTH, expand=True)
            info_var = StringVar(
                value=(
                    "Escribí las notas de esta subvista. Se guardan al cerrar la ventana o al presionar Guardar."
                )
            )
            ttk.Label(frame, textvariable=info_var, justify="left").pack(anchor=W, pady=(0, 6))
            frame_text = ttk.Frame(frame)
            frame_text.pack(fill=BOTH, expand=True)
            scrollbar = ttk.Scrollbar(frame_text, orient=VERTICAL)
            scrollbar.pack(side=RIGHT, fill=Y)
            text_widget = Text(frame_text, wrap="word", undo=True, yscrollcommand=scrollbar.set)
            text_widget.pack(side=LEFT, fill=BOTH, expand=True)
            scrollbar.configure(command=text_widget.yview)
            text_widget.insert("1.0", self._texto_nota_tabla_rel(slot, modo_nota))
            text_widget.bind(
                "<FocusOut>",
                lambda _e, s=slot, m=modo_nota, tw=text_widget, sv=info_var: self._guardar_nota_tabla_rel(s, m, text_widget=tw, status_var=sv),
                add="+",
            )
            frame_buttons = ttk.Frame(frame)
            frame_buttons.pack(fill=X, pady=(8, 0))
            ttk.Button(
                frame_buttons,
                text="Guardar",
                command=lambda s=slot, m=modo_nota, tw=text_widget, sv=info_var: self._guardar_nota_tabla_rel(s, m, text_widget=tw, status_var=sv),
            ).pack(side=LEFT)
            ttk.Button(frame_buttons, text="Cerrar", command=lambda s=slot, m=modo_nota: self._cerrar_popup_notas_tabla_rel(s, m)).pack(side=LEFT, padx=(8, 0))
            self._tabla_rel_notes_windows[clave] = {
                "window": ventana,
                "text": text_widget,
                "status_var": info_var,
            }
            ventana.protocol("WM_DELETE_WINDOW", lambda s=slot, m=modo_nota: self._cerrar_popup_notas_tabla_rel(s, m))
            try:
                text_widget.focus_set()
            except Exception:
                pass
        else:
            try:
                ventana.deiconify()
                ventana.lift()
            except Exception:
                pass
            text_widget = existente.get("text")
            if text_widget is not None:
                try:
                    text_widget.focus_set()
                except Exception:
                    pass

    def _obtener_filas_seleccionadas_tabla_rel(self, slot: int, modo: str) -> list[dict[str, Any]]:
        """Devuelve el tramo visible entre dos filas seleccionadas, incluyendo intermedias."""
        if str(modo) == "intradia":
            widgets = self._intradia_rel_widgets.get(slot, {})
            tree = widgets.get("tree")
            filas = list(self._intradia_rel_last_rows.get(slot, []) or [])
            prefijo = "tabla_rel_intradia_"
        else:
            widgets = self._tabla_rel_widgets.get(slot, {})
            tree = widgets.get("tree")
            filas = list(self._tabla_rel_last_rows.get(slot, []) or [])
            prefijo = "tabla_rel_"
        if tree is None:
            return []
        seleccion = list(tree.selection())
        if len(seleccion) != 2:
            return []
        indices = []
        for item_id in seleccion:
            try:
                indices.append(int(str(item_id).replace(prefijo, "", 1)))
            except Exception:
                continue
        indices = sorted(idx for idx in indices if 0 <= idx < len(filas))
        if len(indices) != 2:
            return []
        idx_ini, idx_fin = indices[0], indices[1]
        if idx_ini == idx_fin:
            return [dict(filas[idx_ini])]
        return [dict(f) for f in filas[idx_ini:idx_fin + 1]]

    def _serie_pnl_entre_filas_tabla_rel(self, filas: list[dict[str, Any]]) -> list[dict[str, Any]]:
        """Construye la serie intermedia de P/L desde la fila de entrada hasta la de salida."""
        if len(filas) < 2:
            return []
        fila_entrada = dict(filas[0])
        valor_ab = convertir_a_numero(fila_entrada.get("costo_bull"))
        valor_spread = convertir_a_numero(fila_entrada.get("a_menos_b_last"))
        valor_pos = convertir_a_numero(fila_entrada.get("ratio_pos_1a2b"))
        valor_inv = convertir_a_numero(fila_entrada.get("ratio_inv_1a2b"))
        salida = []
        for idx, fila in enumerate(filas):
            actual_ab = convertir_a_numero(fila.get("costo_bull"))
            actual_spread = convertir_a_numero(fila.get("a_menos_b_last"))
            actual_pos = convertir_a_numero(fila.get("ratio_pos_1a2b"))
            actual_inv = convertir_a_numero(fila.get("ratio_inv_1a2b"))
            precio_a_egreso = convertir_a_numero(fila.get("precio_a"))
            precio_b_egreso = convertir_a_numero(fila.get("precio_b"))
            salida.append({
                "momento": str(fila.get("fecha") or idx),
                "precio_a": self._formatear_pnl_tabla_rel(precio_a_egreso),
                "precio_b": self._formatear_pnl_tabla_rel(precio_b_egreso),
                "valor_ab": self._formatear_pnl_tabla_rel(actual_ab),
                "valor_spread": self._formatear_pnl_tabla_rel(actual_spread),
                "valor_pos": self._formatear_pnl_tabla_rel(actual_pos),
                "valor_inv": self._formatear_pnl_tabla_rel(actual_inv),
                "pnl_ab": (float(actual_ab) - float(valor_ab)) if actual_ab is not None and valor_ab is not None else None,
                "pnl_spread": (float(actual_spread) - float(valor_spread)) if actual_spread is not None and valor_spread is not None else None,
                "pnl_pos": (float(actual_pos) - float(valor_pos)) if actual_pos is not None and valor_pos is not None else None,
                "pnl_inv": (float(actual_inv) - float(valor_inv)) if actual_inv is not None and valor_inv is not None else None,
                "etapa": "Entrada" if idx == 0 else ("Salida" if idx == len(filas) - 1 else "Intermedia"),
            })
        return salida

    def _formatear_pnl_tabla_rel(self, valor: Any) -> str:
        """Formatea P/L de estrategias para la ventana emergente."""
        numero = convertir_a_numero(valor)
        if numero is None:
            return ""
        return f"{float(numero):.2f}"

    def _formatear_par_precios_tabla_rel(self, precio_a: Any, precio_b: Any) -> str:
        """Formatea los precios de las dos bases para mostrar ingreso y egreso en el popup."""
        valor_a = convertir_a_numero(precio_a)
        valor_b = convertir_a_numero(precio_b)
        if valor_a is None and valor_b is None:
            return ""
        texto_a = "-" if valor_a is None else f"{float(valor_a):.2f}"
        texto_b = "-" if valor_b is None else f"{float(valor_b):.2f}"
        return f"A {texto_a} | B {texto_b}"


    def _abrir_popup_pnl_tabla_rel(self, slot: int, modo: str) -> None:
        """Muestra una ventana con P/L intermedio y final entre dos filas seleccionadas."""
        filas_seleccionadas = self._obtener_filas_seleccionadas_tabla_rel(slot, modo)
        if len(filas_seleccionadas) < 2:
            messagebox.showinfo("P/L entre filas", "Seleccioná exactamente 2 filas con Ctrl + clic izquierdo.")
            return
        filas_ordenadas = list(filas_seleccionadas)
        serie = self._serie_pnl_entre_filas_tabla_rel(filas_ordenadas)
        if not serie:
            messagebox.showinfo("P/L entre filas", "No se pudo construir la serie intermedia entre las dos filas seleccionadas.")
            return

        mostrar_ab = bool(self._tabla_rel_show_ab_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_spread = bool(self._tabla_rel_show_spread_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_ratio_pos = bool(self._tabla_rel_show_ratio_pos_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_ratio_neg = bool(self._tabla_rel_show_ratio_neg_vars.get(slot, BooleanVar(value=True)).get())

        columnas = ["momento", "precio_a", "precio_b"]
        if mostrar_ab:
            columnas.extend(["valor_ab", "pnl_ab"])
        if mostrar_spread:
            columnas.extend(["valor_spread", "pnl_spread"])
        if mostrar_ratio_pos:
            columnas.extend(["valor_pos", "pnl_pos"])
        if mostrar_ratio_neg:
            columnas.extend(["valor_inv", "pnl_inv"])
        columnas.append("etapa")
        columnas = tuple(columnas)

        encabezados = {
            "momento": "Fila",
            "precio_a": "Precio A",
            "precio_b": "Precio B",
            "valor_ab": "Valor A+B",
            "pnl_ab": "P/L A+B",
            "valor_spread": "Valor A-B",
            "pnl_spread": "P/L A-B",
            "valor_pos": "Valor +A-2B",
            "pnl_pos": "P/L +A-2B",
            "valor_inv": "Valor -A+2B",
            "pnl_inv": "P/L -A+2B",
            "etapa": "Etapa",
        }
        anchos = {
            "momento": 120,
            "precio_a": 110,
            "precio_b": 110,
            "valor_ab": 120,
            "pnl_ab": 120,
            "valor_spread": 120,
            "pnl_spread": 120,
            "valor_pos": 130,
            "pnl_pos": 130,
            "valor_inv": 130,
            "pnl_inv": 130,
            "etapa": 110,
        }
        ancho_total = sum(anchos[c] for c in columnas) + 80
        ancho_total = max(980, min(ancho_total, 1500))

        clave = f"{modo}_{slot}"
        existente = self._tabla_rel_pnl_windows.get(clave, {})
        ventana = existente.get("window")
        if ventana is None or not ventana.winfo_exists():
            ventana = Toplevel(self.root)
            ventana.title(f"P/L entre filas - {'Intradía' if str(modo) == 'intradia' else 'Diaria'} - Vista {slot}")
            ventana.geometry(f"{ancho_total}x560")
            frame = ttk.Frame(ventana, padding=6)
            frame.pack(fill=BOTH, expand=True)
            info_var = StringVar(value="")
            ttk.Label(frame, textvariable=info_var, justify="left").pack(anchor=W, pady=(0, 6))
            tree = self._crear_treeview_con_scrollbars(frame, columnas, height=18)
            for col in columnas:
                tree.column(col, width=anchos[col], anchor=W if col in {"momento", "etapa"} else "e", stretch=False)
            self._registrar_tree_ordenable(tree, {c: encabezados[c] for c in columnas})
            tree.tag_configure("resumen", background="#e6f4ea")
            self._tabla_rel_pnl_windows[clave] = {"window": ventana, "tree": tree, "info_var": info_var, "columnas": columnas}
        else:
            tree = existente["tree"]
            info_var = existente["info_var"]
            try:
                tree.configure(columns=columnas, displaycolumns=columnas)
            except Exception:
                pass
            for col in columnas:
                tree.column(col, width=anchos[col], anchor=W if col in {"momento", "etapa"} else "e", stretch=False)
                tree.heading(col, text=encabezados[col])
            self._tabla_rel_pnl_windows[clave]["columnas"] = columnas
            ventana.geometry(f"{ancho_total}x560")
            ventana.deiconify()
            ventana.lift()
        info_var.set(
            f"Entrada: {serie[0].get('momento')} | Salida: {serie[-1].get('momento')} | "
            f"La primera fila es la entrada y cada fila siguiente muestra el P/L acumulado usando esa fila como salida potencial."
        )
        tree.delete(*tree.get_children())
        for idx, fila in enumerate(serie):
            valores = []
            for col in columnas:
                if col == "momento":
                    valores.append(str(fila.get("momento") or ""))
                elif col == "precio_a":
                    valores.append(str(fila.get("precio_a") or ""))
                elif col == "precio_b":
                    valores.append(str(fila.get("precio_b") or ""))
                elif col == "valor_ab":
                    valores.append(str(fila.get("valor_ab") or ""))
                elif col == "pnl_ab":
                    valores.append(self._formatear_pnl_tabla_rel(fila.get("pnl_ab")))
                elif col == "valor_spread":
                    valores.append(str(fila.get("valor_spread") or ""))
                elif col == "pnl_spread":
                    valores.append(self._formatear_pnl_tabla_rel(fila.get("pnl_spread")))
                elif col == "valor_pos":
                    valores.append(str(fila.get("valor_pos") or ""))
                elif col == "pnl_pos":
                    valores.append(self._formatear_pnl_tabla_rel(fila.get("pnl_pos")))
                elif col == "valor_inv":
                    valores.append(str(fila.get("valor_inv") or ""))
                elif col == "pnl_inv":
                    valores.append(self._formatear_pnl_tabla_rel(fila.get("pnl_inv")))
                elif col == "etapa":
                    valores.append(str(fila.get("etapa") or ""))
            tag = ("resumen",) if idx == len(serie) - 1 else ()
            tree.insert("", END, values=tuple(valores), tags=tag)

