    # Alterna el estado de metrica matriz bases.
    def _toggle_metrica_matriz_bases(self) -> None:
        # Variable local para actual.
        actual = self.var_matriz_bases_metric.get().strip().lower() or "ratio"
        try:
            # Variable local para idx.
            idx = self._matriz_bases_metric_modes.index(actual)
        except ValueError:
            idx = 0
        # Variable local para nuevo.
        nuevo = self._matriz_bases_metric_modes[(idx + 1) % len(self._matriz_bases_metric_modes)]
        self.var_matriz_bases_metric.set(nuevo)
