    def _normalizar_trio_registro_mariposa(self, slot: int, opciones_slot: list[str]) -> bool:
        """Normaliza la selección de A/B/C en registro mariposa asegurando valores válidos y distintos."""
        if slot not in self._registro_mariposa_slots:
            return False
        # Variable de Tkinter de texto para A.
        var_a = self._registro_mariposa_vars_a[slot]
        # Variable de Tkinter de texto para B.
        var_b = self._registro_mariposa_vars_b[slot]
        # Variable de Tkinter de texto para C.
        var_c = self._registro_mariposa_vars_c[slot]
        # Variable local para cambio local.
        cambio_local = False
        # Variable local para base idx.
        base_idx = (slot - 1) * 3
        # Variable local para default A.
        default_a = opciones_slot[base_idx] if len(opciones_slot) > base_idx else (opciones_slot[0] if opciones_slot else "")
        # Variable local para default B.
        default_b = opciones_slot[base_idx + 1] if len(opciones_slot) > base_idx + 1 else (opciones_slot[1] if len(opciones_slot) > 1 else default_a)
        # Variable local para default C.
        default_c = opciones_slot[base_idx + 2] if len(opciones_slot) > base_idx + 2 else (opciones_slot[2] if len(opciones_slot) > 2 else (opciones_slot[-1] if opciones_slot else ""))

        if var_a.get().strip() not in opciones_slot:
            var_a.set(default_a)
            cambio_local = True
        if var_b.get().strip() not in opciones_slot:
            var_b.set(default_b)
            cambio_local = True
        if var_c.get().strip() not in opciones_slot:
            var_c.set(default_c)
            cambio_local = True

        # Variable local para usados.
        usados: set[str] = set()
        for variable in (var_a, var_b, var_c):
            # Valor temporal usado en este cálculo.
            valor = variable.get().strip()
            if valor and valor not in usados:
                usados.add(valor)
                continue
            # Variable local para reemplazo.
            reemplazo = next((op for op in opciones_slot if op not in usados), valor)
            if variable.get().strip() != reemplazo:
                variable.set(reemplazo)
                cambio_local = True
            # Variable local para valor nuevo.
            valor_nuevo = variable.get().strip()
            if valor_nuevo:
                usados.add(valor_nuevo)
        return cambio_local

    def _refrescar_selector_matriz_bases(self) -> None:
        """Actualiza la lista de fuentes disponibles para la matriz de bases."""
        if not hasattr(self, "combo_matriz_bases_fuente"):
            return
        # Caché en memoria para cache.
        cache = self._obtener_cache_cierres_json()
        # Variable local para fuentes.
        fuentes = ["HOY (vivo)"] + sorted(cache.keys(), reverse=True)
        self._set_combobox_values_si_cambia(self.combo_matriz_bases_fuente, "matriz_bases_fuentes", fuentes)
        # Variable local para actual.
        actual = self.var_matriz_bases_fuente.get().strip()
        if actual not in fuentes:
            self.var_matriz_bases_fuente.set(fuentes[0] if fuentes else "HOY (vivo)")

    def _formatear_strike_matriz_bases(self, valor: Any) -> str:
        """Formatea el strike usado como etiqueta de filas y columnas en la matriz."""
        # Número temporal calculado en este bloque.
        numero = convertir_a_numero(valor)
        if numero is None:
            return ""
        # Variable local para flotante.
        flotante = float(numero)
        return f"{int(flotante)}" if flotante.is_integer() else f"{flotante:.2f}"

    def _valor_precio_matriz_bases(self, fila: dict[str, Any], *, vivo: bool) -> float | None:
        """Devuelve el precio base a usar en la matriz de relaciones."""
        # Variable local para last.
        last = convertir_a_numero(fila.get("last"))
        if last is not None and float(last) > 0:
            return float(last)
        if vivo:
            # Variable local para ref.
            ref = precio_referencia(fila)
            if ref is not None and float(ref) > 0:
                return float(ref)
        return None

    def _item_cotiza_para_matriz(self, item: dict[str, Any], modo: str) -> bool:
        """Indica si una base tiene precios suficientes para mostrarse en la matriz."""
        if not isinstance(item, dict):
            return False
        # Variable local para modo n.
        modo_n = str(modo or "last_last").strip().lower()
        # Variable local para last.
        last = convertir_a_numero(item.get("last"))
        # Variable local para bid.
        bid = convertir_a_numero(item.get("bid"))
        # Variable local para ask.
        ask = convertir_a_numero(item.get("ask"))
        if modo_n == "last_last":
            return last not in (None, 0)
        return bid not in (None, 0) and ask not in (None, 0)

    def _agrupar_bases_para_matriz(self, filas: list[dict[str, Any]], *, vivo: bool, modo: str) -> list[dict[str, Any]]:
        """Agrupa por strike las bases con todas sus puntas disponibles para la matriz."""
        # Variable local para por strike.
        por_strike: dict[float, dict[str, Any]] = {}
        for fila in filas:
            # Variable local para strike.
            strike = convertir_a_numero(fila.get("strike"))
            if strike is None:
                continue
            # Variable local para last.
            last = convertir_a_numero(fila.get("last"))
            # Variable local para bid.
            bid = convertir_a_numero(fila.get("bid"))
            # Variable local para ask.
            ask = convertir_a_numero(fila.get("ask"))
            # Variable local para ref.
            ref = precio_referencia(fila) if vivo else None
            if last in (None, 0) and bid in (None, 0) and ask in (None, 0) and ref in (None, 0):
                continue
            # Clave temporal usada para indexar o matchear datos.
            clave = float(strike)
            # Variable local para candidato.
            candidato = {
                "strike": clave,
                "ticker": str(fila.get("ticker") or ""),
                "updated_at": str(fila.get("updated_at") or ""),
                "last": float(last) if last not in (None, 0) else None,
                "bid": float(bid) if bid not in (None, 0) else None,
                "ask": float(ask) if ask not in (None, 0) else None,
                "ref": float(ref) if ref not in (None, 0) else None,
                "score": sum(1 for valor in (last, bid, ask, ref) if valor not in (None, 0)),
                "tiene_last": last not in (None, 0),
            }
            # Variable local para previo.
            previo = por_strike.get(clave)
            if previo is None:
                por_strike[clave] = candidato
                continue
            if candidato["score"] > int(previo.get("score") or 0):
                por_strike[clave] = candidato
                continue
            if candidato["score"] == int(previo.get("score") or 0):
                if candidato["tiene_last"] and not previo.get("tiene_last"):
                    por_strike[clave] = candidato
                    continue
                if candidato["updated_at"] > str(previo.get("updated_at") or ""):
                    por_strike[clave] = candidato
        return [por_strike[clave] for clave in sorted(por_strike.keys()) if self._item_cotiza_para_matriz(por_strike[clave], modo)]

    def _precio_item_matriz_bases(self, item: dict[str, Any] | None, lado: str, modo: str) -> float | None:
        """Devuelve el precio a usar para una pierna según el modo activo de la matriz."""
        if not isinstance(item, dict):
            return None
        # Variable local para lado n.
        lado_n = str(lado or "").strip().lower()
        # Variable local para modo n.
        modo_n = str(modo or "last_last").strip().lower()
        if modo_n == "last_last":
            # Variable local para precio.
            precio = convertir_a_numero(item.get("last"))
            return float(precio) if precio not in (None, 0) else None
        if lado_n == "compra":
            precio = convertir_a_numero(item.get("ask"))
            return float(precio) if precio not in (None, 0) else None
        if lado_n == "venta":
            precio = convertir_a_numero(item.get("bid"))
            return float(precio) if precio not in (None, 0) else None
        return None

    def _calcular_valor_matriz_bases(self, precio_a: float | None, precio_b: float | None, metrica: str) -> float | None:
        """Calcula ratio, costo o % de llenado de la relación A/B según la vista elegida."""
        if precio_a is None or precio_b is None:
            return None
        # Variable local para metrica n.
        metrica_n = str(metrica or "ratio").strip().lower()
        if metrica_n in {"cost", "fill_pct"}:
            return float(precio_a) - float(precio_b)
        if float(precio_b) == 0:
            return None
        return float(precio_a) / float(precio_b)

    def _formatear_valor_matriz_bases(self, valor: float | None, metrica: str) -> str:
        """Formatea el valor mostrado en cada celda de la matriz."""
        if valor is None:
            return ""
        # Variable local para metrica n.
        metrica_n = str(metrica or "ratio").strip().lower()
        if metrica_n == "cost":
            return f"{float(valor):.2f}"
        if metrica_n == "fill_pct":
            return f"{float(valor):.1f}%"
        return f"{float(valor):.4f}"


    def _formatear_metricas_registro(self, valor_max: float | None, valor_actual: float | None) -> str:
        """Formatea métricas resumidas de costo actual vs. cobro máximo teórico."""
        if valor_max is None or valor_max <= 0:
            return "Max: s/d | Ahora: s/d | %: s/d"
        # Variable local para texto max.
        texto_max = f"{float(valor_max):.2f}"
        if valor_actual is None:
            return f"Max: {texto_max} | Ahora: s/d | %: s/d"
        # Variable local para porcentaje.
        porcentaje = (float(valor_actual) / float(valor_max)) * 100.0
        return f"Max: {texto_max} | Ahora: {float(valor_actual):.2f} | %: {porcentaje:.1f}%"

    def _valor_actual_registro_desde_serie(
        self,
        valor_live: float | None,
        serie: list[tuple[datetime, float]],
    ) -> float | None:
        """Prioriza el valor vivo y, si no existe, usa el último cierre disponible."""
        if valor_live is not None:
            return float(valor_live)
        if serie:
            try:
                return float(serie[-1][1])
            except Exception:
                return None
        return None

    def _strike_desde_ticker(self, ticker: str) -> float | None:
        """Devuelve el strike numérico del ticker seleccionado, si existe."""
        # Instrumento temporal procesado en este bloque.
        inst = self.instrumentos_por_ticker.get(str(ticker or "").strip())
        if inst is None:
            return None
        # Variable local para strike.
        strike = convertir_a_numero(getattr(inst, "strike", None))
        return float(strike) if strike is not None else None

    def _precio_leg_registro(self, fila: dict[str, Any], lado: str, *, simular_puntas: bool = False) -> float | None:
        """Devuelve el precio a usar para una pierna de estrategia en las vistas de registro."""
        if simular_puntas:
            if lado == "compra":
                # Variable local para precio.
                precio = convertir_a_numero(fila.get("ask"))
                if precio not in (None, 0):
                    return float(precio)
            elif lado == "venta":
                precio = convertir_a_numero(fila.get("bid"))
                if precio not in (None, 0):
                    return float(precio)
        # Variable local para last.
        last = convertir_a_numero(fila.get("last"))
        if last not in (None, 0):
            return float(last)
        # Variable local para ref.
        ref = precio_referencia(fila)
        if ref not in (None, 0):
            return float(ref)
        return None

    def _maximo_cobro_registro_spread(self, ticker_a: str, ticker_b: str) -> float | None:
        """Estimación del valor máximo bruto a cobrar por un vertical A-B."""
        # Variable local para strike A.
        strike_a = self._strike_desde_ticker(ticker_a)
        # Variable local para strike B.
        strike_b = self._strike_desde_ticker(ticker_b)
        if strike_a is None or strike_b is None:
            return None
        # Variable local para diferencia.
        diferencia = abs(float(strike_b) - float(strike_a))
        return diferencia if diferencia > 0 else None

    def _maximo_cobro_registro_mariposa(self, ticker_a: str, ticker_b: str, ticker_c: str) -> float | None:
        """Estimación del valor máximo bruto a cobrar por una mariposa comprada A-2B+C."""
        # Variable local para strike A.
        strike_a = self._strike_desde_ticker(ticker_a)
        # Variable local para strike B.
        strike_b = self._strike_desde_ticker(ticker_b)
        # Variable local para strike C.
        strike_c = self._strike_desde_ticker(ticker_c)
        if strike_a is None or strike_b is None or strike_c is None:
            return None
        # Variable local para izquierda.
        izquierda = float(strike_b) - float(strike_a)
        # Variable local para derecha.
        derecha = float(strike_c) - float(strike_b)
        if izquierda <= 0 or derecha <= 0:
            return None
        # Variable local para maximo.
        maximo = min(izquierda, derecha)
        return maximo if maximo > 0 else None

    def _obtener_serie_cache_registro_spread(self, ticker_a: str, ticker_b: str) -> list[tuple[datetime, float]]:
        """Devuelve la serie histórica de spread A-B usando un caché liviano en memoria."""
        # Clave temporal usada para indexar o matchear datos.
        clave = (str(ticker_a or "").strip(), str(ticker_b or "").strip())
        if not all(clave):
            return []
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if (
            clave not in self._registro_spread_series_cache
            or (ahora_ts - self._registro_spread_cache_loaded_at.get(clave, 0.0)) > ttl_cache
        ):
            self._registro_spread_series_cache[clave] = self._history_db.obtener_serie_spread_cierres(clave[0], clave[1], campo="last")
            self._registro_spread_cache_loaded_at[clave] = ahora_ts
        return list(self._registro_spread_series_cache.get(clave, []))

    def _etiqueta_par_registro_spread(self, slot: int, ticker_a: str, ticker_b: str) -> str:
        """Construye una etiqueta corta y estable para una serie del registro de spreads."""
        def _parte(ticker: str) -> str:
            # Instrumento temporal procesado en este bloque.
            inst = self.instrumentos_por_ticker.get(ticker)
            # Variable local para strike.
            strike = self._formatear_strike_matriz_bases(inst.strike if inst is not None else None)
            if strike:
                # Variable local para pref.
                pref = "C" if str(getattr(inst, "tipo", "")) == "calls" else ("P" if str(getattr(inst, "tipo", "")) == "puts" else "")
                return f"{pref}{strike}" if pref else strike
            return ticker.split(" - ")[-1][:18]
        return f"Par {slot}: {_parte(ticker_a)} - {_parte(ticker_b)}"

    def _obtener_serie_cache_registro_ratio_base(self, ticker_a: str, ticker_b: str) -> list[tuple[datetime, float]]:
        """Devuelve la serie histórica del ratio A/B usando caché liviano compartido."""
        # Clave temporal usada para indexar o matchear datos.
        clave = (str(ticker_a or "").strip(), str(ticker_b or "").strip())
        if not clave[0] or not clave[1]:
            return []
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if (
            clave not in self._registro_ratio_base_series_cache
            or (ahora_ts - self._registro_ratio_base_cache_loaded_at.get(clave, 0.0)) > ttl_cache
        ):
            self._registro_ratio_base_series_cache[clave] = self._history_db.obtener_serie_ratio_cierres(clave[0], clave[1], "last")
            self._registro_ratio_base_cache_loaded_at[clave] = ahora_ts
        return list(self._registro_ratio_base_series_cache.get(clave, []))

    def _color_registro_por_slot(self, slot: int) -> str:
        """Devuelve un color estable por slot para reutilizarlo en los gráficos de registro."""
        # Variable local para palette.
        palette = (
            "tab:blue",
            "tab:orange",
            "tab:green",
            "tab:red",
            "tab:purple",
            "tab:brown",
        )
        try:
            # Variable local para idx.
            idx = int(slot) - 1
        except Exception:
            idx = 0
        return palette[idx % len(palette)]

    def _dibujar_grafico_ratio_registro(
        self,
        ax,
        canvas,
        axis_key: str,
        pares_ratio: list[tuple[str, list[tuple[datetime, float]], float | None]],
        ts_live: datetime,
        titulo: str,
        color_map: dict[str, str] | None = None,
    ) -> None:
        """Dibuja un gráfico compacto con la evolución histórica del ratio A/B de los pares elegidos."""
        if ax is None or canvas is None:
            return
        self._capturar_vistas((axis_key,))
        ax.clear()
        # Variable local para series historicas.
        series_historicas = {etiqueta: serie for etiqueta, serie, _ratio_live in pares_ratio if serie}
        if not pares_ratio:
            ax.text(0.5, 0.5, "Seleccioná pares válidos para ver el ratio A/B.", ha="center", va="center", fontsize=8)
            ax.set_axis_off()
            canvas.draw_idle()
            return
        fechas_base, mapa_pos, etiquetas_x, pos_live_extra = self._construir_eje_categorico_por_datos(series_historicas or {}, ts_live)
        ax.set_axis_on()
        # Variable local para hubo lineas.
        hubo_lineas = False
        for etiqueta, serie, ratio_live in pares_ratio:
            # Variable local para puntos.
            puntos = self._serie_a_puntos_categoricos(serie, mapa_pos, ratio_live=ratio_live, ts_live=ts_live, pos_live_extra=pos_live_extra)
            if not puntos:
                continue
            # Variable local para xs.
            xs = [x for x, _ in puntos]
            # Variable local para ys.
            ys = [float(y) for _, y in puntos]
            # Variable local para color.
            color = (color_map or {}).get(etiqueta)
            ax.plot(xs, ys, marker="o", markersize=1.0, linewidth=1.0, label=etiqueta, color=color)
            ax.scatter([xs[-1]], [ys[-1]], s=10, color=color)
            try:
                ax.annotate(f"{ys[-1]:.2f}", (xs[-1], ys[-1]), xytext=(3, 0), textcoords="offset points", fontsize=7, va="center")
            except Exception:
                pass
            hubo_lineas = True
        if hubo_lineas:
            ax.set_title(titulo, fontsize=9)
            ax.set_xlabel("Fecha", fontsize=8)
            ax.set_ylabel("A/B", fontsize=8)
            ax.grid(True, alpha=0.25)
            self._aplicar_eje_categorico_comparador(ax, etiquetas_x or [])
            for label in ax.get_xticklabels():
                try:
                    label.set_fontsize(7)
                except Exception:
                    pass
            for label in ax.get_yticklabels():
                try:
                    label.set_fontsize(7)
                except Exception:
                    pass
        else:
            ax.text(0.5, 0.5, "No hay histórico suficiente para el ratio A/B.", ha="center", va="center", fontsize=8)
            ax.set_title(titulo, fontsize=9)
            self._aplicar_eje_categorico_comparador(ax, etiquetas_x or [])
        self._restaurar_vistas((axis_key,))
        canvas.draw_idle()

    def _tipo_registro_mariposa_normalizado(self, valor: Any) -> str:
        """Normaliza el selector de tipo de mariposa a comprada o vendida."""
        # Texto temporal usado para armar o normalizar información.
        texto = str(valor or "").strip().lower()
        return "vendida" if texto.startswith("vend") else "comprada"

    def _texto_tipo_registro_mariposa(self, valor: Any) -> str:
        """Devuelve el texto visible del tipo de mariposa."""
        return "Vendida" if self._tipo_registro_mariposa_normalizado(valor) == "vendida" else "Comprada"

    def _valor_mariposa_registro(self, precio_a: float, precio_b: float, precio_c: float, tipo: str = "comprada") -> float:
        """Calcula el valor de la mariposa según sea comprada o vendida."""
        # Variable local para base.
        base = float(precio_a) - 2.0 * float(precio_b) + float(precio_c)
        return -base if self._tipo_registro_mariposa_normalizado(tipo) == "vendida" else base

    def _obtener_serie_cache_registro_mariposa(self, ticker_a: str, ticker_b: str, ticker_c: str, tipo: str = "comprada") -> list[tuple[datetime, float]]:
        """Devuelve la serie histórica de mariposa según el tipo usando caché liviano."""
        # Variable local para tipo norm.
        tipo_norm = self._tipo_registro_mariposa_normalizado(tipo)
        # Clave temporal usada para indexar o matchear datos.
        clave = (str(ticker_a or "").strip(), str(ticker_b or "").strip(), str(ticker_c or "").strip(), tipo_norm)
        if not all(clave[:3]):
            return []
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if (
            clave not in self._registro_mariposa_series_cache
            or (ahora_ts - self._registro_mariposa_cache_loaded_at.get(clave, 0.0)) > ttl_cache
        ):
            # Serie temporal construida en este bloque.
            serie = self._history_db.obtener_serie_mariposa_cierres(clave[0], clave[1], clave[2], campo="last")
            if tipo_norm == "vendida":
                serie = [(ts, -float(valor)) for ts, valor in serie]
            self._registro_mariposa_series_cache[clave] = serie
            self._registro_mariposa_cache_loaded_at[clave] = ahora_ts
        return list(self._registro_mariposa_series_cache.get(clave, []))

    def _obtener_series_cache_registro_mariposa_puntas(self, ticker_a: str, ticker_b: str, ticker_c: str, tipo: str = "comprada") -> dict[str, list[tuple[datetime, float]]]:
        """Devuelve las series históricas de apertura y cierre por puntas para la mariposa."""
        # Variable local para tipo norm.
        tipo_norm = self._tipo_registro_mariposa_normalizado(tipo)
        # Clave temporal usada para indexar o matchear datos.
        clave = (str(ticker_a or "").strip(), str(ticker_b or "").strip(), str(ticker_c or "").strip(), tipo_norm)
        if not all(clave[:3]):
            return {"abrir": [], "cerrar": []}
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if (
            clave not in self._registro_mariposa_puntas_series_cache
            or (ahora_ts - self._registro_mariposa_puntas_cache_loaded_at.get(clave, 0.0)) > ttl_cache
        ):
            self._registro_mariposa_puntas_series_cache[clave] = self._history_db.obtener_series_mariposa_puntas_diarias(clave[0], clave[1], clave[2], tipo_norm)
            self._registro_mariposa_puntas_cache_loaded_at[clave] = ahora_ts
        # Variable local para data.
        data = self._registro_mariposa_puntas_series_cache.get(clave, {}) or {}
        return {
            "abrir": list(data.get("abrir") or []),
            "cerrar": list(data.get("cerrar") or []),
        }

    def _etiqueta_trio_registro_mariposa(self, slot: int, ticker_a: str, ticker_b: str, ticker_c: str, tipo: str = "comprada") -> str:
        """Construye una etiqueta corta y estable para una serie del registro de mariposas."""
        def _parte(ticker: str) -> str:
            # Instrumento temporal procesado en este bloque.
            inst = self.instrumentos_por_ticker.get(ticker)
            # Variable local para strike.
            strike = self._formatear_strike_matriz_bases(inst.strike if inst is not None else None)
            if strike:
                # Variable local para pref.
                pref = "C" if str(getattr(inst, "tipo", "")) == "calls" else ("P" if str(getattr(inst, "tipo", "")) == "puts" else "")
                return f"{pref}{strike}" if pref else strike
            return ticker.split(" - ")[-1][:18]
        # Variable local para pref tipo.
        pref_tipo = "MV" if self._tipo_registro_mariposa_normalizado(tipo) == "vendida" else "MC"
        return f"{pref_tipo} {slot}: {_parte(ticker_a)} - 2×{_parte(ticker_b)} + {_parte(ticker_c)}"

    def _obtener_serie_cache_registro_ratio_invertido(self, ticker_a: str, ticker_b: str, coef_venta: float) -> list[tuple[datetime, float]]:
        """Devuelve la serie histórica de un ratio invertido A - n×B usando caché liviano."""
        try:
            # Variable local para coeficiente.
            coef = float(coef_venta)
        except Exception:
            coef = 1.0
        # Clave temporal usada para indexar o matchear datos.
        clave = (str(ticker_a or "").strip(), str(ticker_b or "").strip(), round(coef, 4))
        if not clave[0] or not clave[1]:
            return []
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if (
            clave not in self._registro_ratio_inv_series_cache
            or (ahora_ts - self._registro_ratio_inv_cache_loaded_at.get(clave, 0.0)) > ttl_cache
        ):
            self._registro_ratio_inv_series_cache[clave] = self._history_db.obtener_serie_ratio_invertido_cierres(clave[0], clave[1], clave[2], campo="last")
            self._registro_ratio_inv_cache_loaded_at[clave] = ahora_ts
        return list(self._registro_ratio_inv_series_cache.get(clave, []))

    def _etiqueta_par_registro_ratio_invertido(self, slot: int, ticker_a: str, ticker_b: str, coef_venta: float) -> str:
        """Construye una etiqueta corta y estable para una serie del registro de ratio invertido."""
        def _parte(ticker: str) -> str:
            # Instrumento temporal procesado en este bloque.
            inst = self.instrumentos_por_ticker.get(ticker)
            # Variable local para strike.
            strike = self._formatear_strike_matriz_bases(inst.strike if inst is not None else None)
            if strike:
                # Variable local para pref.
                pref = "C" if str(getattr(inst, "tipo", "")) == "calls" else ("P" if str(getattr(inst, "tipo", "")) == "puts" else "")
                return f"{pref}{strike}" if pref else strike
            return ticker.split(" - ")[-1][:18]
        return f"Ratio {slot}: {_parte(ticker_a)} - {coef_venta:.2f}×{_parte(ticker_b)}"

    # Devuelve el texto descriptivo para estrategia backtest vencimiento.
    def _texto_estrategia_backtest_vencimiento(self, clave: str) -> str:
        # Variable local para etiquetas.
        etiquetas = {k: v for k, v in self._backtest_venc_strategy_options}
        return etiquetas.get(str(clave or "").strip(), "Comprar A+B")

    def _obtener_serie_cache_backtest_vencimiento(self, ticker_a: str, ticker_b: str, estrategia: str, coef_ratio: float) -> list[tuple[datetime, float]]:
        """Devuelve la serie histórica de valor de estrategia del backtest diario heredado."""
        try:
            # Variable local para coeficiente.
            coef = float(coef_ratio)
        except Exception:
            coef = 1.0
        # Clave temporal usada para indexar o matchear datos.
        clave = (str(ticker_a or "").strip(), str(ticker_b or "").strip(), str(estrategia or "").strip(), round(coef, 4))
        if not clave[0] or not clave[1]:
            return []
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if clave not in self._backtest_venc_series_cache or (ahora_ts - self._backtest_venc_cache_loaded_at.get(clave, 0.0)) > ttl_cache:
            # Variable local para estrategia norm.
            estrategia_norm = clave[2]
            if estrategia_norm == "long_ab":
                # Serie temporal construida en este bloque.
                serie = self._history_db.obtener_serie_suma_cierres(clave[0], clave[1], campo="last")
            elif estrategia_norm == "spread_buy":
                serie = self._history_db.obtener_serie_spread_cierres(clave[0], clave[1], campo="last")
            elif estrategia_norm == "spread_sell":
                serie = [(ts, -float(valor)) for ts, valor in self._history_db.obtener_serie_spread_cierres(clave[0], clave[1], campo="last")]
            elif estrategia_norm == "ratio_buy":
                serie = self._history_db.obtener_serie_ratio_invertido_cierres(clave[0], clave[1], clave[3], campo="last")
            elif estrategia_norm == "ratio_sell":
                serie = [(ts, -float(valor)) for ts, valor in self._history_db.obtener_serie_ratio_invertido_cierres(clave[0], clave[1], clave[3], campo="last")]
            else:
                serie = []
            self._backtest_venc_series_cache[clave] = serie
            self._backtest_venc_cache_loaded_at[clave] = ahora_ts
        return list(self._backtest_venc_series_cache.get(clave, []))

    def _valor_estrategia_backtest_vencimiento(self, precio_a: float | None, precio_b: float | None, estrategia: str, coef_ratio: float) -> float | None:
        """Calcula el valor actual de la estrategia elegida para el backtest por vencimiento."""
        if precio_a is None or precio_b is None:
            return None
        try:
            # Variable local para coeficiente.
            coef = float(coef_ratio)
        except Exception:
            coef = 1.0
        # Variable local para estrategia norm.
        estrategia_norm = str(estrategia or "").strip()
        if estrategia_norm == "long_ab":
            return float(precio_a) + float(precio_b)
        if estrategia_norm == "spread_buy":
            return float(precio_a) - float(precio_b)
        if estrategia_norm == "spread_sell":
            return -float(precio_a) + float(precio_b)
        if estrategia_norm == "ratio_buy":
            return float(precio_a) - float(coef) * float(precio_b)
        if estrategia_norm == "ratio_sell":
            return -float(precio_a) + float(coef) * float(precio_b)
        return None

    def _etiqueta_backtest_vencimiento(self, slot: int, ticker_a: str, ticker_b: str, estrategia: str, coef_ratio: float) -> str:
        """Devuelve una etiqueta compacta para el gráfico de backtest por vencimiento."""
        # Variable local para base.
        base = self._etiqueta_par_registro_spread(slot, ticker_a, ticker_b).replace(f"Par {slot}: ", "")
        # Texto temporal usado para armar o normalizar información.
        texto = self._texto_estrategia_backtest_vencimiento(estrategia)
        if str(estrategia or "").startswith("ratio"):
            texto += f" {float(coef_ratio):.2f}×"
        return f"BT {slot}: {texto} | {base}"

    # Función auxiliar para obtener filas cache backtest vencimiento.
    def _obtener_filas_cache_backtest_vencimiento(self, ticker_a: str, ticker_b: str) -> list[dict[str, Any]]:
        # Clave temporal usada para indexar o matchear datos.
        clave = (ticker_a, ticker_b)
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        # Caché en memoria para ttl cache.
        ttl_cache = 10.0
        if clave not in self._backtest_venc_rows_cache or (ahora_ts - self._backtest_venc_rows_loaded_at.get(clave, 0.0)) > ttl_cache:
            self._backtest_venc_rows_cache[clave] = self._history_db.obtener_cierres_completos_par(ticker_a, ticker_b)
            self._backtest_venc_rows_loaded_at[clave] = ahora_ts
        return list(self._backtest_venc_rows_cache.get(clave, []))

    # Función auxiliar para construir filas backtest vencimiento.
    def _construir_filas_backtest_vencimiento(self, ticker_a: str, ticker_b: str, estrategia: str, coef_ratio: float) -> list[dict[str, Any]]:
        # Filas temporales recuperadas o construidas en este paso.
        filas = self._obtener_filas_cache_backtest_vencimiento(ticker_a, ticker_b)
        # Variable local para salida.
        salida: list[dict[str, Any]] = []
        for fila in filas:
            # Fecha temporal usada en este cálculo.
            fecha = str(fila.get("fecha") or "").strip()
            if not fecha:
                continue
            try:
                # Marca temporal normalizada de la observación actual.
                ts = datetime.strptime(f"{fecha} 17:00:00", "%Y-%m-%d %H:%M:%S")
            except Exception:
                continue
            # Variable local para precio A.
            precio_a = convertir_a_numero(fila.get("precio_a"))
            # Variable local para precio B.
            precio_b = convertir_a_numero(fila.get("precio_b"))
            if precio_a is None or precio_b is None:
                continue
            # Valor temporal usado en este cálculo.
            valor = self._valor_estrategia_backtest_vencimiento(float(precio_a), float(precio_b), estrategia, coef_ratio)
            if valor is None:
                continue
            salida.append({
                "ts": ts,
                "fecha": fecha,
                "a_last": float(precio_a),
                "b_last": float(precio_b),
                "signal_value": float(valor),
            })
        return salida

    # Función auxiliar para simular backtest vencimiento estrategia.
    def _simular_backtest_vencimiento_estrategia(
        self,
        filas: list[dict[str, Any]],
        *,
        estrategia: str,
        sigma_mult: float,
        sigma_refuerzos: list[float],
        close_zone_pct: float = 0.05,
        extreme_sigma_mult: float = BACKTEST_EXTREME_SIGMA_MULT,
        extreme_cooldown_days: float = 0.0,
        enable_extreme_close: bool = True,
        modo_bandas: str = "dinamica",
        anios_bandas: int = 1,
    ) -> dict[str, Any]:
        # Variable local para filas ordenadas.
        filas_ordenadas = [fila for fila in filas if isinstance(fila.get("ts"), datetime) and convertir_a_numero(fila.get("signal_value")) is not None]
        filas_ordenadas.sort(key=lambda fila: fila["ts"])
        if len(filas_ordenadas) < 3:
            return {"operaciones": [], "pnl_total": 0.0, "cerradas": 0, "abiertas": 0}
        # Variable local para operaciones.
        operaciones: list[dict[str, Any]] = []
        # Variable local para posiciones abiertas.
        posiciones_abiertas: list[dict[str, Any]] = []
        # Variable local para sigma refuerzos validos.
        sigma_refuerzos_validos = sorted({float(v) for v in (sigma_refuerzos or []) if float(v) > float(sigma_mult)})[:2]
        # Variable local para cooldown until.
        cooldown_until: datetime | None = None
        # Variable local para modo bandas norm.
        modo_bandas_norm = str(modo_bandas or "dinamica").strip().lower()
        if modo_bandas_norm not in {"dinamica", "fija"}:
            modo_bandas_norm = "dinamica"
        # Variable local para anios norm.
        anios_norm = max(1, min(3, int(anios_bandas or 1)))
        # Variable local para dias ventana.
        dias_ventana = max(365 * anios_norm, 1)
        # Variable local para valores serie.
        valores_serie = [(fila["ts"], float(fila["signal_value"])) for fila in filas_ordenadas]

        if modo_bandas_norm == "fija":
            # Variable local para fecha final.
            fecha_final = valores_serie[-1][0]
            # Variable local para fecha inicio.
            fecha_inicio = fecha_final - timedelta(days=dias_ventana)
            # Variable local para ventana fija.
            ventana_fija = [valor for ts_v, valor in valores_serie if ts_v >= fecha_inicio]
            if len(ventana_fija) < 2:
                ventana_fija = [valor for _ts_v, valor in valores_serie]
            if len(ventana_fija) >= 2:
                # Variable local para media fija.
                media_fija = sum(ventana_fija) / len(ventana_fija)
                # Variable de Tkinter de texto para fija.
                var_fija = sum((valor - media_fija) ** 2 for valor in ventana_fija) / len(ventana_fija)
                # Variable local para desvio fijo.
                desvio_fijo = math.sqrt(max(var_fija, 0.0))
            else:
                media_fija = None
                desvio_fijo = None
        else:
            media_fija = None
            desvio_fijo = None

        def _stats_previos(indice_actual: int) -> tuple[float | None, float | None]:
            if modo_bandas_norm == "fija":
                return media_fija, desvio_fijo
            # Variable local para timestamp actual.
            ts_actual = valores_serie[indice_actual][0]
            # Variable local para fecha limite.
            fecha_limite = ts_actual - timedelta(days=dias_ventana)
            # Variable local para ventana.
            ventana = [valor for ts_v, valor in valores_serie[:indice_actual] if ts_v >= fecha_limite]
            if len(ventana) < 2:
                return None, None
            # Variable local para media.
            media = sum(ventana) / len(ventana)
            # Variable local para var.
            var = sum((valor - media) ** 2 for valor in ventana) / len(ventana)
            return media, math.sqrt(max(var, 0.0))

        def _lado_actual() -> str | None:
            if not posiciones_abiertas:
                return None
            return str(posiciones_abiertas[0].get("lado_trade") or "") or None

        def _abrir_posicion(
            fila_actual: dict[str, Any],
            valor_actual: float,
            nivel_sigma: float,
            *,
            lado_trade: str,
            es_refuerzo: bool = False,
            orden_refuerzo: int = 0,
            media_actual: float | None = None,
            desvio_actual: float | None = None,
        ) -> None:
            ticks_confirmacion_entrada = 0
            ticks_confirmacion_salida = 0
            posiciones_abiertas.append({
                "lado_trade": str(lado_trade or "long"),
                "ts_entrada": fila_actual["ts"],
                "fecha_entrada": fila_actual.get("fecha") or fila_actual["ts"].strftime("%Y-%m-%d"),
                "rel_entrada": float(valor_actual),
                "a_entrada": convertir_a_numero(fila_actual.get("a_last")),
                "b_entrada": convertir_a_numero(fila_actual.get("b_last")),
                "nivel_sigma": float(nivel_sigma),
                "es_refuerzo": bool(es_refuerzo),
                "orden_refuerzo": int(orden_refuerzo or 0),
                "media_entrada": media_actual,
                "desvio_entrada": desvio_actual,
            })

        def _agregar_refuerzos_si_corresponde(fila_actual: dict[str, Any], valor_actual: float, media_actual: float, desvio_actual: float) -> None:
            # Variable local para lado trade.
            lado_trade = _lado_actual()
            if not lado_trade or desvio_actual <= 0 or not sigma_refuerzos_validos:
                return
            # Variable local para niveles abiertos.
            niveles_abiertos = {round(float(pos.get("nivel_sigma") or 0.0), 9) for pos in posiciones_abiertas}
            for indice, nivel in enumerate(sigma_refuerzos_validos, start=1):
                if round(float(nivel), 9) in niveles_abiertos:
                    continue
                if lado_trade == "long" and float(valor_actual) <= float(media_actual) - float(desvio_actual) * float(nivel):
                    _abrir_posicion(fila_actual, valor_actual, nivel, lado_trade=lado_trade, es_refuerzo=True, orden_refuerzo=indice, media_actual=media_actual, desvio_actual=desvio_actual)
                    niveles_abiertos.add(round(float(nivel), 9))
                elif lado_trade == "short" and float(valor_actual) >= float(media_actual) + float(desvio_actual) * float(nivel):
                    _abrir_posicion(fila_actual, valor_actual, nivel, lado_trade=lado_trade, es_refuerzo=True, orden_refuerzo=indice, media_actual=media_actual, desvio_actual=desvio_actual)
                    niveles_abiertos.add(round(float(nivel), 9))

        def _cerrar_posiciones(fila_salida: dict[str, Any], valor_salida: float, *, causa: str) -> None:
            nonlocal posiciones_abiertas
            for posicion in list(posiciones_abiertas):
                # Variable local para entrada valor.
                entrada_valor = float(posicion.get("rel_entrada") or 0.0)
                # Variable local para lado trade.
                lado_trade = str(posicion.get("lado_trade") or "long")
                # Variable local para PnL.
                pnl = float(valor_salida) - entrada_valor if lado_trade == "long" else entrada_valor - float(valor_salida)
                # Variable local para causa txt.
                causa_txt = str(causa or "")
                # Variable local para sufijo.
                sufijo = "_sup" if lado_trade == "short" else "_inf"
                operaciones.append({
                    "entrada": f"{posicion.get('fecha_entrada')} 17:00",
                    "salida": f"{fila_salida.get('fecha') or fila_salida['ts'].strftime('%Y-%m-%d')} 17:00",
                    "ts_entrada": posicion.get("ts_entrada"),
                    "ts_salida": fila_salida.get("ts"),
                    "base_a": "",
                    "base_b": "",
                    "estrategia": "",
                    "rel_entrada": entrada_valor,
                    "rel_salida": float(valor_salida),
                    "a_entrada": posicion.get("a_entrada"),
                    "b_entrada": posicion.get("b_entrada"),
                    "a_salida": convertir_a_numero(fila_salida.get("a_last")),
                    "b_salida": convertir_a_numero(fila_salida.get("b_last")),
                    "pnl": pnl,
                    "causa": f"{causa_txt}{sufijo}" if causa_txt else lado_trade,
                })
            # Variable local para posiciones abiertas.
            posiciones_abiertas = []

        # Registro temporal o último valor usado para ultimo valor.
        ultimo_valor: float | None = None
        for indice, fila in enumerate(filas_ordenadas):
            # Marca temporal normalizada de la observación actual.
            ts = fila["ts"]
            # Valor temporal usado en este cálculo.
            valor = float(fila["signal_value"])
            media_actual, desvio_actual = _stats_previos(indice)
            if cooldown_until is not None and ts < cooldown_until:
                ultimo_valor = valor
                continue
            if media_actual is None or desvio_actual is None or desvio_actual <= 0:
                ultimo_valor = valor
                continue
            # Variable local para limite extremo.
            limite_extremo = float(desvio_actual) * max(float(extreme_sigma_mult or 0.0), 0.0)
            if posiciones_abiertas and bool(enable_extreme_close) and limite_extremo > 0 and abs(float(valor) - float(media_actual)) > limite_extremo:
                _cerrar_posiciones(fila, valor, causa="cerrada_extrema")
                # Variable local para espera.
                espera = max(float(extreme_cooldown_days or 0.0), 0.0)
                if espera > 0:
                    cooldown_until = ts + timedelta(days=espera)
                ultimo_valor = valor
                continue
            # Variable local para banda sup.
            banda_sup = float(media_actual) + float(desvio_actual) * float(sigma_mult)
            # Variable local para banda inf.
            banda_inf = float(media_actual) - float(desvio_actual) * float(sigma_mult)
            # Variable local para ancho cierre.
            ancho_cierre = abs(float(media_actual)) * max(float(close_zone_pct), 0.0)
            # Variable local para banda cierre sup.
            banda_cierre_sup = float(media_actual) + ancho_cierre
            # Variable local para banda cierre inf.
            banda_cierre_inf = float(media_actual) - ancho_cierre
            if posiciones_abiertas:
                if banda_cierre_inf <= valor <= banda_cierre_sup:
                    _cerrar_posiciones(fila, valor, causa="cerrada")
                else:
                    _agregar_refuerzos_si_corresponde(fila, valor, media_actual, desvio_actual)
                ultimo_valor = valor
                continue
            # Variable local para lado apertura.
            lado_apertura = None
            if valor <= banda_inf:
                lado_apertura = "long"
            elif valor >= banda_sup:
                lado_apertura = "short"
            if lado_apertura is not None:
                _abrir_posicion(fila, valor, sigma_mult, lado_trade=lado_apertura, es_refuerzo=False, orden_refuerzo=0, media_actual=media_actual, desvio_actual=desvio_actual)
                _agregar_refuerzos_si_corresponde(fila, valor, media_actual, desvio_actual)
            ultimo_valor = valor
        if posiciones_abiertas and filas_ordenadas:
            # Variable local para fila final.
            fila_final = filas_ordenadas[-1]
            # Variable local para valor final.
            valor_final = float(fila_final.get("signal_value") or (ultimo_valor if ultimo_valor is not None else 0.0))
            _cerrar_posiciones(fila_final, valor_final, causa="cerrada_forzada")
        # Variable local para cerradas.
        cerradas = [op for op in operaciones if op.get("causa") != "abierta" and convertir_a_numero(op.get("pnl")) is not None]
        # Variable local para PnL total.
        pnl_total = sum(float(op.get("pnl") or 0.0) for op in cerradas)
        return {"operaciones": operaciones, "pnl_total": pnl_total, "cerradas": len(cerradas), "abiertas": len(posiciones_abiertas)}

    def _refrescar_backtest_vencimiento(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]], info: dict[str, Any], *, forzar: bool = False) -> None:
        """Carga la tabla del backtest de vencimiento y un gráfico inferior usando cierres diarios."""
        # Variable local para tree.
        tree = getattr(self, "tree_backtest_vencimiento", None)
        if tree is None:
            return
        # Variable local para opciones.
        opciones = self._listar_bases_disponibles_vencimiento(filas_calls, filas_puts)
        # Variable local para firma live.
        firma_live: list[Any] = []
        # Variable local para operaciones totales.
        operaciones_totales: list[dict[str, Any]] = []
        # Variable local para series activas.
        series_activas: list[tuple[int, str, list[tuple[datetime, float]]]] = []
        # Variable local para operaciones por slot.
        operaciones_por_slot: dict[int, list[dict[str, Any]]] = {}
        # Variable local para info textos.
        info_textos: list[str] = []
        try:
            # Variable local para sigma múltiplo.
            sigma_mult = max(0.1, float(str(self.var_backtest_venc_sigma.get()).replace(",", ".").strip() or "1.0"))
        except Exception:
            sigma_mult = 1.0
        # Variable local para sigma refuerzos.
        sigma_refuerzos: list[float] = []
        for raw in (self.var_backtest_venc_sigma_refuerzo_1.get(), self.var_backtest_venc_sigma_refuerzo_2.get()):
            try:
                # Valor temporal usado en este cálculo.
                valor = float(str(raw).replace(",", ".").strip())
            except Exception:
                continue
            if valor > sigma_mult:
                sigma_refuerzos.append(valor)
        sigma_refuerzos = sorted({float(v) for v in sigma_refuerzos})[:2]
        try:
            # Variable local para extreme sigma múltiplo.
            extreme_sigma_mult = max(0.0, float(str(self.var_backtest_venc_extreme_sigma_mult.get()).replace(",", ".").strip() or str(BACKTEST_EXTREME_SIGMA_MULT)))
        except Exception:
            extreme_sigma_mult = float(BACKTEST_EXTREME_SIGMA_MULT)
        try:
            # Variable local para extreme wait days.
            extreme_wait_days = max(0.0, float(str(self.var_backtest_venc_extreme_wait_days.get()).replace(",", ".").strip() or "0"))
        except Exception:
            extreme_wait_days = 0.0
        # Variable local para enable extreme close.
        enable_extreme_close = bool(self.var_backtest_venc_extreme_enabled.get())
        # Variable local para modo bandas.
        modo_bandas = str(self.var_backtest_venc_band_mode.get() or "dinamica").strip().lower()
        if modo_bandas not in self._backtest_venc_band_modes:
            modo_bandas = "dinamica"
        # Variable local para anios bandas.
        anios_bandas = self._obtener_backtest_venc_band_years()
        firma_live.extend((round(sigma_mult, 4), tuple(round(v, 4) for v in sigma_refuerzos), round(extreme_sigma_mult, 4), round(extreme_wait_days, 4), enable_extreme_close, modo_bandas, anios_bandas))
        for slot in self._backtest_venc_slots:
            # Variable local para ticker A.
            ticker_a = self._backtest_venc_vars_a[slot].get().strip()
            # Variable local para ticker B.
            ticker_b = self._backtest_venc_vars_b[slot].get().strip()
            # Variable local para estrategia txt.
            estrategia_txt = self._backtest_venc_strategy_vars[slot].get().strip()
            # Variable local para estrategia.
            estrategia = next((k for k, v in self._backtest_venc_strategy_options if v == estrategia_txt or k == estrategia_txt), "long_ab")
            # Variable local para activo.
            activo = bool(self._backtest_venc_enabled_vars[slot].get())
            try:
                # Variable local para coeficiente ratio.
                coef_ratio = float(self._backtest_venc_ratio_coef_vars[slot].get().strip().replace(",", "."))
            except Exception:
                coef_ratio = 1.0
            coef_ratio = min(3.0, max(1.0, coef_ratio))
            firma_live.extend((slot, ticker_a, ticker_b, estrategia, f"{coef_ratio:.2f}", activo))
            if not ticker_a or not ticker_b or ticker_a == ticker_b or ticker_a not in opciones or ticker_b not in opciones:
                self._backtest_venc_metric_vars[slot].set("Ops: 0 | Cerradas: 0 | PnL: s/d")
                continue
            # Variable local para filas bt.
            filas_bt = self._construir_filas_backtest_vencimiento(ticker_a, ticker_b, estrategia, coef_ratio)
            # Resultado acumulado o final del cálculo.
            resultado = self._simular_backtest_vencimiento_estrategia(
                filas_bt,
                estrategia=estrategia,
                sigma_mult=sigma_mult,
                sigma_refuerzos=sigma_refuerzos,
                close_zone_pct=0.05,
                extreme_sigma_mult=extreme_sigma_mult,
                extreme_cooldown_days=extreme_wait_days,
                enable_extreme_close=enable_extreme_close,
                modo_bandas=modo_bandas,
                anios_bandas=anios_bandas,
            )
            # Variable local para operaciones.
            operaciones = list(resultado.get("operaciones") or [])
            # Variable local para PnL total.
            pnl_total = convertir_a_numero(resultado.get("pnl_total"))
            self._backtest_venc_metric_vars[slot].set(
                f"Ops: {len(operaciones)} | Cerradas: {int(resultado.get('cerradas') or 0)} | PnL: {(float(pnl_total) if pnl_total is not None else 0.0):.2f}"
            )
            # Variable local para texto estrategia.
            texto_estrategia = self._etiqueta_backtest_vencimiento(slot, ticker_a, ticker_b, estrategia, coef_ratio)
            # Variable local para serie historica.
            serie_historica = self._obtener_serie_cache_backtest_vencimiento(ticker_a, ticker_b, estrategia, coef_ratio)
            firma_live.extend((len(serie_historica), round(float(serie_historica[-1][1]), 6) if serie_historica else None))
            if activo:
                series_activas.append((slot, texto_estrategia, serie_historica))
                # Variable local para operaciones slot.
                operaciones_slot: list[dict[str, Any]] = []
                for operacion in operaciones:
                    # Variable local para fila op.
                    fila_op = dict(operacion)
                    fila_op["base_a"] = ticker_a
                    fila_op["base_b"] = ticker_b
                    fila_op["estrategia"] = texto_estrategia
                    fila_op["causa"] = str(fila_op.get("causa") or fila_op.get("estado") or "")
                    operaciones_totales.append(fila_op)
                    operaciones_slot.append(fila_op)
                operaciones_por_slot[slot] = operaciones_slot
                info_textos.append(f"{texto_estrategia}: {int(resultado.get('cerradas') or 0)} ops | PnL {(float(pnl_total) if pnl_total is not None else 0.0):.2f}")
        operaciones_totales.sort(key=lambda fila: (fila.get("ts_entrada") or datetime.min, fila.get("base_a") or "", fila.get("base_b") or ""))
        # Variable local para firma live t.
        firma_live_t = tuple(
            firma_live
            + [
                len(operaciones_totales),
                tuple((fila.get("entrada"), fila.get("salida"), round(float(convertir_a_numero(fila.get("pnl")) or 0.0), 6)) for fila in operaciones_totales[:80]),
                tuple((slot, etiqueta, len(serie), round(float(serie[-1][1]), 6) if serie else None) for slot, etiqueta, serie in series_activas),
            ]
        )
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        if (not forzar) and (ahora_ts - self._backtest_venc_last_render_at < self._backtest_venc_refresh_interval) and (firma_live_t == self._backtest_venc_live_signature):
            return
        self._cargar_tree_backtest_vencimiento(operaciones_totales)
        self._refrescar_grafico_backtest_vencimiento(
            series_activas,
            modo_bandas=modo_bandas,
            anios_bandas=anios_bandas,
            operaciones_por_slot=operaciones_por_slot,
        )
        if info_textos:
            self.var_backtest_venc_info.set("Backtest diario heredado: " + " | ".join(info_textos[:6]) + f" | Entrada=±{sigma_mult:.2f}σ | Cierre=±5% media | Banda ±1σ {'dyn' if modo_bandas == 'dinamica' else 'fija'} ({anios_bandas}a)")
        else:
            self.var_backtest_venc_info.set(
                f"Backtest diario heredado: elegí hasta 6 pares independientes del vencimiento seleccionado y una estrategia por par para simular aperturas a ±{sigma_mult:.2f}σ y cierres dentro de ±5% de la media. Banda ±1σ {'dinámica' if modo_bandas == 'dinamica' else 'fija'} con ventana de {anios_bandas} año{'s' if anios_bandas != 1 else ''}."
            )
        self._backtest_venc_live_signature = firma_live_t
        self._backtest_venc_last_render_at = ahora_ts


    def _refrescar_registro_spread(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]], info: dict[str, Any], *, forzar: bool = False) -> None:
        """Dibuja en un único gráfico la historia de hasta 6 spreads A-B independientes."""
        if not hasattr(self, "ax_registro_spread"):
            return
        # Variable local para opciones.
        opciones = self._listar_bases_disponibles_vencimiento(filas_calls, filas_puts)
        # Variable local para mapa actual.
        mapa_actual = {str(fila.get("ticker") or ""): fila for fila in list(filas_calls) + list(filas_puts)}
        # Variable local para firma live.
        firma_live: list[Any] = []
        # Variable local para pares activos.
        pares_activos: list[tuple[int, str, str, str, list[tuple[datetime, float]], float | None]] = []
        # Variable local para pares ratio.
        pares_ratio: list[tuple[str, list[tuple[datetime, float]], float | None]] = []
        # Variable local para color map ratio.
        color_map_ratio: dict[str, str] = {}
        # Variable local para firmas series.
        firmas_series: dict[str, list[tuple[datetime, float]]] = {}
        # Variable local para info pares.
        info_pares: list[str] = []
        # Variable local para timestamp live texto.
        ts_live_texto = str(info.get("last_event_at") or ahora_texto())
        try:
            # Variable local para timestamp live.
            ts_live = datetime.strptime(ts_live_texto, "%Y-%m-%d %H:%M:%S")
        except Exception:
            ts_live = ahora().replace(tzinfo=None)
        for slot in self._registro_spread_slots:
            # Variable local para ticker A.
            ticker_a = self._registro_spread_vars_a[slot].get().strip()
            # Variable local para ticker B.
            ticker_b = self._registro_spread_vars_b[slot].get().strip()
            # Variable local para activo.
            activo = bool(self._registro_spread_enabled_vars[slot].get())
            firma_live.extend((slot, activo, ticker_a, ticker_b))
            if not ticker_a or not ticker_b or ticker_a == ticker_b:
                self._registro_spread_metric_vars[slot].set("Max: s/d | Ahora: s/d | %: s/d")
                continue
            if ticker_a not in opciones or ticker_b not in opciones:
                self._registro_spread_metric_vars[slot].set("Max: s/d | Ahora: s/d | %: s/d")
                continue
            # Serie temporal construida en este bloque.
            serie = self._obtener_serie_cache_registro_spread(ticker_a, ticker_b)
            # Variable local para serie ratio.
            serie_ratio = self._obtener_serie_cache_registro_ratio_base(ticker_a, ticker_b)
            # Variable local para fila A.
            fila_a = mapa_actual.get(ticker_a, {})
            # Variable local para fila B.
            fila_b = mapa_actual.get(ticker_b, {})
            # Variable local para precio A live.
            precio_a_live = convertir_a_numero(fila_a.get("last"))
            if precio_a_live in (None, 0):
                precio_a_live = convertir_a_numero(precio_referencia(fila_a))
            # Variable local para precio B live.
            precio_b_live = convertir_a_numero(fila_b.get("last"))
            if precio_b_live in (None, 0):
                precio_b_live = convertir_a_numero(precio_referencia(fila_b))
            # Variable local para spread live.
            spread_live = None
            # Variable local para ratio live.
            ratio_live = None
            if precio_a_live is not None and precio_b_live is not None:
                spread_live = float(precio_a_live) - float(precio_b_live)
                if float(precio_b_live) != 0:
                    ratio_live = float(precio_a_live) / float(precio_b_live)
            # Variable local para maximo cobro.
            maximo_cobro = self._maximo_cobro_registro_spread(ticker_a, ticker_b)
            # Variable local para valor actual.
            valor_actual = self._valor_actual_registro_desde_serie(spread_live, serie)
            self._registro_spread_metric_vars[slot].set(self._formatear_metricas_registro(maximo_cobro, valor_actual))
            # Variable local para etiqueta.
            etiqueta = self._etiqueta_par_registro_spread(slot, ticker_a, ticker_b)
            firma_live.extend(
                (
                    round(ratio_live, 6) if ratio_live is not None else None,
                    len(serie_ratio),
                )
            )
            if not activo:
                continue
            color_map_ratio[etiqueta] = self._color_registro_por_slot(slot)
            pares_ratio.append((etiqueta, serie_ratio, ratio_live))
            firmas_series[etiqueta] = serie
            pares_activos.append((slot, ticker_a, ticker_b, etiqueta, serie, spread_live))
            firma_live.extend(
                (
                    round(spread_live, 6) if spread_live is not None else None,
                    round(maximo_cobro, 6) if maximo_cobro is not None else None,
                    round(valor_actual, 6) if valor_actual is not None else None,
                    len(serie),
                )
            )
            if spread_live is not None:
                info_pares.append(f"{etiqueta} = {spread_live:.2f}")
            else:
                info_pares.append(f"{etiqueta} = s/d")
        # Variable local para firma live t.
        firma_live_t = tuple(firma_live)
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        if (not forzar) and (ahora_ts - self._registro_spread_last_render_at < self._registro_spread_refresh_interval) and (firma_live_t == self._registro_spread_live_signature):
            return
        self._capturar_vistas(("registro_spread",))
        self.ax_registro_spread.clear()
        if not pares_activos:
            self.ax_registro_spread.text(0.5, 0.5, "Activá al menos un par independiente para graficar el spread A-B.", ha="center", va="center")
            self.ax_registro_spread.set_axis_off()
        else:
            fechas_base, mapa_pos, etiquetas_x, pos_live_extra = self._construir_eje_categorico_por_datos(firmas_series, ts_live)
            self.ax_registro_spread.set_axis_on()
            # Variable local para hubo lineas.
            hubo_lineas = False
            for _slot, _ticker_a, _ticker_b, etiqueta, serie, spread_live in pares_activos:
                # Variable local para puntos.
                puntos = self._serie_a_puntos_categoricos(serie, mapa_pos, ratio_live=spread_live, ts_live=ts_live, pos_live_extra=pos_live_extra)
                if not puntos:
                    continue
                # Variable local para xs.
                xs = [x for x, _ in puntos]
                # Variable local para ys.
                ys = [float(y) for _, y in puntos]
                # Variable local para color.
                color = self._color_registro_por_slot(_slot)
                self.ax_registro_spread.plot(xs, ys, marker="o", markersize=1.4, linewidth=1.2, label=etiqueta, color=color)
                self.ax_registro_spread.scatter([xs[-1]], [ys[-1]], s=12, color=color)
                hubo_lineas = True
            if hubo_lineas:
                self.ax_registro_spread.set_title("Registro histórico de spreads A-B")
                self.ax_registro_spread.set_xlabel("Fecha")
                self.ax_registro_spread.set_ylabel("Spread (A - B)")
                self.ax_registro_spread.grid(True, alpha=0.3)
                self._aplicar_eje_categorico_comparador(self.ax_registro_spread, etiquetas_x or [])
                self.ax_registro_spread.legend(loc="best", fontsize=8)
            else:
                self.ax_registro_spread.text(0.5, 0.5, "Los spreads activos no tienen cierres históricos suficientes para graficar.", ha="center", va="center")
                self.ax_registro_spread.set_title("Registro histórico de spreads A-B")
                self._aplicar_eje_categorico_comparador(self.ax_registro_spread, etiquetas_x or [])
        self._restaurar_vistas(("registro_spread",))
        self.canvas_registro_spread.draw_idle()
        self._dibujar_grafico_ratio_registro(
            getattr(self, "ax_registro_spread_ratio", None),
            getattr(self, "canvas_registro_spread_ratio", None),
            "registro_spread_ratio",
            pares_ratio,
            ts_live,
            "Ratios A/B seleccionados",
            color_map=color_map_ratio,
        )
        if pares_activos:
            self.var_registro_spread_info.set("Registro spread: " + " | ".join(info_pares[:6]))
        else:
            self.var_registro_spread_info.set(
                "Registro spread: elegí hasta 6 pares independientes, marcá Activo y vas a ver en un único gráfico los cierres históricos del spread A-B más el punto vivo si hay datos."
            )
        self._registro_spread_live_signature = firma_live_t
        self._registro_spread_last_render_at = ahora_ts

    def _refrescar_registro_mariposa(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]], info: dict[str, Any], *, forzar: bool = False) -> None:
        """Dibuja en un único gráfico la historia de hasta 6 mariposas compradas o vendidas.

        Se endurece esta vista porque un error en una sola combinación A/B/C no debe cerrar
        la aplicación completa. Además, las series históricas por puntas se consultan y se
        dibujan solo cuando la simulación de puntas está activa, para reducir costo y evitar
        bloqueos innecesarios al abrir la pestaña.

        También evita reentrancia y redibujados cuando la pestaña deja de estar visible,
        porque al cambiar muy rápido entre vistas matplotlib puede acumular trabajo pesado.
        """
        if not hasattr(self, "ax_registro_mariposa"):
            return
        if not forzar and self._tab_activa_texto() != "Registro mariposa":
            return
        if getattr(self, "_registro_mariposa_refresh_running", False) and not forzar:
            return
        self._registro_mariposa_refresh_running = True
        try:
            # Variable local para opciones.
            opciones = self._listar_bases_disponibles_vencimiento(filas_calls, filas_puts)
            # Variable local para mapa actual.
            mapa_actual = {str(fila.get("ticker") or ""): fila for fila in list(filas_calls) + list(filas_puts)}
            # Variable local para firma live.
            firma_live: list[Any] = []
            # Variable local para trios activos.
            trios_activos: list[dict[str, Any]] = []
            # Variable local para firmas series.
            firmas_series: dict[str, list[tuple[datetime, float]]] = {}
            # Variable local para info trios.
            info_trios: list[str] = []
            # Variable local para mostrar puntas.
            mostrar_puntas = bool(self.var_registro_mariposa_simular_puntas.get())
            # Variable local para timestamp live texto.
            ts_live_texto = str(info.get("last_event_at") or ahora_texto())
            try:
                # Variable local para timestamp live.
                ts_live = datetime.strptime(ts_live_texto, "%Y-%m-%d %H:%M:%S")
            except Exception:
                ts_live = ahora().replace(tzinfo=None)
            for slot in self._registro_mariposa_slots:
                # Variable local para ticker A.
                ticker_a = self._registro_mariposa_vars_a[slot].get().strip()
                # Variable local para ticker B.
                ticker_b = self._registro_mariposa_vars_b[slot].get().strip()
                # Variable local para ticker C.
                ticker_c = self._registro_mariposa_vars_c[slot].get().strip()
                # Variable local para tipo.
                tipo = self._tipo_registro_mariposa_normalizado(self._registro_mariposa_tipo_vars[slot].get())
                # Variable local para activo.
                activo = bool(self._registro_mariposa_enabled_vars[slot].get())
                firma_live.extend((slot, activo, ticker_a, ticker_b, ticker_c, tipo, mostrar_puntas))
                if not ticker_a or not ticker_b or not ticker_c or len({ticker_a, ticker_b, ticker_c}) < 3:
                    self._registro_mariposa_metric_vars[slot].set("Max: s/d | Ahora: s/d | %: s/d")
                    continue
                if ticker_a not in opciones or ticker_b not in opciones or ticker_c not in opciones:
                    self._registro_mariposa_metric_vars[slot].set("Max: s/d | Ahora: s/d | %: s/d")
                    continue
                # Variable local para serie last.
                serie_last = self._obtener_serie_cache_registro_mariposa(ticker_a, ticker_b, ticker_c, tipo)
                # Variable local para serie abrir.
                serie_abrir: list[tuple[datetime, float]] = []
                # Variable local para serie cerrar.
                serie_cerrar: list[tuple[datetime, float]] = []
                if activo and mostrar_puntas:
                    # Variable local para series puntas.
                    series_puntas = self._obtener_series_cache_registro_mariposa_puntas(ticker_a, ticker_b, ticker_c, tipo)
                    serie_abrir = list(series_puntas.get("abrir") or [])
                    serie_cerrar = list(series_puntas.get("cerrar") or [])
                # Variable local para fila A.
                fila_a = mapa_actual.get(ticker_a, {})
                # Variable local para fila B.
                fila_b = mapa_actual.get(ticker_b, {})
                # Variable local para fila C.
                fila_c = mapa_actual.get(ticker_c, {})
                if tipo == "vendida":
                    # Variable local para precio A live.
                    precio_a_live = self._precio_leg_registro(fila_a, "venta", simular_puntas=mostrar_puntas)
                    # Variable local para precio B live.
                    precio_b_live = self._precio_leg_registro(fila_b, "compra", simular_puntas=mostrar_puntas)
                    # Variable local para precio C live.
                    precio_c_live = self._precio_leg_registro(fila_c, "venta", simular_puntas=mostrar_puntas)
                else:
                    precio_a_live = self._precio_leg_registro(fila_a, "compra", simular_puntas=mostrar_puntas)
                    precio_b_live = self._precio_leg_registro(fila_b, "venta", simular_puntas=mostrar_puntas)
                    precio_c_live = self._precio_leg_registro(fila_c, "compra", simular_puntas=mostrar_puntas)
                # Variable local para valor live last.
                valor_live_last = None
                if precio_a_live is not None and precio_b_live is not None and precio_c_live is not None:
                    valor_live_last = self._valor_mariposa_registro(precio_a_live, precio_b_live, precio_c_live, tipo)
                # Variable local para valor live abrir.
                valor_live_abrir = None
                # Variable local para valor live cerrar.
                valor_live_cerrar = None
                if mostrar_puntas:
                    if tipo == "vendida":
                        # Variable local para abrir A live.
                        abrir_a_live = self._precio_leg_registro(fila_a, "venta", simular_puntas=True)
                        # Variable local para abrir B live.
                        abrir_b_live = self._precio_leg_registro(fila_b, "compra", simular_puntas=True)
                        # Variable local para abrir C live.
                        abrir_c_live = self._precio_leg_registro(fila_c, "venta", simular_puntas=True)
                        # Variable local para cerrar A live.
                        cerrar_a_live = self._precio_leg_registro(fila_a, "compra", simular_puntas=True)
                        # Variable local para cerrar B live.
                        cerrar_b_live = self._precio_leg_registro(fila_b, "venta", simular_puntas=True)
                        # Variable local para cerrar C live.
                        cerrar_c_live = self._precio_leg_registro(fila_c, "compra", simular_puntas=True)
                    else:
                        abrir_a_live = self._precio_leg_registro(fila_a, "compra", simular_puntas=True)
                        abrir_b_live = self._precio_leg_registro(fila_b, "venta", simular_puntas=True)
                        abrir_c_live = self._precio_leg_registro(fila_c, "compra", simular_puntas=True)
                        cerrar_a_live = self._precio_leg_registro(fila_a, "venta", simular_puntas=True)
                        cerrar_b_live = self._precio_leg_registro(fila_b, "compra", simular_puntas=True)
                        cerrar_c_live = self._precio_leg_registro(fila_c, "venta", simular_puntas=True)
                    if abrir_a_live is not None and abrir_b_live is not None and abrir_c_live is not None:
                        valor_live_abrir = self._valor_mariposa_registro(abrir_a_live, abrir_b_live, abrir_c_live, tipo)
                    if cerrar_a_live is not None and cerrar_b_live is not None and cerrar_c_live is not None:
                        valor_live_cerrar = self._valor_mariposa_registro(cerrar_a_live, cerrar_b_live, cerrar_c_live, tipo)
                # Variable local para maximo cobro.
                maximo_cobro = self._maximo_cobro_registro_mariposa(ticker_a, ticker_b, ticker_c) if tipo == "comprada" else None
                # Variable local para valor actual.
                valor_actual = self._valor_actual_registro_desde_serie(valor_live_last, serie_last)
                self._registro_mariposa_metric_vars[slot].set(self._formatear_metricas_registro(maximo_cobro, valor_actual))
                if not activo:
                    continue
                # Variable local para etiqueta.
                etiqueta = self._etiqueta_trio_registro_mariposa(slot, ticker_a, ticker_b, ticker_c, tipo)
                firmas_series[f"{etiqueta}_last"] = serie_last
                if mostrar_puntas:
                    firmas_series[f"{etiqueta}_abrir"] = serie_abrir
                    firmas_series[f"{etiqueta}_cerrar"] = serie_cerrar
                trios_activos.append({
                    "slot": slot,
                    "tipo": tipo,
                    "etiqueta": etiqueta,
                    "serie_last": serie_last,
                    "serie_abrir": serie_abrir,
                    "serie_cerrar": serie_cerrar,
                    "valor_live_last": valor_live_last,
                    "valor_live_abrir": valor_live_abrir,
                    "valor_live_cerrar": valor_live_cerrar,
                })
                firma_live.extend(
                    (
                        round(valor_live_last, 6) if valor_live_last is not None else None,
                        round(valor_live_abrir, 6) if valor_live_abrir is not None else None,
                        round(valor_live_cerrar, 6) if valor_live_cerrar is not None else None,
                        round(maximo_cobro, 6) if maximo_cobro is not None else None,
                        round(valor_actual, 6) if valor_actual is not None else None,
                        len(serie_last),
                        len(serie_abrir),
                        len(serie_cerrar),
                    )
                )
                if valor_live_last is not None:
                    info_trios.append(f"{etiqueta} last={valor_live_last:.2f}")
                else:
                    info_trios.append(f"{etiqueta} = s/d")
            # Variable local para firma live t.
            firma_live_t = tuple(firma_live)
            # Variable local para ahora timestamp.
            ahora_ts = time.time()
            if (not forzar) and (ahora_ts - self._registro_mariposa_last_render_at < self._registro_mariposa_refresh_interval) and (firma_live_t == self._registro_mariposa_live_signature):
                return
            if self._tab_activa_texto() != "Registro mariposa":
                return
            try:
                widget_canvas = self.canvas_registro_mariposa.get_tk_widget()
                if widget_canvas is not None and not bool(widget_canvas.winfo_ismapped()):
                    return
            except Exception:
                pass
            self._capturar_vistas(("registro_mariposa",))
            self.ax_registro_mariposa.clear()
            if not trios_activos:
                self.ax_registro_mariposa.text(0.5, 0.5, "Activá al menos una mariposa independiente para graficar la estrategia.", ha="center", va="center")
                self.ax_registro_mariposa.set_axis_off()
                try:
                    self.canvas_registro_mariposa.draw_idle()
                except Exception:
                    LOGGER.exception("No se pudo redibujar el canvas de registro mariposa vacío")
                self.var_registro_mariposa_info.set(
                    "Registro mariposa: elegí hasta 6 tríos independientes, definí si la mariposa es comprada o vendida y activalos para ver last y, opcionalmente, puntas simuladas."
                )
                self._registro_mariposa_live_signature = firma_live_t
                self._registro_mariposa_last_render_at = ahora_ts
                return
            fechas_base, mapa_pos, etiquetas_x, pos_live_extra = self._construir_eje_categorico_por_datos(firmas_series, ts_live)
            self.ax_registro_mariposa.set_axis_on()
            # Variable local para hubo lineas.
            hubo_lineas = False
            for item in trios_activos:
                # Variable local para color.
                color = self._color_registro_por_slot(item["slot"])
                if mostrar_puntas:
                    # Variable local para puntos abrir.
                    puntos_abrir = self._serie_a_puntos_categoricos(item["serie_abrir"], mapa_pos, ratio_live=item["valor_live_abrir"], ts_live=ts_live, pos_live_extra=pos_live_extra)
                    if puntos_abrir:
                        # Variable local para xs.
                        xs = [x for x, _ in puntos_abrir]
                        # Variable local para ys.
                        ys = [float(y) for _, y in puntos_abrir]
                        self.ax_registro_mariposa.plot(xs, ys, linewidth=0.95, linestyle="--", alpha=0.35, color=color, label=f"{item['etiqueta']} abrir")
                        hubo_lineas = True
                    # Variable local para puntos cerrar.
                    puntos_cerrar = self._serie_a_puntos_categoricos(item["serie_cerrar"], mapa_pos, ratio_live=item["valor_live_cerrar"], ts_live=ts_live, pos_live_extra=pos_live_extra)
                    if puntos_cerrar:
                        xs = [x for x, _ in puntos_cerrar]
                        ys = [float(y) for _, y in puntos_cerrar]
                        self.ax_registro_mariposa.plot(xs, ys, linewidth=0.95, linestyle=":", alpha=0.28, color=color, label=f"{item['etiqueta']} cerrar")
                        hubo_lineas = True
                # Variable local para puntos last.
                puntos_last = self._serie_a_puntos_categoricos(item["serie_last"], mapa_pos, ratio_live=item["valor_live_last"], ts_live=ts_live, pos_live_extra=pos_live_extra)
                if puntos_last:
                    xs = [x for x, _ in puntos_last]
                    ys = [float(y) for _, y in puntos_last]
                    self.ax_registro_mariposa.plot(xs, ys, marker="o", markersize=1.5, linewidth=1.35, color=color, label=f"{item['etiqueta']} last")
                    self.ax_registro_mariposa.scatter([xs[-1]], [ys[-1]], s=12, color=color)
                    hubo_lineas = True
            if hubo_lineas:
                titulo = "Registro histórico de mariposas (last"
                if mostrar_puntas:
                    titulo += " y puntas simuladas)"
                else:
                    titulo += ")"
                self.ax_registro_mariposa.set_title(titulo)
                self.ax_registro_mariposa.set_xlabel("Fecha")
                self.ax_registro_mariposa.set_ylabel("Valor estrategia")
                self.ax_registro_mariposa.grid(True, alpha=0.3)
                self._aplicar_eje_categorico_comparador(self.ax_registro_mariposa, etiquetas_x or [])
                try:
                    handles, labels = self.ax_registro_mariposa.get_legend_handles_labels()
                    if handles and len(handles) <= 12:
                        self.ax_registro_mariposa.legend(loc="best", fontsize=7)
                except Exception:
                    LOGGER.exception("No se pudo construir la leyenda de registro mariposa")
            else:
                self.ax_registro_mariposa.text(0.5, 0.5, "Las mariposas activas no tienen histórico suficiente para graficar.", ha="center", va="center")
                self.ax_registro_mariposa.set_title("Registro histórico de mariposas")
                self._aplicar_eje_categorico_comparador(self.ax_registro_mariposa, etiquetas_x or [])
            self._restaurar_vistas(("registro_mariposa",))
            try:
                if self._tab_activa_texto() == "Registro mariposa":
                    self.canvas_registro_mariposa.draw_idle()
            except Exception:
                LOGGER.exception("No se pudo redibujar el canvas de registro mariposa")
            # Variable local para prefijo info.
            prefijo_info = "Registro mariposa: "
            if info_trios:
                self.var_registro_mariposa_info.set(prefijo_info + " | ".join(info_trios[:6]))
            else:
                self.var_registro_mariposa_info.set(
                    "Registro mariposa: elegí hasta 6 tríos independientes, definí si la mariposa es comprada o vendida y activalos para ver last y, opcionalmente, puntas simuladas."
                )
            self._registro_mariposa_live_signature = firma_live_t
            self._registro_mariposa_last_render_at = ahora_ts
        except Exception:
            LOGGER.exception("Fallo al refrescar la vista Registro mariposa")
            try:
                self.ax_registro_mariposa.clear()
                self.ax_registro_mariposa.text(0.5, 0.5, "Error al cargar Registro mariposa. Revisá el log y probá con una sola mariposa activa.", ha="center", va="center")
                self.ax_registro_mariposa.set_axis_off()
                self.canvas_registro_mariposa.draw_idle()
            except Exception:
                LOGGER.exception("No se pudo mostrar el mensaje de error de Registro mariposa")
            try:
                self.var_registro_mariposa_info.set("Registro mariposa: error al refrescar la vista. Revisá el log para más detalle.")
            except Exception:
                pass
        finally:
            self._registro_mariposa_refresh_running = False

    def _refrescar_registro_ratio_invertido(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]], info: dict[str, Any], *, forzar: bool = False) -> None:
        """Dibuja en un único gráfico la historia de hasta 6 ratios invertidos A - n×B."""
        if not hasattr(self, "ax_registro_ratio_invertido"):
            return
        # Variable local para opciones.
        opciones = self._listar_bases_disponibles_vencimiento(filas_calls, filas_puts)
        # Variable local para mapa actual.
        mapa_actual = {str(fila.get("ticker") or ""): fila for fila in list(filas_calls) + list(filas_puts)}
        # Variable local para firma live.
        firma_live: list[Any] = []
        # Variable local para pares activos.
        pares_activos: list[tuple[int, str, str, float, str, list[tuple[datetime, float]], float | None]] = []
        # Variable local para pares ratio.
        pares_ratio: list[tuple[str, list[tuple[datetime, float]], float | None]] = []
        # Variable local para color map ratio.
        color_map_ratio: dict[str, str] = {}
        # Variable local para firmas series.
        firmas_series: dict[str, list[tuple[datetime, float]]] = {}
        # Variable local para info pares.
        info_pares: list[str] = []
        # Variable local para timestamp live texto.
        ts_live_texto = str(info.get("last_event_at") or ahora_texto())
        try:
            # Variable local para timestamp live.
            ts_live = datetime.strptime(ts_live_texto, "%Y-%m-%d %H:%M:%S")
        except Exception:
            ts_live = ahora().replace(tzinfo=None)
        for slot in self._registro_ratio_inv_slots:
            # Variable local para ticker A.
            ticker_a = self._registro_ratio_inv_vars_a[slot].get().strip()
            # Variable local para ticker B.
            ticker_b = self._registro_ratio_inv_vars_b[slot].get().strip()
            # Variable local para activo.
            activo = bool(self._registro_ratio_inv_enabled_vars[slot].get())
            # Variable local para coeficiente txt.
            coef_txt = self._registro_ratio_inv_coef_vars[slot].get().strip()
            try:
                # Variable local para coeficiente venta.
                coef_venta = float(coef_txt.replace(",", ".")) if coef_txt else 1.0
            except Exception:
                coef_venta = 1.0
            coef_venta = min(3.0, max(1.0, coef_venta))
            # Variable local para coeficiente norm.
            coef_norm = f"{coef_venta:.2f}"
            if coef_txt != coef_norm:
                self._registro_ratio_inv_coef_vars[slot].set(coef_norm)
            firma_live.extend((slot, activo, ticker_a, ticker_b, coef_norm))
            if not ticker_a or not ticker_b or ticker_a == ticker_b:
                self._registro_ratio_inv_metric_vars[slot].set("Ahora: s/d")
                continue
            if ticker_a not in opciones or ticker_b not in opciones:
                self._registro_ratio_inv_metric_vars[slot].set("Ahora: s/d")
                continue
            # Serie temporal construida en este bloque.
            serie = self._obtener_serie_cache_registro_ratio_invertido(ticker_a, ticker_b, coef_venta)
            # Variable local para serie ratio.
            serie_ratio = self._obtener_serie_cache_registro_ratio_base(ticker_a, ticker_b)
            # Variable local para fila A.
            fila_a = mapa_actual.get(ticker_a, {})
            # Variable local para fila B.
            fila_b = mapa_actual.get(ticker_b, {})
            # Variable local para precio A live.
            precio_a_live = self._precio_leg_registro(fila_a, "compra", simular_puntas=False)
            # Variable local para precio B live.
            precio_b_live = self._precio_leg_registro(fila_b, "venta", simular_puntas=False)
            # Variable local para ratio live.
            ratio_live = None
            # Variable local para valor live.
            valor_live = None
            if precio_a_live is not None and precio_b_live is not None:
                valor_live = float(precio_a_live) - float(coef_venta) * float(precio_b_live)
                if float(precio_b_live) != 0:
                    ratio_live = float(precio_a_live) / float(precio_b_live)
            # Variable local para valor actual.
            valor_actual = self._valor_actual_registro_desde_serie(valor_live, serie)
            self._registro_ratio_inv_metric_vars[slot].set(
                f"Ahora: {valor_actual:.2f}" if valor_actual is not None else "Ahora: s/d"
            )
            # Variable local para etiqueta.
            etiqueta = self._etiqueta_par_registro_ratio_invertido(slot, ticker_a, ticker_b, coef_venta)
            firma_live.extend(
                (
                    round(ratio_live, 6) if ratio_live is not None else None,
                    len(serie_ratio),
                )
            )
            if not activo:
                continue
            color_map_ratio[etiqueta] = self._color_registro_por_slot(slot)
            pares_ratio.append((etiqueta, serie_ratio, ratio_live))
            firmas_series[etiqueta] = serie
            pares_activos.append((slot, ticker_a, ticker_b, coef_venta, etiqueta, serie, valor_live))
            firma_live.extend(
                (
                    round(valor_live, 6) if valor_live is not None else None,
                    round(valor_actual, 6) if valor_actual is not None else None,
                    len(serie),
                )
            )
            if valor_live is not None:
                info_pares.append(f"{etiqueta} = {valor_live:.2f}")
            else:
                info_pares.append(f"{etiqueta} = s/d")
        # Variable local para firma live t.
        firma_live_t = tuple(firma_live)
        # Variable local para ahora timestamp.
        ahora_ts = time.time()
        if (not forzar) and (ahora_ts - self._registro_ratio_inv_last_render_at < self._registro_ratio_inv_refresh_interval) and (firma_live_t == self._registro_ratio_inv_live_signature):
            return
        self._capturar_vistas(("registro_ratio_invertido",))
        self.ax_registro_ratio_invertido.clear()
        if not pares_activos:
            self.ax_registro_ratio_invertido.text(0.5, 0.5, "Activá al menos un ratio invertido independiente para graficar A - n×B.", ha="center", va="center")
            self.ax_registro_ratio_invertido.set_axis_off()
        else:
            fechas_base, mapa_pos, etiquetas_x, pos_live_extra = self._construir_eje_categorico_por_datos(firmas_series, ts_live)
            self.ax_registro_ratio_invertido.set_axis_on()
            # Variable local para hubo lineas.
            hubo_lineas = False
            for _slot, _ticker_a, _ticker_b, _coef_venta, etiqueta, serie, valor_live in pares_activos:
                # Variable local para puntos.
                puntos = self._serie_a_puntos_categoricos(serie, mapa_pos, ratio_live=valor_live, ts_live=ts_live, pos_live_extra=pos_live_extra)
                if not puntos:
                    continue
                # Variable local para xs.
                xs = [x for x, _ in puntos]
                # Variable local para ys.
                ys = [float(y) for _, y in puntos]
                # Variable local para color.
                color = self._color_registro_por_slot(_slot)
                self.ax_registro_ratio_invertido.plot(xs, ys, marker="o", markersize=1.4, linewidth=1.2, label=etiqueta, color=color)
                self.ax_registro_ratio_invertido.scatter([xs[-1]], [ys[-1]], s=12, color=color)
                hubo_lineas = True
            if hubo_lineas:
                self.ax_registro_ratio_invertido.set_title("Registro histórico de ratios invertidos")
                self.ax_registro_ratio_invertido.set_xlabel("Fecha")
                self.ax_registro_ratio_invertido.set_ylabel("A - n×B")
                self.ax_registro_ratio_invertido.grid(True, alpha=0.3)
                self._aplicar_eje_categorico_comparador(self.ax_registro_ratio_invertido, etiquetas_x or [])
                self.ax_registro_ratio_invertido.legend(loc="best", fontsize=8)
            else:
                self.ax_registro_ratio_invertido.text(0.5, 0.5, "Los ratios invertidos activos no tienen cierres históricos suficientes para graficar.", ha="center", va="center")
                self.ax_registro_ratio_invertido.set_title("Registro histórico de ratios invertidos")
                self._aplicar_eje_categorico_comparador(self.ax_registro_ratio_invertido, etiquetas_x or [])
        self._restaurar_vistas(("registro_ratio_invertido",))
        self.canvas_registro_ratio_invertido.draw_idle()
        self._dibujar_grafico_ratio_registro(
            getattr(self, "ax_registro_ratio_invertido_ratio", None),
            getattr(self, "canvas_registro_ratio_invertido_ratio", None),
            "registro_ratio_invertido_ratio",
            pares_ratio,
            ts_live,
            "Ratios A/B seleccionados",
            color_map=color_map_ratio,
        )
        if pares_activos:
            self.var_registro_ratio_inv_info.set("Registro ratio invertido: " + " | ".join(info_pares[:6]))
        else:
            self.var_registro_ratio_inv_info.set(
                "Registro ratio invertido: elegí hasta 6 pares independientes, marcá Activo y vas a ver en un único gráfico los cierres históricos de A - n×B más el punto vivo si hay datos."
            )
        self._registro_ratio_inv_live_signature = firma_live_t
        self._registro_ratio_inv_last_render_at = ahora_ts

    def _crear_widget_matriz_bases_compuesta(self, parent, height: int = 18):
        """Crea una sola vista con calls a la izquierda, strikes al centro y puts a la derecha.

        La columna de strikes debe quedar visualmente centrada en la ventana. Para lograrlo,
        se reserva un pequeño margen fijo a la izquierda equivalente al espacio ocupado por la
        barra vertical de la derecha, y se fuerzan ambos lados a compartir el mismo ancho útil.
        """
        # Variable local para frame.
        frame = ttk.Frame(parent)
        frame.pack(fill=BOTH, expand=True)
        frame.columnconfigure(0, weight=0, minsize=18)
        frame.columnconfigure(1, weight=1, uniform="matriz_lados")
        frame.columnconfigure(2, weight=0)
        frame.columnconfigure(3, weight=1, uniform="matriz_lados")
        frame.columnconfigure(4, weight=0)
        frame.rowconfigure(1, weight=1)

        ttk.Label(frame, text="Calls | base baja / base alta").grid(row=0, column=1, sticky="w", padx=(0, 6), pady=(0, 4))
        ttk.Label(frame, text="Puts | base alta / base baja").grid(row=0, column=3, sticky="w", padx=(6, 0), pady=(0, 4))

        # Variable local para frame calls.
        frame_calls = ttk.Frame(frame)
        frame_calls.grid(row=1, column=1, sticky="nsew")
        frame_calls.columnconfigure(0, weight=1)
        frame_calls.rowconfigure(0, weight=1)

        # Variable local para tree calls.
        tree_calls = ttk.Treeview(frame_calls, columns=(), show="headings", height=height)
        tree_calls.grid(row=0, column=0, sticky="nsew")
        # Variable local para hsb calls.
        hsb_calls = ttk.Scrollbar(frame_calls, orient="horizontal", command=tree_calls.xview)
        hsb_calls.grid(row=1, column=0, sticky="ew")
        tree_calls.configure(xscrollcommand=hsb_calls.set)

        # Variable local para tree strikes.
        tree_strikes = ttk.Treeview(frame, columns=("strike",), show="headings", height=height)
        tree_strikes.grid(row=1, column=2, sticky="ns", padx=6)
        tree_strikes.column("strike", width=84, anchor="center", stretch=False)
        tree_strikes.heading("strike", text="Strike")

        # Variable local para frame puts.
        frame_puts = ttk.Frame(frame)
        frame_puts.grid(row=1, column=3, sticky="nsew")
        frame_puts.columnconfigure(0, weight=1)
        frame_puts.rowconfigure(0, weight=1)

        # Variable local para tree puts.
        tree_puts = ttk.Treeview(frame_puts, columns=(), show="headings", height=height)
        tree_puts.grid(row=0, column=0, sticky="nsew")
        # Variable local para hsb puts.
        hsb_puts = ttk.Scrollbar(frame_puts, orient="horizontal", command=tree_puts.xview)
        hsb_puts.grid(row=1, column=0, sticky="ew")
        tree_puts.configure(xscrollcommand=hsb_puts.set)

        # Variable local para vsb.
        vsb = ttk.Scrollbar(frame, orient=VERTICAL)
        vsb.grid(row=1, column=4, sticky="ns")

        # Variable local para widget.
        widget = {
            "frame": frame,
            "tree_calls": tree_calls,
            "tree_strikes": tree_strikes,
            "tree_puts": tree_puts,
            "hsb_calls": hsb_calls,
            "hsb_puts": hsb_puts,
            "vsb": vsb,
        }

        def _yview(*args):
            tree_calls.yview(*args)
            tree_strikes.yview(*args)
            tree_puts.yview(*args)
            try:
                primero, ultimo = tree_strikes.yview()
            except Exception:
                primero, ultimo = (0.0, 1.0)
            vsb.set(primero, ultimo)

        for tree in (tree_calls, tree_strikes, tree_puts):
            tree.configure(yscrollcommand=lambda primero, ultimo: vsb.set(primero, ultimo))
            tree.tag_configure("par", background="#fbfbfb")
            tree.tag_configure("impar", background="#f2f2f2")
            tree.bind("<MouseWheel>", lambda event, w=widget: self._on_mousewheel_matriz_bases_compuesta(w, event), add="+")
            tree.bind("<Button-4>", lambda event, w=widget: self._on_mousewheel_matriz_bases_compuesta(w, event), add="+")
            tree.bind("<Button-5>", lambda event, w=widget: self._on_mousewheel_matriz_bases_compuesta(w, event), add="+")
        vsb.configure(command=_yview)
        return widget

    def _on_mousewheel_matriz_bases_compuesta(self, widget: dict[str, Any], event) -> str | None:
        """Sincroniza el scroll vertical entre calls, strikes y puts."""
        # Variable local para tree calls.
        tree_calls = widget.get("tree_calls")
        # Variable local para tree strikes.
        tree_strikes = widget.get("tree_strikes")
        # Variable local para tree puts.
        tree_puts = widget.get("tree_puts")
        if tree_calls is None or tree_strikes is None or tree_puts is None:
            return None
        try:
            if getattr(event, "num", None) == 4:
                # Variable local para delta.
                delta = -1
            elif getattr(event, "num", None) == 5:
                delta = 1
            else:
                # Variable local para raw.
                raw = getattr(event, "delta", 0)
                if raw == 0:
                    return None
                delta = -1 if raw > 0 else 1
            for tree in (tree_calls, tree_strikes, tree_puts):
                tree.yview_scroll(delta, "units")
            # Variable local para vsb.
            vsb = widget.get("vsb")
            if vsb is not None:
                primero, ultimo = tree_strikes.yview()
                vsb.set(primero, ultimo)
            return "break"
        except Exception:
            LOGGER.debug("No se pudo desplazar la matriz de bases con la rueda", exc_info=True)
            return None

    def _cargar_widget_matriz_bases_compuesta(
        self,
        widget: dict[str, Any],
        bases_calls: list[dict[str, Any]],
        bases_puts: list[dict[str, Any]],
    ) -> None:
        """Carga una sola matriz combinada con calls a la izquierda y puts a la derecha."""
        # Variable local para tree calls.
        tree_calls = widget.get("tree_calls")
        # Variable local para tree strikes.
        tree_strikes = widget.get("tree_strikes")
        # Variable local para tree puts.
        tree_puts = widget.get("tree_puts")
        if tree_calls is None or tree_strikes is None or tree_puts is None:
            return

        # Variable local para calls ordenadas base.
        calls_ordenadas_base = list(sorted(bases_calls, key=lambda item: float(item.get("strike") or 0.0)))
        # Variable local para calls ordenadas.
        calls_ordenadas = list(reversed(calls_ordenadas_base))
        # Variable local para puts ordenadas.
        puts_ordenadas = list(sorted(bases_puts, key=lambda item: float(item.get("strike") or 0.0)))
        # Variable local para mapa calls.
        mapa_calls = {float(item.get("strike") or 0.0): item for item in calls_ordenadas_base}
        # Variable local para mapa puts.
        mapa_puts = {float(item.get("strike") or 0.0): item for item in puts_ordenadas}
        # Variable local para strikes union.
        strikes_union = sorted({*mapa_calls.keys(), *mapa_puts.keys()})

        # Variable local para columnas calls.
        columnas_calls = tuple(f"call_{idx}" for idx in range(len(calls_ordenadas)))
        # Variable local para columnas puts.
        columnas_puts = tuple(f"put_{idx}" for idx in range(len(puts_ordenadas)))
        tree_calls.configure(columns=columnas_calls, displaycolumns=columnas_calls)
        tree_puts.configure(columns=columnas_puts, displaycolumns=columnas_puts)
        # Variable local para modo matriz.
        modo_matriz = self.var_matriz_bases_mode.get().strip() or "last_last"
        # Variable local para metrica matriz.
        metrica_matriz = self.var_matriz_bases_metric.get().strip() or "ratio"

        for idx, base in enumerate(calls_ordenadas):
            # Variable local para col.
            col = columnas_calls[idx]
            tree_calls.column(col, width=72, anchor="e", stretch=False)
            tree_calls.heading(col, text=self._formatear_strike_matriz_bases(base.get("strike")))
        for idx, base in enumerate(puts_ordenadas):
            col = columnas_puts[idx]
            tree_puts.column(col, width=72, anchor="e", stretch=False)
            tree_puts.heading(col, text=self._formatear_strike_matriz_bases(base.get("strike")))

        for tree in (tree_calls, tree_strikes, tree_puts):
            tree.delete(*tree.get_children())

        for idx_fila, strike in enumerate(strikes_union):
            # Variable local para iid.
            iid = f"matriz_compuesta_{idx_fila}"
            # Variable local para tag.
            tag = ("par" if idx_fila % 2 == 0 else "impar",)
            tree_strikes.insert("", END, iid=iid, values=(self._formatear_strike_matriz_bases(strike),), tags=tag)

            # Variable local para valores calls.
            valores_calls: list[str] = []
            # Variable local para item fila call.
            item_fila_call = mapa_calls.get(strike)
            for item_col in calls_ordenadas:
                # Variable local para strike col.
                strike_col = float(item_col.get("strike") or 0.0)
                # Valor temporal usado en este cálculo.
                valor = None
                if item_fila_call and strike > strike_col:
                    if modo_matriz == "buy_a_sell_b":
                        # Variable local para precio A.
                        precio_a = self._precio_item_matriz_bases(item_col, "compra", modo_matriz)
                        # Variable local para precio B.
                        precio_b = self._precio_item_matriz_bases(item_fila_call, "venta", modo_matriz)
                    elif modo_matriz == "buy_b_sell_a":
                        precio_a = self._precio_item_matriz_bases(item_fila_call, "compra", modo_matriz)
                        precio_b = self._precio_item_matriz_bases(item_col, "venta", modo_matriz)
                    else:
                        precio_a = self._precio_item_matriz_bases(item_col, "", modo_matriz)
                        precio_b = self._precio_item_matriz_bases(item_fila_call, "", modo_matriz)
                    # Variable local para valor base.
                    valor_base = self._calcular_valor_matriz_bases(precio_a, precio_b, metrica_matriz)
                    if str(metrica_matriz or "").strip().lower() == "fill_pct":
                        # Variable local para diferencia strike.
                        diferencia_strike = abs(float(strike) - float(strike_col))
                        valor = (abs(float(valor_base)) / diferencia_strike * 100.0) if (valor_base is not None and diferencia_strike > 0) else None
                    else:
                        valor = valor_base
                valores_calls.append(self._formatear_valor_matriz_bases(valor, metrica_matriz))
            tree_calls.insert("", END, iid=iid, values=tuple(valores_calls), tags=tag)

            # Variable local para valores puts.
            valores_puts: list[str] = []
            # Variable local para item fila put.
            item_fila_put = mapa_puts.get(strike)
            for item_col in puts_ordenadas:
                strike_col = float(item_col.get("strike") or 0.0)
                valor = None
                if item_fila_put and strike > strike_col:
                    if modo_matriz == "buy_a_sell_b":
                        precio_a = self._precio_item_matriz_bases(item_fila_put, "compra", modo_matriz)
                        precio_b = self._precio_item_matriz_bases(item_col, "venta", modo_matriz)
                    elif modo_matriz == "buy_b_sell_a":
                        precio_a = self._precio_item_matriz_bases(item_col, "compra", modo_matriz)
                        precio_b = self._precio_item_matriz_bases(item_fila_put, "venta", modo_matriz)
                    else:
                        precio_a = self._precio_item_matriz_bases(item_fila_put, "", modo_matriz)
                        precio_b = self._precio_item_matriz_bases(item_col, "", modo_matriz)
                    valor_base = self._calcular_valor_matriz_bases(precio_a, precio_b, metrica_matriz)
                    if str(metrica_matriz or "").strip().lower() == "fill_pct":
                        diferencia_strike = abs(float(strike) - float(strike_col))
                        valor = (abs(float(valor_base)) / diferencia_strike * 100.0) if (valor_base is not None and diferencia_strike > 0) else None
                    else:
                        valor = valor_base
                valores_puts.append(self._formatear_valor_matriz_bases(valor, metrica_matriz))
            tree_puts.insert("", END, iid=iid, values=tuple(valores_puts), tags=tag)

    def _refrescar_matriz_bases(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]], info: dict[str, Any], forzar: bool = False) -> None:
        """Muestra calls y puts en una sola vista con strikes al centro."""
        self._refrescar_selector_matriz_bases()
        # Variable local para fuente.
        fuente = self.var_matriz_bases_fuente.get().strip() or "HOY (vivo)"
        # Variable local para modo matriz.
        modo_matriz = self.var_matriz_bases_mode.get().strip() or "last_last"
        # Variable local para metrica matriz.
        metrica_matriz = self.var_matriz_bases_metric.get().strip() or "ratio"
        # Variable local para vencimiento.
        vencimiento = self.var_vencimiento.get().strip()
        # Variable local para fuente viva.
        fuente_viva = fuente == "HOY (vivo)"
        # Variable local para marca tiempo.
        marca_tiempo = ahora().strftime("%Y-%m-%d %H:%M") if (fuente_viva and mercado_en_horario_operativo()) else (info.get("last_event_at") if fuente_viva else fuente)
        # Caché en memoria para clave cache.
        clave_cache = (fuente, modo_matriz, metrica_matriz, vencimiento, marca_tiempo)
        if not forzar and self._matriz_bases_cache_key == clave_cache:
            return

        if fuente_viva:
            # Variable local para filas calls src.
            filas_calls_src = list(filas_calls)
            # Variable local para filas puts src.
            filas_puts_src = list(filas_puts)
            # Variable local para fuente txt.
            fuente_txt = "HOY (vivo)"
            # Variable local para detalle valor.
            detalle_valor = self._texto_modo_matriz_bases(modo_matriz).replace("Relación: ", "")
            # Variable local para detalle metrica.
            detalle_metrica = self._texto_metrica_matriz_bases(metrica_matriz).replace("Vista: ", "")
        else:
            # Payload temporal procesado en este bloque.
            payload = self._obtener_cache_cierres_json().get(fuente)
            # Colección temporal de instrumentos usada en este bloque.
            instrumentos = payload.get("instrumentos") if isinstance(payload, dict) else []
            filas_calls_src = []
            filas_puts_src = []
            for fila in instrumentos or []:
                if not isinstance(fila, dict):
                    continue
                # Variable local para tipo.
                tipo = str(fila.get("tipo") or "").strip()
                if tipo not in {"calls", "puts"}:
                    continue
                if vencimiento and str(fila.get("vencimiento") or "") != vencimiento:
                    continue
                if not fila_tiene_cotizacion(fila):
                    continue
                if tipo == "calls":
                    filas_calls_src.append(dict(fila))
                else:
                    filas_puts_src.append(dict(fila))
            filas_calls_src.sort(key=lambda item: (float(item.get("strike")) if isinstance(item.get("strike"), (int, float)) else float("inf"), str(item.get("ticker") or "")))
            filas_puts_src.sort(key=lambda item: (float(item.get("strike")) if isinstance(item.get("strike"), (int, float)) else float("inf"), str(item.get("ticker") or "")))
            fuente_txt = f"Cierre {fuente}"
            detalle_valor = self._texto_modo_matriz_bases(modo_matriz).replace("Relación: ", "")
            detalle_metrica = self._texto_metrica_matriz_bases(metrica_matriz).replace("Vista: ", "")

        # Variable local para bases calls.
        bases_calls = self._agrupar_bases_para_matriz(filas_calls_src, vivo=fuente_viva, modo=modo_matriz)
        # Variable local para bases puts.
        bases_puts = self._agrupar_bases_para_matriz(filas_puts_src, vivo=fuente_viva, modo=modo_matriz)
        self._cargar_widget_matriz_bases_compuesta(self.widget_matriz_bases, bases_calls, bases_puts)
        self.var_matriz_bases_info.set(
            f"Matriz bases: fuente={fuente_txt} | vencimiento={vencimiento or 'todos'} | modo={detalle_valor} | vista={detalle_metrica} | calls activas={len(bases_calls)} a la izquierda (base baja / base alta) | strikes al centro | puts activas={len(bases_puts)} a la derecha (base alta / base baja) | refresco vivo=1 minuto con mercado abierto."
        )
        self._matriz_bases_cache_key = clave_cache

    def _ratios_float_var(self, variable: StringVar, default: float) -> float:
        """Lee un umbral editable aceptando coma decimal."""
        try:
            return float(str(variable.get() or "").replace(",", "."))
        except Exception:
            return default

    def _ratio_color_tag(self, valor: float | None) -> str:
        """Clasifica un ratio segun umbrales editables."""
        if valor is None:
            return "ratio_sin_dato"
        ri_bajo = self._ratios_float_var(self.var_ratios_umbral_ri_bajo, 0.30)
        ri_alto = self._ratios_float_var(self.var_ratios_umbral_ri_alto, 0.50)
        rc_bajo = self._ratios_float_var(self.var_ratios_umbral_rc_bajo, 1.50)
        rc_alto = self._ratios_float_var(self.var_ratios_umbral_rc_alto, 2.50)
        if valor <= ri_bajo:
            return "ratio_ri_bajo"
        if valor <= ri_alto:
            return "ratio_ri_alto"
        if valor < rc_bajo:
            return "ratio_normal"
        if valor < rc_alto:
            return "ratio_rc_bajo"
        return "ratio_extremo"

    def _ratio_color_style(self, valor: float | None) -> dict[str, str]:
        """Devuelve colores por celda para la matriz de ratios."""
        tag = self._ratio_color_tag(valor)
        estilos = {
            "ratio_ri_bajo": {"background": "#9a75d6", "foreground": "#ffffff"},
            "ratio_ri_alto": {"background": "#4f95d9", "foreground": "#ffffff"},
            "ratio_normal": {"background": "#38afa7", "foreground": "#ffffff"},
            "ratio_rc_bajo": {"background": "#42a85f", "foreground": "#ffffff"},
            "ratio_rc_alto": {"background": "#d4aa43", "foreground": "#111827"},
            "ratio_extremo": {"background": "#d8565b", "foreground": "#ffffff"},
            "ratio_sin_dato": {"background": "#1b2430", "foreground": "#8aa0bd"},
            "ratio_centro": {"background": "#202a38", "foreground": "#ffffff"},
        }
        return estilos.get(tag, estilos["ratio_sin_dato"])

    def _ratio_precio_base(self, item: dict[str, Any] | None) -> float | None:
        """Precio usado para ratios: last y fallback a referencia."""
        if not isinstance(item, dict):
            return None
        precio = convertir_a_numero(item.get("last"))
        if precio not in (None, 0):
            return float(precio)
        ref = precio_referencia(item)
        return float(ref) if ref not in (None, 0) else None

    def _ratio_base_label(self, item: dict[str, Any]) -> str:
        """Etiqueta visible para selector de base central."""
        strike = self._formatear_strike_matriz_bases(item.get("strike"))
        precio = self._ratio_precio_base(item)
        precio_txt = self._formatear_valor("last", precio) if precio is not None else "s/d"
        return f"{strike} - {precio_txt}"

    def _ratios_bases_por_tipo(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]], tipo: str) -> list[dict[str, Any]]:
        """Devuelve bases ordenadas para el tipo indicado."""
        tipo_norm = str(tipo or "calls").strip().lower()
        filas = filas_puts if tipo_norm in {"put", "puts"} else filas_calls
        bases = self._agrupar_bases_para_matriz(filas, vivo=True, modo="last_last")
        return list(sorted(bases, key=lambda item: float(item.get("strike") or 0.0)))

    def _ratios_bases_actuales(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]]) -> list[dict[str, Any]]:
        """Devuelve bases ordenadas para el tipo Call/Put elegido."""
        return self._ratios_bases_por_tipo(filas_calls, filas_puts, self.var_ratios_tipo.get())

    def _ratios_ventana_bases(self, bases: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], int]:
        """Recorta 7 bases a cada lado de la base central seleccionada."""
        if not bases:
            return [], 0
        labels = [self._ratio_base_label(item) for item in bases]
        if hasattr(self, "combo_ratios_base"):
            self.combo_ratios_base["values"] = labels
        actual = self.var_ratios_base_centro.get().strip()
        if actual not in labels:
            idx = len(bases) // 2
            self.var_ratios_base_centro.set(labels[idx])
        else:
            idx = labels.index(actual)
        inicio = max(0, idx - 7)
        fin = min(len(bases), idx + 8)
        return bases[inicio:fin], idx - inicio

    def _ratios_ventana_por_strike(self, bases: list[dict[str, Any]], strike_centro: float | None) -> tuple[list[dict[str, Any]], int]:
        """Recorta la ventana alrededor del strike central pedido."""
        if not bases:
            return [], 0
        if strike_centro is None:
            idx = len(bases) // 2
        else:
            idx = min(range(len(bases)), key=lambda pos: abs(float(bases[pos].get("strike") or 0.0) - float(strike_centro)))
        inicio = max(0, idx - 7)
        fin = min(len(bases), idx + 8)
        return bases[inicio:fin], idx - inicio

    def _ratios_valor(self, base_a: dict[str, Any], base_b: dict[str, Any]) -> float | None:
        """Calcula precio A / precio B."""
        precio_a = self._ratio_precio_base(base_a)
        precio_b = self._ratio_precio_base(base_b)
        if precio_a is None or precio_b in (None, 0):
            return None
        return float(precio_a) / float(precio_b)

    def _formatear_ratio_badge(self, valor: float | None) -> str:
        return "--" if valor is None else f"{float(valor):.2f}"

    def _set_ratios_vista(self, vista: str) -> None:
        self.var_ratios_vista.set(vista)
        self._al_cambiar_selector_matriz_bases()

    def _toggle_ratios_tipo(self) -> None:
        actual = str(self.var_ratios_tipo.get() or "Call").strip().lower()
        self.var_ratios_tipo.set("Put" if actual in {"call", "calls"} else "Call")
        self._al_cambiar_selector_matriz_bases()

    def _crear_tree_ratios_cuadro(self, parent):
        if TksheetWidget is not None:
            tree = SheetTableAdapter(parent, tuple(), height=8)
            tree.pack(fill=BOTH, expand=True)
        else:
            tree = self._crear_treeview_con_scrollbars(parent, tuple(), 8)
        for tag, color in {
            "ratio_ri_bajo": "#9a75d6",
            "ratio_ri_alto": "#4f95d9",
            "ratio_normal": "#38afa7",
            "ratio_rc_bajo": "#42a85f",
            "ratio_rc_alto": "#d4aa43",
            "ratio_extremo": "#d8565b",
            "ratio_sin_dato": "#1b2430",
            "ratio_centro": "#202a38",
        }.items():
            tree.tag_configure(tag, background=color, foreground="#ffffff")
        return tree

    def _crear_panel_ratios_cuadro(self, parent, titulo: str, peso: int = 1):
        panel = ttk.LabelFrame(parent, text=titulo)
        panel.pack(fill=BOTH, expand=True, pady=(0, 4))
        return self._crear_tree_ratios_cuadro(panel)

    def _crear_tree_ratios_cadena(self, parent):
        columnas = ("precio_izq", "r_1", "r_2", "r_3", "r_4", "strike", "r1", "r2", "r3", "r4", "precio_der")
        tree = self._crear_treeview_con_scrollbars(parent, columnas, 22)
        textos = {
            "precio_izq": "Precio",
            "r_1": "-1",
            "r_2": "-2",
            "r_3": "-3",
            "r_4": "-4",
            "strike": "Strike",
            "r1": "+1",
            "r2": "+2",
            "r3": "+3",
            "r4": "+4",
            "precio_der": "Precio",
        }
        for col in columnas:
            tree.column(col, width=96 if col != "strike" else 115, anchor="center", stretch=col in {"precio_izq", "precio_der"})
            tree.heading(col, text=textos[col])
        for tag, color in {
            "ratio_ri_bajo": "#9a75d6",
            "ratio_ri_alto": "#4f95d9",
            "ratio_normal": "#38afa7",
            "ratio_rc_bajo": "#42a85f",
            "ratio_rc_alto": "#d4aa43",
            "ratio_extremo": "#d8565b",
            "ratio_sin_dato": "#1b2430",
            "ratio_detalle": "#111820",
        }.items():
            tree.tag_configure(tag, background=color, foreground="#ffffff")
        return tree

    def _crear_vista_ratios(self, parent) -> None:
        """Cadena unificada centrada en ATM (puts izq / strike centro / calls der) + vista de Alas."""
        frame_controls = ttk.Frame(parent)
        frame_controls.pack(fill=X, pady=(0, 6))
        ttk.Label(frame_controls, text="Base central:").pack(side=LEFT)
        self.combo_ratios_base = ttk.Combobox(frame_controls, textvariable=self.var_ratios_base_centro, state="readonly", width=22)
        self.combo_ratios_base.pack(side=LEFT, padx=(4, 6))
        self.combo_ratios_base.bind("<<ComboboxSelected>>", lambda _e: self._al_cambiar_selector_matriz_bases())
        ttk.Button(frame_controls, text="Auto ATM", command=self._ratios_centrar_en_atm).pack(side=LEFT, padx=(0, 12))
        for texto, variable in (
            ("RI <", self.var_ratios_umbral_ri_bajo),
            ("RI >", self.var_ratios_umbral_ri_alto),
            ("RC <", self.var_ratios_umbral_rc_bajo),
            ("RC >", self.var_ratios_umbral_rc_alto),
        ):
            ttk.Label(frame_controls, text=texto).pack(side=LEFT)
            entrada = ttk.Entry(frame_controls, textvariable=variable, width=6)
            entrada.pack(side=LEFT, padx=(2, 6))
            entrada.bind("<KeyRelease>", lambda _e: self._al_cambiar_selector_matriz_bases())
        ttk.Button(frame_controls, text="Recalcular", command=self._al_cambiar_selector_matriz_bases).pack(side=LEFT, padx=(6, 0))
        # Cadena unificada: puts izq — strike centro — calls der
        frame_cadena = ttk.LabelFrame(parent, text="Cadena unificada  ←  Puts  |  Strike  |  Calls  →")
        frame_cadena.pack(fill=BOTH, expand=True, pady=(0, 4))
        self.tree_ratios_cadena_unif = self._crear_tree_cadena_unificada(frame_cadena)
        # Vista Alas: propuesta alternativa — simetría por distancia al ATM
        frame_alas = ttk.LabelFrame(parent, text="Vista Alas  —  simetría put/call por distancia al ATM")
        frame_alas.pack(fill=X, pady=(0, 4))
        self.tree_ratios_alas = self._crear_tree_ratios_alas(frame_alas)
        # Atributos de compatibilidad (vistas antiguas eliminadas, referenciados como None)
        self.frame_ratios_body = None
        self.frame_ratios_cuadro_tree = None
        self.tree_ratios_cuadro_calls = None
        self.tree_ratios_cuadro_puts = None
        self.tree_ratios_cuadro = None
        self.tree_ratios_cadena = None
        self.frame_ratios_cadena_tree = None
        ttk.Label(parent, textvariable=self.var_ratios_info, justify="left", wraplength=1500).pack(fill=X, pady=(4, 0))

    def _mostrar_tree_ratios(self) -> Any:
        vista = str(self.var_ratios_vista.get() or "cuadro").strip().lower()
        if vista == "cadena":
            self.frame_ratios_cuadro_tree.pack_forget()
            self.frame_ratios_cadena_tree.pack(fill=BOTH, expand=True)
            return self.tree_ratios_cadena
        self.frame_ratios_cadena_tree.pack_forget()
        self.frame_ratios_cuadro_tree.pack(fill=BOTH, expand=True)
        return self.tree_ratios_cuadro

    def _refrescar_ratios(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]], _info: dict[str, Any], forzar: bool = False) -> None:
        """Refresca la cadena unificada (puts izq / strike centro / calls der) y la vista de Alas."""
        if not hasattr(self, "tree_ratios_cadena_unif") or self.tree_ratios_cadena_unif is None:
            return
        bases_calls = self._ratios_bases_por_tipo(filas_calls, filas_puts, "calls")
        bases_puts = self._ratios_bases_por_tipo(filas_calls, filas_puts, "puts")
        calls_por_strike: dict[float, dict[str, Any]] = {float(b["strike"]): b for b in bases_calls}
        puts_por_strike: dict[float, dict[str, Any]] = {float(b["strike"]): b for b in bases_puts}
        todos_strikes = sorted(set(calls_por_strike) | set(puts_por_strike))
        if not todos_strikes:
            self.var_ratios_info.set("Ratios: sin bases activas para el vencimiento seleccionado.")
            return
        # Detectar ATM por spot; si no hay spot, usar el strike del combo o el central
        spot = getattr(self, "_precio_subyacente_actual", None)
        actual_label = self.var_ratios_base_centro.get().strip()
        atm_strike: float
        if actual_label:
            # El usuario eligió base manual: buscar ese strike
            for b in bases_calls or bases_puts:
                if self._ratio_base_label(b) == actual_label:
                    atm_strike = float(b["strike"])
                    break
            else:
                atm_strike = min(todos_strikes, key=lambda k: abs(k - float(spot or 0))) if spot else todos_strikes[len(todos_strikes) // 2]
        elif spot is not None:
            atm_strike = min(todos_strikes, key=lambda k: abs(k - float(spot)))
        else:
            atm_strike = todos_strikes[len(todos_strikes) // 2]
        # Actualizar combo con labels actuales
        labels_calls = [self._ratio_base_label(b) for b in bases_calls]
        if hasattr(self, "combo_ratios_base"):
            self.combo_ratios_base["values"] = labels_calls
        cache_key = (
            "ratios_v2",
            atm_strike,
            tuple((s, calls_por_strike[s].get("last"), calls_por_strike[s].get("bid"), calls_por_strike[s].get("ask")) for s in sorted(calls_por_strike)),
            tuple((s, puts_por_strike[s].get("last"), puts_por_strike[s].get("bid"), puts_por_strike[s].get("ask")) for s in sorted(puts_por_strike)),
            self.var_ratios_umbral_ri_bajo.get(),
            self.var_ratios_umbral_ri_alto.get(),
            self.var_ratios_umbral_rc_bajo.get(),
            self.var_ratios_umbral_rc_alto.get(),
        )
        if not forzar and self._matriz_bases_cache_key == cache_key:
            return
        # Precios ATM de referencia
        precio_atm_call = self._ratio_precio_base(calls_por_strike.get(atm_strike))
        precio_atm_put = self._ratio_precio_base(puts_por_strike.get(atm_strike))
        # Ventana ±8 strikes alrededor del ATM
        idx_atm = min(range(len(todos_strikes)), key=lambda i: abs(todos_strikes[i] - atm_strike))
        ventana = todos_strikes[max(0, idx_atm - 8): idx_atm + 9]
        self._cargar_cadena_unificada(ventana, calls_por_strike, puts_por_strike, atm_strike, precio_atm_call, precio_atm_put)
        self._cargar_vista_alas_ratios(todos_strikes, calls_por_strike, puts_por_strike, atm_strike, precio_atm_call, precio_atm_put)
        atm_txt = self._formatear_strike_matriz_bases(atm_strike)
        spot_txt = f" | Spot: {spot:.2f}" if spot is not None else ""
        self.var_ratios_info.set(
            f"Ratios: {len(calls_por_strike)} calls / {len(puts_por_strike)} puts | ATM: {atm_txt}{spot_txt} | ventana ±8 strikes | umbrales RI<{self.var_ratios_umbral_ri_bajo.get()} RC>{self.var_ratios_umbral_rc_bajo.get()}"
        )
        self._matriz_bases_cache_key = cache_key

    def _cargar_ratios_cuadro(self, tree, bases: list[dict[str, Any]], idx_centro: int) -> None:
        self._mostrar_tree_ratios()
        columnas = ("eje_y",) + tuple(f"c_{idx}" for idx in range(len(bases)))
        tree.configure(columns=columnas, displaycolumns=columnas)
        tree.column("eje_y", width=120, anchor="e", stretch=False)
        tree.heading("eje_y", text="Strike / Precio")
        for idx, item in enumerate(bases):
            col = f"c_{idx}"
            precio = self._ratio_precio_base(item)
            encabezado = f"{self._formatear_strike_matriz_bases(item.get('strike'))}\n{self._formatear_valor('last', precio) if precio is not None else 's/d'}"
            tree.column(col, width=82, anchor="center", stretch=False)
            tree.heading(col, text=encabezado)
        tree.delete(*tree.get_children())
        rows_sheet: list[dict[str, Any]] = []
        for r_idx, base_fila in enumerate(bases):
            precio_fila = self._ratio_precio_base(base_fila)
            etiqueta_fila = (
                f"{self._formatear_strike_matriz_bases(base_fila.get('strike'))} / "
                f"{self._formatear_valor('last', precio_fila) if precio_fila is not None else 's/d'}"
            )
            valores = [etiqueta_fila]
            tags = []
            cell_styles = {"eje_y": {"background": "#1b2430", "foreground": "#b7c7df"}}
            for c_idx, base_col in enumerate(bases):
                col = f"c_{c_idx}"
                if r_idx == c_idx:
                    valores.append("CENTRO" if r_idx == idx_centro else "")
                    cell_styles[col] = {"background": "#202a38", "foreground": "#ffffff"}
                    continue
                valor = self._ratios_valor(base_col, base_fila)
                valores.append(self._formatear_ratio_badge(valor))
                tags.append(self._ratio_color_tag(valor))
                cell_styles[col] = self._ratio_color_style(valor)
            tag = ("ratio_centro",) if r_idx == idx_centro else ()
            row = {"iid": f"ratio_cuadro_{id(tree)}_{r_idx}", "values": tuple(valores), "tags": tag, "raw": {"_cell_styles": cell_styles}}
            rows_sheet.append(row)
            if not hasattr(tree, "load_rows"):
                tree.insert("", END, iid=row["iid"], values=row["values"], tags=tag)
        if hasattr(tree, "load_rows"):
            tree.load_rows(rows_sheet)

    def _cargar_ratios_cadena(self, bases: list[dict[str, Any]]) -> None:
        self._mostrar_tree_ratios()
        tree = self.tree_ratios_cadena
        tree.delete(*tree.get_children())
        for idx, base in enumerate(bases):
            precio = self._ratio_precio_base(base)
            izquierda = []
            derecha = []
            for salto in range(1, 5):
                base_izq = bases[idx - salto] if idx - salto >= 0 else None
                base_der = bases[idx + salto] if idx + salto < len(bases) else None
                izquierda.append(self._formatear_ratio_badge(self._ratios_valor(base, base_izq)) if base_izq else "--")
                derecha.append(self._formatear_ratio_badge(self._ratios_valor(base_der, base)) if base_der else "--")
            valores = (
                self._formatear_valor("last", precio),
                *izquierda,
                self._formatear_strike_matriz_bases(base.get("strike")),
                *derecha,
                self._formatear_valor("last", precio),
            )
            ratios_validos = [convertir_a_numero(valor) for valor in izquierda + derecha if valor != "--"]
            tag = self._ratio_color_tag(float(ratios_validos[0])) if ratios_validos else "ratio_sin_dato"
            parent_id = f"ratio_cadena_{idx}"
            tree.insert("", END, iid=parent_id, values=valores, tags=(tag,), open=False)
            for salto in range(1, 5):
                for direccion, base_rel in (("abajo", bases[idx - salto] if idx - salto >= 0 else None), ("arriba", bases[idx + salto] if idx + salto < len(bases) else None)):
                    if base_rel is None:
                        continue
                    ratio = self._ratios_valor(base, base_rel) if direccion == "abajo" else self._ratios_valor(base_rel, base)
                    detalle = (
                        f"{direccion} {salto}",
                        "",
                        "",
                        self._formatear_ratio_badge(ratio),
                        "",
                        self._formatear_strike_matriz_bases(base_rel.get("strike")),
                        "",
                        "",
                        "",
                        "",
                        self._formatear_valor("last", self._ratio_precio_base(base_rel)),
                    )
                    tree.insert(parent_id, END, values=detalle, tags=("ratio_detalle",))

    def _cargar_cadena_unificada(
        self,
        ventana: list[float],
        calls_por_strike: dict[float, dict[str, Any]],
        puts_por_strike: dict[float, dict[str, Any]],
        atm_strike: float,
        precio_atm_call: float | None,
        precio_atm_put: float | None,
    ) -> None:
        """Carga la cadena unificada: puts izquierda, strike centro, calls derecha."""
        tree = self.tree_ratios_cadena_unif
        tree.delete(*tree.get_children())
        # Strikes de mayor a menor → ATM queda en el centro visual
        for strike in reversed(ventana):
            es_atm = (strike == atm_strike)
            call = calls_por_strike.get(strike)
            put = puts_por_strike.get(strike)
            precio_call = self._ratio_precio_base(call)
            precio_put = self._ratio_precio_base(put)
            ratio_call: float | None = None
            ratio_put: float | None = None
            if precio_call is not None and precio_atm_call not in (None, 0):
                ratio_call = precio_call / precio_atm_call
            if precio_put is not None and precio_atm_put not in (None, 0):
                ratio_put = precio_put / precio_atm_put
            atm_marker = " ◀ ATM" if es_atm else ""
            strike_txt = self._formatear_strike_matriz_bases(strike) + atm_marker
            put_atm_txt  = self._formatear_ratio_badge(ratio_put)
            put_precio_txt = self._formatear_valor("last", precio_put) if precio_put is not None else "--"
            call_precio_txt = self._formatear_valor("last", precio_call) if precio_call is not None else "--"
            call_atm_txt = self._formatear_ratio_badge(ratio_call)
            valores = (put_atm_txt, put_precio_txt, strike_txt, call_precio_txt, call_atm_txt)
            if es_atm:
                tag = ("ratio_atm",)
            else:
                # Colorear la fila según el ratio de call (derecha); si no hay call usar put
                ratio_ref = ratio_call if ratio_call is not None else ratio_put
                tag = (self._ratio_color_tag(ratio_ref),)
            tree.insert("", END, values=valores, tags=tag)

    def _cargar_vista_alas_ratios(
        self,
        todos_strikes: list[float],
        calls_por_strike: dict[float, dict[str, Any]],
        puts_por_strike: dict[float, dict[str, Any]],
        atm_strike: float,
        precio_atm_call: float | None,
        precio_atm_put: float | None,
    ) -> None:
        """Carga la vista Alas: para cada distancia n, put en ATM-n vs call en ATM+n."""
        tree = self.tree_ratios_alas
        tree.delete(*tree.get_children())
        if atm_strike not in todos_strikes:
            return
        idx_atm = todos_strikes.index(atm_strike)
        max_alas = min(8, idx_atm, len(todos_strikes) - idx_atm - 1)
        if max_alas <= 0:
            return
        for n in range(1, max_alas + 1):
            strike_put = todos_strikes[idx_atm - n]
            strike_call = todos_strikes[idx_atm + n]
            put_item = puts_por_strike.get(strike_put)
            call_item = calls_por_strike.get(strike_call)
            precio_put = self._ratio_precio_base(put_item)
            precio_call = self._ratio_precio_base(call_item)
            ratio_put_atm: float | None = None
            ratio_call_atm: float | None = None
            if precio_put is not None and precio_atm_put not in (None, 0):
                ratio_put_atm = precio_put / precio_atm_put
            if precio_call is not None and precio_atm_call not in (None, 0):
                ratio_call_atm = precio_call / precio_atm_call
            # Simetría: cuánto más cara está la ala de put vs la de call (>1 → skew negativo)
            simetria: float | None = None
            if ratio_put_atm is not None and ratio_call_atm not in (None, 0):
                simetria = ratio_put_atm / ratio_call_atm
            valores = (
                f"±{n}",
                self._formatear_strike_matriz_bases(strike_put),
                self._formatear_valor("last", precio_put) if precio_put is not None else "--",
                self._formatear_ratio_badge(ratio_put_atm),
                self._formatear_strike_matriz_bases(strike_call),
                self._formatear_valor("last", precio_call) if precio_call is not None else "--",
                self._formatear_ratio_badge(ratio_call_atm),
                self._formatear_ratio_badge(simetria),
            )
            tag = (self._ratio_color_tag(simetria),)
            tree.insert("", END, values=valores, tags=tag)

    def _crear_tree_cadena_unificada(self, parent):
        """Árbol de la cadena unificada: Put/ATM | Put$ | Strike | Call$ | Call/ATM."""
        cols = ("put_atm", "put_precio", "strike", "call_precio", "call_atm")
        tree = self._crear_treeview_con_scrollbars(parent, cols, 18)
        configs = {
            "put_atm":    (90,  "center", "Put/ATM"),
            "put_precio": (85,  "e",      "Put $"),
            "strike":     (115, "center", "Strike $"),
            "call_precio":(85,  "e",      "Call $"),
            "call_atm":   (90,  "center", "Call/ATM"),
        }
        for col, (w, anchor, heading) in configs.items():
            tree.column(col, width=w, anchor=anchor, stretch=(col == "strike"))
            tree.heading(col, text=heading)
        for tag, bg, fg in (
            ("ratio_ri_bajo",  "#9a75d6", "#ffffff"),
            ("ratio_ri_alto",  "#4f95d9", "#ffffff"),
            ("ratio_normal",   "#38afa7", "#ffffff"),
            ("ratio_rc_bajo",  "#42a85f", "#ffffff"),
            ("ratio_rc_alto",  "#d4aa43", "#111827"),
            ("ratio_extremo",  "#d8565b", "#ffffff"),
            ("ratio_sin_dato", "#1b2430", "#8aa0bd"),
            ("ratio_atm",      "#1a3050", "#f0e870"),
        ):
            tree.tag_configure(tag, background=bg, foreground=fg)
        return tree

    def _crear_tree_ratios_alas(self, parent):
        """Árbol de la vista Alas: simetría put/call por distancia al ATM."""
        cols = ("dist", "put_strike", "put_precio", "put_atm", "call_strike", "call_precio", "call_atm", "simetria")
        tree = self._crear_treeview_con_scrollbars(parent, cols, 7)
        configs = {
            "dist":       (50,  "center", "Ala"),
            "put_strike": (85,  "center", "Put K"),
            "put_precio": (75,  "e",      "Put $"),
            "put_atm":    (80,  "center", "Put/ATM"),
            "call_strike":(85,  "center", "Call K"),
            "call_precio":(75,  "e",      "Call $"),
            "call_atm":   (80,  "center", "Call/ATM"),
            "simetria":   (90,  "center", "P/C simét."),
        }
        for col, (w, anchor, heading) in configs.items():
            tree.column(col, width=w, anchor=anchor, stretch=(col == "simetria"))
            tree.heading(col, text=heading)
        for tag, bg, fg in (
            ("ratio_ri_bajo",  "#9a75d6", "#ffffff"),
            ("ratio_ri_alto",  "#4f95d9", "#ffffff"),
            ("ratio_normal",   "#38afa7", "#ffffff"),
            ("ratio_rc_bajo",  "#42a85f", "#ffffff"),
            ("ratio_rc_alto",  "#d4aa43", "#111827"),
            ("ratio_extremo",  "#d8565b", "#ffffff"),
            ("ratio_sin_dato", "#1b2430", "#8aa0bd"),
        ):
            tree.tag_configure(tag, background=bg, foreground=fg)
        return tree

    def _ratios_centrar_en_atm(self) -> None:
        """Limpia la base central elegida manualmente para que el refresco la detecte en ATM."""
        self.var_ratios_base_centro.set("")
        self._al_cambiar_selector_matriz_bases()

    def _obtener_cache_smile_cierres(self) -> dict[str, Any]:
        """Construye y cachea smiles de cierre por fecha y vencimiento."""
        # Caché en memoria para cache.
        cache = getattr(self, "_smile_cierres_cache", None)
        if isinstance(cache, dict) and cache:
            return cache
        # Variable local para por fecha.
        por_fecha: dict[str, dict[str, Any]] = {}
        # Variable local para vencimientos.
        vencimientos: set[str] = set()
        for payload in self._leer_cierres_diarios():
            # Fecha temporal usada en este cálculo.
            fecha = str(payload.get("_fecha_archivo") or "").strip()
            if not fecha:
                continue
            # Variable local para por vencimiento.
            por_venc: dict[str, dict[str, Any]] = {}
            # Colección temporal de instrumentos usada en este bloque.
            instrumentos = payload.get("instrumentos") or []
            for fila in instrumentos:
                if not isinstance(fila, dict):
                    continue
                # Variable local para vencimiento.
                vencimiento = str(fila.get("vencimiento") or "").strip()
                # Variable local para strike.
                strike = convertir_a_numero(fila.get("strike"))
                # Variable local para VI.
                iv = convertir_a_numero(fila.get("iv"))
                # Variable local para tipo.
                tipo = str(fila.get("tipo") or "").strip()
                if not vencimiento or strike is None or iv is None or tipo not in {"calls", "puts"}:
                    continue
                vencimientos.add(vencimiento)
                # Variable local para bucket.
                bucket = por_venc.setdefault(vencimiento, {"calls": [], "puts": [], "spot": convertir_a_numero(payload.get("spot_referencia"))})
                bucket[tipo].append((float(strike), float(iv)))
            if not por_venc:
                continue
            for datos_venc in por_venc.values():
                datos_venc["calls"] = sorted(datos_venc.get("calls") or [])
                datos_venc["puts"] = sorted(datos_venc.get("puts") or [])
            por_fecha[fecha] = {
                "vencimientos": sorted(por_venc.keys()),
                "datos": por_venc,
                "spot": convertir_a_numero(payload.get("spot_referencia")),
            }
        cache = {
            "fechas": sorted(por_fecha.keys(), reverse=True),
            "por_fecha": por_fecha,
            "vencimientos": sorted(vencimientos),
        }
        self._smile_cierres_cache = cache
        return cache

    def _tab_smile_activa_indice(self) -> int:
        """Devuelve el índice de la subvista activa del módulo Smile."""
        try:
            if not hasattr(self, "notebook_smile"):
                return 1
            return int(self.notebook_smile.index(self.notebook_smile.select())) + 1
        except Exception:
            LOGGER.debug("No se pudo detectar la subpestaña Smile activa", exc_info=True)
            return 1

    def _tab_matriz_bases_activa_indice(self) -> int:
        """Devuelve el índice de la subvista activa de matriz bases."""
        try:
            if not hasattr(self, "notebook_matriz_bases"):
                return 1
            return int(self.notebook_matriz_bases.index(self.notebook_matriz_bases.select())) + 1
        except Exception:
            LOGGER.debug("No se pudo detectar la subpestaña de matriz bases", exc_info=True)
            return 1

    def _tab_intradia_rel_activa_indice(self) -> int:
        """Devuelve el índice de la subvista activa de Tabla rel. intradía."""
        try:
            if not hasattr(self, "notebook_intradia_rel"):
                return 1
            return int(self.notebook_intradia_rel.index(self.notebook_intradia_rel.select())) + 1
        except Exception:
            LOGGER.debug("No se pudo detectar la subpestaña de Tabla rel. intradía", exc_info=True)
            return 1

    def _refrescar_selectores_smile(self, filas_vivas: list[dict[str, Any]], vencimiento_por_defecto: str = "") -> None:
        """Actualiza las opciones de fecha y vencimiento de las vistas Smile."""
        if not hasattr(self, "combo_smile_fecha"):
            return
        # Caché en memoria para cache.
        cache = self._obtener_cache_smile_cierres()
        # Variable local para fuentes.
        fuentes = ["HOY (vivo)"] + list(cache.get("fechas") or [])
        self._set_combobox_values_si_cambia(self.combo_smile_fecha, "smile_fuentes", fuentes)
        # Variable local para fuente actual.
        fuente_actual = self.var_smile_fecha.get().strip()
        if fuente_actual not in fuentes:
            self.var_smile_fecha.set("HOY (vivo)" if "HOY (vivo)" in fuentes else (fuentes[0] if fuentes else ""))
            fuente_actual = self.var_smile_fecha.get().strip()
        # Variable local para vencs vivo.
        vencs_vivo = []
        for venc in sorted({str(fila.get("vencimiento") or "").strip() for fila in filas_vivas if str(fila.get("vencimiento") or "").strip()}):
            calls_vivo, puts_vivo = construir_datos_smile(filas_vivas, venc)
            if calls_vivo or puts_vivo:
                vencs_vivo.append(venc)
        if not vencs_vivo:
            vencs_vivo = [v for v in self._vencimientos if v]
        if fuente_actual == "HOY (vivo)":
            # Variable local para vencs dia.
            vencs_dia = list(vencs_vivo)
        else:
            # Variable local para datos fecha.
            datos_fecha = (cache.get("por_fecha") or {}).get(fuente_actual) or {}
            vencs_dia = list(datos_fecha.get("vencimientos") or [])
        if not vencs_dia and vencimiento_por_defecto:
            vencs_dia = [vencimiento_por_defecto]
        self._set_combobox_values_si_cambia(self.combo_smile_vencimiento, "smile_vencimientos_dia", vencs_dia)
        # Variable local para vencimiento actual.
        venc_actual = self.var_smile_vencimiento.get().strip()
        if venc_actual not in vencs_dia:
            # Variable local para preferido.
            preferido = vencimiento_por_defecto if vencimiento_por_defecto in vencs_dia else ""
            self.var_smile_vencimiento.set(preferido or (vencs_dia[0] if vencs_dia else ""))
        if hasattr(self, "combo_smile_superficie_vencimiento"):
            vencs_superficie = list(cache.get("vencimientos") or vencs_dia)
            self._set_combobox_values_si_cambia(
                self.combo_smile_superficie_vencimiento,
                "smile_vencimientos_superficie",
                vencs_superficie,
            )
            venc_superficie_actual = self.var_smile_superficie_vencimiento.get().strip()
            if venc_superficie_actual not in vencs_superficie:
                preferido_superficie = self.var_smile_vencimiento.get().strip()
                if preferido_superficie not in vencs_superficie:
                    preferido_superficie = vencimiento_por_defecto if vencimiento_por_defecto in vencs_superficie else ""
                self.var_smile_superficie_vencimiento.set(preferido_superficie or (vencs_superficie[0] if vencs_superficie else ""))
    def _obtener_smile_cierre_fecha(self, fecha: str, vencimiento: str) -> tuple[list[tuple[float, float]], list[tuple[float, float]], dict[str, Any]]:
        """Devuelve calls y puts del smile de cierre para una fecha y vencimiento."""
        # Caché en memoria para cache.
        cache = self._obtener_cache_smile_cierres()
        # Variable local para datos fecha.
        datos_fecha = (cache.get("por_fecha") or {}).get(str(fecha).strip()) or {}
        # Variable local para datos vencimiento.
        datos_venc = (datos_fecha.get("datos") or {}).get(str(vencimiento).strip()) or {}
        # Variable local para calls.
        calls = list(datos_venc.get("calls") or [])
        # Variable local para puts.
        puts = list(datos_venc.get("puts") or [])
        # Variable local para meta.
        meta = {
            "spot": convertir_a_numero((datos_fecha or {}).get("spot")),
            "cantidad": len(calls) + len(puts),
            "fechas_disponibles": len(cache.get("fechas") or []),
        }
        return calls, puts, meta

    def _obtener_superficie_smile_cierres(
        self,
        vencimiento: str,
        filas_vivas: list[dict[str, Any]] | None = None,
        fecha_hasta: str | None = None,
    ) -> tuple[list[dict[str, Any]], list[dict[str, Any]], int]:
        """Arma series 3D del smile histórico de cierre hasta una fecha y suma el día vivo si aplica."""
        # Caché en memoria para cache.
        cache = self._obtener_cache_smile_cierres()
        # Variable local para series calls.
        series_calls: list[dict[str, Any]] = []
        # Variable local para series puts.
        series_puts: list[dict[str, Any]] = []
        # Variable local para fechas utiles.
        fechas_utiles = 0
        # Variable local para vencimiento.
        vencimiento = str(vencimiento).strip()
        # Variable local para incluir vivo.
        incluir_vivo = (not self.offline_mode) and mercado_en_horario_operativo() and bool(filas_vivas)
        # Variable local para fecha hasta txt.
        fecha_hasta_txt = str(fecha_hasta or "").strip()
        # Variable local para fecha limite.
        fecha_limite: date | None = None
        if incluir_vivo:
            try:
                fecha_limite = ahora().date()
            except Exception:
                fecha_limite = None
        elif fecha_hasta_txt and fecha_hasta_txt != "HOY (vivo)":
            try:
                fecha_limite = datetime.strptime(fecha_hasta_txt, "%Y-%m-%d").date()
            except Exception:
                fecha_limite = None
        for fecha in sorted(cache.get("fechas") or []):
            try:
                # Variable local para fecha actual.
                fecha_actual = datetime.strptime(fecha, "%Y-%m-%d").date()
            except Exception:
                continue
            if fecha_limite is not None and fecha_actual > fecha_limite:
                continue
            # Variable local para datos fecha.
            datos_fecha = (cache.get("por_fecha") or {}).get(fecha) or {}
            # Variable local para datos vencimiento.
            datos_venc = (datos_fecha.get("datos") or {}).get(vencimiento) or {}
            # Variable local para calls.
            calls = list(datos_venc.get("calls") or [])
            # Variable local para puts.
            puts = list(datos_venc.get("puts") or [])
            if not calls and not puts:
                continue
            # Variable local para timestamp fecha.
            ts_fecha = datetime(fecha_actual.year, fecha_actual.month, fecha_actual.day, 12, 0, 0, 0)
            fechas_utiles += 1
            if calls:
                series_calls.append({"fecha": ts_fecha, "label": fecha, "puntos": sorted(calls), "es_vivo": False})
            if puts:
                series_puts.append({"fecha": ts_fecha, "label": fecha, "puntos": sorted(puts), "es_vivo": False})
        if incluir_vivo and vencimiento:
            calls_vivo, puts_vivo = construir_datos_smile(filas_vivas or [], vencimiento)
            if calls_vivo or puts_vivo:
                # Variable local para timestamp vivo.
                ts_vivo = ahora().replace(tzinfo=None)
                # Variable local para label vivo.
                label_vivo = f"{ts_vivo.strftime('%Y-%m-%d')} vivo"
                if calls_vivo:
                    series_calls.append({"fecha": ts_vivo, "label": label_vivo, "puntos": sorted(calls_vivo), "es_vivo": True})
                if puts_vivo:
                    series_puts.append({"fecha": ts_vivo, "label": label_vivo, "puntos": sorted(puts_vivo), "es_vivo": True})
        return series_calls, series_puts, fechas_utiles

    def _dibujar_superficie_smile_lineas_3d(
        self,
        ax: Any,
        series: list[dict[str, Any]],
        titulo: str,
        *,
        mostrar_xlabel: bool,
    ) -> None:
        """Dibuja una línea 3D por fecha con ejes fecha, strike y VI."""
        ax.clear()
        ax.set_axis_on()
        if not series:
            ax.text2D(0.5, 0.5, f"Sin nodos suficientes para {titulo.lower()}", ha="center", va="center", transform=ax.transAxes)
            ax.set_title(titulo)
            return
        # Variable local para total.
        total = max(len(series) - 1, 1)
        # Variable local para x positions.
        x_positions: list[float] = []
        # Variable local para x labels.
        x_labels: list[str] = []
        for idx, serie in enumerate(series):
            # Variable local para puntos.
            puntos = list(serie.get("puntos") or [])
            if not puntos:
                continue
            # Fecha temporal usada en este cálculo.
            fecha = serie.get("fecha")
            try:
                # Variable local para x val.
                x_val = mdates.date2num(fecha)
            except Exception:
                continue
            # Variable local para strikes.
            strikes = [float(strike) for strike, _ in puntos]
            # Variable local para ivs.
            ivs = [float(iv) for _, iv in puntos]
            if not strikes or not ivs:
                continue
            # Variable local para es vivo.
            es_vivo = bool(serie.get("es_vivo"))
            # Variable local para color.
            color = cm.plasma(idx / total)
            # Variable local para etiqueta.
            etiqueta = str(serie.get("label") or "")
            ax.plot(
                [x_val] * len(strikes),
                strikes,
                ivs,
                color=("crimson" if es_vivo else color),
                linewidth=(2.6 if es_vivo else 1.2),
                marker="o",
                markersize=(4.2 if es_vivo else 2.0),
                alpha=(1.0 if es_vivo else 0.65),
                label=(etiqueta if es_vivo else None),
            )
            x_positions.append(x_val)
            x_labels.append(etiqueta)
        if not x_positions:
            ax.text2D(0.5, 0.5, f"Sin nodos suficientes para {titulo.lower()}", ha="center", va="center", transform=ax.transAxes)
            ax.set_title(titulo)
            return
        # Variable local para orden.
        orden = sorted(zip(x_positions, x_labels), key=lambda item: item[0])
        # Variable local para tick count.
        tick_count = min(8, len(orden))
        if tick_count <= 1:
            # Variable local para ticks.
            ticks = [orden[0][0]]
            # Variable local para labels.
            labels = [orden[0][1]]
        else:
            # Variable local para idxs.
            idxs = sorted({round(i * (len(orden) - 1) / (tick_count - 1)) for i in range(tick_count)})
            ticks = [orden[i][0] for i in idxs]
            labels = [orden[i][1] for i in idxs]
        ax.set_xticks(ticks)
        ax.set_xticklabels(labels, rotation=18, ha="right")
        ax.set_title(titulo)
        ax.set_ylabel("Strike")
        ax.set_zlabel("VI %")
        ax.set_xlabel("Fecha" if mostrar_xlabel else "")
        ax.view_init(elev=24, azim=-58)
        ax.grid(True, alpha=0.22)
        try:
            # Variable local para x min.
            x_min = min(x_positions)
            # Variable local para x max.
            x_max = max(x_positions)
            # Variable local para pad.
            pad = max((x_max - x_min) * 0.05, 0.5)
            ax.set_xlim(x_min - pad, x_max + pad)
        except Exception:
            LOGGER.debug("No se pudo ajustar el rango X de la superficie Smile", exc_info=True)
        try:
            if any(bool(serie.get("es_vivo")) for serie in series):
                ax.legend(loc="upper left")
        except Exception:
            LOGGER.debug("No se pudo dibujar la leyenda de la superficie Smile", exc_info=True)

    def _normalizar_griega_casi_cero(self, valor: Any, eps: float = 1e-8) -> float | None:
        """Normaliza griegas muy pequeñas a 0 para evitar huecos y ruido numérico."""
        numero = convertir_a_numero(valor)
        if numero is None:
            return None
        valor_f = float(numero)
        return 0.0 if abs(valor_f) <= float(max(eps, 0.0)) else valor_f

    def _combinar_griega_lineal(self, *componentes: tuple[float, Any], eps: float = 1e-8) -> float | None:
        """Combina griegas lineales tolerando faltantes parciales y colapsando casi-cero a 0.

        Si al menos una pata tiene dato válido, las patas faltantes se tratan como 0 para que la
        estrategia no quede vacía por un pequeño faltante de metadata histórica. Si todas faltan,
        devuelve None.
        """
        total = 0.0
        tiene_dato = False
        for coef, valor in componentes:
            numero = self._normalizar_griega_casi_cero(valor, eps=eps)
            if numero is None:
                continue
            total += float(coef) * float(numero)
            tiene_dato = True
        if not tiene_dato:
            return None
        return 0.0 if abs(total) <= float(max(eps, 0.0)) else total

    def _calcular_resumen_relacion(
        self,
        fecha: str,
        precio_a: Any,
        precio_b: Any,
        fuente: str,
        *,
        delta_a: Any = None,
        delta_b: Any = None,
        vega_a: Any = None,
        vega_b: Any = None,
        theta_a: Any = None,
        theta_b: Any = None,
        ratio_prev: Any = None,
        ask_a: Any = None,
        bid_b: Any = None,
        minmax_ab_dia: Any = None,
        minmax_spread_dia: Any = None,
        minmax_ratio_pos_1a2b_dia: Any = None,
        minmax_ratio_inv_1a2b_dia: Any = None,
        max_spread: Any = None,
    ) -> dict[str, Any]:
        """Calcula columnas de la tabla diaria para dos bases seleccionadas."""
        pa = convertir_a_numero(precio_a)
        pb = convertir_a_numero(precio_b)
        da = self._normalizar_griega_casi_cero(delta_a)
        db = self._normalizar_griega_casi_cero(delta_b)
        va = self._normalizar_griega_casi_cero(vega_a)
        vb = self._normalizar_griega_casi_cero(vega_b)
        ta = self._normalizar_griega_casi_cero(theta_a)
        tb = self._normalizar_griega_casi_cero(theta_b)
        ratio_ab = (float(pa) / float(pb)) if pa is not None and pb not in (None, 0) else None
        ratio_n = round(float(ratio_ab), 2) if ratio_ab is not None else None
        costo_ratio = (float(pa) - float(ratio_n) * float(pb)) if pa is not None and pb is not None and ratio_n is not None else None
        costo_bull = (float(pa) + float(pb)) if pa is not None and pb is not None else None
        aa = convertir_a_numero(ask_a)
        bb = convertir_a_numero(bid_b)
        a_menos_b_last = (float(pa) - float(pb)) if pa is not None and pb is not None else None
        a_menos_b_bidask = (float(aa) - float(bb)) if aa is not None and bb is not None else None
        a_menos_b = a_menos_b_bidask if a_menos_b_bidask is not None else a_menos_b_last
        max_spread_num = convertir_a_numero(max_spread)
        pct_llenado_spread = None
        if a_menos_b is not None and max_spread_num not in (None, 0):
            try:
                pct_llenado_spread = (abs(float(a_menos_b)) / abs(float(max_spread_num))) * 100.0
            except Exception:
                pct_llenado_spread = None
        ratio_pos_1a2b = (float(pa) - 2.0 * float(pb)) if pa is not None and pb is not None else None
        ratio_inv_1a2b = (-float(pa) + 2.0 * float(pb)) if pa is not None and pb is not None else None
        delta_bull = self._combinar_griega_lineal((1.0, da), (1.0, db))
        delta_spread = self._combinar_griega_lineal((1.0, da), (-1.0, db))
        delta_ratio_pos_1a2b = self._combinar_griega_lineal((1.0, da), (-2.0, db))
        delta_ratio_inv_1a2b = self._combinar_griega_lineal((-1.0, da), (2.0, db))
        vega_bull = self._combinar_griega_lineal((1.0, va), (1.0, vb))
        vega_spread = self._combinar_griega_lineal((1.0, va), (-1.0, vb))
        vega_ratio_pos_1a2b = self._combinar_griega_lineal((1.0, va), (-2.0, vb))
        vega_ratio_inv_1a2b = self._combinar_griega_lineal((-1.0, va), (2.0, vb))
        theta_bull = self._combinar_griega_lineal((1.0, ta), (1.0, tb))
        theta_spread = self._combinar_griega_lineal((1.0, ta), (-1.0, tb))
        theta_ratio_pos_1a2b = self._combinar_griega_lineal((1.0, ta), (-2.0, tb))
        theta_ratio_inv_1a2b = self._combinar_griega_lineal((-1.0, ta), (2.0, tb))
        return {
            "fecha": fecha,
            "precio_a": pa,
            "precio_b": pb,
            "ratio_ab": ratio_ab,
            "var_dia_ratio_ab": None,
            "rel_ratio_ab": None,
            "logdelta_ratio_ab": None,
            "logratio_ratio_ab": None,
            "ecdf_ratio_ab": None,
            "costo_bull": costo_bull,
            "var_dia_bull": None,
            "rel_bull": None,
            "rel_spread": None,
            "rel_ratio_pos_1a2b": None,
            "rel_ratio_inv_1a2b": None,
            "logdelta_bull": None,
            "ecdf_bull": None,
            "var_ratio_bull": None,
            "logratio_bull": None,
            "ecdfratio_bull": None,
            "probratio_bull": None,
            "minmax_ab_dia": minmax_ab_dia,
            "a_menos_b_last": a_menos_b_last,
            "a_menos_b_bidask": a_menos_b_bidask,
            "a_menos_b": a_menos_b,
            "pct_llenado_spread": pct_llenado_spread,
            "var_dia_spread": None,
            "logdelta_spread": None,
            "ecdf_spread": None,
            "var_ratio_spread": None,
            "logratio_spread": None,
            "ecdfratio_spread": None,
            "probratio_spread": None,
            "minmax_spread_dia": minmax_spread_dia,
            "ratio_pos_1a2b": ratio_pos_1a2b,
            "var_dia_ratio_pos_1a2b": None,
            "logdelta_ratio_pos_1a2b": None,
            "ecdf_ratio_pos_1a2b": None,
            "var_ratio_ratio_pos_1a2b": None,
            "logratio_ratio_pos_1a2b": None,
            "ecdfratio_ratio_pos_1a2b": None,
            "probratio_ratio_pos_1a2b": None,
            "minmax_ratio_pos_1a2b_dia": minmax_ratio_pos_1a2b_dia,
            "ratio_inv_1a2b": ratio_inv_1a2b,
            "var_dia_ratio_inv_1a2b": None,
            "logdelta_ratio_inv_1a2b": None,
            "ecdf_ratio_inv_1a2b": None,
            "var_ratio_ratio_inv_1a2b": None,
            "logratio_ratio_inv_1a2b": None,
            "ecdfratio_ratio_inv_1a2b": None,
            "probratio_ratio_inv_1a2b": None,
            "minmax_ratio_inv_1a2b_dia": minmax_ratio_inv_1a2b_dia,
            "delta_a": da,
            "delta_b": db,
            "delta_bull": delta_bull,
            "delta_spread": delta_spread,
            "delta_ratio_pos_1a2b": delta_ratio_pos_1a2b,
            "delta_ratio_inv_1a2b": delta_ratio_inv_1a2b,
            "vega_a": va,
            "vega_b": vb,
            "vega_bull": vega_bull,
            "vega_spread": vega_spread,
            "vega_ratio_pos_1a2b": vega_ratio_pos_1a2b,
            "vega_ratio_inv_1a2b": vega_ratio_inv_1a2b,
            "theta_bull": theta_bull,
            "theta_spread": theta_spread,
            "theta_ratio_pos_1a2b": theta_ratio_pos_1a2b,
            "theta_ratio_inv_1a2b": theta_ratio_inv_1a2b,
            "ecdf_delta_griegas": None,
            "ecdf_vega_griegas": None,
            "ecdf_theta_griegas": None,
            "ratio_n": ratio_n,
            "costo_ratio": costo_ratio,
            "fuente": fuente,
        }

    def _percentil_acumulado(self, valor: Any, historico: list[float]) -> float | None:
        """Devuelve una pseudo-probabilidad acumulada basada en percentil histórico empírico."""
        # Variable local para v.
        v = convertir_a_numero(valor)
        # Serie temporal construida en este bloque.
        serie = [float(x) for x in historico if convertir_a_numero(x) is not None]
        if v is None or not serie:
            return None
        # Variable local para menores iguales.
        menores_iguales = sum(1 for x in serie if x <= float(v))
        return menores_iguales / len(serie)

    def _retorno_relativo_con_signo_tabla_rel(self, valor_actual: Any, valor_previo: Any, epsilon: float = 1e-9) -> float | None:
        """Calcula el retorno logarítmico relativo con signo direccional.

        Usa la razón entre valores absolutos para poder trabajar también con spreads y estrategias
        que pueden acercarse a cero o cambiar de signo. El signo externo conserva la dirección del
        cambio entre la observación actual y la previa.
        """
        numero_actual = convertir_a_numero(valor_actual)
        numero_previo = convertir_a_numero(valor_previo)
        if numero_actual is None or numero_previo is None:
            return None
        actual = float(numero_actual)
        previo = float(numero_previo)
        if not math.isfinite(actual) or not math.isfinite(previo):
            return None
        if abs(previo) < epsilon and abs(actual) < epsilon:
            return 0.0
        ratio = (abs(actual) + epsilon) / (abs(previo) + epsilon)
        if ratio <= 0 or not math.isfinite(ratio):
            return None
        signo = 0.0
        if actual > previo:
            signo = 1.0
        elif actual < previo:
            signo = -1.0
        return signo * math.log(ratio)

    def _ecdf_directo_tabla_rel(self, valor: Any, historico: list[float]) -> float | None:
        """Calcula ECDF directo sobre una serie ya transformada."""
        numero = convertir_a_numero(valor)
        if numero is None:
            return None
        valor_num = float(numero)
        serie = [float(item) for item in historico if item is not None and math.isfinite(float(item))]
        if not serie:
            return None
        menores_iguales = sum(1 for item in serie if item <= valor_num)
        return menores_iguales / len(serie)

    def _log_neperiano_con_signo_tabla_rel(self, valor: Any) -> float | None:
        """Transforma un valor con log neperiano con signo para poder ordenar positivos, cero y negativos."""
        # Variable local para numero.
        numero = convertir_a_numero(valor)
        if numero is None:
            return None
        # Variable local para v.
        v = float(numero)
        if not math.isfinite(v):
            return None
        if v == 0:
            return 0.0
        return math.copysign(math.log1p(abs(v)), v)

    def _ecdf_jerarquia_tabla_rel(self, valor: Any, historico: list[float]) -> float | None:
        """Calcula ECDF como jerarquía ascendente de Excel dividida por la cantidad de filas con datos."""
        numero = convertir_a_numero(valor)
        if numero is None:
            return None
        valor_num = float(numero)
        serie = [float(item) for item in historico if item is not None and math.isfinite(float(item))]
        if not serie:
            return None
        rango = 1 + sum(1 for item in serie if item < valor_num)
        return float(rango) / float(len(serie))

    def _columnas_log_ecdf_prob_tabla_rel(self) -> tuple[str, ...]:
        """Lista centralizada de columnas obsoletas que se siguen limpiando para evitar arrastre visual."""
        return (
            "ecdfratio_bull",
            "ecdfratio_spread",
            "ecdfratio_ratio_pos_1a2b",
            "ecdfratio_ratio_inv_1a2b",
            "probratio_bull",
            "probratio_spread",
            "probratio_ratio_pos_1a2b",
            "probratio_ratio_inv_1a2b",
        )

    def _limpiar_calculos_log_ecdf_tabla_rel(self, filas: list[dict[str, Any]]) -> list[dict[str, Any]]:
        """Limpia columnas obsoletas del modo ratio sin tocar logs ni ECDF vigentes."""
        if not filas:
            return []
        columnas = self._columnas_log_ecdf_prob_tabla_rel()
        salida: list[dict[str, Any]] = []
        for fila in filas:
            actual = dict(fila)
            for columna in columnas:
                actual[columna] = None
            salida.append(actual)
        return salida

    def _enriquecer_ecdf_desde_logs_tabla_rel(self, filas: list[dict[str, Any]], slot: int = 1) -> list[dict[str, Any]]:
        """Calcula el ECDF de cada estrategia activa usando jerarquía Excel sobre los logs elegidos.

        Modo dinámica: cada fila se compara contra todo el histórico visible actual.
        Modo fija: cada fila queda valuada contra el histórico acumulado hasta esa propia fila,
        de modo que las filas anteriores no cambian cuando luego se agregan nuevas ruedas o períodos.
        """
        salida = self._limpiar_calculos_log_ecdf_tabla_rel(filas)
        if not salida:
            return []
        usar_relacional = self._modo_calculo_relativo_tabla_rel(slot)
        usar_fija = self._modo_ecdf_fijo_tabla_rel(slot)
        # En modo relacional, para evitar señales excesivas en estrategias que cruzan por cero,
        # el ECDF se calcula sobre el valor actual de la estrategia respecto de su propio histórico
        # visible, en lugar de usar el cambio relacional entre filas. En modo directo se conserva la
        # lógica anterior basada en el log de la diferencia.
        mapa_fuentes = {
            "ecdf_ratio_ab": "ratio_ab" if usar_relacional else "logdelta_ratio_ab",
            "ecdf_bull": "costo_bull" if usar_relacional else "logdelta_bull",
            "ecdf_spread": "a_menos_b_last" if usar_relacional else "logdelta_spread",
            "ecdf_ratio_pos_1a2b": "ratio_pos_1a2b" if usar_relacional else "logdelta_ratio_pos_1a2b",
            "ecdf_ratio_inv_1a2b": "ratio_inv_1a2b" if usar_relacional else "logdelta_ratio_inv_1a2b",
        }
        for columna_ecdf, columna_fuente in mapa_fuentes.items():
            historico_total: list[float] = []
            for fila in salida:
                numero = convertir_a_numero(fila.get(columna_fuente))
                if numero is None:
                    continue
                valor_num = float(numero)
                if math.isfinite(valor_num):
                    historico_total.append(valor_num)
            if not usar_fija:
                for fila in salida:
                    fila[columna_ecdf] = self._ecdf_jerarquia_tabla_rel(fila.get(columna_fuente), historico_total)
                continue
            historico_acumulado: list[float] = []
            for fila in salida:
                numero = convertir_a_numero(fila.get(columna_fuente))
                if numero is None:
                    fila[columna_ecdf] = None
                    continue
                valor_num = float(numero)
                if not math.isfinite(valor_num):
                    fila[columna_ecdf] = None
                    continue
                historico_acumulado.append(valor_num)
                fila[columna_ecdf] = self._ecdf_jerarquia_tabla_rel(valor_num, historico_acumulado)
        return salida

    def _enriquecer_probabilidades_tabla_rel(self, filas: list[dict[str, Any]], slot: int = 1) -> list[dict[str, Any]]:
        """Calcula los ECDF de la tabla diaria usando la fuente definida por el botón Calcula."""
        return self._enriquecer_ecdf_desde_logs_tabla_rel(filas, slot)

    def _enriquecer_variaciones_tabla_rel(self, filas: list[dict[str, Any]], slot: int = 1, modo: str = "diaria") -> list[dict[str, Any]]:
        """Agrega variaciones absolutas y relativas contra el dato anterior para cada estrategia.

        Además calcula internamente los logs fuente y los ECDF visibles de delta,
        vega y theta por estrategia (A+B, A-B, +A-2B y -A+2B), usando un modo de
        cálculo propio por estrategia que se define desde el menú contextual.
        """
        if not filas:
            return []
        salida = [dict(fila) for fila in filas]
        series = {
            "ratio_ab": _np_float_array(fila.get("ratio_ab") for fila in filas),
            "bull": _np_float_array(fila.get("costo_bull") for fila in filas),
            "spread": _np_float_array(fila.get("a_menos_b_last") for fila in filas),
            "ratio_pos": _np_float_array(fila.get("ratio_pos_1a2b") for fila in filas),
            "ratio_inv": _np_float_array(fila.get("ratio_inv_1a2b") for fila in filas),
        }
        mostrar_ab = bool(self._tabla_rel_show_ab_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_spread = bool(self._tabla_rel_show_spread_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_ratio_pos = bool(self._tabla_rel_show_ratio_pos_vars.get(slot, BooleanVar(value=True)).get())
        mostrar_ratio_neg = bool(self._tabla_rel_show_ratio_neg_vars.get(slot, BooleanVar(value=True)).get())
        modo_n = self._normalizar_modo_tabla_rel(modo)
        self._asegurar_estado_ecdf_griegas_estrategia_tabla_rel()

        strategy_series = {
            "bull": {
                "delta": _np_float_array(fila.get("delta_bull") for fila in filas),
                "vega": _np_float_array(fila.get("vega_bull") for fila in filas),
                "theta": _np_float_array(fila.get("theta_bull") for fila in filas),
            },
            "spread": {
                "delta": _np_float_array(fila.get("delta_spread") for fila in filas),
                "vega": _np_float_array(fila.get("vega_spread") for fila in filas),
                "theta": _np_float_array(fila.get("theta_spread") for fila in filas),
            },
            "ratio_pos": {
                "delta": _np_float_array(fila.get("delta_ratio_pos_1a2b") for fila in filas),
                "vega": _np_float_array(fila.get("vega_ratio_pos_1a2b") for fila in filas),
                "theta": _np_float_array(fila.get("theta_ratio_pos_1a2b") for fila in filas),
            },
            "ratio_neg": {
                "delta": _np_float_array(fila.get("delta_ratio_inv_1a2b") for fila in filas),
                "vega": _np_float_array(fila.get("vega_ratio_inv_1a2b") for fila in filas),
                "theta": _np_float_array(fila.get("theta_ratio_inv_1a2b") for fila in filas),
            },
        }
        diff_ratio_ab = _np_variacion_absoluta_ffill(series["ratio_ab"])
        diff_bull = _np_variacion_absoluta_ffill(series["bull"])
        diff_spread = _np_variacion_absoluta_ffill(series["spread"])
        diff_ratio_pos = _np_variacion_absoluta_ffill(series["ratio_pos"])
        diff_ratio_inv = _np_variacion_absoluta_ffill(series["ratio_inv"])
        rel_ratio_ab = _np_relacion_ffill(series["ratio_ab"])
        rel_bull = _np_relacion_ffill(series["bull"])
        rel_spread = _np_relacion_ffill(series["spread"])
        rel_ratio_pos = _np_relacion_ffill(series["ratio_pos"])
        rel_ratio_inv = _np_relacion_ffill(series["ratio_inv"])
        usar_fija = self._modo_ecdf_fijo_tabla_rel(slot)

        def _ecdf_por_array(arr_fuente: np.ndarray) -> np.ndarray:
            out = np.full(len(filas), np.nan, dtype=float)
            hist = [float(v) for v in np.asarray(arr_fuente, dtype=float) if np.isfinite(v)]
            if not usar_fija:
                for i, valor in enumerate(np.asarray(arr_fuente, dtype=float)):
                    if np.isfinite(valor) and hist:
                        res = self._ecdf_jerarquia_tabla_rel(float(valor), hist)
                        out[i] = float(res) if res is not None else np.nan
                return out
            hist_acum: list[float] = []
            for i, valor in enumerate(np.asarray(arr_fuente, dtype=float)):
                if not np.isfinite(valor):
                    continue
                hist_acum.append(float(valor))
                res = self._ecdf_jerarquia_tabla_rel(float(valor), hist_acum)
                out[i] = float(res) if res is not None else np.nan
            return out

        ecdf_griegas_por_estrategia: dict[str, np.ndarray] = {}
        for strategy_key, columnas_ecdf in (("bull", self._tabla_rel_ecdf_griegas_strategy_columns("bull")), ("spread", self._tabla_rel_ecdf_griegas_strategy_columns("spread")), ("ratio_pos", self._tabla_rel_ecdf_griegas_strategy_columns("ratio_pos")), ("ratio_neg", self._tabla_rel_ecdf_griegas_strategy_columns("ratio_neg"))):
            modo_calc_ecdf = self._modo_ecdf_griegas_estrategia_tabla_rel(slot, modo_n, strategy_key)
            usar_relacional_greeks = modo_calc_ecdf == "relacional"
            for greek_name, col_dest in zip(("delta", "vega", "theta"), columnas_ecdf):
                serie = strategy_series[strategy_key][greek_name]
                diff = _np_variacion_absoluta_ffill(serie)
                rel = _np_relacion_ffill(serie)
                fuente = _np_log_relacion_estable_ffill(serie) if usar_relacional_greeks else _np_signed_log1p(diff)
                ecdf_griegas_por_estrategia[col_dest] = _ecdf_por_array(fuente)

        calculadas = {
            "var_dia_ratio_ab": diff_ratio_ab,
            "var_dia_bull": diff_bull,
            "var_dia_spread": diff_spread,
            "var_dia_ratio_pos_1a2b": diff_ratio_pos,
            "var_dia_ratio_inv_1a2b": diff_ratio_inv,
            "rel_ratio_ab": rel_ratio_ab,
            "rel_bull": rel_bull,
            "rel_spread": rel_spread,
            "rel_ratio_pos_1a2b": rel_ratio_pos,
            "rel_ratio_inv_1a2b": rel_ratio_inv,
            "logdelta_ratio_ab": _np_signed_log1p(diff_ratio_ab),
            "logdelta_bull": _np_signed_log1p(diff_bull),
            "logdelta_spread": _np_signed_log1p(diff_spread),
            "logdelta_ratio_pos_1a2b": _np_signed_log1p(diff_ratio_pos),
            "logdelta_ratio_inv_1a2b": _np_signed_log1p(diff_ratio_inv),
            "logratio_ratio_ab": _np_log_relacion_positiva(rel_ratio_ab),
            "logratio_bull": _np_log_relacion_positiva(rel_bull),
            "logratio_spread": _np_log_relacion_estable_ffill(series["spread"]),
            "logratio_ratio_pos_1a2b": _np_log_relacion_estable_ffill(series["ratio_pos"]),
            "logratio_ratio_inv_1a2b": _np_log_relacion_estable_ffill(series["ratio_inv"]),
            "var_ratio_bull": _np_variacion_relativa_ffill(series["bull"]),
            "var_ratio_spread": _np_variacion_relativa_ffill(series["spread"]),
            "var_ratio_ratio_pos_1a2b": _np_variacion_relativa_ffill(series["ratio_pos"]),
            "var_ratio_ratio_inv_1a2b": _np_variacion_relativa_ffill(series["ratio_inv"]),
        }
        calculadas.update(ecdf_griegas_por_estrategia)
        for idx, actual in enumerate(salida):
            for clave, arr in calculadas.items():
                valor = arr[idx]
                actual[clave] = float(valor) if np.isfinite(valor) else None
        return salida

    def _enriquecer_ln_ecdf_intradia_tabla_rel(self, filas: list[dict[str, Any]], slot: int = 1) -> list[dict[str, Any]]:
        """Calcula los ECDF intradía usando la misma lógica de jerarquía Excel por período visible."""
        return self._enriquecer_ecdf_desde_logs_tabla_rel(filas, slot)

    def _formatear_valor_tabla_rel(self, columna: str, valor: Any, slot: int | None = None, modo: str | None = None) -> str:
        """Formatea la tabla de relaciones entre bases y agrega marcadores ECDF por celda."""
        if valor is None:
            return ""
        if columna in {"fecha", "fuente", "minmax_ab_dia", "minmax_spread_dia", "minmax_ratio_pos_1a2b_dia", "minmax_ratio_inv_1a2b_dia"}:
            texto = str(valor)
        elif columna in {"pct_llenado_spread"}:
            try:
                texto = f"{float(valor):.2f}%"
            except Exception:
                texto = str(valor)
        elif columna in {"var_dia_ratio_ab", "rel_ratio_ab", "rel_bull", "rel_spread", "rel_ratio_pos_1a2b", "rel_ratio_inv_1a2b"}:
            try:
                texto = f"{float(valor):.4f}"
            except Exception:
                texto = str(valor)
        elif columna in {"logdelta_ratio_ab", "logdelta_bull", "logdelta_spread", "logdelta_ratio_pos_1a2b", "logdelta_ratio_inv_1a2b",
                       "logratio_ratio_ab", "logratio_bull", "logratio_spread", "logratio_ratio_pos_1a2b", "logratio_ratio_inv_1a2b"}:
            try:
                texto = f"{float(valor):.4f}"
            except Exception:
                texto = str(valor)
        elif columna in {"ecdf_ratio_ab", "ecdf_bull", "ecdf_spread", "ecdf_ratio_pos_1a2b", "ecdf_ratio_inv_1a2b", "ecdf_delta_bull", "ecdf_vega_bull", "ecdf_theta_bull", "ecdf_delta_spread", "ecdf_vega_spread", "ecdf_theta_spread", "ecdf_delta_ratio_pos_1a2b", "ecdf_vega_ratio_pos_1a2b", "ecdf_theta_ratio_pos_1a2b", "ecdf_delta_ratio_inv_1a2b", "ecdf_vega_ratio_inv_1a2b", "ecdf_theta_ratio_inv_1a2b", "ecdf_delta_griegas", "ecdf_vega_griegas", "ecdf_theta_griegas",
                       "ecdfratio_bull", "ecdfratio_spread", "ecdfratio_ratio_pos_1a2b", "ecdfratio_ratio_inv_1a2b",
                       "probratio_bull", "probratio_spread", "probratio_ratio_pos_1a2b", "probratio_ratio_inv_1a2b",
                       "var_ratio_bull", "var_ratio_spread", "var_ratio_ratio_pos_1a2b", "var_ratio_ratio_inv_1a2b",
                       "ecdf_delta_griegas", "ecdf_vega_griegas", "ecdf_theta_griegas"}:
            try:
                texto = f"{float(valor) * 100:.2f}%"
            except Exception:
                texto = str(valor)
        elif columna in {
            "delta_a", "delta_b", "delta_bull", "delta_spread", "delta_ratio_pos_1a2b", "delta_ratio_inv_1a2b",
            "vega_a", "vega_b", "vega_bull", "vega_spread", "vega_ratio_pos_1a2b", "vega_ratio_inv_1a2b",
            "theta_bull", "theta_spread", "theta_ratio_pos_1a2b", "theta_ratio_inv_1a2b",
        }:
            try:
                texto = f"{float(valor):.4f}"
            except Exception:
                texto = str(valor)
        else:
            try:
                texto = f"{float(valor):.2f}"
            except Exception:
                texto = str(valor)
        prefijo = self._prefijo_ecdf_celda_tabla_rel(columna, valor, slot, modo)
        return f"{prefijo}{texto}" if prefijo else texto

    def _filas_base_tabla_rel(self, filas: list[dict[str, Any]]) -> list[dict[str, Any]]:
        """Devuelve solo las filas reales de la tabla, excluyendo resúmenes agregados al final."""
        fuentes_resumen = {"promedio", "ema", "prob_positiva"}
        return [
            dict(fila)
            for fila in filas
            if str(fila.get("fuente") or "").lower() not in fuentes_resumen
        ]

    def _fila_promedio_tabla_rel(self, filas: list[dict[str, Any]]) -> dict[str, Any] | None:
        """Construye una fila resumen con el promedio de todas las columnas numéricas disponibles."""
        # Variable local para filas base.
        filas_base = self._filas_base_tabla_rel(filas)
        if not filas_base:
            return None
        # Variable local para promedio.
        promedio: dict[str, Any] = {"fecha": "PROMEDIO", "fuente": "promedio"}
        # Variable local para columnas excluir.
        columnas_excluir = {"fecha", "fuente"}
        for columna in self.TABLA_REL_COLUMNAS:
            if columna in columnas_excluir:
                continue
            # Colección temporal de valores usada en este cálculo.
            valores: list[float] = []
            for fila in filas_base:
                # Número temporal calculado en este bloque.
                numero = convertir_a_numero(fila.get(columna))
                if numero is not None:
                    valores.append(float(numero))
            promedio[columna] = (sum(valores) / len(valores)) if valores else None
        return promedio

    def _fila_ema_tabla_rel(self, filas: list[dict[str, Any]]) -> dict[str, Any] | None:
        """Calcula una media exponencial simple sobre las filas visibles, privilegiando lo reciente."""
        # Variable local para filas base.
        filas_base = self._filas_base_tabla_rel(filas)
        if not filas_base:
            return None
        # Variable local para ema.
        ema: dict[str, Any] = {"fecha": "MEDIA EXP", "fuente": "ema"}
        # Variable local para columnas excluir.
        columnas_excluir = {"fecha", "fuente"}
        for columna in self.TABLA_REL_COLUMNAS:
            if columna in columnas_excluir:
                continue
            # Colección temporal de valores usada en este cálculo.
            valores: list[float] = []
            for fila in filas_base:
                # Número temporal calculado en este bloque.
                numero = convertir_a_numero(fila.get(columna))
                if numero is not None:
                    valores.append(float(numero))
            if not valores:
                ema[columna] = None
                continue
            if len(valores) == 1:
                ema[columna] = valores[0]
                continue
            # Variable local para alpha.
            alpha = 2.0 / (len(valores) + 1.0)
            # Variable local para valor ema.
            valor_ema = valores[0]
            for valor in valores[1:]:
                valor_ema = alpha * valor + (1.0 - alpha) * valor_ema
            ema[columna] = valor_ema
        return ema

    def _fila_zscore_tabla_rel(self, filas: list[dict[str, Any]]) -> dict[str, Any] | None:
        """Calcula el z-score del último dato disponible contra la historia previa de cada columna."""
        # Variable local para filas base.
        filas_base = self._filas_base_tabla_rel(filas)
        if not filas_base:
            return None
        # Registro temporal o último valor usado para ultima.
        ultima = dict(filas_base[-1])
        # Variable local para zscore.
        zscore: dict[str, Any] = {"fecha": "Z-SCORE", "fuente": "zscore"}
        # Variable local para columnas excluir.
        columnas_excluir = {"fecha", "fuente"}
        for columna in self.TABLA_REL_COLUMNAS:
            if columna in columnas_excluir:
                continue
            # Variable local para objetivo.
            objetivo = convertir_a_numero(ultima.get(columna))
            if objetivo is None:
                zscore[columna] = None
                continue
            # Variable local para historico.
            historico: list[float] = []
            for fila in filas_base[:-1]:
                # Número temporal calculado en este bloque.
                numero = convertir_a_numero(fila.get(columna))
                if numero is not None:
                    historico.append(float(numero))
            if len(historico) < 2:
                zscore[columna] = None
                continue
            # Variable local para media.
            media = sum(historico) / len(historico)
            # Variable local para varianza.
            varianza = sum((valor - media) ** 2 for valor in historico) / len(historico)
            # Variable local para desvio.
            desvio = math.sqrt(varianza)
            if desvio <= 0:
                zscore[columna] = None
                continue
            zscore[columna] = (float(objetivo) - media) / desvio
        return zscore

    def _fila_prob_positiva_tabla_rel(self, filas: list[dict[str, Any]]) -> dict[str, Any] | None:
        """Construye una fila final con el porcentaje histórico de variaciones positivas de cada estrategia."""
        filas_base = self._filas_base_tabla_rel(filas)
        filas_historicas = [
            dict(fila)
            for fila in filas_base
            if str(fila.get("fuente") or "").strip().lower() == "cierre"
        ]
        if not filas_historicas:
            return None
        columnas_objetivo = (
            "var_dia_bull",
            "var_dia_spread",
            "var_dia_ratio_pos_1a2b",
            "var_dia_ratio_inv_1a2b",
        )
        salida = {"fecha": "% POSITIVO HIST.", "fuente": "prob_positiva"}
        hay_datos = False
        for columna in columnas_objetivo:
            valores = [
                float(convertir_a_numero(fila.get(columna)))
                for fila in filas_historicas
                if convertir_a_numero(fila.get(columna)) is not None
            ]
            if valores:
                hay_datos = True
                salida[columna] = f"{(sum(1 for valor in valores if valor > 0) / len(valores)) * 100.0:.2f}%"
        return salida if hay_datos else None

    def _tags_base_tabla_rel(self, idx: int, fila: dict[str, Any], modo: str) -> tuple[str, ...]:
        """Devuelve los tags base de la fila antes de sumar el formato condicional ECDF."""
        if str(modo).strip().lower() == "intradia":
            fuente = str(fila.get("fuente") or "").lower()
            if fuente.startswith("vivo"):
                return ("live_par",) if idx % 2 == 0 else ("live_impar",)
            return ("cambio",) if fuente == "cambio" else (("par",) if idx % 2 == 0 else ("impar",))
        fuente = str(fila.get("fuente") or "").lower()
        if fuente in {"promedio", "ema", "prob_positiva"}:
            return ("resumen_final",)
        if fuente.startswith("vivo"):
            return ("live_par",) if idx % 2 == 0 else ("live_impar",)
        return ("par",) if idx % 2 == 0 else ("impar",)

    def _tags_visuales_tabla_rel(self, idx: int, fila: dict[str, Any], slot: int, modo: str) -> tuple[str, ...]:
        """Devuelve solo los tags base de la fila.

        El formato condicional ECDF se aplica ahora por celda dentro del texto y no
        mediante fondo de fila, para permitir que cada columna ECDF se marque de
        forma individual dentro del Treeview actual.
        """
        return tuple(self._tags_base_tabla_rel(idx, fila, modo) or ())

    def _cargar_tree_tabla_rel_en(self, tree, filas: list[dict[str, Any]], slot: int) -> None:
        """Carga la tabla diaria de relaciones en el árbol indicado respetando selección y formato ECDF."""
        self._persistir_seleccion_filas_tabla_rel(tree, slot, "diaria")
        if isinstance(tree, SheetTableAdapter):
            registros = self._construir_registros_tabla_rel_cache(filas, slot, 'diaria')
            tree.set_context(self, slot, 'diaria')
            tree.load_rows(registros)
        else:
            tree.delete(*tree.get_children())
            for idx, fila in enumerate(filas):
                valores = [self._formatear_valor_tabla_rel(col, fila.get(col), slot=slot, modo="diaria") for col in self.TABLA_REL_COLUMNAS]
                tags = self._tags_visuales_tabla_rel(idx, fila, slot, "diaria")
                tree.insert("", END, iid=f"tabla_rel_{idx}", values=valores, tags=tuple(tags))
        self._reaplicar_orden_tree(tree)
        self._reaplicar_seleccion_filas_tabla_rel(tree, filas, slot, "diaria")

    def _cargar_tree_tabla_rel(self, filas: list[dict[str, Any]]) -> None:
        """Carga la tabla diaria de cierres, costo bull y costo ratio."""
        slot = self._tab_tabla_rel_activa_indice()
        self._cargar_tree_tabla_rel_en(self.tree_tabla_rel, filas, slot)

    def _refrescar_tabla_relaciones(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]], info: dict[str, Any]) -> None:
        """Muestra cierres diarios de dos bases y una última fila con el último precio vivo."""
        # Variable local para opciones.
        opciones = self._listar_bases_disponibles_vencimiento(filas_calls, filas_puts)
        self._sincronizar_aliases_tabla_rel_activos()
        # Variable local para slot.
        slot = self._tab_tabla_rel_activa_indice()
        # Variable local para ticker A.
        ticker_a = self.var_tabla_rel_a.get().strip()
        # Variable local para ticker B.
        ticker_b = self.var_tabla_rel_b.get().strip()
        if ticker_a not in opciones or ticker_b not in opciones or not ticker_a or not ticker_b:
            self.tree_tabla_rel.delete(*self.tree_tabla_rel.get_children())
            self._tabla_rel_last_rows[slot] = []
            self._refrescar_popup_grafico_tabla_rel(slot)
            self.var_tabla_rel_info.set(
                "Tabla relaciones: elegí dos bases activas del vencimiento para ver cierres diarios, ratio A/B, A + B con last, Δ A+B, A - B last siempre visible, % llenado configurable por botón, además de su Maxi-Min diario, -A+2B (RI), Δ A-B, Δ -A+2B, tres columnas Ln% Δ y tres columnas ECDF calculadas sobre los cambios Δ A-B, Δ -A+2B y Δ A+B. Podés arrastrar los encabezados para reordenar columnas. Con Ctrl+clic podés marcar una o más columnas y con clic derecho graficarlas en una ventana emergente."
            )
            return
        # Variable local para filas hist.
        filas_hist = self._history_db.obtener_tabla_cierres_par(ticker_a, ticker_b, 90)
        # Refuerzo: si SQLite quedó incompleto para alguna rueda reciente, complementar desde cierres JSON oficiales.
        filas_hist_json = self._obtener_tabla_cierres_par_desde_json(ticker_a, ticker_b, 90)
        if filas_hist_json:
            por_fecha_hist: dict[str, dict[str, Any]] = {
                str(fila.get("fecha") or ""): dict(fila)
                for fila in filas_hist
                if str(fila.get("fecha") or "").strip()
            }
            for fila_json in filas_hist_json:
                fecha_json = str(fila_json.get("fecha") or "").strip()
                if not fecha_json:
                    continue
                por_fecha_hist.setdefault(fecha_json, dict(fila_json))
            filas_hist = [por_fecha_hist[fecha] for fecha in sorted(por_fecha_hist.keys())][-90:]
        # Variable local para rangos historicos.
        rangos_historicos = self._obtener_rangos_cache_comparador(ticker_a, ticker_b)
        # Variable local para mapa rango ab dia.
        mapa_rango_ab_dia: dict[str, str] = {}
        # Variable local para mapa rango spread dia.
        mapa_rango_spread_dia: dict[str, str] = {}
        # Variable local para mapa rango ratio inv 1a2b dia.
        mapa_rango_ratio_pos_1a2b_dia: dict[str, str] = {}
        mapa_rango_ratio_inv_1a2b_dia: dict[str, str] = {}
        for ts_rango, valor_min, valor_max in list(rangos_historicos.get("last_total") or []):
            try:
                # Variable local para fecha rango.
                fecha_rango = ts_rango.strftime("%Y-%m-%d")
            except Exception:
                continue
            mapa_rango_ab_dia[fecha_rango] = self._formatear_rango_tabla_rel_ab(valor_max, valor_min)
        for ts_rango, valor_min, valor_max in list(rangos_historicos.get("last_spread") or []):
            try:
                fecha_rango = ts_rango.strftime("%Y-%m-%d")
            except Exception:
                continue
            mapa_rango_spread_dia[fecha_rango] = self._formatear_rango_tabla_rel_ab(valor_max, valor_min)
        for ts_rango, valor_min, valor_max in list(rangos_historicos.get("last_ratio_inv_1a2b") or []):
            try:
                fecha_rango = ts_rango.strftime("%Y-%m-%d")
            except Exception:
                continue
            mapa_rango_ratio_inv_1a2b_dia[fecha_rango] = self._formatear_rango_tabla_rel_ab(valor_max, valor_min)
            mapa_rango_ratio_pos_1a2b_dia[fecha_rango] = self._formatear_rango_tabla_rel_ab(-float(valor_min), -float(valor_max))
        # Variable local para max spread tabla relaciones.
        max_spread_tabla_rel = self._maximo_cobro_registro_spread(ticker_a, ticker_b)
        # Variable local para salida.
        salida = [
            self._calcular_resumen_relacion(
                str(fila.get("fecha") or ""),
                fila.get("precio_a"),
                fila.get("precio_b"),
                "cierre",
                delta_a=fila.get("delta_a"),
                delta_b=fila.get("delta_b"),
                vega_a=fila.get("vega_a"),
                vega_b=fila.get("vega_b"),
                theta_a=fila.get("theta_a"),
                theta_b=fila.get("theta_b"),
                minmax_ab_dia=mapa_rango_ab_dia.get(str(fila.get("fecha") or ""), ""),
                minmax_spread_dia=mapa_rango_spread_dia.get(str(fila.get("fecha") or ""), ""),
                minmax_ratio_pos_1a2b_dia=mapa_rango_ratio_pos_1a2b_dia.get(str(fila.get("fecha") or ""), ""),
                minmax_ratio_inv_1a2b_dia=mapa_rango_ratio_inv_1a2b_dia.get(str(fila.get("fecha") or ""), ""),
                max_spread=max_spread_tabla_rel,
            )
            for fila in filas_hist
        ]
        # Variable local para mapa actual.
        mapa_actual = {str(fila.get("ticker") or ""): fila for fila in list(filas_calls) + list(filas_puts)}
        # Variable local para fila A.
        fila_a = dict(mapa_actual.get(ticker_a, {}) or {})
        # Variable local para fila B.
        fila_b = dict(mapa_actual.get(ticker_b, {}) or {})
        # Variable local para fallback valor A.
        fallback_valor_a = self._history_db.obtener_ultimo_valor_ticker(ticker_a) if ticker_a else None
        # Variable local para fallback valor B.
        fallback_valor_b = self._history_db.obtener_ultimo_valor_ticker(ticker_b) if ticker_b else None
        # Variable local para last A.
        last_a = convertir_a_numero(fila_a.get("last"))
        # Variable local para last B.
        last_b = convertir_a_numero(fila_b.get("last"))
        # Variable local para usando fallback last.
        usando_fallback_last = False
        if last_a is None and fallback_valor_a is not None:
            last_a = convertir_a_numero(fallback_valor_a.get("last"))
            usando_fallback_last = last_a is not None or usando_fallback_last
        if last_b is None and fallback_valor_b is not None:
            last_b = convertir_a_numero(fallback_valor_b.get("last"))
            usando_fallback_last = last_b is not None or usando_fallback_last
        # Variable local para delta A ahora.
        delta_a_ahora = fila_a.get("delta") if convertir_a_numero(fila_a.get("delta")) is not None else ((fallback_valor_a or {}).get("delta"))
        # Variable local para delta B ahora.
        delta_b_ahora = fila_b.get("delta") if convertir_a_numero(fila_b.get("delta")) is not None else ((fallback_valor_b or {}).get("delta"))
        # Variable local para vega A ahora.
        vega_a_ahora = fila_a.get("vega") if convertir_a_numero(fila_a.get("vega")) is not None else ((fallback_valor_a or {}).get("vega"))
        # Variable local para vega B ahora.
        vega_b_ahora = fila_b.get("vega") if convertir_a_numero(fila_b.get("vega")) is not None else ((fallback_valor_b or {}).get("vega"))
        # Variable local para theta A ahora.
        theta_a_ahora = fila_a.get("theta") if convertir_a_numero(fila_a.get("theta")) is not None else ((fallback_valor_a or {}).get("theta"))
        # Variable local para theta B ahora.
        theta_b_ahora = fila_b.get("theta") if convertir_a_numero(fila_b.get("theta")) is not None else ((fallback_valor_b or {}).get("theta"))
        # Variable local para ask A ahora.
        ask_a_ahora = fila_a.get("ask") if convertir_a_numero(fila_a.get("ask")) is not None else last_a
        # Variable local para bid B ahora.
        bid_b_ahora = fila_b.get("bid") if convertir_a_numero(fila_b.get("bid")) is not None else last_b
        # Variable local para texto rango vivo ab.
        texto_rango_vivo_ab = ""
        # Variable local para texto rango vivo spread.
        texto_rango_vivo_spread = ""
        # Variable local para texto rango vivo ratio inv 1a2b.
        texto_rango_vivo_ratio_pos_1a2b = ""
        texto_rango_vivo_ratio_inv_1a2b = ""
        if mercado_en_horario_operativo() and last_a is not None and last_b is not None:
            # Variable local para fecha hoy.
            fecha_hoy = ahora().strftime("%Y-%m-%d")
            # Mientras la rueda está abierta, si la tabla diaria ya tiene una fila del día actual
            # la ocultamos y dejamos solo la fila AHORA para evitar duplicados visuales.
            salida = [
                dict(fila_existente)
                for fila_existente in salida
                if not (
                    str(fila_existente.get("fecha") or "").strip() == fecha_hoy
                    and str(fila_existente.get("fuente") or "").strip().lower() == "cierre"
                )
            ]
            if not usando_fallback_last:
                # Variable local para last evento texto.
                last_evento_texto = str(info.get("last_event_at") or ahora_texto())
                try:
                    # Variable local para timestamp live.
                    ts_live = datetime.strptime(last_evento_texto, "%Y-%m-%d %H:%M:%S")
                except Exception:
                    ts_live = ahora().replace(tzinfo=None)
                max_ab_dia, min_ab_dia = self._extremos_intradia_tabla_rel_estrategia(
                    fecha_hoy, ticker_a, ticker_b, estrategia="ab", last_a_live=float(last_a), last_b_live=float(last_b), ts_live=ts_live
                )
                max_spread_dia, min_spread_dia = self._extremos_intradia_tabla_rel_estrategia(
                    fecha_hoy, ticker_a, ticker_b, estrategia="spread", last_a_live=float(last_a), last_b_live=float(last_b), ts_live=ts_live
                )
                max_ratio_pos_1a2b_dia, min_ratio_pos_1a2b_dia = self._extremos_intradia_tabla_rel_estrategia(
                    fecha_hoy, ticker_a, ticker_b, estrategia="ratio_pos_1a2b", last_a_live=float(last_a), last_b_live=float(last_b), ts_live=ts_live
                )
                max_ratio_inv_1a2b_dia, min_ratio_inv_1a2b_dia = self._extremos_intradia_tabla_rel_estrategia(
                    fecha_hoy, ticker_a, ticker_b, estrategia="ratio_inv_1a2b", last_a_live=float(last_a), last_b_live=float(last_b), ts_live=ts_live
                )
                texto_rango_vivo_ab = self._formatear_rango_tabla_rel_ab(max_ab_dia, min_ab_dia)
                texto_rango_vivo_spread = self._formatear_rango_tabla_rel_ab(max_spread_dia, min_spread_dia)
                texto_rango_vivo_ratio_pos_1a2b = self._formatear_rango_tabla_rel_ab(max_ratio_pos_1a2b_dia, min_ratio_pos_1a2b_dia)
                texto_rango_vivo_ratio_inv_1a2b = self._formatear_rango_tabla_rel_ab(max_ratio_inv_1a2b_dia, min_ratio_inv_1a2b_dia)
            # Variable local para fuente ahora.
            fuente_ahora = "últ. last" if usando_fallback_last else "vivo"
            salida.append(
                self._calcular_resumen_relacion(
                    "AHORA",
                    last_a,
                    last_b,
                    fuente_ahora,
                    delta_a=delta_a_ahora,
                    delta_b=delta_b_ahora,
                    vega_a=vega_a_ahora,
                    vega_b=vega_b_ahora,
                    theta_a=theta_a_ahora,
                    theta_b=theta_b_ahora,
                    ask_a=ask_a_ahora,
                    bid_b=bid_b_ahora,
                    minmax_ab_dia=texto_rango_vivo_ab,
                    minmax_spread_dia=texto_rango_vivo_spread,
                    minmax_ratio_pos_1a2b_dia=texto_rango_vivo_ratio_pos_1a2b,
                    minmax_ratio_inv_1a2b_dia=texto_rango_vivo_ratio_inv_1a2b,
                    max_spread=max_spread_tabla_rel,
                )
            )
        salida = self._enriquecer_variaciones_tabla_rel(salida, slot, modo="diaria")
        salida = self._enriquecer_probabilidades_tabla_rel(salida, slot)
        # Variable local para fila promedio.
        fila_promedio = self._fila_promedio_tabla_rel(salida)
        if fila_promedio is not None:
            salida.append(fila_promedio)
        # Variable local para fila ema.
        fila_ema = self._fila_ema_tabla_rel(salida)
        if fila_ema is not None:
            salida.append(fila_ema)
        # Variable local para fila probabilidad positiva.
        fila_prob_positiva = self._fila_prob_positiva_tabla_rel(salida)
        if fila_prob_positiva is not None:
            salida.append(fila_prob_positiva)
        self._tabla_rel_last_rows[slot] = [dict(f) for f in salida]
        self._cargar_tree_tabla_rel(salida)
        self._refrescar_popup_grafico_tabla_rel(slot)
        self.var_tabla_rel_info.set(
            f"Tabla relaciones: {ticker_a} / {ticker_b} | filas históricas={len(filas_hist)} | A + B usa last de ambas bases, Δ A+B compara contra la rueda anterior y la columna Min Max A+B muestra el rango intradía (max - min) de esa estrategia | A - B last muestra last A menos last B y el % de llenado del spread puede mostrarse u ocultarse con su botón; si todavía no llegaron datos al iniciar, la fila AHORA completa los last con el último valor guardado | incluye A/B, A+B, A-B, +A-2B y -A+2B con sus columnas de diferencias, relaciones, logs y ECDF calculados por jerarquía Excel según el modo Directo o Relacional | filas finales: promedio, media exponencial y % histórico de variaciones positivas | arrastrá encabezados para reordenar columnas. Con Ctrl+clic marcá una o más columnas y con clic derecho las podés graficar en una ventana aparte."
        )
    def _percentil_simple(self, valores: list[float], q: float) -> float | None:
        """Calcula un percentil simple por interpolación lineal."""
        # Variable local para nums.
        nums = sorted(float(v) for v in (valores or []) if convertir_a_numero(v) is not None and math.isfinite(float(v)))
        if not nums:
            return None
        if len(nums) == 1:
            return float(nums[0])
        # Variable local para q.
        q = min(max(float(q), 0.0), 1.0)
        # Variable local para pos.
        pos = q * (len(nums) - 1)
        # Variable local para lo.
        lo = int(math.floor(pos))
        # Variable local para hi.
        hi = int(math.ceil(pos))
        if lo == hi:
            return float(nums[lo])
        # Variable local para frac.
        frac = pos - lo
        return float(nums[lo] * (1.0 - frac) + nums[hi] * frac)

    def _aplicar_escala_y_abierta(self, ax: Any, valores: list[float]) -> None:
        """Abre la escala Y ignorando outliers extremos que aplastan la serie principal."""
        # Variable local para nums.
        nums = [float(v) for v in (valores or []) if convertir_a_numero(v) is not None and math.isfinite(float(v))]
        if len(nums) < 4:
            return
        # Variable local para q10.
        q10 = self._percentil_simple(nums, 0.10)
        # Variable local para q25.
        q25 = self._percentil_simple(nums, 0.25)
        # Variable local para q75.
        q75 = self._percentil_simple(nums, 0.75)
        # Variable local para q90.
        q90 = self._percentil_simple(nums, 0.90)
        if None in {q10, q25, q75, q90}:
            return
        # Variable local para iqr.
        iqr = max(float(q75) - float(q25), 0.0)
        # Variable local para base min.
        base_min = min(float(q10), float(q25) - 1.2 * iqr)
        # Variable local para base max.
        base_max = max(float(q90), float(q75) + 1.2 * iqr)
        if not math.isfinite(base_min) or not math.isfinite(base_max):
            return
        if base_max <= base_min:
            # Variable local para centro.
            centro = float(q75)
            # Variable local para pad.
            pad = max(abs(centro) * 0.08, 0.05)
            base_min = centro - pad
            base_max = centro + pad
        # Variable local para margen.
        margen = max((base_max - base_min) * 0.12, 0.03)
        try:
            ax.set_ylim(base_min - margen, base_max + margen)
        except Exception:
            LOGGER.debug("No se pudo aplicar escala Y abierta", exc_info=True)

    def _dibujar_ratio_con_media(
        self,
        ax: Any,
        puntos: list[tuple[Any, float]],
        titulo: str,
        *,
        modo: str,
        etiquetas_x: list[str] | None = None,
        inicio: datetime | None = None,
        fin: datetime | None = None,
        modo_bandas_intradia: str = "dia_completo",
        modo_bandas_historico: str = "fija",
        puntos_rango_inf: list[tuple[Any, float]] | None = None,
        puntos_rango_sup: list[tuple[Any, float]] | None = None,
        y_label: str | None = None,
        modo_escala_y: str = "normal",
    ) -> None:
        """Dibuja una serie de ratio, su media y una banda de ±1 desvío estándar."""
        ax.set_axis_on()
        if puntos:
            # Variable local para xs.
            xs = [x for x, _ in puntos]
            # Variable local para ys.
            ys = [float(y) for _, y in puntos]
            # Variable local para valores escala.
            valores_escala = list(ys)
            if puntos_rango_inf and puntos_rango_sup and len(puntos_rango_inf) == len(puntos_rango_sup):
                # Variable local para xs rango.
                xs_rango = [x for x, _ in puntos_rango_sup]
                # Variable local para ys rango inf.
                ys_rango_inf = [float(y) for _, y in puntos_rango_inf]
                # Variable local para ys rango sup.
                ys_rango_sup = [float(y) for _, y in puntos_rango_sup]
                if xs_rango:
                    valores_escala.extend(ys_rango_inf)
                    valores_escala.extend(ys_rango_sup)
                    ax.fill_between(
                        xs_rango,
                        ys_rango_inf,
                        ys_rango_sup,
                        facecolor="#D9E6F2",
                        edgecolor="none",
                        alpha=0.22,
                        zorder=0,
                    )
                    ax.plot(xs_rango, ys_rango_sup, linestyle=":", linewidth=0.7, alpha=0.45)
                    ax.plot(xs_rango, ys_rango_inf, linestyle=":", linewidth=0.7, alpha=0.45)
            ax.plot(xs, ys, marker="o", markersize=1.5, linewidth=1.1)
            ax.scatter([xs[-1]], [ys[-1]], s=12)
            # Variable local para usar bandas dinamicas.
            usar_bandas_dinamicas = (
                (modo == "intradia" and modo_bandas_intradia == "dinamica")
                or (modo == "historico" and modo_bandas_historico == "dinamica")
            )
            if usar_bandas_dinamicas:
                if modo == "intradia":
                    # Resultado acumulado o final del cálculo.
                    resultado = self._calcular_ratio_dinamico_intradia(
                        [
                            (ts, float(valor))
                            for ts, valor in puntos
                            if isinstance(ts, datetime) and convertir_a_numero(valor) is not None
                        ]
                    )
                else:
                    resultado = self._calcular_ratio_dinamico_generico(puntos)
                # Variable local para puntos media.
                puntos_media = list(resultado.get("puntos_media") or [])
                # Variable local para puntos banda sup.
                puntos_banda_sup = list(resultado.get("puntos_banda_sup") or [])
                # Variable local para puntos banda inf.
                puntos_banda_inf = list(resultado.get("puntos_banda_inf") or [])
                # Variable local para media actual.
                media_actual = convertir_a_numero(resultado.get("media"))
                # Variable local para desvio actual.
                desvio_actual = convertir_a_numero(resultado.get("desvio"))
                if puntos_banda_sup and puntos_banda_inf:
                    # Variable local para xs fill.
                    xs_fill = [x for x, _ in puntos_banda_sup]
                    # Variable local para ys sup.
                    ys_sup = [float(valor) for _, valor in puntos_banda_sup]
                    # Variable local para ys inf.
                    ys_inf = [float(valor) for _, valor in puntos_banda_inf]
                    valores_escala.extend(ys_sup)
                    valores_escala.extend(ys_inf)
                    ax.fill_between(
                        xs_fill,
                        ys_inf,
                        ys_sup,
                        facecolor="#FFF4D6",
                        edgecolor="none",
                        alpha=0.28,
                        zorder=0,
                    )
                    ax.plot(xs_fill, ys_sup, linestyle=":", linewidth=0.8, alpha=0.8)
                    ax.plot(xs_fill, ys_inf, linestyle=":", linewidth=0.8, alpha=0.8)
                if puntos_media:
                    # Variable local para ys media.
                    ys_media = [float(valor) for _, valor in puntos_media]
                    valores_escala.extend(ys_media)
                    ax.plot(
                        [x for x, _ in puntos_media],
                        ys_media,
                        linestyle="--",
                        linewidth=1.0,
                        alpha=0.9,
                    )
                # Variable local para texto media.
                texto_media = f"Media dyn: {float(media_actual):.6f}" if media_actual is not None else "Media dyn: s/d"
                # Variable local para texto desvio.
                texto_desvio = f"σ dyn: {float(desvio_actual):.6f}" if desvio_actual is not None else "σ dyn: s/d"
            else:
                # Variable local para media.
                media = sum(ys) / len(ys)
                if len(ys) > 1:
                    # Variable local para varianza.
                    varianza = sum((y - media) ** 2 for y in ys) / len(ys)
                    # Variable local para desvio.
                    desvio = math.sqrt(max(varianza, 0.0))
                else:
                    desvio = 0.0
                if desvio > 0:
                    valores_escala.extend([media - desvio, media + desvio])
                    ax.axhspan(
                        media - desvio,
                        media + desvio,
                        facecolor="#FFF4D6",
                        edgecolor="none",
                        alpha=0.45,
                        zorder=0,
                    )
                valores_escala.append(media)
                ax.axhline(media, linestyle="--", linewidth=1.0, alpha=0.9)
                texto_media = f"Media: {media:.6f}"
                texto_desvio = f"σ: {desvio:.6f}"
            ax.text(
                0.02,
                0.98,
                f"{texto_media}\n{texto_desvio}",
                transform=ax.transAxes,
                ha="left",
                va="top",
                fontsize=9,
                bbox={"boxstyle": "round,pad=0.2", "alpha": 0.25},
            )
            ax.set_title(titulo)
            ax.set_xlabel("Fecha" if modo == "historico" else "Hora")
            ax.set_ylabel(y_label or "A/B")
            ax.grid(True, alpha=0.3)
            if str(modo_escala_y or "").strip().lower() == "abierta":
                self._aplicar_escala_y_abierta(ax, valores_escala)
            if modo == "historico":
                self._aplicar_eje_categorico_comparador(ax, etiquetas_x or [])
            else:
                self._aplicar_eje_intradia(ax, inicio, fin)
        else:
            # Variable local para mensaje.
            mensaje = f"Sin datos suficientes para {titulo.lower()}"
            ax.text(0.5, 0.5, mensaje, ha="center", va="center")
            ax.set_title(titulo)
            if modo == "historico":
                self._aplicar_eje_categorico_comparador(ax, etiquetas_x or [])
            else:
                self._aplicar_eje_intradia(ax, inicio, fin)

    def _calcular_ratio_dinamico_generico(
        self,
        puntos: list[tuple[Any, float]],
    ) -> dict[str, Any]:
        """Calcula media y desvío dinámicos acumulados preservando el orden natural de la serie."""
        # Serie temporal construida en este bloque.
        serie = [
            (x, float(valor))
            for x, valor in (puntos or [])
            if convertir_a_numero(valor) is not None
        ]
        # Variable local para puntos ratio.
        puntos_ratio: list[tuple[Any, float]] = []
        # Variable local para puntos media.
        puntos_media: list[tuple[Any, float]] = []
        # Variable local para puntos banda sup.
        puntos_banda_sup: list[tuple[Any, float]] = []
        # Variable local para puntos banda inf.
        puntos_banda_inf: list[tuple[Any, float]] = []
        # Variable local para acumulados.
        acumulados: list[float] = []
        # Variable local para media actual.
        media_actual: float | None = None
        # Variable local para desvio actual.
        desvio_actual: float = 0.0
        # Variable local para zscore actual.
        zscore_actual: float | None = None
        for x, valor in serie:
            acumulados.append(float(valor))
            # Variable local para media local.
            media_local = sum(acumulados) / len(acumulados)
            if len(acumulados) > 1:
                # Variable local para varianza local.
                varianza_local = sum((item - media_local) ** 2 for item in acumulados) / len(acumulados)
                # Variable local para desvio local.
                desvio_local = math.sqrt(max(varianza_local, 0.0))
            else:
                desvio_local = 0.0
            puntos_ratio.append((x, float(valor)))
            puntos_media.append((x, float(media_local)))
            puntos_banda_sup.append((x, float(media_local + desvio_local)))
            puntos_banda_inf.append((x, float(media_local - desvio_local)))
            media_actual = float(media_local)
            desvio_actual = float(desvio_local)
            zscore_actual = ((float(valor) - float(media_local)) / float(desvio_local)) if desvio_local > 0 else 0.0
        return {
            "puntos_ratio": puntos_ratio,
            "puntos_media": puntos_media,
            "puntos_banda_sup": puntos_banda_sup,
            "puntos_banda_inf": puntos_banda_inf,
            "media": media_actual,
            "desvio": desvio_actual,
            "zscore": zscore_actual,
        }

    def _calcular_ratio_dinamico_intradia(
        self,
        puntos: list[tuple[datetime, float]],
    ) -> dict[str, Any]:
        """Calcula media y desvío dinámicos acumulados sobre un ratio intradía."""
        # Serie temporal construida en este bloque.
        serie = sorted(
            [
                (ts, float(valor))
                for ts, valor in (puntos or [])
                if isinstance(ts, datetime) and convertir_a_numero(valor) is not None
            ],
            key=lambda item: item[0],
        )
        return self._calcular_ratio_dinamico_generico(serie)

    def _dibujar_ratio_intradia_dinamico(
        self,
        ax: Any,
        puntos: list[tuple[datetime, float]],
        titulo: str,
        *,
        inicio: datetime | None,
        fin: datetime | None,
    ) -> dict[str, Any]:
        """Dibuja un gráfico compacto del ratio intradía con media y desvío dinámicos acumulados."""
        ax.set_axis_on()
        # Resultado acumulado o final del cálculo.
        resultado = self._calcular_ratio_dinamico_intradia(puntos)
        # Variable local para puntos ratio.
        puntos_ratio = list(resultado.get("puntos_ratio") or [])
        # Variable local para puntos media.
        puntos_media = list(resultado.get("puntos_media") or [])
        # Variable local para puntos banda sup.
        puntos_banda_sup = list(resultado.get("puntos_banda_sup") or [])
        # Variable local para puntos banda inf.
        puntos_banda_inf = list(resultado.get("puntos_banda_inf") or [])

        if puntos_ratio:
            # Variable local para xs.
            xs = [ts for ts, _ in puntos_ratio]
            # Variable local para ys.
            ys = [float(valor) for _, valor in puntos_ratio]
            ax.plot(xs, ys, linewidth=1.15)
            if puntos_banda_sup and puntos_banda_inf:
                # Variable local para xs fill.
                xs_fill = [ts for ts, _ in puntos_banda_sup]
                # Variable local para ys sup.
                ys_sup = [float(valor) for _, valor in puntos_banda_sup]
                # Variable local para ys inf.
                ys_inf = [float(valor) for _, valor in puntos_banda_inf]
                ax.fill_between(xs_fill, ys_inf, ys_sup, alpha=0.10)
                ax.plot(xs_fill, ys_sup, linestyle=":", linewidth=0.8, alpha=0.8)
                ax.plot(xs_fill, ys_inf, linestyle=":", linewidth=0.8, alpha=0.8)
            if puntos_media:
                ax.plot([ts for ts, _ in puntos_media], [float(valor) for _, valor in puntos_media], linestyle="--", linewidth=0.95, alpha=0.9)
            ax.scatter([xs[-1]], [ys[-1]], s=26)
            # Variable local para media actual.
            media_actual = convertir_a_numero(resultado.get("media"))
            # Variable local para desvio actual.
            desvio_actual = convertir_a_numero(resultado.get("desvio"))
            # Variable local para zscore actual.
            zscore_actual = convertir_a_numero(resultado.get("zscore"))
            # Variable local para lineas.
            lineas = [f"Actual: {ys[-1]:.6f}"]
            lineas.append(f"Media dyn: {float(media_actual):.6f}" if media_actual is not None else "Media dyn: s/d")
            lineas.append(f"σ dyn: {float(desvio_actual):.6f}" if desvio_actual is not None else "σ dyn: s/d")
            lineas.append(f"Z: {float(zscore_actual):.2f}" if zscore_actual is not None else "Z: s/d")
            ax.text(
                0.02,
                0.98,
                "\n".join(lineas),
                transform=ax.transAxes,
                ha="left",
                va="top",
                fontsize=8.5,
                bbox={"boxstyle": "round,pad=0.18", "alpha": 0.24},
            )
            ax.set_title(titulo)
            ax.set_ylabel("Ratio A/B")
            ax.grid(True, alpha=0.3)
            self._aplicar_eje_intradia(ax, inicio or xs[0], fin or xs[-1])
        else:
            ax.text(0.5, 0.5, "Sin ratio intradía suficiente", ha="center", va="center")
            ax.set_title(titulo)
            self._aplicar_eje_intradia(ax, inicio, fin)
        return resultado

    # Función auxiliar para obtener filas cierre par.
    def _obtener_filas_cierre_par(self, ticker_a: str, ticker_b: str, limite: int = 90) -> list[dict[str, Any]]:
        # Filas temporales recuperadas o construidas en este paso.
        filas = list(self._history_db.obtener_tabla_cierres_par(ticker_a, ticker_b, limite) or [])
        filas.reverse()
        return filas

    # Función auxiliar para series costos cierre comparador.
    def _series_costos_cierre_comparador(
        self,
        ticker_a: str,
        ticker_b: str,
        modo: str,
    ) -> tuple[list[tuple[datetime, float]], list[tuple[datetime, float]], list[tuple[datetime, float]]]:
        # Filas temporales recuperadas o construidas en este paso.
        filas = self._obtener_filas_cierre_par(ticker_a, ticker_b, 90)
        # Variable local para serie principal.
        serie_principal: list[tuple[datetime, float]] = []
        # Variable local para serie secundaria.
        serie_secundaria: list[tuple[datetime, float]] = []
        # Variable local para serie last.
        serie_last: list[tuple[datetime, float]] = []
        for fila in filas:
            try:
                # Marca temporal normalizada de la observación actual.
                ts = datetime.strptime(str(fila.get("fecha") or ""), "%Y-%m-%d")
                # Variable local para precio A.
                precio_a = convertir_a_numero(fila.get("precio_a"))
                # Variable local para precio B.
                precio_b = convertir_a_numero(fila.get("precio_b"))
                if precio_a is None or precio_b is None:
                    continue
                # Variable local para pa.
                pa = float(precio_a)
                # Variable local para pb.
                pb = float(precio_b)
            except Exception:
                continue
            if modo == "buy_a_sell_b":
                serie_principal.append((ts, pa - pb))
                serie_last.append((ts, pa - pb))
            elif modo == "sell_a_buy_b":
                serie_principal.append((ts, -pa + pb))
                serie_last.append((ts, -pa + pb))
            else:
                serie_last.append((ts, pa + pb))
        return serie_principal, serie_secundaria, serie_last

    # Función auxiliar para dibujar costos comparador.
    def _dibujar_costos_comparador(
        self,
        ax: Any,
        serie_principal: list[tuple[float, float]],
        serie_secundaria: list[tuple[float, float]],
        serie_last: list[tuple[float, float]],
        titulo: str,
        etiquetas_x: list[str],
        *,
        label_principal: str,
        label_secundaria: str | None = None,
        label_last: str = "Last estrategia",
        destacar_last: bool = False,
    ) -> None:
        ax.set_axis_on()
        # Variable local para hay datos.
        hay_datos = False
        if serie_principal:
            # Variable local para xs.
            xs = [x for x, _ in serie_principal]
            # Variable local para ys.
            ys = [float(y) for _, y in serie_principal]
            ax.plot(xs, ys, marker="o", markersize=1.4, linewidth=1.0, alpha=0.55, label=label_principal)
            ax.scatter([xs[-1]], [ys[-1]], s=10, alpha=0.55)
            hay_datos = True
        if serie_secundaria:
            xs = [x for x, _ in serie_secundaria]
            ys = [float(y) for _, y in serie_secundaria]
            ax.plot(xs, ys, marker="o", markersize=1.4, linewidth=0.95, linestyle="--", alpha=0.55, label=label_secundaria or "Serie secundaria")
            ax.scatter([xs[-1]], [ys[-1]], s=10, alpha=0.55)
            hay_datos = True
        if serie_last:
            xs = [x for x, _ in serie_last]
            ys = [float(y) for _, y in serie_last]
            if destacar_last:
                ax.plot(xs, ys, marker="o", markersize=1.6, linewidth=2.2, color="#4d4d4d", alpha=0.95, label=label_last)
                ax.scatter([xs[-1]], [ys[-1]], s=14, color="#4d4d4d")
            else:
                ax.plot(xs, ys, marker="o", markersize=1.3, linewidth=0.95, linestyle=(0, (1.4, 2.2)), color="#7a7a7a", alpha=0.9, label=label_last)
                ax.scatter([xs[-1]], [ys[-1]], s=10, color="#7a7a7a")
            hay_datos = True
        if hay_datos:
            ax.set_title(titulo)
            ax.set_xlabel("Fecha")
            ax.set_ylabel("Costo total")
            ax.grid(True, alpha=0.3)
            ax.legend(loc="best", fontsize=8)
            self._aplicar_eje_categorico_comparador(ax, etiquetas_x or [])
        else:
            ax.text(0.5, 0.5, "Sin datos suficientes para costos de la estrategia", ha="center", va="center")
            ax.set_title(titulo)
            self._aplicar_eje_categorico_comparador(ax, etiquetas_x or [])

