    def _leer_limite_eventos_extremos_backtest(self) -> int:
        """Lee cuántas veces puede activarse la restricción extrema en el día (1 a 10)."""
        # Texto temporal usado para armar o normalizar información.
        texto = str(self.var_backtest_extreme_max_events.get() or "").strip()
        try:
            # Valor temporal usado en este cálculo.
            valor = int(float(texto))
        except Exception:
            valor = int(getattr(self, "_backtest_extreme_max_events_ultimo_valido", BACKTEST_EXTREME_MAX_EVENTS_DEFAULT) or BACKTEST_EXTREME_MAX_EVENTS_DEFAULT)
        valor = max(1, min(10, int(valor)))
        self._backtest_extreme_max_events_ultimo_valido = int(valor)
        if texto != str(valor):
            self.var_backtest_extreme_max_events.set(str(valor))
        return int(valor)

