    # Función auxiliar para hay config backtest en edicion.
    def _hay_config_backtest_en_edicion(self) -> bool:
        return any(
            bool(getattr(self, nombre, False))
            for nombre in (
                "_backtest_sigma_en_edicion",
                "_backtest_extreme_sigma_en_edicion",
                "_backtest_extreme_wait_en_edicion",
                "_backtest_loss_limit_en_edicion",
                "_backtest_loss_wait_en_edicion",
                "_backtest_volshock_window_en_edicion",
                "_backtest_volshock_mult_en_edicion",
                "_backtest_volshock_wait_en_edicion",
                "_backtest_media_shift_sigma_en_edicion",
                "_backtest_media_shift_wait_en_edicion",
            )
        )

    def _confirmar_config_backtest_en_edicion(self) -> bool:
        """Confirma cualquier campo editable del backtest antes de recalcular.

        Esto evita que al apretar Recalcular o cambiar un selector mientras un
        Entry sigue con foco quede tomado solo el valor parcial (por ejemplo `3`
        en lugar de `30`).
        """
        # Variable local para hubo cambios.
        hubo_cambios = False
        # Variable local para confirmaciones.
        confirmaciones = (
            ("_backtest_sigma_en_edicion", lambda: self._leer_sigma_backtest(confirmar=True)),
            ("_backtest_extreme_sigma_en_edicion", lambda: self._leer_sigma_extrema_backtest(confirmar=True)),
            ("_backtest_extreme_wait_en_edicion", lambda: self._leer_espera_extrema_backtest(confirmar=True)),
            ("_backtest_loss_limit_en_edicion", lambda: self._leer_perdida_maxima_backtest(confirmar=True)),
            ("_backtest_loss_wait_en_edicion", lambda: self._leer_espera_perdida_backtest(confirmar=True)),
            ("_backtest_volshock_window_en_edicion", lambda: self._leer_ventana_shock_vol_backtest(confirmar=True)),
            ("_backtest_volshock_mult_en_edicion", lambda: self._leer_mult_shock_vol_backtest(confirmar=True)),
            ("_backtest_volshock_wait_en_edicion", lambda: self._leer_espera_shock_vol_backtest(confirmar=True)),
            ("_backtest_media_shift_sigma_en_edicion", lambda: self._leer_sigma_cambio_media_backtest(confirmar=True)),
            ("_backtest_media_shift_wait_en_edicion", lambda: self._leer_espera_cambio_media_backtest(confirmar=True)),
        )
        for attr_edicion, funcion_confirmar in confirmaciones:
            if bool(getattr(self, attr_edicion, False)):
                setattr(self, attr_edicion, False)
                funcion_confirmar()
                hubo_cambios = True
        return hubo_cambios

    # Función auxiliar para leer float config backtest.
    def _leer_float_config_backtest(
        self,
        var: StringVar,
        *,
        ultimo_attr: str,
        edit_attr: str,
        confirmar: bool = False,
        minimo: float = 0.0,
        maximo: float | None = None,
        predeterminado: float = 0.0,
        decimales: int = 2,
    ) -> float:
        # Texto temporal usado para armar o normalizar información.
        texto = str(var.get() or "").strip().replace(",", ".")
        # Registro temporal o último valor usado para ultimo valido.
        ultimo_valido = float(getattr(self, ultimo_attr, predeterminado) or predeterminado)
        # Variable local para en edicion.
        en_edicion = bool(getattr(self, edit_attr, False))
        if en_edicion and not confirmar:
            # Variable local para valor edicion.
            valor_edicion = ultimo_valido
            if valor_edicion < minimo:
                valor_edicion = minimo
            if maximo is not None and valor_edicion > maximo:
                valor_edicion = maximo
            return float(valor_edicion)
        try:
            # Valor temporal usado en este cálculo.
            valor = float(texto)
        except Exception:
            valor = None
        if valor is not None:
            if valor < minimo:
                valor = minimo
            if maximo is not None and valor > maximo:
                valor = maximo
            setattr(self, ultimo_attr, float(valor))
            if confirmar:
                var.set(f"{float(valor):.{decimales}f}".rstrip("0").rstrip("."))
            return float(valor)
        if confirmar:
            # Variable local para valor confirmado.
            valor_confirmado = ultimo_valido
            if valor_confirmado < minimo:
                valor_confirmado = minimo
            if maximo is not None and valor_confirmado > maximo:
                valor_confirmado = maximo
            setattr(self, ultimo_attr, float(valor_confirmado))
            var.set(f"{float(valor_confirmado):.{decimales}f}".rstrip("0").rstrip("."))
            return float(valor_confirmado)
        # Variable local para valor seguro.
        valor_seguro = ultimo_valido
        if valor_seguro < minimo:
            valor_seguro = minimo
        if maximo is not None and valor_seguro > maximo:
            valor_seguro = maximo
        return float(valor_seguro)

    # Función auxiliar para leer ventana shock vol backtest.
    def _leer_ventana_shock_vol_backtest(self, *, confirmar: bool = False) -> float:
        return self._leer_float_config_backtest(
            self.var_backtest_volshock_window_min,
            ultimo_attr="_backtest_volshock_window_ultimo_valido",
            edit_attr="_backtest_volshock_window_en_edicion",
            confirmar=confirmar,
            minimo=1.0,
            maximo=120.0,
            predeterminado=float(BACKTEST_VOL_SHOCK_WINDOW_MIN_DEFAULT),
            decimales=0,
        )

