    def _leer_espera_cambio_media_backtest(self, *, confirmar: bool = False) -> float:
        """Lee la pausa de cambio de media sin perder el texto recién escrito por el usuario."""
        # Registro temporal o último valor usado para ultimo valido.
        ultimo_valido = float(getattr(self, "_backtest_media_shift_wait_ultimo_valido", BACKTEST_REGIME_COOLDOWN_MIN_DEFAULT) or BACKTEST_REGIME_COOLDOWN_MIN_DEFAULT)
        # Variable local para en edicion.
        en_edicion = bool(getattr(self, "_backtest_media_shift_wait_en_edicion", False))
        # Variable local para texto pendiente.
        texto_pendiente = str(getattr(self, "_backtest_media_shift_wait_texto_pendiente", "") or "").strip()
        # Variable local para texto var.
        texto_var = str(self.var_backtest_media_shift_wait_min.get() or "").strip()
        # Variable local para texto fuente.
        texto_fuente = texto_pendiente if (confirmar or en_edicion) and texto_pendiente else texto_var
        # Texto temporal usado para armar o normalizar información.
        texto = texto_fuente.replace(",", ".")
        try:
            # Valor temporal usado en este cálculo.
            valor = float(texto)
        except Exception:
            valor = None
        if valor is not None:
            if valor < 0.0:
                valor = 0.0
            if valor > 240.0:
                valor = 240.0
            self._backtest_media_shift_wait_ultimo_valido = float(valor)
            if confirmar:
                # Variable local para texto confirmado.
                texto_confirmado = f"{float(valor):.0f}"
                self.var_backtest_media_shift_wait_min.set(texto_confirmado)
                self._backtest_media_shift_wait_texto_pendiente = texto_confirmado
            return float(valor)
        if confirmar:
            # Variable local para valor confirmado.
            valor_confirmado = ultimo_valido
            if valor_confirmado < 0.0:
                valor_confirmado = 0.0
            if valor_confirmado > 240.0:
                valor_confirmado = 240.0
            texto_confirmado = f"{float(valor_confirmado):.0f}"
            self._backtest_media_shift_wait_ultimo_valido = float(valor_confirmado)
            self.var_backtest_media_shift_wait_min.set(texto_confirmado)
            self._backtest_media_shift_wait_texto_pendiente = texto_confirmado
            return float(valor_confirmado)
        # Variable local para valor seguro.
        valor_seguro = ultimo_valido
        if valor_seguro < 0.0:
            valor_seguro = 0.0
        if valor_seguro > 240.0:
            valor_seguro = 240.0
        return float(valor_seguro)

    # Función auxiliar para al entrar espera cambio media backtest.
    def _al_entrar_espera_cambio_media_backtest(self, _event=None) -> None:
        self._backtest_media_shift_wait_en_edicion = True
        self._backtest_media_shift_wait_texto_pendiente = str(self.var_backtest_media_shift_wait_min.get() or "").strip()

    # Función auxiliar para al teclear espera cambio media backtest.
    def _al_teclear_espera_cambio_media_backtest(self, event=None) -> None:
        self._backtest_media_shift_wait_en_edicion = True
        try:
            self._backtest_media_shift_wait_texto_pendiente = str(event.widget.get() or "")
        except Exception:
            self._backtest_media_shift_wait_texto_pendiente = str(self.var_backtest_media_shift_wait_min.get() or "")

    def _confirmar_espera_cambio_media_backtest_diferido(self, texto: str | None = None) -> None:
        """Confirma la pausa de cambio de media con el texto final realmente escrito en el Entry."""
        if texto is not None:
            self._backtest_media_shift_wait_texto_pendiente = str(texto or "")
        self._backtest_media_shift_wait_en_edicion = False
        self._leer_espera_cambio_media_backtest(confirmar=True)
        self._al_cambiar_selector_backtest()

    # Función auxiliar para al confirmar espera cambio media backtest.
    def _al_confirmar_espera_cambio_media_backtest(self, event=None):
        try:
            # Texto temporal usado para armar o normalizar información.
            texto = str(event.widget.get() or "") if event is not None and hasattr(event, "widget") else str(self.var_backtest_media_shift_wait_min.get() or "")
        except Exception:
            texto = str(self.var_backtest_media_shift_wait_min.get() or "")
        self._backtest_media_shift_wait_texto_pendiente = texto
        try:
            self.root.after_idle(lambda t=texto: self._confirmar_espera_cambio_media_backtest_diferido(t))
        except Exception:
            self._confirmar_espera_cambio_media_backtest_diferido(texto)
        return None

    def _leer_sigma_umbral_backtest(self, var: StringVar, sigma_base: float, *, predeterminado: str = "Sin aumento") -> float | None:
        """Lee un umbral opcional donde el backtest suma una unidad adicional."""
        # Variable local para texto original.
        texto_original = str(var.get() or "").strip()
        # Texto temporal usado para armar o normalizar información.
        texto = texto_original.replace(",", ".")
        if not texto or texto.lower() in {"sin aumento", "sin refuerzo", "ninguno", "none", "off", "0"}:
            var.set(predeterminado)
            return None
        try:
            # Valor temporal usado en este cálculo.
            valor = float(texto)
        except Exception:
            var.set(predeterminado)
            return None
        if valor <= sigma_base:
            var.set(predeterminado)
            return None
        var.set(f"{valor:.2f}".rstrip("0").rstrip("."))
        return valor

    def _leer_sigmas_refuerzo_backtest(self, sigma_base: float) -> list[float]:
        """Devuelve hasta dos niveles crecientes para aumentar posición en el backtest."""
        # Variable local para candidatos.
        candidatos = [
            self._leer_sigma_umbral_backtest(self.var_backtest_sigma_refuerzo_1, sigma_base),
            self._leer_sigma_umbral_backtest(self.var_backtest_sigma_refuerzo_2, sigma_base),
        ]
        # Variable local para niveles.
        niveles: list[float] = []
        for valor in candidatos:
            if valor is None:
                continue
            # Variable local para valor f.
            valor_f = float(valor)
            if valor_f <= sigma_base:
                continue
            if any(abs(valor_f - existente) < 1e-9 for existente in niveles):
                continue
            niveles.append(valor_f)
        niveles.sort()
        return niveles[:2]

    def _normalizar_hora_backtest_texto(self, valor: str, predeterminado: str) -> str:
        """Normaliza una hora HH:MM y devuelve un valor seguro para la vista de backtest."""
        # Texto temporal usado para armar o normalizar información.
        texto = str(valor or predeterminado).strip()
        if re.fullmatch(r"\d{1,2}:\d{2}", texto):
            hora, minuto = texto.split(":", 1)
            try:
                # Variable local para hh.
                hh = int(hora)
                # Variable local para mm.
                mm = int(minuto)
            except Exception:
                hh = mm = -1
            if 0 <= hh <= 23 and 0 <= mm <= 59:
                return f"{hh:02d}:{mm:02d}"
        return predeterminado

    def _leer_hora_backtest(self, var: StringVar, predeterminado: str) -> str:
        """Lee y normaliza una hora editable del backtest intradía."""
        # Valor temporal usado en este cálculo.
        valor = self._normalizar_hora_backtest_texto(var.get(), predeterminado)
        try:
            hh, mm = valor.split(":", 1)
            # Variable local para minutos.
            minutos = int(hh) * 60 + int(mm)
        except Exception:
            minutos = 0
        # Variable local para inicio min.
        inicio_min = 10 * 60 + 30
        # Variable local para fin min.
        fin_min = 17 * 60
        minutos = max(inicio_min, min(fin_min, minutos))
        valor = f"{minutos // 60:02d}:{minutos % 60:02d}"
        var.set(valor)
        return valor

    def _leer_ticks_confirmacion_backtest(self, var: StringVar, predeterminado: int = 1) -> int:
        """Lee una cantidad de ticks consecutivos y la normaliza para el backtest intradía."""
        texto = str(var.get() or predeterminado).strip().replace(",", ".")
        try:
            valor = int(float(texto))
        except Exception:
            valor = int(predeterminado)
        valor = max(BACKTEST_MIN_CONFIRM_TICKS, min(BACKTEST_MAX_CONFIRM_TICKS, valor))
        var.set(str(valor))
        return valor

    def _leer_intervalo_backtest_minutos(self) -> int:
        """Devuelve el intervalo del backtest intradía en minutos."""
        texto = str(self.var_backtest_interval.get() or BACKTEST_DEFAULT_INTERVAL).strip()
        mapa = {"1 min": 1, "5 min": 5, "10 min": 10, "15 min": 15, "30 min": 30, "60 min": 60}
        if texto not in mapa:
            texto = BACKTEST_DEFAULT_INTERVAL
            self.var_backtest_interval.set(texto)
        return int(mapa.get(texto, 1))

    def _resamplear_filas_backtest_intradia(self, filas_intradia: list[dict[str, Any]], intervalo_minutos: int) -> list[dict[str, Any]]:
        """Reduce la serie intradía del backtest tomando la última observación de cada intervalo."""
        try:
            intervalo = max(1, int(intervalo_minutos))
        except Exception:
            intervalo = 1
        if intervalo <= 1 or not filas_intradia:
            return list(filas_intradia)
        filas_ordenadas = [fila for fila in filas_intradia if isinstance(fila.get("ts"), datetime)]
        filas_ordenadas.sort(key=lambda fila: fila["ts"])
        if not filas_ordenadas:
            return []
        buckets: dict[tuple[int, int, int, int, int], dict[str, Any]] = {}
        for fila in filas_ordenadas:
            ts = fila.get("ts")
            if not isinstance(ts, datetime):
                continue
            minuto_bucket = (ts.minute // intervalo) * intervalo
            clave = (ts.year, ts.month, ts.day, ts.hour, minuto_bucket)
            buckets[clave] = fila
        salida = [buckets[clave] for clave in sorted(buckets.keys())]
        return salida

    def _texto_lado_backtest(self, lado: str, nivel_sigma: float | None = None) -> str:
        """Devuelve el texto descriptivo del lado y el nivel de entrada del backtest."""
        if lado == "long_a_short_b":
            # Variable local para base.
            base = "Comprar A / Vender B"
        elif lado == "short_a_long_b":
            base = "Vender A / Comprar B"
        elif lado == "long_cono":
            base = "Comprar A + Comprar B"
        elif lado == "short_cono":
            base = "Vender A + Vender B"
        else:
            base = "Operación"
        if nivel_sigma is None:
            return base
        return f"{base} | {float(nivel_sigma):.2f}σ"

    def _calcular_sigma_historico_backtest(self, ticker_a: str, ticker_b: str) -> tuple[float | None, int]:
        """Devuelve la σ histórica del ratio last A/B usando todos los cierres oficiales disponibles."""
        if not ticker_a or not ticker_b:
            return None, 0
        try:
            # Variable local para series historicas.
            series_historicas = self._obtener_series_cache_comparador(ticker_a, ticker_b)
        except Exception:
            LOGGER.debug("No se pudo obtener la serie histórica del comparador para el backtest", exc_info=True)
            return None, 0
        # Variable local para serie last.
        serie_last = list(series_historicas.get("last") or [])
        # Colección temporal de valores usada en este cálculo.
        valores: list[float] = []
        for _ts, valor in serie_last:
            # Número temporal calculado en este bloque.
            numero = convertir_a_numero(valor)
            if numero is None:
                continue
            valores.append(float(numero))
        if len(valores) < 2:
            return None, len(valores)
        # Variable local para media hist.
        media_hist = sum(valores) / len(valores)
        # Variable de Tkinter de texto para hist.
        var_hist = sum((valor - media_hist) ** 2 for valor in valores) / len(valores)
        # Variable local para sigma hist.
        sigma_hist = math.sqrt(max(var_hist, 0.0))
        if sigma_hist <= 0:
            return None, len(valores)
        return float(sigma_hist), len(valores)

    def _calcular_sigma_historico_cono_backtest(self, ticker_a: str, ticker_b: str) -> tuple[float | None, int]:
        """Devuelve la σ histórica del cono last A+B usando todos los cierres disponibles."""
        if not ticker_a or not ticker_b:
            return None, 0
        try:
            # Variable local para serie historica.
            serie_historica = self._history_db.obtener_serie_suma_cierres(ticker_a, ticker_b, campo="last")
        except Exception:
            LOGGER.debug("No se pudo obtener la serie histórica del cono para el backtest", exc_info=True)
            return None, 0
        # Colección temporal de valores usada en este cálculo.
        valores: list[float] = []
        for _ts, valor in list(serie_historica or []):
            # Número temporal calculado en este bloque.
            numero = convertir_a_numero(valor)
            if numero is None:
                continue
            valores.append(float(numero))
        if len(valores) < 2:
            return None, len(valores)
        # Variable local para media hist.
        media_hist = sum(valores) / len(valores)
        # Variable de Tkinter de texto para hist.
        var_hist = sum((valor - media_hist) ** 2 for valor in valores) / len(valores)
        # Variable local para sigma hist.
        sigma_hist = math.sqrt(max(var_hist, 0.0))
        if sigma_hist <= 0:
            return None, len(valores)
        return float(sigma_hist), len(valores)

    def _modo_salida_backtest_actual(self, modo_ejecucion: str) -> str:
        """Devuelve si la salida del backtest debe valuarse a last o a mercado."""
        # Variable local para configurado.
        configurado = str(getattr(self, "var_backtest_exit_mode", StringVar(value="last")).get() or "").strip().lower()
        if configurado in {"last", "market"}:
            return configurado
        # Variable local para modo norm.
        modo_norm = str(modo_ejecucion or "last").strip().lower()
        if modo_norm in {"last_exit_market", "bid_ask"}:
            return "market"
        return "last"

    def _texto_modo_ejecucion_backtest(self, modo_ejecucion: str) -> str:
        """Devuelve un texto legible con el modo de entrada y salida del backtest."""
        # Variable local para modo entrada.
        modo_entrada = str(modo_ejecucion or "last").strip().lower()
        if modo_entrada == "last_exit_market":
            modo_entrada = "last"
        if modo_entrada not in {"last", "bid_ask"}:
            modo_entrada = "last"
        # Variable local para entrada txt.
        entrada_txt = "Last" if modo_entrada == "last" else "Bid/Ask"
        # Variable local para salida txt.
        salida_txt = "Mercado" if self._modo_salida_backtest_actual(modo_ejecucion) == "market" else "Last"
        return f"Entrada {entrada_txt} / salida {salida_txt}"

    def _precio_ejecucion_backtest(self, fila: dict[str, Any], lado: str, momento: str, base: str, modo: str) -> float | None:
        """Devuelve el precio usado para simular cada pata del backtest."""
        if base not in {"a", "b"}:
            return None
        # Variable local para prefijo.
        prefijo = f"{base}_"
        # Variable local para modo norm.
        modo_norm = str(modo or "last").strip().lower()
        # Variable local para modo salida.
        modo_salida = self._modo_salida_backtest_actual(modo_norm)
        usa_puntas = False
        if momento == "entrada":
            usa_puntas = (modo_norm == "bid_ask")
        else:
            usa_puntas = (modo_salida == "market")
        if usa_puntas:
            if lado == "long_a_short_b":
                # Variable local para campo.
                campo = {
                    ("entrada", "a"): "ask",
                    ("entrada", "b"): "bid",
                    ("salida", "a"): "bid",
                    ("salida", "b"): "ask",
                }.get((momento, base), "last")
            elif lado == "short_a_long_b":
                campo = {
                    ("entrada", "a"): "bid",
                    ("entrada", "b"): "ask",
                    ("salida", "a"): "ask",
                    ("salida", "b"): "bid",
                }.get((momento, base), "last")
            elif lado == "long_cono":
                campo = {
                    ("entrada", "a"): "ask",
                    ("entrada", "b"): "ask",
                    ("salida", "a"): "bid",
                    ("salida", "b"): "bid",
                }.get((momento, base), "last")
            else:
                campo = {
                    ("entrada", "a"): "bid",
                    ("entrada", "b"): "bid",
                    ("salida", "a"): "ask",
                    ("salida", "b"): "ask",
                }.get((momento, base), "last")
        else:
            campo = "last"
        # Valor temporal usado en este cálculo.
        valor = convertir_a_numero(fila.get(prefijo + campo))
        return float(valor) if valor is not None else None

    def _calcular_pnl_patas_backtest(self, lado: str, fila_entrada: dict[str, Any], fila_salida: dict[str, Any], modo: str) -> tuple[float | None, float | None]:
        """Calcula el PnL individual de las patas A y B del backtest."""
        # Variable local para A ent.
        a_ent = self._precio_ejecucion_backtest(fila_entrada, lado, "entrada", "a", modo)
        # Variable local para B ent.
        b_ent = self._precio_ejecucion_backtest(fila_entrada, lado, "entrada", "b", modo)
        # Variable local para A sal.
        a_sal = self._precio_ejecucion_backtest(fila_salida, lado, "salida", "a", modo)
        # Variable local para B sal.
        b_sal = self._precio_ejecucion_backtest(fila_salida, lado, "salida", "b", modo)
        # Variable local para PnL A.
        pnl_a: float | None = None
        # Variable local para PnL B.
        pnl_b: float | None = None
        if None not in {a_ent, a_sal}:
            if lado in {"long_a_short_b", "long_cono"}:
                pnl_a = float(a_sal) - float(a_ent)
            else:
                pnl_a = float(a_ent) - float(a_sal)
        if None not in {b_ent, b_sal}:
            if lado == "long_a_short_b":
                pnl_b = float(b_ent) - float(b_sal)
            elif lado == "short_a_long_b":
                pnl_b = float(b_sal) - float(b_ent)
            elif lado == "long_cono":
                pnl_b = float(b_sal) - float(b_ent)
            else:
                pnl_b = float(b_ent) - float(b_sal)
        return pnl_a, pnl_b

    def _calcular_pnl_backtest(self, lado: str, fila_entrada: dict[str, Any], fila_salida: dict[str, Any], modo: str) -> float | None:
        """Calcula el PnL total de una operación cerrada del backtest."""
        pnl_a, pnl_b = self._calcular_pnl_patas_backtest(lado, fila_entrada, fila_salida, modo)
        if pnl_a is None or pnl_b is None:
            return None
        return float(pnl_a) + float(pnl_b)


    def _simular_backtest_ratio_intradia(
        self,
        filas_intradia: list[dict[str, Any]],
        *,
        sigma_mult: float,
        sigma_refuerzos: list[float],
        modo_ejecucion: str,
        fecha: str | None = None,
        hora_inicio_test: str = BACKTEST_DEFAULT_START_TIME,
        hora_cierre_test: str = BACKTEST_DEFAULT_END_TIME,
        close_zone_pct: float = BACKTEST_CLOSE_ZONE_PCT_OF_SIGMA,
        modo_bandas: str = "dinamica",
        historical_sigma_extreme: float | None = None,
        extreme_sigma_mult: float = BACKTEST_EXTREME_SIGMA_MULT,
        extreme_cooldown_minutes: float = 0.0,
        extreme_max_events_per_day: int = BACKTEST_EXTREME_MAX_EVENTS_DEFAULT,
        confirmar_segundo_tick_fuera_bandas: bool = False,
        entry_confirmation_ticks: int = 1,
        exit_confirmation_ticks: int = 1,
        loss_limit_amount: float = 0.0,
        loss_cooldown_minutes: float = 0.0,
        enable_extreme_close: bool = True,
        enable_loss_close: bool = True,
        enable_volatility_regime_close: bool = False,
        volatility_regime_window_minutes: float = BACKTEST_VOL_SHOCK_WINDOW_MIN_DEFAULT,
        volatility_regime_mult: float = BACKTEST_VOL_SHOCK_MULT_DEFAULT,
        volatility_regime_cooldown_minutes: float = BACKTEST_REGIME_COOLDOWN_MIN_DEFAULT,
        enable_moving_mean_shift_close: bool = False,
        moving_mean_shift_sigma_mult: float = BACKTEST_MEDIA_SHIFT_SIGMA_DEFAULT,
        moving_mean_shift_cooldown_minutes: float = BACKTEST_REGIME_COOLDOWN_MIN_DEFAULT,
        signal_mode: str = "ratio",
        coverage_mode_for_loss: str | None = None,
    ) -> dict[str, Any]:
        """Simula una estrategia intradía de reversión a la media con cierres adicionales configurables."""
        # Variable local para modo senal.
        modo_senal = str(signal_mode or "ratio").strip().lower()
        if modo_senal not in {"ratio", "cono"}:
            modo_senal = "ratio"
        entry_confirmation_ticks = max(BACKTEST_MIN_CONFIRM_TICKS, min(BACKTEST_MAX_CONFIRM_TICKS, int(entry_confirmation_ticks or 1)))
        exit_confirmation_ticks = max(BACKTEST_MIN_CONFIRM_TICKS, min(BACKTEST_MAX_CONFIRM_TICKS, int(exit_confirmation_ticks or 1)))
        # Variable local para cobertura stop norm.
        cobertura_stop_norm = str(coverage_mode_for_loss or "").strip().lower()
        if cobertura_stop_norm not in {"1a1", "precio", "delta", "vega"}:
            cobertura_stop_norm = ""
        # Variable local para enable volatility regime close.
        enable_volatility_regime_close = False
        # Variable local para volatility regime window minutes.
        volatility_regime_window_minutes = 0.0
        # Variable local para volatility regime múltiplo.
        volatility_regime_mult = 0.0
        # Variable local para volatility regime cooldown minutes.
        volatility_regime_cooldown_minutes = 0.0

        def _valor_senal_fila(fila: dict[str, Any]) -> float | None:
            if modo_senal == "cono":
                # Variable local para A last.
                a_last = convertir_a_numero(fila.get("a_last"))
                # Variable local para B last.
                b_last = convertir_a_numero(fila.get("b_last"))
                if a_last is None or b_last is None:
                    return None
                try:
                    return float(a_last) + float(b_last)
                except Exception:
                    return None
            # Variable local para valor ratio.
            valor_ratio = convertir_a_numero(fila.get("ratio_last"))
            return float(valor_ratio) if valor_ratio is not None else None

        # Variable local para filas ordenadas.
        filas_ordenadas = [
            fila for fila in filas_intradia
            if isinstance(fila.get("ts"), datetime) and _valor_senal_fila(fila) is not None
        ]
        filas_ordenadas.sort(key=lambda fila: fila["ts"])
        # Variable local para puntos ratio.
        puntos_ratio = [(fila["ts"], float(_valor_senal_fila(fila))) for fila in filas_ordenadas]
        if len(puntos_ratio) < 2:
            return {
                "puntos_ratio": puntos_ratio,
                "puntos_media": [],
                "puntos_banda_sup": [],
                "puntos_banda_inf": [],
                "puntos_banda_cierre_sup": [],
                "puntos_banda_cierre_inf": [],
                "puntos_bandas_refuerzo_sup": [],
                "puntos_bandas_refuerzo_inf": [],
                "operaciones": [],
                "puntos_pnl": [],
                "media": None,
                "desvio": None,
                "warmup_fin": None,
                "warmup_puntos": 0,
                "entradas_refuerzo_1": 0,
                "entradas_refuerzo_2": 0,
                "cierres_forzados": 0,
                "force_exit_ts": None,
                "pnl_total": 0.0,
                "pnl_promedio": 0.0,
                "aciertos": 0,
                "abiertas": 0,
                "sigma_refuerzos": list(sigma_refuerzos or []),
                "modo_bandas": str(modo_bandas or "dinamica"),
                "historical_sigma_extreme": historical_sigma_extreme,
                "extreme_sigma_mult": float(extreme_sigma_mult),
                "extreme_cooldown_minutes": float(extreme_cooldown_minutes),
                "extreme_max_events_per_day": int(max(1, min(10, int(extreme_max_events_per_day or BACKTEST_EXTREME_MAX_EVENTS_DEFAULT)))),
                "eventos_extremos": 0,
                "cierres_extremos": 0,
                "cierres_perdida": 0,
                "cierres_regimen_vol": 0,
                "cierres_cambio_media": 0,
                "puntos_extremos": [],
                "puntos_stop_loss": [],
                "puntos_regimen_vol": [],
                "puntos_cambio_media": [],
                "cooldown_spans": [],
                "loss_limit_amount": float(loss_limit_amount or 0.0),
                "loss_cooldown_minutes": float(loss_cooldown_minutes or 0.0),
                "enable_extreme_close": bool(enable_extreme_close),
                "enable_loss_close": bool(enable_loss_close),
                "enable_volatility_regime_close": bool(enable_volatility_regime_close),
                "volatility_regime_window_minutes": float(volatility_regime_window_minutes or 0.0),
                "volatility_regime_mult": float(volatility_regime_mult or 0.0),
                "volatility_regime_cooldown_minutes": float(volatility_regime_cooldown_minutes or 0.0),
                "enable_moving_mean_shift_close": bool(enable_moving_mean_shift_close),
                "moving_mean_shift_sigma_mult": float(moving_mean_shift_sigma_mult or 0.0),
                "moving_mean_shift_cooldown_minutes": float(moving_mean_shift_cooldown_minutes or 0.0),
                "confirmar_segundo_tick_fuera_bandas": bool(confirmar_segundo_tick_fuera_bandas),
                "entry_confirmation_ticks": int(entry_confirmation_ticks),
                "exit_confirmation_ticks": int(exit_confirmation_ticks),
                "signal_mode": modo_senal,
                "signal_label": "Cono last A+B" if modo_senal == "cono" else "Ratio A/B",
            }

        # Variable local para modo bandas norm.
        modo_bandas_norm = str(modo_bandas or "dinamica").strip().lower()
        if modo_bandas_norm not in {"dinamica", "fija"}:
            modo_bandas_norm = "dinamica"
        valores_ratio_np = np.asarray([float(valor) for _, valor in puntos_ratio], dtype=float)
        timestamps_ratio = [ts for ts, _ in puntos_ratio]
        stats_backtest_np = _np_precalcular_backtest_stats(timestamps_ratio, valores_ratio_np, max(float(volatility_regime_window_minutes or 0.0), 1.0))
        media_prev_np = stats_backtest_np["media_prev"]
        desvio_prev_np = stats_backtest_np["std_prev"]
        media_window_np = stats_backtest_np["media_window"]
        desvio_window_np = stats_backtest_np["std_window"]
        if len(puntos_ratio) >= 2:
            media_fija = float(np.mean(valores_ratio_np))
            desvio_fijo = float(np.std(valores_ratio_np))
        else:
            media_fija = None
            desvio_fijo = None
        # Variable local para hora inicio norm.
        hora_inicio_norm = self._normalizar_hora_backtest_texto(hora_inicio_test, BACKTEST_DEFAULT_START_TIME)
        # Variable local para hora cierre norm.
        hora_cierre_norm = self._normalizar_hora_backtest_texto(hora_cierre_test, BACKTEST_DEFAULT_END_TIME)
        # Variable local para inicio sesion.
        inicio_sesion: datetime | None = None
        # Variable local para fin sesion.
        fin_sesion: datetime | None = None
        # Variable local para warmup fin.
        warmup_fin: datetime | None = None
        # Variable local para force exit timestamp.
        force_exit_ts: datetime | None = None
        if fecha:
            inicio_sesion, fin_sesion = self._construir_limites_intradia(fecha, BACKTEST_SESSION_START_TIME, hora_cierre_norm)
            try:
                warmup_fin = datetime.strptime(f"{fecha} {hora_inicio_norm}:00", "%Y-%m-%d %H:%M:%S")
                force_exit_ts = datetime.strptime(f"{fecha} {hora_cierre_norm}:00", "%Y-%m-%d %H:%M:%S")
            except Exception:
                warmup_fin = None
                force_exit_ts = None
        if warmup_fin is None and puntos_ratio:
            try:
                warmup_fin = datetime.strptime(puntos_ratio[0][0].strftime("%Y-%m-%d") + f" {hora_inicio_norm}:00", "%Y-%m-%d %H:%M:%S")
            except Exception:
                warmup_fin = puntos_ratio[0][0]
        if force_exit_ts is None and puntos_ratio:
            try:
                force_exit_ts = datetime.strptime(puntos_ratio[0][0].strftime("%Y-%m-%d") + f" {hora_cierre_norm}:00", "%Y-%m-%d %H:%M:%S")
            except Exception:
                force_exit_ts = puntos_ratio[-1][0]
        if force_exit_ts is not None and warmup_fin is not None and force_exit_ts <= warmup_fin:
            force_exit_ts = warmup_fin + timedelta(minutes=5)

        # Variable local para sigma refuerzos validos.
        sigma_refuerzos_validos = sorted({float(v) for v in (sigma_refuerzos or []) if float(v) > float(sigma_mult)})[:2]
        # Variable local para puntos media.
        puntos_media: list[tuple[datetime, float]] = []
        # Variable local para puntos banda sup.
        puntos_banda_sup: list[tuple[datetime, float]] = []
        # Variable local para puntos banda inf.
        puntos_banda_inf: list[tuple[datetime, float]] = []
        # Variable local para puntos banda cierre sup.
        puntos_banda_cierre_sup: list[tuple[datetime, float]] = []
        # Variable local para puntos banda cierre inf.
        puntos_banda_cierre_inf: list[tuple[datetime, float]] = []
        # Variable local para puntos bandas refuerzo sup.
        puntos_bandas_refuerzo_sup: list[list[tuple[datetime, float]]] = [[] for _ in sigma_refuerzos_validos]
        # Variable local para puntos bandas refuerzo inf.
        puntos_bandas_refuerzo_inf: list[list[tuple[datetime, float]]] = [[] for _ in sigma_refuerzos_validos]
        # Variable local para historial ratios.
        historial_ratios: list[float] = []
        # Variable local para warmup puntos.
        warmup_puntos = 0
        # Registro temporal o último valor usado para ultima fila valida.
        ultima_fila_valida: dict[str, Any] | None = None
        # Registro temporal o último valor usado para fila ultimo antes cierre.
        fila_ultimo_antes_cierre: dict[str, Any] | None = None
        # Registro temporal o último valor usado para ultima media.
        ultima_media: float | None = None
        # Registro temporal o último valor usado para ultimo desvio.
        ultimo_desvio: float | None = None

        # Variable local para operaciones.
        operaciones: list[dict[str, Any]] = []
        # Variable local para puntos PnL.
        puntos_pnl: list[tuple[datetime, float]] = []
        # Variable local para PnL acum.
        pnl_acum = 0.0
        # Variable local para posiciones abiertas.
        posiciones_abiertas: list[dict[str, Any]] = []
        # Variable local para media referencia operacion.
        media_referencia_operacion: float | None = None
        # Variable local para desvio referencia operacion.
        desvio_referencia_operacion: float | None = None
        # Variable local para entradas refuerzo por orden.
        entradas_refuerzo_por_orden = {1: 0, 2: 0}
        # Variable local para cierres forzados.
        cierres_forzados = 0
        # Variable local para cierres extremos.
        cierres_extremos = 0
        # Variable local para cierres perdida.
        cierres_perdida = 0
        # Variable local para cierres regimen vol.
        cierres_regimen_vol = 0
        # Variable local para cierres cambio media.
        cierres_cambio_media = 0
        # Variable local para eventos extremos.
        eventos_extremos = 0
        # Variable local para puntos extremos.
        puntos_extremos: list[tuple[datetime, float]] = []
        # Variable local para puntos stop loss.
        puntos_stop_loss: list[tuple[datetime, float]] = []
        # Variable local para puntos regimen vol.
        puntos_regimen_vol: list[tuple[datetime, float]] = []
        # Variable local para puntos cambio media.
        puntos_cambio_media: list[tuple[datetime, float]] = []
        # Variable local para cooldown spans.
        cooldown_spans: list[tuple[datetime, datetime]] = []
        # Variable local para cooldown until.
        cooldown_until: datetime | None = None
        # Variable local para limite eventos extremos.
        limite_eventos_extremos = max(1, min(10, int(extreme_max_events_per_day or BACKTEST_EXTREME_MAX_EVENTS_DEFAULT)))
        # Variable local para confirmar doble tick.
        confirmar_doble_tick = bool(confirmar_segundo_tick_fuera_bandas)
        # Variable local para lado pendiente entrada.
        lado_pendiente_entrada: str | None = None
        # Variable local para ticks confirmacion entrada.
        ticks_confirmacion_entrada = 0
        # Variable local para ticks confirmacion salida.
        ticks_confirmacion_salida = 0
        # Variable local para ventana volatilidad.
        ventana_volatilidad: list[tuple[datetime, float]] = []
        # Variable local para sigma base regimen.
        sigma_base_regimen: float | None = None
        # Variable local para ventana regimen min.
        ventana_regimen_min = max(float(volatility_regime_window_minutes or 0.0), 1.0)
        # Variable local para múltiplo regimen.
        mult_regimen = max(float(volatility_regime_mult or 0.0), 0.0)
        # Variable local para indice actual loop.
        indice_actual_loop = -1

        def _stats_previos() -> tuple[float | None, float | None]:
            if indice_actual_loop < 0 or indice_actual_loop >= len(media_prev_np):
                return None, None
            media_local = media_prev_np[indice_actual_loop]
            desvio_local = desvio_prev_np[indice_actual_loop]
            if not np.isfinite(media_local) or not np.isfinite(desvio_local):
                return None, None
            return float(media_local), float(desvio_local)

        def _umbral_por_lado(media_local: float, desvio_local: float, nivel_sigma: float, lado: str) -> float:
            if lado in {"long_a_short_b", "long_cono"}:
                return media_local - desvio_local * nivel_sigma
            return media_local + desvio_local * nivel_sigma

        def _stats_ventana_actual(ts_actual: datetime) -> tuple[float | None, float | None]:
            if indice_actual_loop < 0 or indice_actual_loop >= len(media_window_np):
                return None, None
            media_local = media_window_np[indice_actual_loop]
            desvio_local = desvio_window_np[indice_actual_loop]
            if not np.isfinite(media_local) or not np.isfinite(desvio_local):
                return None, None
            return float(media_local), float(desvio_local)

        def _abrir_posicion(
            fila: dict[str, Any],
            lado: str,
            ratio_valor: float,
            nivel_sigma: float,
            *,
            es_refuerzo: bool,
            orden_refuerzo: int = 0,
            media_local: float | None = None,
            desvio_local: float | None = None,
        ) -> None:
            nonlocal media_referencia_operacion, desvio_referencia_operacion, ticks_confirmacion_entrada, ticks_confirmacion_salida, lado_pendiente_entrada
            if not posiciones_abiertas:
                # Variable local para media referencia operacion.
                media_referencia_operacion = float(media_local) if media_local is not None else None
                # Variable local para desvio referencia operacion.
                desvio_referencia_operacion = float(desvio_local) if desvio_local is not None and desvio_local > 0 else None
            posiciones_abiertas.append({
                "lado": lado,
                "entrada": fila,
                "ts_entrada": fila["ts"],
                "ratio_entrada": ratio_valor,
                "nivel_sigma": nivel_sigma,
                "es_refuerzo": es_refuerzo,
                "orden_refuerzo": orden_refuerzo,
                "media_entrada": media_local,
                "desvio_entrada": desvio_local,
            })
            if es_refuerzo and orden_refuerzo in entradas_refuerzo_por_orden:
                entradas_refuerzo_por_orden[orden_refuerzo] += 1

        def _agregar_refuerzos_si_corresponde(
            fila: dict[str, Any],
            ratio_valor: float,
            media_local: float,
            desvio_local: float,
        ) -> None:
            if not posiciones_abiertas or desvio_local <= 0 or not sigma_refuerzos_validos:
                return
            # Variable local para lado abierto.
            lado_abierto = str(posiciones_abiertas[0].get("lado") or "")
            # Variable local para niveles abiertos.
            niveles_abiertos = {round(float(pos.get("nivel_sigma") or 0.0), 9) for pos in posiciones_abiertas}
            for indice, nivel in enumerate(sigma_refuerzos_validos, start=1):
                if round(float(nivel), 9) in niveles_abiertos:
                    continue
                # Variable local para umbral.
                umbral = _umbral_por_lado(media_local, desvio_local, nivel, lado_abierto)
                if lado_abierto == "long_a_short_b" and ratio_valor <= umbral:
                    _abrir_posicion(fila, lado_abierto, ratio_valor, nivel, es_refuerzo=True, orden_refuerzo=indice, media_local=media_local, desvio_local=desvio_local)
                    niveles_abiertos.add(round(float(nivel), 9))
                elif lado_abierto == "short_a_long_b" and ratio_valor >= umbral:
                    _abrir_posicion(fila, lado_abierto, ratio_valor, nivel, es_refuerzo=True, orden_refuerzo=indice, media_local=media_local, desvio_local=desvio_local)
                    niveles_abiertos.add(round(float(nivel), 9))

        def _pnl_abierto_total(fila_actual: dict[str, Any]) -> float | None:
            if not posiciones_abiertas:
                return None
            # Variable local para total.
            total = 0.0
            # Variable local para hay.
            hay = False
            # Variable local para usar cobertura.
            usar_cobertura = bool(cobertura_stop_norm and cobertura_stop_norm != "1a1")
            for posicion in posiciones_abiertas:
                # Variable local para lado.
                lado = str(posicion.get("lado") or "")
                if usar_cobertura:
                    pnl_a, pnl_b = self._calcular_pnl_patas_backtest(lado, posicion["entrada"], fila_actual, modo_ejecucion)
                    if pnl_a is None and pnl_b is None:
                        continue
                    qty_a, qty_b, _fallback = self._calcular_factor_cobertura_backtest(
                        posicion.get("entrada") if isinstance(posicion.get("entrada"), dict) else None,
                        lado,
                        modo_ejecucion,
                        cobertura_stop_norm,
                    )
                    # Variable local para subtotal.
                    subtotal = 0.0
                    # Variable local para tuvo subtotal.
                    tuvo_subtotal = False
                    if pnl_a is not None:
                        subtotal += float(pnl_a) * float(qty_a)
                        tuvo_subtotal = True
                    if pnl_b is not None:
                        subtotal += float(pnl_b) * float(qty_b)
                        tuvo_subtotal = True
                    if not tuvo_subtotal:
                        continue
                    total += subtotal
                    hay = True
                else:
                    # Variable local para PnL.
                    pnl = self._calcular_pnl_backtest(lado, posicion["entrada"], fila_actual, modo_ejecucion)
                    if pnl is None:
                        continue
                    total += float(pnl)
                    hay = True
            return total if hay else None

        def _segmento_cruza_zona(prev_ratio: float | None, ratio_actual: float, banda_inf_local: float, banda_sup_local: float) -> bool:
            if prev_ratio is None:
                return False
            # Variable local para minimo.
            minimo = min(float(prev_ratio), float(ratio_actual))
            # Variable local para maximo.
            maximo = max(float(prev_ratio), float(ratio_actual))
            return maximo >= float(banda_inf_local) and minimo <= float(banda_sup_local)

        def _debe_cerrar_posicion(
            ratio_actual: float,
            media_local: float,
            banda_inf_local: float,
            banda_sup_local: float,
        ) -> bool:
            if not posiciones_abiertas:
                return False
            if banda_inf_local <= ratio_actual <= banda_sup_local:
                return True
            # Variable local para lado abierto.
            lado_abierto = str(posiciones_abiertas[0].get("lado") or "")
            # Variable local para prev ratio.
            prev_ratio = convertir_a_numero(historial_ratios[-1]) if historial_ratios else None
            if _segmento_cruza_zona(prev_ratio, ratio_actual, banda_inf_local, banda_sup_local):
                return True
            if lado_abierto in {"short_a_long_b", "short_cono"} and ratio_actual <= media_local:
                return True
            if lado_abierto in {"long_a_short_b", "long_cono"} and ratio_actual >= media_local:
                return True
            return False

        def _cerrar_posiciones(fila_salida: dict[str, Any], ratio_salida: float, *, estado: str = "cerrada") -> int:
            nonlocal pnl_acum, posiciones_abiertas, media_referencia_operacion, desvio_referencia_operacion, ticks_confirmacion_salida, ticks_confirmacion_entrada, lado_pendiente_entrada
            if not posiciones_abiertas:
                return 0
            # Variable local para timestamp salida.
            ts_salida = fila_salida["ts"]
            # Variable local para PnL lote.
            pnl_lote = 0.0
            # Variable local para hubo PnL.
            hubo_pnl = False
            # Variable local para cantidad.
            cantidad = len(posiciones_abiertas)
            for posicion in posiciones_abiertas:
                # Variable local para lado.
                lado = str(posicion.get("lado") or "")
                pnl_a, pnl_b = self._calcular_pnl_patas_backtest(lado, posicion["entrada"], fila_salida, modo_ejecucion)
                # Variable local para PnL.
                pnl = self._calcular_pnl_backtest(lado, posicion["entrada"], fila_salida, modo_ejecucion)
                if pnl is not None:
                    pnl_lote += float(pnl)
                    hubo_pnl = True
                operaciones.append({
                    "entrada": posicion["ts_entrada"].strftime("%H:%M"),
                    "salida": ts_salida.strftime("%H:%M"),
                    "ts_entrada": posicion["ts_entrada"],
                    "lado_codigo": lado,
                    "lado": self._texto_lado_backtest(lado, posicion.get("nivel_sigma")),
                    "ratio_entrada": posicion["ratio_entrada"],
                    "ratio_salida": ratio_salida,
                    "a_entrada": self._precio_ejecucion_backtest(posicion["entrada"], lado, "entrada", "a", modo_ejecucion),
                    "b_entrada": self._precio_ejecucion_backtest(posicion["entrada"], lado, "entrada", "b", modo_ejecucion),
                    "a_salida": self._precio_ejecucion_backtest(fila_salida, lado, "salida", "a", modo_ejecucion),
                    "b_salida": self._precio_ejecucion_backtest(fila_salida, lado, "salida", "b", modo_ejecucion),
                    "pnl_a": pnl_a,
                    "pnl_b": pnl_b,
                    "pnl": pnl,
                    "estado": estado,
                    "ts_salida": ts_salida,
                    "nivel_sigma": posicion.get("nivel_sigma"),
                    "es_refuerzo": bool(posicion.get("es_refuerzo")),
                    "orden_refuerzo": int(posicion.get("orden_refuerzo") or 0),
                })
            if hubo_pnl:
                pnl_acum += pnl_lote
                puntos_pnl.append((ts_salida, pnl_acum))
            # Variable local para posiciones abiertas.
            posiciones_abiertas = []
            ticks_confirmacion_salida = 0
            ticks_confirmacion_entrada = 0
            lado_pendiente_entrada = None
            # Variable local para media referencia operacion.
            media_referencia_operacion = None
            # Variable local para desvio referencia operacion.
            desvio_referencia_operacion = None
            return cantidad

        for idx, fila in enumerate(filas_ordenadas):
            # Marca temporal normalizada de la observación actual.
            ts = fila.get("ts")
            # Ratio calculado para la observación actual.
            ratio = _valor_senal_fila(fila)
            if not isinstance(ts, datetime) or ratio is None:
                continue
            ratio = float(ratio)
            indice_actual_loop = idx
            ventana_volatilidad.append((ts, ratio))
            # Variable local para este elemento.
            _ = _stats_ventana_actual(ts)

            ultima_fila_valida = fila
            if force_exit_ts is not None and ts <= force_exit_ts:
                fila_ultimo_antes_cierre = fila

            if modo_bandas_norm == "fija" and media_fija is not None and desvio_fijo is not None:
                media_actual, desvio_actual = media_fija, desvio_fijo
            else:
                media_actual, desvio_actual = _stats_previos()
            if media_actual is not None and desvio_actual is not None and desvio_actual > 0:
                ultima_media = media_actual
                ultimo_desvio = desvio_actual
                puntos_media.append((ts, media_actual))
                puntos_banda_sup.append((ts, media_actual + desvio_actual * sigma_mult))
                puntos_banda_inf.append((ts, media_actual - desvio_actual * sigma_mult))
                # Variable local para ancho cierre.
                ancho_cierre = desvio_actual * max(float(close_zone_pct), 0.0)
                puntos_banda_cierre_sup.append((ts, media_actual + ancho_cierre))
                puntos_banda_cierre_inf.append((ts, media_actual - ancho_cierre))
                for indice, nivel in enumerate(sigma_refuerzos_validos):
                    puntos_bandas_refuerzo_sup[indice].append((ts, media_actual + desvio_actual * nivel))
                    puntos_bandas_refuerzo_inf[indice].append((ts, media_actual - desvio_actual * nivel))

            if warmup_fin is not None and ts < warmup_fin:
                warmup_puntos += 1
                historial_ratios.append(ratio)
                continue

            if sigma_base_regimen is None and desvio_actual is not None and desvio_actual > 0:
                sigma_base_regimen = float(desvio_actual)

            if force_exit_ts is not None and ts >= force_exit_ts:
                if posiciones_abiertas:
                    # Variable local para fila cierre.
                    fila_cierre = fila_ultimo_antes_cierre or fila
                    # Variable local para ratio cierre.
                    ratio_cierre = _valor_senal_fila(fila_cierre)
                    if ratio_cierre is None:
                        ratio_cierre = ratio
                    cierres_forzados += _cerrar_posiciones(fila_cierre, float(ratio_cierre), estado="cerrada_forzada")
                break

            if media_actual is None or desvio_actual is None or desvio_actual <= 0:
                historial_ratios.append(ratio)
                continue

            # Variable local para sigma hist extremo.
            sigma_hist_extremo = float(historical_sigma_extreme) if historical_sigma_extreme is not None else None
            # Variable local para fuera extremo.
            fuera_extremo = False
            if bool(enable_extreme_close) and sigma_hist_extremo is not None and sigma_hist_extremo > 0 and extreme_sigma_mult > 0:
                # Variable local para limite extremo.
                limite_extremo = sigma_hist_extremo * float(extreme_sigma_mult)
                fuera_extremo = abs(float(ratio) - float(media_actual)) > limite_extremo

            # Variable local para restriccion extrema activa.
            restriccion_extrema_activa = isinstance(cooldown_until, datetime) and ts < cooldown_until
            if restriccion_extrema_activa:
                lado_pendiente_entrada = None
                ticks_confirmacion_entrada = 0
                historial_ratios.append(ratio)
                continue

            if fuera_extremo and sigma_hist_extremo is not None and sigma_hist_extremo > 0 and float(extreme_sigma_mult) > 0 and eventos_extremos < limite_eventos_extremos:
                lado_pendiente_entrada = None
                eventos_extremos += 1
                puntos_extremos.append((ts, ratio))
                if posiciones_abiertas:
                    cierres_extremos += _cerrar_posiciones(fila, ratio, estado="cerrada_extrema")
                # Variable local para espera extrema.
                espera_extrema = max(float(extreme_cooldown_minutes or 0.0), 0.0)
                if espera_extrema > 0:
                    cooldown_until = ts + timedelta(minutes=espera_extrema)
                    if cooldown_until > ts:
                        cooldown_spans.append((ts, cooldown_until))
                else:
                    cooldown_until = ts
                historial_ratios.append(ratio)
                continue

            # Variable local para banda sup.
            banda_sup = media_actual + desvio_actual * sigma_mult
            # Variable local para banda inf.
            banda_inf = media_actual - desvio_actual * sigma_mult
            ancho_cierre = desvio_actual * max(float(close_zone_pct), 0.0)
            # Variable local para banda cierre sup.
            banda_cierre_sup = media_actual + ancho_cierre
            # Variable local para banda cierre inf.
            banda_cierre_inf = media_actual - ancho_cierre

            if posiciones_abiertas:
                lado_pendiente_entrada = None
                # Variable local para PnL abierto.
                pnl_abierto = _pnl_abierto_total(fila)
                # Variable local para limite perdida.
                limite_perdida = max(float(loss_limit_amount or 0.0), 0.0)
                ventana_media_regimen, sigma_ventana_regimen = _stats_ventana_actual(ts)
                # Variable local para shock vol.
                shock_vol = (
                    bool(enable_volatility_regime_close)
                    and sigma_base_regimen is not None
                    and sigma_base_regimen > 0
                    and sigma_ventana_regimen is not None
                    and sigma_ventana_regimen > 0
                    and mult_regimen > 0
                    and float(sigma_ventana_regimen) > float(sigma_base_regimen) * float(mult_regimen)
                )
                # Variable local para cambio media.
                cambio_media = (
                    bool(enable_moving_mean_shift_close)
                    and media_referencia_operacion is not None
                    and desvio_referencia_operacion is not None
                    and desvio_referencia_operacion > 0
                    and float(moving_mean_shift_sigma_mult or 0.0) > 0
                    and abs(float(media_actual) - float(media_referencia_operacion)) > float(desvio_referencia_operacion) * float(moving_mean_shift_sigma_mult)
                )
                if bool(enable_loss_close) and limite_perdida > 0 and pnl_abierto is not None and float(pnl_abierto) <= -limite_perdida:
                    cierres_perdida += _cerrar_posiciones(fila, ratio, estado="cerrada_perdida")
                    puntos_stop_loss.append((ts, ratio))
                    # Variable local para espera perdida.
                    espera_perdida = max(float(loss_cooldown_minutes or 0.0), 0.0)
                    if espera_perdida > 0:
                        cooldown_until = ts + timedelta(minutes=espera_perdida)
                        if cooldown_until > ts:
                            cooldown_spans.append((ts, cooldown_until))
                    else:
                        cooldown_until = ts
                elif shock_vol:
                    cierres_regimen_vol += _cerrar_posiciones(fila, ratio, estado="cerrada_regimen_vol")
                    puntos_regimen_vol.append((ts, ratio))
                    # Variable local para espera regimen.
                    espera_regimen = max(float(volatility_regime_cooldown_minutes or 0.0), 0.0)
                    if espera_regimen > 0:
                        cooldown_until = ts + timedelta(minutes=espera_regimen)
                        if cooldown_until > ts:
                            cooldown_spans.append((ts, cooldown_until))
                    else:
                        cooldown_until = ts
                elif cambio_media:
                    cierres_cambio_media += _cerrar_posiciones(fila, ratio, estado="cerrada_cambio_media")
                    puntos_cambio_media.append((ts, ratio))
                    # Variable local para espera media.
                    espera_media = max(float(moving_mean_shift_cooldown_minutes or 0.0), 0.0)
                    if espera_media > 0:
                        cooldown_until = ts + timedelta(minutes=espera_media)
                        if cooldown_until > ts:
                            cooldown_spans.append((ts, cooldown_until))
                    else:
                        cooldown_until = ts
                elif _debe_cerrar_posicion(ratio, media_actual, banda_cierre_inf, banda_cierre_sup):
                    ticks_confirmacion_salida += 1
                    if ticks_confirmacion_salida >= exit_confirmation_ticks:
                        _cerrar_posiciones(fila, ratio, estado="cerrada")
                else:
                    ticks_confirmacion_salida = 0
                    _agregar_refuerzos_si_corresponde(fila, ratio, media_actual, desvio_actual)
                historial_ratios.append(ratio)
                continue

            # Variable local para lado senal.
            lado_senal: str | None = None
            if ratio >= banda_sup:
                lado_senal = "short_cono" if modo_senal == "cono" else "short_a_long_b"
            elif ratio <= banda_inf:
                lado_senal = "long_cono" if modo_senal == "cono" else "long_a_short_b"

            if lado_senal is None:
                lado_pendiente_entrada = None
                ticks_confirmacion_entrada = 0
            elif entry_confirmation_ticks <= 1:
                _abrir_posicion(fila, lado_senal, ratio, sigma_mult, es_refuerzo=False, orden_refuerzo=0, media_local=media_actual, desvio_local=desvio_actual)
                _agregar_refuerzos_si_corresponde(fila, ratio, media_actual, desvio_actual)
            elif lado_pendiente_entrada == lado_senal:
                ticks_confirmacion_entrada += 1
                if ticks_confirmacion_entrada >= entry_confirmation_ticks:
                    _abrir_posicion(fila, lado_senal, ratio, sigma_mult, es_refuerzo=False, orden_refuerzo=0, media_local=media_actual, desvio_local=desvio_actual)
                    _agregar_refuerzos_si_corresponde(fila, ratio, media_actual, desvio_actual)
            else:
                lado_pendiente_entrada = lado_senal
                ticks_confirmacion_entrada = 1

            historial_ratios.append(ratio)

        if posiciones_abiertas:
            fila_cierre = fila_ultimo_antes_cierre or ultima_fila_valida
            if fila_cierre is not None:
                ratio_cierre = _valor_senal_fila(fila_cierre)
                if ratio_cierre is None and puntos_ratio:
                    ratio_cierre = float(puntos_ratio[-1][1])
                if ratio_cierre is None:
                    ratio_cierre = ultima_media if ultima_media is not None else 0.0
                cierres_forzados += _cerrar_posiciones(fila_cierre, float(ratio_cierre), estado="cerrada_forzada")

        # Variable local para estados cerrados.
        estados_cerrados = {"cerrada", "cerrada_forzada", "cerrada_extrema", "cerrada_perdida", "cerrada_cambio_media"}
        # Variable local para cerradas.
        cerradas = [op for op in operaciones if op.get("estado") in estados_cerrados and op.get("pnl") is not None]
        # Variable local para PnL total.
        pnl_total = sum(float(op.get("pnl") or 0.0) for op in cerradas)
        # Variable local para aciertos.
        aciertos = sum(1 for op in cerradas if float(op.get("pnl") or 0.0) > 0)
        # Variable local para PnL promedio.
        pnl_promedio = (pnl_total / len(cerradas)) if cerradas else 0.0
        return {
            "puntos_ratio": puntos_ratio,
            "puntos_media": puntos_media,
            "puntos_banda_sup": puntos_banda_sup,
            "puntos_banda_inf": puntos_banda_inf,
            "puntos_banda_cierre_sup": puntos_banda_cierre_sup,
            "puntos_banda_cierre_inf": puntos_banda_cierre_inf,
            "puntos_bandas_refuerzo_sup": puntos_bandas_refuerzo_sup,
            "puntos_bandas_refuerzo_inf": puntos_bandas_refuerzo_inf,
            "operaciones": operaciones,
            "puntos_pnl": puntos_pnl,
            "media": ultima_media,
            "desvio": ultimo_desvio,
            "warmup_fin": warmup_fin,
            "warmup_puntos": warmup_puntos,
            "entradas_refuerzo_1": entradas_refuerzo_por_orden.get(1, 0),
            "entradas_refuerzo_2": entradas_refuerzo_por_orden.get(2, 0),
            "cierres_forzados": cierres_forzados,
            "cierres_extremos": cierres_extremos,
            "cierres_perdida": cierres_perdida,
            "cierres_regimen_vol": cierres_regimen_vol,
            "cierres_cambio_media": cierres_cambio_media,
            "eventos_extremos": eventos_extremos,
            "puntos_extremos": puntos_extremos,
            "puntos_stop_loss": puntos_stop_loss,
            "puntos_regimen_vol": puntos_regimen_vol,
            "puntos_cambio_media": puntos_cambio_media,
            "cooldown_spans": cooldown_spans,
            "historical_sigma_extreme": historical_sigma_extreme,
            "loss_limit_amount": float(loss_limit_amount or 0.0),
            "loss_cooldown_minutes": float(loss_cooldown_minutes or 0.0),
            "extreme_sigma_mult": float(extreme_sigma_mult),
            "extreme_cooldown_minutes": float(extreme_cooldown_minutes),
            "extreme_max_events_per_day": int(limite_eventos_extremos),
            "enable_extreme_close": bool(enable_extreme_close),
            "enable_loss_close": bool(enable_loss_close),
            "enable_volatility_regime_close": bool(enable_volatility_regime_close),
            "volatility_regime_window_minutes": float(ventana_regimen_min),
            "volatility_regime_mult": float(mult_regimen),
            "volatility_regime_cooldown_minutes": float(volatility_regime_cooldown_minutes or 0.0),
            "sigma_base_regimen": sigma_base_regimen,
            "enable_moving_mean_shift_close": bool(enable_moving_mean_shift_close),
            "moving_mean_shift_sigma_mult": float(moving_mean_shift_sigma_mult or 0.0),
            "moving_mean_shift_cooldown_minutes": float(moving_mean_shift_cooldown_minutes or 0.0),
            "bloqueo_extremos_resto_dia": False,
            "force_exit_ts": force_exit_ts,
            "pnl_total": pnl_total,
            "pnl_promedio": pnl_promedio,
            "aciertos": aciertos,
            "abiertas": 0,
            "sigma_refuerzos": sigma_refuerzos_validos,
            "modo_bandas": modo_bandas_norm,
            "confirmar_segundo_tick_fuera_bandas": bool(confirmar_doble_tick),
            "signal_mode": modo_senal,
            "signal_label": "Cono last A+B" if modo_senal == "cono" else "Ratio A/B",
        }

    # Devuelve el texto descriptivo para modo cobertura backtest.
    def _texto_modo_cobertura_backtest(self, modo: str) -> str:
        # Variable local para etiquetas.
        etiquetas = {
            "1a1": "1 a 1",
            "precio": "Precio",
            "delta": "Delta",
            "vega": "Vega",
        }
        return etiquetas.get(str(modo or "").strip(), "Precio")

    # Función auxiliar para inferir lado codigo backtest.
    def _inferir_lado_codigo_backtest(self, operacion: dict[str, Any]) -> str:
        # Variable local para lado codigo.
        lado_codigo = str(operacion.get("lado_codigo") or "").strip()
        if lado_codigo in {"long_a_short_b", "short_a_long_b", "long_cono", "short_cono"}:
            return lado_codigo
        # Texto temporal usado para armar o normalizar información.
        texto = str(operacion.get("lado") or "").lower()
        if texto.startswith("comprar a + comprar b"):
            return "long_cono"
        if texto.startswith("vender a + vender b"):
            return "short_cono"
        if texto.startswith("comprar a"):
            return "long_a_short_b"
        return "short_a_long_b"

    # Función auxiliar para calcular factor cobertura backtest.
    def _calcular_factor_cobertura_backtest(self, fila_entrada: dict[str, Any] | None, lado_codigo: str, modo_ejecucion: str, modo_cobertura: str) -> tuple[float, float, bool]:
        # Variable local para modo.
        modo = str(modo_cobertura or "precio").strip().lower()
        if modo == "1a1":
            return 1.0, 1.0, False
        if not isinstance(fila_entrada, dict):
            return 1.0, 1.0, True
        # Variable local para numerador.
        numerador = None
        # Variable local para denominador.
        denominador = None
        if modo == "precio":
            numerador = self._precio_ejecucion_backtest(fila_entrada, lado_codigo, "entrada", "a", modo_ejecucion)
            denominador = self._precio_ejecucion_backtest(fila_entrada, lado_codigo, "entrada", "b", modo_ejecucion)
        elif modo == "delta":
            numerador = convertir_a_numero(fila_entrada.get("a_delta"))
            denominador = convertir_a_numero(fila_entrada.get("b_delta"))
        elif modo == "vega":
            numerador = convertir_a_numero(fila_entrada.get("a_vega"))
            denominador = convertir_a_numero(fila_entrada.get("b_vega"))
        else:
            numerador = self._precio_ejecucion_backtest(fila_entrada, lado_codigo, "entrada", "a", modo_ejecucion)
            denominador = self._precio_ejecucion_backtest(fila_entrada, lado_codigo, "entrada", "b", modo_ejecucion)
        try:
            if numerador is None or denominador is None or abs(float(denominador)) <= 1e-12:
                return 1.0, 1.0, True
            # Variable local para cantidad B.
            qty_b = abs(float(numerador)) / abs(float(denominador))
            if not math.isfinite(qty_b) or qty_b <= 0:
                return 1.0, 1.0, True
            return 1.0, float(qty_b), False
        except Exception:
            return 1.0, 1.0, True

    def _aplicar_cobertura_a_operaciones_backtest(
        self,
        operaciones: list[dict[str, Any]],
        filas_intradia: list[dict[str, Any]],
        *,
        modo_ejecucion: str,
        modo_cobertura: str,
    ) -> tuple[list[dict[str, Any]], list[tuple[datetime, float]], dict[str, Any]]:
        """Recalcula el PnL del backtest usando tamaños cubiertos sin alterar la señal base."""
        # Variable local para filas por timestamp.
        filas_por_ts: dict[datetime, dict[str, Any]] = {}
        # Variable local para filas por hora.
        filas_por_hora: dict[str, dict[str, Any]] = {}
        for fila in filas_intradia:
            # Marca temporal normalizada de la observación actual.
            ts = fila.get("ts")
            if isinstance(ts, datetime):
                filas_por_ts[ts] = fila
                filas_por_hora[ts.strftime("%H:%M")] = fila
        # Variable local para salida.
        salida: list[dict[str, Any]] = []
        # Variable local para puntos PnL.
        puntos_pnl: list[tuple[datetime, float]] = []
        # Variable local para PnL acum.
        pnl_acum = 0.0
        # Variable local para fallback count.
        fallback_count = 0
        # Variable local para cantidad B vals.
        qty_b_vals: list[float] = []
        for operacion in list(operaciones or []):
            # Variable local para op.
            op = dict(operacion)
            # Variable local para lado codigo.
            lado_codigo = self._inferir_lado_codigo_backtest(op)
            # Variable local para timestamp entrada.
            ts_entrada = op.get("ts_entrada")
            # Variable local para fila entrada.
            fila_entrada = filas_por_ts.get(ts_entrada) if isinstance(ts_entrada, datetime) else None
            if fila_entrada is None:
                fila_entrada = filas_por_hora.get(str(op.get("entrada") or "").strip())
            qty_a, qty_b, fallback = self._calcular_factor_cobertura_backtest(fila_entrada, lado_codigo, modo_ejecucion, modo_cobertura)
            if fallback:
                fallback_count += 1
            qty_b_vals.append(float(qty_b))
            # Variable local para PnL A base.
            pnl_a_base = convertir_a_numero(op.get("pnl_a"))
            # Variable local para PnL B base.
            pnl_b_base = convertir_a_numero(op.get("pnl_b"))
            # Variable local para PnL A.
            pnl_a = float(pnl_a_base) * float(qty_a) if pnl_a_base is not None else None
            # Variable local para PnL B.
            pnl_b = float(pnl_b_base) * float(qty_b) if pnl_b_base is not None else None
            # Variable local para PnL total.
            pnl_total = None
            if pnl_a is not None and pnl_b is not None:
                pnl_total = float(pnl_a) + float(pnl_b)
            op["qty_a"] = float(qty_a)
            op["qty_b"] = float(qty_b)
            op["metodo_cobertura"] = self._texto_modo_cobertura_backtest(modo_cobertura)
            op["pnl_a"] = pnl_a
            op["pnl_b"] = pnl_b
            op["pnl"] = pnl_total
            salida.append(op)
            # Variable local para timestamp salida.
            ts_salida = op.get("ts_salida")
            if isinstance(ts_salida, datetime) and pnl_total is not None and str(op.get("estado") or "") in {"cerrada", "cerrada_forzada", "cerrada_extrema", "cerrada_perdida", "cerrada_cambio_media", "cerrada_regimen_vol"}:
                pnl_acum += float(pnl_total)
                puntos_pnl.append((ts_salida, pnl_acum))
        estados_cerrados = {"cerrada", "cerrada_forzada", "cerrada_extrema", "cerrada_perdida", "cerrada_cambio_media", "cerrada_regimen_vol"}
        pnl_cerradas = _np_float_array(
            op.get("pnl") if str(op.get("estado") or "") in estados_cerrados else None
            for op in salida
        )
        mask_cerradas = np.isfinite(pnl_cerradas)
        pnl_total = float(np.nansum(pnl_cerradas)) if np.any(mask_cerradas) else 0.0
        pnl_promedio = float(np.nanmean(pnl_cerradas)) if np.any(mask_cerradas) else 0.0
        aciertos = int(np.sum(pnl_cerradas[mask_cerradas] > 0.0)) if np.any(mask_cerradas) else 0
        qty_b_arr = _np_float_array(qty_b_vals)
        resumen = {
            "pnl_total": float(pnl_total),
            "pnl_promedio": float(pnl_promedio),
            "aciertos": int(aciertos),
            "fallbacks_cobertura": int(fallback_count),
            "qty_b_promedio": float(np.nanmean(qty_b_arr)) if np.any(np.isfinite(qty_b_arr)) else 0.0,
            "cantidad_operaciones": len(salida),
        }
        return salida, puntos_pnl, resumen

    def _formatear_valor_backtest(self, columna: str, valor: Any) -> str:
        """Formatea la tabla de operaciones del backtest intradía."""
        if valor is None:
            return ""
        if columna in {"entrada", "salida", "lado", "estado"}:
            return str(valor)
        try:
            if columna in {"ratio_entrada", "ratio_salida"}:
                # Variable local para precision.
                precision = self._precision_senal_backtest(getattr(self, "_backtest_table_signal_mode", "ratio"))
                return f"{float(valor):.{precision}f}"
            return f"{float(valor):.2f}"
        except Exception:
            return str(valor)

    def _cargar_tree_backtest(self, operaciones: list[dict[str, Any]]) -> None:
        """Carga la tabla de operaciones del backtest intradía."""
        # Variable local para tree.
        tree = getattr(self, "tree_backtest", None)
        if tree is None:
            return
        self._actualizar_headings_tree_backtest(tree, getattr(self, "_backtest_table_signal_mode", "ratio"))
        tree.delete(*tree.get_children())
        # Variable local para total PnL A.
        total_pnl_a = 0.0
        # Variable local para total PnL B.
        total_pnl_b = 0.0
        # Variable local para total PnL.
        total_pnl = 0.0
        # Variable local para hay totales.
        hay_totales = False
        for idx, fila in enumerate(operaciones):
            # Colección temporal de valores usada en este cálculo.
            valores = [self._formatear_valor_backtest(col, fila.get(col)) for col in self.BACKTEST_COLUMNAS]
            # Variable local para tags.
            tags: list[str] = []
            # Variable local para estado.
            estado = str(fila.get("estado") or "")
            # Variable local para PnL.
            pnl = convertir_a_numero(fila.get("pnl"))
            # Variable local para PnL A.
            pnl_a = convertir_a_numero(fila.get("pnl_a"))
            # Variable local para PnL B.
            pnl_b = convertir_a_numero(fila.get("pnl_b"))
            if pnl_a is not None:
                total_pnl_a += float(pnl_a)
                hay_totales = True
            if pnl_b is not None:
                total_pnl_b += float(pnl_b)
                hay_totales = True
            if pnl is not None:
                total_pnl += float(pnl)
                hay_totales = True
            if estado == "abierta":
                tags.append("abierta")
            elif pnl is not None and float(pnl) > 0:
                tags.append("ganadora")
            elif pnl is not None and float(pnl) < 0:
                tags.append("perdedora")
            tags.append("par" if idx % 2 == 0 else "impar")
            tree.insert("", END, iid=f"backtest_{idx}", values=valores, tags=tuple(tags))
        if operaciones and hay_totales:
            # Variable local para fila totales.
            fila_totales = {col: "" for col in self.BACKTEST_COLUMNAS}
            fila_totales["lado"] = "TOTAL"
            fila_totales["pnl_a"] = total_pnl_a
            fila_totales["pnl_b"] = total_pnl_b
            fila_totales["pnl"] = total_pnl
            # Variable local para valores totales.
            valores_totales = [self._formatear_valor_backtest(col, fila_totales.get(col)) for col in self.BACKTEST_COLUMNAS]
            tree.insert("", END, iid="backtest_totales", values=valores_totales, tags=("totales",))
        self._reaplicar_orden_tree(tree)

    def _formatear_valor_backtest_hedge(self, columna: str, valor: Any) -> str:
        """Formatea la tabla del backtest con cobertura."""
        if valor is None:
            return ""
        if columna in {"entrada", "salida", "lado", "estado", "metodo_cobertura"}:
            return str(valor)
        try:
            if columna in {"qty_a", "qty_b"}:
                return f"{float(valor):.3f}"
            if columna in {"ratio_entrada", "ratio_salida"}:
                # Variable local para precision.
                precision = self._precision_senal_backtest(getattr(self, "_backtest_hedge_table_signal_mode", "ratio"))
                return f"{float(valor):.{precision}f}"
            return f"{float(valor):.2f}"
        except Exception:
            return str(valor)

    def _crear_tree_backtest_hedge(self, parent, height: int = 10):
        """Crea la tabla de operaciones del backtest con cobertura."""
        # Variable local para tree.
        tree = self._crear_treeview_con_scrollbars(parent, self.HEDGE_BACKTEST_COLUMNAS, height)
        # Variable local para anchos.
        anchos = {
            "entrada": 78,
            "salida": 78,
            "lado": 190,
            "ratio_entrada": 90,
            "ratio_salida": 90,
            "qty_a": 62,
            "qty_b": 72,
            "metodo_cobertura": 98,
            "a_entrada": 80,
            "b_entrada": 80,
            "a_salida": 80,
            "b_salida": 80,
            "pnl_a": 86,
            "pnl_b": 86,
            "pnl": 90,
            "estado": 92,
        }
        # Colección temporal de textos usada para normalizar información.
        textos = {
            "entrada": "Entrada",
            "salida": "Salida",
            "lado": "Estrategia",
            "ratio_entrada": "Ratio ent.",
            "ratio_salida": "Ratio sal.",
            "qty_a": "Qty A",
            "qty_b": "Qty B",
            "metodo_cobertura": "Cobertura",
            "a_entrada": "A ent.",
            "b_entrada": "B ent.",
            "a_salida": "A sal.",
            "b_salida": "B sal.",
            "pnl_a": "PnL A",
            "pnl_b": "PnL B",
            "pnl": "PnL",
            "estado": "Estado",
        }
        for columna in self.HEDGE_BACKTEST_COLUMNAS:
            # Variable local para anchor.
            anchor = W if columna in {"entrada", "salida", "lado", "estado", "metodo_cobertura"} else "e"
            tree.column(columna, width=anchos[columna], anchor=anchor, stretch=(columna == "lado"))
        self._registrar_tree_ordenable(tree, textos)
        tree.tag_configure("ganadora", background="#eefcf0")
        tree.tag_configure("perdedora", background="#fff2f2")
        tree.tag_configure("abierta", background="#fff9e8")
        tree.tag_configure("totales", background="#eaf1ff")
        tree.tag_configure("par", background="#fbfbfb")
        tree.tag_configure("impar", background="#f2f2f2")
        return tree

    def _cargar_tree_backtest_hedge(self, operaciones: list[dict[str, Any]]) -> None:
        """Carga la tabla de operaciones del backtest con cobertura."""
        # Variable local para tree.
        tree = getattr(self, "tree_backtest_hedge", None)
        if tree is None:
            return
        self._actualizar_headings_tree_backtest(tree, getattr(self, "_backtest_hedge_table_signal_mode", "ratio"))
        tree.delete(*tree.get_children())
        # Variable local para total PnL A.
        total_pnl_a = 0.0
        # Variable local para total PnL B.
        total_pnl_b = 0.0
        # Variable local para total PnL.
        total_pnl = 0.0
        # Variable local para hay totales.
        hay_totales = False
        for idx, fila in enumerate(operaciones):
            # Colección temporal de valores usada en este cálculo.
            valores = [self._formatear_valor_backtest_hedge(col, fila.get(col)) for col in self.HEDGE_BACKTEST_COLUMNAS]
            # Variable local para tags.
            tags: list[str] = []
            # Variable local para estado.
            estado = str(fila.get("estado") or "")
            # Variable local para PnL.
            pnl = convertir_a_numero(fila.get("pnl"))
            # Variable local para PnL A.
            pnl_a = convertir_a_numero(fila.get("pnl_a"))
            # Variable local para PnL B.
            pnl_b = convertir_a_numero(fila.get("pnl_b"))
            if pnl_a is not None:
                total_pnl_a += float(pnl_a)
                hay_totales = True
            if pnl_b is not None:
                total_pnl_b += float(pnl_b)
                hay_totales = True
            if pnl is not None:
                total_pnl += float(pnl)
                hay_totales = True
            if estado == "abierta":
                tags.append("abierta")
            elif pnl is not None and float(pnl) > 0:
                tags.append("ganadora")
            elif pnl is not None and float(pnl) < 0:
                tags.append("perdedora")
            tags.append("par" if idx % 2 == 0 else "impar")
            tree.insert("", END, iid=f"backtest_hedge_{idx}", values=valores, tags=tuple(tags))
        if operaciones and hay_totales:
            # Variable local para fila totales.
            fila_totales = {col: "" for col in self.HEDGE_BACKTEST_COLUMNAS}
            fila_totales["lado"] = "TOTAL"
            fila_totales["pnl_a"] = total_pnl_a
            fila_totales["pnl_b"] = total_pnl_b
            fila_totales["pnl"] = total_pnl
            # Variable local para valores totales.
            valores_totales = [self._formatear_valor_backtest_hedge(col, fila_totales.get(col)) for col in self.HEDGE_BACKTEST_COLUMNAS]
            tree.insert("", END, iid="backtest_hedge_totales", values=valores_totales, tags=("totales",))
        self._reaplicar_orden_tree(tree)

    def _refrescar_backtest_intradia(
        self,
        filas_calls: list[dict[str, Any]],
        filas_puts: list[dict[str, Any]],
        _info: dict[str, Any],
        *,
        forzar: bool = False,
    ) -> None:
        """Refresca la vista de backtest intradía de reversión a la media."""
        self._sincronizar_aliases_backtest_activos()
        # Variable local para slot.
        slot = self._tab_backtest_activa_indice()
        # Variable local para widgets.
        widgets = self._backtest_widgets.get(slot, {})
        if not widgets:
            return
        # Variable local para fecha bt original.
        fecha_bt_original = self.var_backtest_fecha.get().strip()
        # Variable local para fecha bt.
        fecha_bt = self._resolver_fecha_historial(fecha_bt_original)
        if fecha_bt != fecha_bt_original:
            self.var_backtest_fecha.set(fecha_bt)
        # Variable local para ticker A.
        ticker_a = self.var_backtest_a.get().strip()
        # Variable local para ticker B.
        ticker_b = self.var_backtest_b.get().strip()
        # Variable local para modo ejecucion.
        modo_ejecucion = self.var_backtest_exec_mode.get().strip() or "last"
        # Variable local para modo bandas.
        modo_bandas = self.var_backtest_band_mode.get().strip() or "dinamica"
        # Variable local para sigma extrema múltiplo.
        sigma_extrema_mult = self._leer_sigma_extrema_backtest(confirmar=False)
        # Variable local para espera extrema min.
        espera_extrema_min = self._leer_espera_extrema_backtest(confirmar=False)
        # Variable local para max eventos extremos dia.
        max_eventos_extremos_dia = self._leer_limite_eventos_extremos_backtest()
        # Variable local para extrema habilitada.
        extrema_habilitada = bool(self.var_backtest_extreme_enabled.get())
        self.var_backtest_extreme_enabled_button.set(self._texto_toggle_backtest_cierre("Cierre extremo", extrema_habilitada))
        # Variable local para perdida habilitada.
        perdida_habilitada = bool(self.var_backtest_loss_enabled.get())
        self.var_backtest_loss_enabled_button.set(self._texto_toggle_backtest_cierre("Stop pérdida", perdida_habilitada))
        # Variable local para perdida maxima.
        perdida_maxima = self._leer_perdida_maxima_backtest(confirmar=False)
        # Variable local para espera perdida min.
        espera_perdida_min = self._leer_espera_perdida_backtest(confirmar=False)
        # Variable local para shock vol habilitado.
        shock_vol_habilitado = False
        # Variable local para shock vol ventana.
        shock_vol_ventana = 0.0
        # Variable local para shock vol múltiplo.
        shock_vol_mult = 0.0
        # Variable local para shock vol espera.
        shock_vol_espera = 0.0
        # Variable local para media shift habilitado.
        media_shift_habilitado = bool(self.var_backtest_media_shift_enabled.get())
        self.var_backtest_media_shift_enabled_button.set(self._texto_toggle_backtest_cierre("Cambio media", media_shift_habilitado))
        # Variable local para media shift sigma.
        media_shift_sigma = self._leer_sigma_cambio_media_backtest(confirmar=False)
        # Variable local para media shift espera.
        media_shift_espera = self._leer_espera_cambio_media_backtest(confirmar=False)
        # Variable local para ticks entrada.
        ticks_entrada = self._leer_ticks_confirmacion_backtest(self.var_backtest_entry_ticks, 2 if bool(self.var_backtest_confirm_second_tick.get()) else 1)
        # Variable local para ticks salida.
        ticks_salida = self._leer_ticks_confirmacion_backtest(self.var_backtest_exit_ticks, 1)
        # Variable local para confirmar segundo tick.
        confirmar_segundo_tick = bool(ticks_entrada >= 2)
        self.var_backtest_confirm_second_tick.set(confirmar_segundo_tick)
        self.var_backtest_confirm_second_tick_button.set(self._texto_confirmacion_entrada_backtest(confirmar_segundo_tick))
        # Variable local para modo serie var.
        modo_serie_var = self._backtest_series_mode_vars[slot]
        # Variable local para modo serie btn var.
        modo_serie_btn_var = self._backtest_series_mode_button_vars[slot]
        # Variable local para modo serie.
        modo_serie = modo_serie_var.get().strip().lower() or "ratio"
        if modo_serie not in {"ratio", "cono"}:
            modo_serie = "ratio"
            modo_serie_var.set(modo_serie)
        modo_serie_btn_var.set(self._texto_modo_serie_backtest(modo_serie))
        self._backtest_table_signal_mode = modo_serie
        if modo_bandas not in {"dinamica", "fija"}:
            modo_bandas = "dinamica"
            self.var_backtest_band_mode.set(modo_bandas)
        self.var_backtest_band_mode_button.set(self._texto_modo_bandas_backtest(modo_bandas))
        # Variable local para sigma múltiplo.
        sigma_mult = self._leer_sigma_backtest(confirmar=False)
        # Variable local para sigma refuerzos.
        sigma_refuerzos = self._leer_sigmas_refuerzo_backtest(sigma_mult)
        # Variable local para hora inicio test.
        hora_inicio_test = self._leer_hora_backtest(self.var_backtest_hora_inicio, BACKTEST_DEFAULT_START_TIME)
        # Variable local para hora cierre test.
        hora_cierre_test = self._leer_hora_backtest(self.var_backtest_hora_cierre, BACKTEST_DEFAULT_END_TIME)
        # Variable local para intervalo backtest minutos.
        intervalo_backtest_min = self._leer_intervalo_backtest_minutos()
        inicio_test_dt, cierre_test_dt = self._construir_limites_intradia(fecha_bt, hora_inicio_test, hora_cierre_test)
        if inicio_test_dt is not None and cierre_test_dt is not None and cierre_test_dt <= inicio_test_dt:
            try:
                # Variable local para nuevo cierre.
                nuevo_cierre = min(inicio_test_dt + timedelta(minutes=5), datetime.strptime(f"{fecha_bt} {BACKTEST_SESSION_END_TIME}:00", "%Y-%m-%d %H:%M:%S"))
                hora_cierre_test = nuevo_cierre.strftime("%H:%M")
            except Exception:
                hora_cierre_test = BACKTEST_DEFAULT_END_TIME
            self.var_backtest_hora_cierre.set(hora_cierre_test)
            _inicio_tmp, _fin_tmp = self._construir_limites_intradia(fecha_bt, hora_inicio_test, hora_cierre_test)
            # Variable local para inicio test dt.
            inicio_test_dt = _inicio_tmp or inicio_test_dt
            # Variable local para cierre test dt.
            cierre_test_dt = _fin_tmp or cierre_test_dt
        # Variable local para opciones.
        opciones = self._listar_bases_disponibles_vencimiento(filas_calls, filas_puts, fecha_hist=(fecha_bt or None))
        # Variable local para ax ratio.
        ax_ratio = widgets.get("ax_ratio")
        # Variable local para ax PnL.
        ax_pnl = widgets.get("ax_pnl")
        # Variable local para canvas.
        canvas = widgets.get("canvas")
        if not fecha_bt or ticker_a not in opciones or ticker_b not in opciones or not ticker_a or not ticker_b:
            for ax in (ax_ratio, ax_pnl):
                if ax is None:
                    continue
                ax.clear()
                ax.text(0.5, 0.5, "Elegí día y dos bases activas del vencimiento", ha="center", va="center")
                ax.set_axis_off()
            if canvas is not None:
                canvas.draw_idle()
            self._cargar_tree_backtest([])
            self.var_backtest_info.set(
                "Backtest cobertura: elegí un día con snapshots y dos bases activas. La señal puede usar el ratio last A/B o el cono last A+B, alternar entre bandas dinámicas y fijas, definir horario de inicio y cierre, sumar hasta dos aumentos, cerrar cerca de la media elegida, cortar por extremos históricos configurables, por pérdida monetaria máxima o por desplazamiento de la media dinámica, cada uno con pausa posterior configurable y botón de activación."
            )
            self._invalidar_cache_backtest()
            return
        sigma_hist_extrema, puntos_hist_extrema = (self._calcular_sigma_historico_cono_backtest(ticker_a, ticker_b) if modo_serie == "cono" else self._calcular_sigma_historico_backtest(ticker_a, ticker_b))
        # Caché en memoria para clave cache.
        clave_cache = (
            fecha_bt,
            ticker_a,
            ticker_b,
            modo_ejecucion,
            round(float(sigma_mult), 6),
            tuple(round(float(valor), 6) for valor in sigma_refuerzos),
            hora_inicio_test,
            hora_cierre_test,
            int(intervalo_backtest_min),
            int(ticks_entrada),
            int(ticks_salida),
            modo_bandas,
            round(float(espera_extrema_min), 6),
            round(float(sigma_extrema_mult), 6),
            int(max_eventos_extremos_dia),
            round(float(sigma_hist_extrema), 8) if sigma_hist_extrema is not None else None,
            int(puntos_hist_extrema),
            BACKTEST_CLOSE_ZONE_PCT_OF_SIGMA,
            bool(confirmar_segundo_tick),
            modo_serie,
            bool(extrema_habilitada),
            round(float(perdida_maxima), 6),
            round(float(espera_perdida_min), 6),
            bool(perdida_habilitada),
            bool(media_shift_habilitado),
            round(float(media_shift_sigma), 6),
            round(float(media_shift_espera), 6),
        )
        if (not forzar) and clave_cache == self._backtest_cache_key and self._backtest_cache_result is not None and self._backtest_render_signature.get(slot) == clave_cache:
            return
        # Variable local para filas intradía.
        filas_intradia = self._history_db.obtener_filas_intradia_par(
            fecha_bt,
            ticker_a,
            ticker_b,
            hora_desde=BACKTEST_SESSION_START_TIME,
            hora_hasta=hora_cierre_test,
        )
        filas_intradia = self._resamplear_filas_backtest_intradia(filas_intradia, intervalo_backtest_min)
        # Resultado acumulado o final del cálculo.
        resultado = self._simular_backtest_ratio_intradia(
            filas_intradia,
            sigma_mult=sigma_mult,
            sigma_refuerzos=sigma_refuerzos,
            modo_ejecucion=modo_ejecucion,
            fecha=fecha_bt,
            hora_inicio_test=hora_inicio_test,
            hora_cierre_test=hora_cierre_test,
            close_zone_pct=BACKTEST_CLOSE_ZONE_PCT_OF_SIGMA,
            modo_bandas=modo_bandas,
            historical_sigma_extreme=sigma_hist_extrema,
            extreme_sigma_mult=sigma_extrema_mult,
            extreme_cooldown_minutes=espera_extrema_min,
            extreme_max_events_per_day=max_eventos_extremos_dia,
            confirmar_segundo_tick_fuera_bandas=confirmar_segundo_tick,
            entry_confirmation_ticks=ticks_entrada,
            exit_confirmation_ticks=ticks_salida,
            loss_limit_amount=perdida_maxima,
            loss_cooldown_minutes=espera_perdida_min,
            enable_extreme_close=extrema_habilitada,
            enable_loss_close=perdida_habilitada,
            enable_volatility_regime_close=False,
            volatility_regime_window_minutes=0.0,
            volatility_regime_mult=0.0,
            volatility_regime_cooldown_minutes=0.0,
            enable_moving_mean_shift_close=media_shift_habilitado,
            moving_mean_shift_sigma_mult=media_shift_sigma,
            moving_mean_shift_cooldown_minutes=media_shift_espera,
            signal_mode=modo_serie,
        )
        self._capturar_vistas((f"backtest{slot}_ratio", f"backtest{slot}_pnl"))
        ax_ratio.clear()
        ax_pnl.clear()
        # Variable local para puntos ratio.
        puntos_ratio = list(resultado.get("puntos_ratio") or [])
        # Variable local para media.
        media = resultado.get("media")
        # Variable local para warmup fin.
        warmup_fin = resultado.get("warmup_fin")
        # Variable local para force exit timestamp.
        force_exit_ts = resultado.get("force_exit_ts")
        inicio_sesion, fin_sesion = self._construir_limites_intradia(fecha_bt, BACKTEST_SESSION_START_TIME, hora_cierre_test)

        def _plot_series(ax: Any, puntos: list[tuple[datetime, float]], **kwargs: Any) -> None:
            if not puntos:
                return
            ax.plot([ts for ts, _ in puntos], [float(valor) for _, valor in puntos], **kwargs)

        def _fill_between(ax: Any, sup: list[tuple[datetime, float]], inf: list[tuple[datetime, float]], *, alpha: float) -> None:
            if not sup or not inf:
                return
            # Variable local para largos.
            largos = min(len(sup), len(inf))
            if largos <= 0:
                return
            # Variable local para xs.
            xs = [sup[i][0] for i in range(largos)]
            # Variable local para ys sup.
            ys_sup = [float(sup[i][1]) for i in range(largos)]
            # Variable local para ys inf.
            ys_inf = [float(inf[i][1]) for i in range(largos)]
            ax.fill_between(xs, ys_inf, ys_sup, alpha=alpha)

        if puntos_ratio:
            # Variable local para xs.
            xs = [ts for ts, _ in puntos_ratio]
            # Variable local para ys.
            ys = [float(valor) for _, valor in puntos_ratio]
            ax_ratio.plot(xs, ys, linewidth=1.2)
            # Variable local para puntos media.
            puntos_media = list(resultado.get("puntos_media") or [])
            # Variable local para puntos banda sup.
            puntos_banda_sup = list(resultado.get("puntos_banda_sup") or [])
            # Variable local para puntos banda inf.
            puntos_banda_inf = list(resultado.get("puntos_banda_inf") or [])
            # Variable local para puntos banda cierre sup.
            puntos_banda_cierre_sup = list(resultado.get("puntos_banda_cierre_sup") or [])
            # Variable local para puntos banda cierre inf.
            puntos_banda_cierre_inf = list(resultado.get("puntos_banda_cierre_inf") or [])
            _fill_between(ax_ratio, puntos_banda_sup, puntos_banda_inf, alpha=0.10)
            _fill_between(ax_ratio, puntos_banda_cierre_sup, puntos_banda_cierre_inf, alpha=0.07)
            _plot_series(ax_ratio, puntos_media, linestyle="--", linewidth=1.0, alpha=0.9)
            _plot_series(ax_ratio, puntos_banda_sup, linestyle=":", linewidth=0.9, alpha=0.8)
            _plot_series(ax_ratio, puntos_banda_inf, linestyle=":", linewidth=0.9, alpha=0.8)
            _plot_series(ax_ratio, puntos_banda_cierre_sup, linestyle="-.", linewidth=0.8, alpha=0.6)
            _plot_series(ax_ratio, puntos_banda_cierre_inf, linestyle="-.", linewidth=0.8, alpha=0.6)
            # Variable local para bandas ref sup.
            bandas_ref_sup = list(resultado.get("puntos_bandas_refuerzo_sup") or [])
            # Variable local para bandas ref inf.
            bandas_ref_inf = list(resultado.get("puntos_bandas_refuerzo_inf") or [])
            for serie_sup, serie_inf in zip(bandas_ref_sup, bandas_ref_inf):
                _plot_series(ax_ratio, list(serie_sup), linestyle="-.", linewidth=0.8, alpha=0.55)
                _plot_series(ax_ratio, list(serie_inf), linestyle="-.", linewidth=0.8, alpha=0.55)
            if inicio_sesion is not None and warmup_fin is not None and warmup_fin > inicio_sesion:
                ax_ratio.axvspan(inicio_sesion, warmup_fin, alpha=0.10)
                ax_ratio.axvline(warmup_fin, linestyle="--", linewidth=0.9, alpha=0.7)
            if isinstance(force_exit_ts, datetime):
                ax_ratio.axvline(force_exit_ts, linestyle="--", linewidth=0.9, alpha=0.7)
            for inicio_cd, fin_cd in list(resultado.get("cooldown_spans") or []):
                if isinstance(inicio_cd, datetime) and isinstance(fin_cd, datetime) and fin_cd > inicio_cd:
                    ax_ratio.axvspan(inicio_cd, fin_cd, alpha=0.06)
            for ts_ext, ratio_ext in list(resultado.get("puntos_extremos") or []):
                if isinstance(ts_ext, datetime):
                    ax_ratio.scatter([ts_ext], [float(ratio_ext)], s=34, marker="x")
            for ts_stop, ratio_stop in list(resultado.get("puntos_stop_loss") or []):
                if isinstance(ts_stop, datetime):
                    ax_ratio.scatter([ts_stop], [float(ratio_stop)], s=34, marker="v")
            for ts_reg, ratio_reg in list(resultado.get("puntos_regimen_vol") or []):
                if isinstance(ts_reg, datetime):
                    ax_ratio.scatter([ts_reg], [float(ratio_reg)], s=38, marker="P")
            for ts_media, ratio_media in list(resultado.get("puntos_cambio_media") or []):
                if isinstance(ts_media, datetime):
                    ax_ratio.scatter([ts_media], [float(ratio_media)], s=36, marker="X")
            for operacion in resultado.get("operaciones") or []:
                # Variable local para entrada txt.
                entrada_txt = str(operacion.get("entrada") or "")
                # Variable local para ratio ent.
                ratio_ent = convertir_a_numero(operacion.get("ratio_entrada"))
                if entrada_txt and ratio_ent is not None:
                    try:
                        # Variable local para timestamp ent.
                        ts_ent = datetime.strptime(f"{fecha_bt} {entrada_txt}:00", "%Y-%m-%d %H:%M:%S")
                        # Variable local para orden refuerzo.
                        orden_refuerzo = int(operacion.get("orden_refuerzo") or 0)
                        # Variable local para marker.
                        marker = "^" if orden_refuerzo == 0 else ("s" if orden_refuerzo == 1 else "D")
                        ax_ratio.scatter([ts_ent], [float(ratio_ent)], s=30, marker=marker)
                    except Exception:
                        pass
                # Variable local para salida txt.
                salida_txt = str(operacion.get("salida") or "")
                # Variable local para ratio sal.
                ratio_sal = convertir_a_numero(operacion.get("ratio_salida"))
                if salida_txt and ratio_sal is not None:
                    try:
                        # Variable local para timestamp sal.
                        ts_sal = datetime.strptime(f"{fecha_bt} {salida_txt}:00", "%Y-%m-%d %H:%M:%S")
                        ax_ratio.scatter([ts_sal], [float(ratio_sal)], s=28, marker="o")
                    except Exception:
                        pass
            # Variable local para signal label.
            signal_label = str(resultado.get("signal_label") or self._descripcion_serie_backtest(modo_serie))
            # Variable local para sufijo modo.
            sufijo_modo = "dinámico" if modo_bandas == "dinamica" else "fijo"
            ax_ratio.set_title(f"Backtest {signal_label.lower()} {sufijo_modo} | {ticker_a} / {ticker_b}")
            ax_ratio.set_ylabel(signal_label)
            ax_ratio.grid(True, alpha=0.3)
            self._aplicar_eje_intradia(ax_ratio, inicio_sesion or puntos_ratio[0][0], fin_sesion or puntos_ratio[-1][0])
        else:
            ax_ratio.text(0.5, 0.5, "Sin datos suficientes para el backtest", ha="center", va="center")
            ax_ratio.set_axis_off()
        # Variable local para puntos PnL.
        puntos_pnl = list(resultado.get("puntos_pnl") or [])
        if puntos_pnl:
            xs = [ts for ts, _ in puntos_pnl]
            ys = [float(valor) for _, valor in puntos_pnl]
            ax_pnl.plot(xs, ys, marker="o", markersize=2.8, linewidth=1.0)
            ax_pnl.axhline(0.0, linestyle="--", linewidth=0.9, alpha=0.8)
            ax_pnl.set_ylabel("PnL acumulado")
            ax_pnl.set_xlabel("Hora")
            ax_pnl.grid(True, alpha=0.3)
            self._aplicar_eje_intradia(ax_pnl, inicio_sesion or puntos_pnl[0][0], fin_sesion or puntos_pnl[-1][0])
        else:
            ax_pnl.text(0.5, 0.5, "Sin operaciones cerradas", ha="center", va="center")
            ax_pnl.set_axis_off()
        self._restaurar_vistas((f"backtest{slot}_ratio", f"backtest{slot}_pnl"))
        if canvas is not None:
            canvas.draw_idle()
        # Variable local para operaciones.
        operaciones = list(resultado.get("operaciones") or [])
        self._cargar_tree_backtest(operaciones)
        # Variable local para cerradas.
        cerradas = [op for op in operaciones if str(op.get("estado") or "") in {"cerrada", "cerrada_forzada", "cerrada_extrema", "cerrada_perdida", "cerrada_cambio_media"}]
        # Variable local para aciertos.
        aciertos = int(resultado.get("aciertos") or 0)
        # Variable local para tasa acierto.
        tasa_acierto = (aciertos / len(cerradas) * 100.0) if cerradas else 0.0
        # Variable local para modo txt.
        modo_txt = self._texto_modo_ejecucion_backtest(modo_ejecucion)
        # Variable local para sigmas txt.
        sigmas_txt = "sin aumentos"
        if sigma_refuerzos:
            sigmas_txt = ", ".join(f"±{float(valor):.2f}σ" for valor in sigma_refuerzos)
        # Variable local para bandas txt.
        bandas_txt = "dinámicas" if modo_bandas == "dinamica" else "fijas"
        # Variable local para cierre txt.
        cierre_txt = f" | cierre media {bandas_txt}=±{BACKTEST_CLOSE_ZONE_PCT_OF_SIGMA * 100:.0f}%σ"
        # Variable local para warmup txt.
        warmup_txt = f" | inicio test={hora_inicio_test}"
        # Variable local para confirmacion txt.
        confirmacion_txt = " | entrada=2do tick fuera de banda" if confirmar_segundo_tick else " | entrada=1er tick fuera de banda"
        # Variable local para force exit txt.
        force_exit_txt = f" | cierre test={hora_cierre_test}"
        # Variable local para sigma hist txt.
        sigma_hist_txt = f"{float(sigma_hist_extrema):.6f}" if sigma_hist_extrema is not None else "n/d"
        # Variable local para extrema txt.
        extrema_txt = (
            f" | cierre extremo={'on' if extrema_habilitada else 'off'}"
            f" | σ hist comp={sigma_hist_txt} ({int(puntos_hist_extrema)} cierres)"
            f" | corte extremo=±{float(sigma_extrema_mult):.2f}σ hist | pausa extrema={float(espera_extrema_min):.0f} min | límite extremos/día={int(max_eventos_extremos_dia)}"
        )
        # Variable local para perdida txt.
        perdida_txt = (
            f" | stop pérdida={'on' if perdida_habilitada else 'off'}={float(perdida_maxima):.2f}"
            if float(perdida_maxima or 0.0) > 0 else
            f" | stop pérdida={'on' if perdida_habilitada else 'off'}"
        )
        # Variable local para espera perdida txt.
        espera_perdida_txt = f" | pausa pérdida={float(espera_perdida_min):.0f} min"
        # Variable local para cambio media txt.
        cambio_media_txt = (
            f" | cambio media={'on' if media_shift_habilitado else 'off'} umbral={float(media_shift_sigma):.2f}σ pausa={float(media_shift_espera):.0f}m"
        )
        self.var_backtest_info.set(
            (
                f"Backtest cobertura: {ticker_a} / {ticker_b} | fecha={fecha_bt} | serie={self._descripcion_serie_backtest(modo_serie)} | ejecución={modo_txt} | intervalo={intervalo_backtest_min}m | ticks ent/sal={ticks_entrada}/{ticks_salida} | bandas={bandas_txt} | media final={float(media):.6f} | σ final={float(resultado.get('desvio') or 0.0):.6f} | umbral base=±{sigma_mult:.2f}σ"
                f" | aumentos={sigmas_txt}{cierre_txt}{warmup_txt}{confirmacion_txt}{force_exit_txt}{extrema_txt}{perdida_txt}{espera_perdida_txt}{cambio_media_txt} | puntos previos al inicio={int(resultado.get('warmup_puntos') or 0)}"
                f" | refuerzo1={int(resultado.get('entradas_refuerzo_1') or 0)} | refuerzo2={int(resultado.get('entradas_refuerzo_2') or 0)} | cierres forzados={int(resultado.get('cierres_forzados') or 0)} | eventos extremos={int(resultado.get('eventos_extremos') or 0)} | cierres extremos={int(resultado.get('cierres_extremos') or 0)} | cierres pérdida={int(resultado.get('cierres_perdida') or 0)} | cierres cambio media={int(resultado.get('cierres_cambio_media') or 0)} | límite extremos agotado={'sí' if bool(resultado.get('limite_extremos_agotado')) else 'no'}"
                f" | cerradas={len(cerradas)} | acierto={tasa_acierto:.1f}% | pnl total={float(resultado.get('pnl_total') or 0.0):.2f} | pnl medio={float(resultado.get('pnl_promedio') or 0.0):.2f}"
            )
            if media is not None else
            "Backtest cobertura: sin datos suficientes para calcular las bandas del ratio."
        )
        self._backtest_cache_key = clave_cache
        self._backtest_cache_result = resultado
        self._backtest_render_signature[slot] = clave_cache

    def _refrescar_backtest_cobertura_intradia(
        self,
        filas_calls: list[dict[str, Any]],
        filas_puts: list[dict[str, Any]],
        _info: dict[str, Any],
        *,
        forzar: bool = False,
    ) -> None:
        """Refresca una vista paralela del backtest usando tamaños cubiertos."""
        self._sincronizar_aliases_backtest_hedge_activos()
        # Variable local para slot.
        slot = self._tab_backtest_hedge_activa_indice()
        # Variable local para widgets.
        widgets = self._backtest_hedge_widgets.get(slot, {})
        if not widgets:
            return
        # Variable local para fecha bt original.
        fecha_bt_original = self.var_backtest_fecha.get().strip()
        # Variable local para fecha bt.
        fecha_bt = self._resolver_fecha_historial(fecha_bt_original)
        if fecha_bt != fecha_bt_original:
            self.var_backtest_fecha.set(fecha_bt)
        # Variable local para ticker A.
        ticker_a = self.var_backtest_a.get().strip()
        # Variable local para ticker B.
        ticker_b = self.var_backtest_b.get().strip()
        # Variable local para modo ejecucion.
        modo_ejecucion = self.var_backtest_exec_mode.get().strip() or "last"
        # Variable local para modo bandas.
        modo_bandas = self.var_backtest_band_mode.get().strip() or "dinamica"
        # Variable local para modo cobertura.
        modo_cobertura = self.var_backtest_hedge_mode.get().strip() or "precio"
        if modo_cobertura not in {"1a1", "precio", "delta", "vega"}:
            modo_cobertura = "precio"
            self.var_backtest_hedge_mode.set(modo_cobertura)
        # Variable local para sigma extrema múltiplo.
        sigma_extrema_mult = self._leer_sigma_extrema_backtest(confirmar=False)
        # Variable local para espera extrema min.
        espera_extrema_min = self._leer_espera_extrema_backtest(confirmar=False)
        # Variable local para max eventos extremos dia.
        max_eventos_extremos_dia = self._leer_limite_eventos_extremos_backtest()
        # Variable local para extrema habilitada.
        extrema_habilitada = bool(self.var_backtest_extreme_enabled.get())
        self.var_backtest_extreme_enabled_button.set(self._texto_toggle_backtest_cierre("Cierre extremo", extrema_habilitada))
        # Variable local para perdida habilitada.
        perdida_habilitada = bool(self.var_backtest_loss_enabled.get())
        self.var_backtest_loss_enabled_button.set(self._texto_toggle_backtest_cierre("Stop pérdida", perdida_habilitada))
        # Variable local para perdida maxima.
        perdida_maxima = self._leer_perdida_maxima_backtest(confirmar=False)
        # Variable local para espera perdida min.
        espera_perdida_min = self._leer_espera_perdida_backtest(confirmar=False)
        # Variable local para shock vol habilitado.
        shock_vol_habilitado = False
        # Variable local para shock vol ventana.
        shock_vol_ventana = 0.0
        # Variable local para shock vol múltiplo.
        shock_vol_mult = 0.0
        # Variable local para shock vol espera.
        shock_vol_espera = 0.0
        # Variable local para media shift habilitado.
        media_shift_habilitado = bool(self.var_backtest_media_shift_enabled.get())
        self.var_backtest_media_shift_enabled_button.set(self._texto_toggle_backtest_cierre("Cambio media", media_shift_habilitado))
        # Variable local para media shift sigma.
        media_shift_sigma = self._leer_sigma_cambio_media_backtest(confirmar=False)
        # Variable local para media shift espera.
        media_shift_espera = self._leer_espera_cambio_media_backtest(confirmar=False)
        # Variable local para ticks entrada.
        ticks_entrada = self._leer_ticks_confirmacion_backtest(self.var_backtest_entry_ticks, 2 if bool(self.var_backtest_confirm_second_tick.get()) else 1)
        # Variable local para ticks salida.
        ticks_salida = self._leer_ticks_confirmacion_backtest(self.var_backtest_exit_ticks, 1)
        # Variable local para confirmar segundo tick.
        confirmar_segundo_tick = bool(ticks_entrada >= 2)
        self.var_backtest_confirm_second_tick.set(confirmar_segundo_tick)
        self.var_backtest_confirm_second_tick_button.set(self._texto_confirmacion_entrada_backtest(confirmar_segundo_tick))
        # Variable local para modo serie var.
        modo_serie_var = self._backtest_hedge_series_mode_vars[slot]
        # Variable local para modo serie btn var.
        modo_serie_btn_var = self._backtest_hedge_series_mode_button_vars[slot]
        # Variable local para modo serie.
        modo_serie = modo_serie_var.get().strip().lower() or "ratio"
        if modo_serie not in {"ratio", "cono"}:
            modo_serie = "ratio"
            modo_serie_var.set(modo_serie)
        modo_serie_btn_var.set(self._texto_modo_serie_backtest(modo_serie))
        self._backtest_hedge_table_signal_mode = modo_serie
        if modo_bandas not in {"dinamica", "fija"}:
            modo_bandas = "dinamica"
            self.var_backtest_band_mode.set(modo_bandas)
        self.var_backtest_band_mode_button.set(self._texto_modo_bandas_backtest(modo_bandas))
        # Variable local para sigma múltiplo.
        sigma_mult = self._leer_sigma_backtest(confirmar=False)
        # Variable local para sigma refuerzos.
        sigma_refuerzos = self._leer_sigmas_refuerzo_backtest(sigma_mult)
        # Variable local para hora inicio test.
        hora_inicio_test = self._leer_hora_backtest(self.var_backtest_hora_inicio, BACKTEST_DEFAULT_START_TIME)
        # Variable local para hora cierre test.
        hora_cierre_test = self._leer_hora_backtest(self.var_backtest_hora_cierre, BACKTEST_DEFAULT_END_TIME)
        # Variable local para intervalo backtest minutos.
        intervalo_backtest_min = self._leer_intervalo_backtest_minutos()
        inicio_test_dt, cierre_test_dt = self._construir_limites_intradia(fecha_bt, hora_inicio_test, hora_cierre_test)
        if inicio_test_dt is not None and cierre_test_dt is not None and cierre_test_dt <= inicio_test_dt:
            try:
                # Variable local para nuevo cierre.
                nuevo_cierre = min(inicio_test_dt + timedelta(minutes=5), datetime.strptime(f"{fecha_bt} {BACKTEST_SESSION_END_TIME}:00", "%Y-%m-%d %H:%M:%S"))
                hora_cierre_test = nuevo_cierre.strftime("%H:%M")
            except Exception:
                hora_cierre_test = BACKTEST_DEFAULT_END_TIME
            self.var_backtest_hora_cierre.set(hora_cierre_test)
        # Variable local para opciones.
        opciones = self._listar_bases_disponibles_vencimiento(filas_calls, filas_puts, fecha_hist=(fecha_bt or None))
        # Variable local para ax ratio.
        ax_ratio = widgets.get("ax_ratio")
        # Variable local para ax PnL.
        ax_pnl = widgets.get("ax_pnl")
        # Variable local para canvas.
        canvas = widgets.get("canvas")
        if not fecha_bt or ticker_a not in opciones or ticker_b not in opciones or not ticker_a or not ticker_b:
            for ax in (ax_ratio, ax_pnl):
                if ax is None:
                    continue
                ax.clear()
                ax.text(0.5, 0.5, "Elegí día y dos bases activas del vencimiento", ha="center", va="center")
                ax.set_axis_off()
            if canvas is not None:
                canvas.draw_idle()
            self._cargar_tree_backtest_hedge([])
            self.var_backtest_hedge_info.set(
                "Backtest cobertura: elegí un día con snapshots y dos bases activas. Esta vista mantiene la misma señal del backtest intradía, ya sea ratio A/B o cono last A+B, y recalcula el PnL con tamaños 1 a 1, por precio, por delta o por vega para comparar el efecto del hedge ratio."
            )
            self._invalidar_cache_backtest_hedge()
            return
        sigma_hist_extrema, puntos_hist_extrema = (self._calcular_sigma_historico_cono_backtest(ticker_a, ticker_b) if modo_serie == "cono" else self._calcular_sigma_historico_backtest(ticker_a, ticker_b))
        # Caché en memoria para clave cache.
        clave_cache = (
            fecha_bt,
            ticker_a,
            ticker_b,
            modo_ejecucion,
            modo_cobertura,
            round(float(sigma_mult), 6),
            tuple(round(float(valor), 6) for valor in sigma_refuerzos),
            hora_inicio_test,
            hora_cierre_test,
            int(intervalo_backtest_min),
            int(ticks_entrada),
            int(ticks_salida),
            modo_bandas,
            round(float(espera_extrema_min), 6),
            round(float(sigma_extrema_mult), 6),
            int(max_eventos_extremos_dia),
            round(float(sigma_hist_extrema), 8) if sigma_hist_extrema is not None else None,
            int(puntos_hist_extrema),
            BACKTEST_CLOSE_ZONE_PCT_OF_SIGMA,
            bool(confirmar_segundo_tick),
            modo_serie,
            bool(extrema_habilitada),
            round(float(perdida_maxima), 6),
            round(float(espera_perdida_min), 6),
            bool(perdida_habilitada),
            bool(media_shift_habilitado),
            round(float(media_shift_sigma), 6),
            round(float(media_shift_espera), 6),
        )
        if (not forzar) and clave_cache == self._backtest_hedge_cache_key and self._backtest_hedge_cache_result is not None and self._backtest_hedge_render_signature.get(slot) == clave_cache:
            return
        # Variable local para filas intradía.
        filas_intradia = self._history_db.obtener_filas_intradia_par_cobertura(
            fecha_bt,
            ticker_a,
            ticker_b,
            hora_desde=BACKTEST_SESSION_START_TIME,
            hora_hasta=hora_cierre_test,
        )
        filas_intradia = self._resamplear_filas_backtest_intradia(filas_intradia, intervalo_backtest_min)
        # En cobertura, el stop de pérdida debe evaluarse con el PnL cubierto y no con la versión 1 a 1.
        # Variable local para resultado base.
        resultado_base = self._simular_backtest_ratio_intradia(
            filas_intradia,
            sigma_mult=sigma_mult,
            sigma_refuerzos=sigma_refuerzos,
            modo_ejecucion=modo_ejecucion,
            fecha=fecha_bt,
            hora_inicio_test=hora_inicio_test,
            hora_cierre_test=hora_cierre_test,
            close_zone_pct=BACKTEST_CLOSE_ZONE_PCT_OF_SIGMA,
            modo_bandas=modo_bandas,
            historical_sigma_extreme=sigma_hist_extrema,
            extreme_sigma_mult=sigma_extrema_mult,
            extreme_cooldown_minutes=espera_extrema_min,
            extreme_max_events_per_day=max_eventos_extremos_dia,
            confirmar_segundo_tick_fuera_bandas=confirmar_segundo_tick,
            entry_confirmation_ticks=ticks_entrada,
            exit_confirmation_ticks=ticks_salida,
            loss_limit_amount=perdida_maxima,
            loss_cooldown_minutes=espera_perdida_min,
            enable_extreme_close=extrema_habilitada,
            enable_loss_close=perdida_habilitada,
            enable_volatility_regime_close=False,
            volatility_regime_window_minutes=0.0,
            volatility_regime_mult=0.0,
            volatility_regime_cooldown_minutes=0.0,
            enable_moving_mean_shift_close=media_shift_habilitado,
            moving_mean_shift_sigma_mult=media_shift_sigma,
            moving_mean_shift_cooldown_minutes=media_shift_espera,
            signal_mode=modo_serie,
            coverage_mode_for_loss=modo_cobertura,
        )
        operaciones_hedge, puntos_pnl, resumen_hedge = self._aplicar_cobertura_a_operaciones_backtest(
            list(resultado_base.get("operaciones") or []),
            filas_intradia,
            modo_ejecucion=modo_ejecucion,
            modo_cobertura=modo_cobertura,
        )
        # Resultado acumulado o final del cálculo.
        resultado = dict(resultado_base)
        resultado["operaciones"] = operaciones_hedge
        resultado["puntos_pnl"] = puntos_pnl
        resultado.update(resumen_hedge)
        self._capturar_vistas((f"backtesthedge{slot}_ratio", f"backtesthedge{slot}_pnl"))
        ax_ratio.clear()
        ax_pnl.clear()
        # Variable local para puntos ratio.
        puntos_ratio = list(resultado.get("puntos_ratio") or [])
        # Variable local para media.
        media = resultado.get("media")
        # Variable local para warmup fin.
        warmup_fin = resultado.get("warmup_fin")
        # Variable local para force exit timestamp.
        force_exit_ts = resultado.get("force_exit_ts")
        inicio_sesion, fin_sesion = self._construir_limites_intradia(fecha_bt, BACKTEST_SESSION_START_TIME, hora_cierre_test)

        def _plot_series(ax: Any, puntos: list[tuple[datetime, float]], **kwargs: Any) -> None:
            if not puntos:
                return
            ax.plot([ts for ts, _ in puntos], [float(valor) for _, valor in puntos], **kwargs)

        def _fill_between(ax: Any, sup: list[tuple[datetime, float]], inf: list[tuple[datetime, float]], *, alpha: float) -> None:
            if not sup or not inf:
                return
            # Variable local para largos.
            largos = min(len(sup), len(inf))
            if largos <= 0:
                return
            # Variable local para xs.
            xs = [sup[i][0] for i in range(largos)]
            # Variable local para ys sup.
            ys_sup = [float(sup[i][1]) for i in range(largos)]
            # Variable local para ys inf.
            ys_inf = [float(inf[i][1]) for i in range(largos)]
            ax.fill_between(xs, ys_inf, ys_sup, alpha=alpha)

        if puntos_ratio:
            # Variable local para xs.
            xs = [ts for ts, _ in puntos_ratio]
            # Variable local para ys.
            ys = [float(valor) for _, valor in puntos_ratio]
            ax_ratio.plot(xs, ys, linewidth=1.2)
            # Variable local para puntos media.
            puntos_media = list(resultado.get("puntos_media") or [])
            # Variable local para puntos banda sup.
            puntos_banda_sup = list(resultado.get("puntos_banda_sup") or [])
            # Variable local para puntos banda inf.
            puntos_banda_inf = list(resultado.get("puntos_banda_inf") or [])
            # Variable local para puntos banda cierre sup.
            puntos_banda_cierre_sup = list(resultado.get("puntos_banda_cierre_sup") or [])
            # Variable local para puntos banda cierre inf.
            puntos_banda_cierre_inf = list(resultado.get("puntos_banda_cierre_inf") or [])
            _fill_between(ax_ratio, puntos_banda_sup, puntos_banda_inf, alpha=0.10)
            _fill_between(ax_ratio, puntos_banda_cierre_sup, puntos_banda_cierre_inf, alpha=0.07)
            _plot_series(ax_ratio, puntos_media, linestyle="--", linewidth=1.0, alpha=0.9)
            _plot_series(ax_ratio, puntos_banda_sup, linestyle=":", linewidth=0.9, alpha=0.8)
            _plot_series(ax_ratio, puntos_banda_inf, linestyle=":", linewidth=0.9, alpha=0.8)
            _plot_series(ax_ratio, puntos_banda_cierre_sup, linestyle="-.", linewidth=0.8, alpha=0.6)
            _plot_series(ax_ratio, puntos_banda_cierre_inf, linestyle="-.", linewidth=0.8, alpha=0.6)
            # Variable local para bandas ref sup.
            bandas_ref_sup = list(resultado.get("puntos_bandas_refuerzo_sup") or [])
            # Variable local para bandas ref inf.
            bandas_ref_inf = list(resultado.get("puntos_bandas_refuerzo_inf") or [])
            for serie_sup, serie_inf in zip(bandas_ref_sup, bandas_ref_inf):
                _plot_series(ax_ratio, list(serie_sup), linestyle="-.", linewidth=0.8, alpha=0.55)
                _plot_series(ax_ratio, list(serie_inf), linestyle="-.", linewidth=0.8, alpha=0.55)
            if inicio_sesion is not None and warmup_fin is not None and warmup_fin > inicio_sesion:
                ax_ratio.axvspan(inicio_sesion, warmup_fin, alpha=0.10)
                ax_ratio.axvline(warmup_fin, linestyle="--", linewidth=0.9, alpha=0.7)
            if isinstance(force_exit_ts, datetime):
                ax_ratio.axvline(force_exit_ts, linestyle="--", linewidth=0.9, alpha=0.7)
            for inicio_cd, fin_cd in list(resultado.get("cooldown_spans") or []):
                if isinstance(inicio_cd, datetime) and isinstance(fin_cd, datetime) and fin_cd > inicio_cd:
                    ax_ratio.axvspan(inicio_cd, fin_cd, alpha=0.06)
            for ts_ext, ratio_ext in list(resultado.get("puntos_extremos") or []):
                if isinstance(ts_ext, datetime):
                    ax_ratio.scatter([ts_ext], [float(ratio_ext)], s=34, marker="x")
            for ts_stop, ratio_stop in list(resultado.get("puntos_stop_loss") or []):
                if isinstance(ts_stop, datetime):
                    ax_ratio.scatter([ts_stop], [float(ratio_stop)], s=34, marker="v")
            for operacion in operaciones_hedge:
                # Variable local para timestamp ent.
                ts_ent = operacion.get("ts_entrada")
                # Variable local para ratio ent.
                ratio_ent = convertir_a_numero(operacion.get("ratio_entrada"))
                if isinstance(ts_ent, datetime) and ratio_ent is not None:
                    # Variable local para orden refuerzo.
                    orden_refuerzo = int(operacion.get("orden_refuerzo") or 0)
                    # Variable local para marker.
                    marker = "^" if orden_refuerzo == 0 else ("s" if orden_refuerzo == 1 else "D")
                    ax_ratio.scatter([ts_ent], [float(ratio_ent)], s=30, marker=marker)
                # Variable local para timestamp sal.
                ts_sal = operacion.get("ts_salida")
                # Variable local para ratio sal.
                ratio_sal = convertir_a_numero(operacion.get("ratio_salida"))
                if isinstance(ts_sal, datetime) and ratio_sal is not None:
                    ax_ratio.scatter([ts_sal], [float(ratio_sal)], s=28, marker="o")
            # Variable local para signal label.
            signal_label = str(resultado.get("signal_label") or self._descripcion_serie_backtest(modo_serie))
            # Variable local para sufijo modo.
            sufijo_modo = "dinámico" if modo_bandas == "dinamica" else "fijo"
            ax_ratio.set_title(f"Backtest cobertura {self._texto_modo_cobertura_backtest(modo_cobertura)} | {ticker_a} / {ticker_b} | {signal_label.lower()} {sufijo_modo}")
            ax_ratio.set_ylabel(signal_label)
            ax_ratio.grid(True, alpha=0.3)
            self._aplicar_eje_intradia(ax_ratio, inicio_sesion or puntos_ratio[0][0], fin_sesion or puntos_ratio[-1][0])
        else:
            ax_ratio.text(0.5, 0.5, "Sin datos suficientes para el backtest", ha="center", va="center")
            ax_ratio.set_axis_off()
        if puntos_pnl:
            xs = [ts for ts, _ in puntos_pnl]
            ys = [float(valor) for _, valor in puntos_pnl]
            ax_pnl.plot(xs, ys, marker="o", markersize=2.8, linewidth=1.0)
            ax_pnl.axhline(0.0, linestyle="--", linewidth=0.9, alpha=0.8)
            ax_pnl.set_ylabel("PnL acumulado")
            ax_pnl.set_xlabel("Hora")
            ax_pnl.grid(True, alpha=0.3)
            self._aplicar_eje_intradia(ax_pnl, inicio_sesion or puntos_pnl[0][0], fin_sesion or puntos_pnl[-1][0])
        else:
            ax_pnl.text(0.5, 0.5, "Sin operaciones cerradas", ha="center", va="center")
            ax_pnl.set_axis_off()
        self._restaurar_vistas((f"backtesthedge{slot}_ratio", f"backtesthedge{slot}_pnl"))
        if canvas is not None:
            canvas.draw_idle()
        self._cargar_tree_backtest_hedge(operaciones_hedge)
        # Variable local para cerradas.
        cerradas = [op for op in operaciones_hedge if str(op.get("estado") or "") in {"cerrada", "cerrada_forzada", "cerrada_extrema", "cerrada_perdida", "cerrada_cambio_media", "cerrada_regimen_vol"}]
        # Variable local para aciertos.
        aciertos = int(resultado.get("aciertos") or 0)
        # Variable local para tasa acierto.
        tasa_acierto = (aciertos / len(cerradas) * 100.0) if cerradas else 0.0
        # Variable local para modo txt.
        modo_txt = self._texto_modo_ejecucion_backtest(modo_ejecucion)
        # Variable local para confirmacion txt.
        confirmacion_txt = " | entrada=2do tick fuera de banda" if confirmar_segundo_tick else " | entrada=1er tick fuera de banda"
        # Variable local para sigmas txt.
        sigmas_txt = "sin aumentos"
        if sigma_refuerzos:
            sigmas_txt = ", ".join(f"±{float(valor):.2f}σ" for valor in sigma_refuerzos)
        # Variable local para bandas txt.
        bandas_txt = "dinámicas" if modo_bandas == "dinamica" else "fijas"
        # Variable local para sigma hist txt.
        sigma_hist_txt = f"{float(sigma_hist_extrema):.6f}" if sigma_hist_extrema is not None else "n/d"
        # Variable local para perdida txt.
        perdida_txt = (
            f" | stop pérdida={'on' if perdida_habilitada else 'off'}={float(perdida_maxima):.2f}"
            if float(perdida_maxima or 0.0) > 0 else
            f" | stop pérdida={'on' if perdida_habilitada else 'off'}"
        )
        # Variable local para espera perdida txt.
        espera_perdida_txt = f" | pausa pérdida={float(espera_perdida_min):.0f} min"
        # Variable local para extrema txt.
        extrema_txt = f" | cierre extremo={'on' if extrema_habilitada else 'off'} | corte extremo=±{float(sigma_extrema_mult):.2f}σ hist | pausa extrema={float(espera_extrema_min):.0f} min | límite extremos/día={int(max_eventos_extremos_dia)}"
        # Variable local para cambio media txt.
        cambio_media_txt = f" | cambio media={'on' if media_shift_habilitado else 'off'} umbral={float(media_shift_sigma):.2f}σ pausa={float(media_shift_espera):.0f}m"
        self.var_backtest_hedge_info.set(
            (
                f"Backtest cobertura: {ticker_a} / {ticker_b} | fecha={fecha_bt} | serie={self._descripcion_serie_backtest(modo_serie)} | ejecución={modo_txt} | cobertura={self._texto_modo_cobertura_backtest(modo_cobertura)} | bandas={bandas_txt} | media final={float(media):.6f} | σ final={float(resultado.get('desvio') or 0.0):.6f} | umbral base=±{sigma_mult:.2f}σ"
                f" | aumentos={sigmas_txt} | inicio test={hora_inicio_test}{confirmacion_txt} | cierre test={hora_cierre_test} | σ hist comp={sigma_hist_txt} ({int(puntos_hist_extrema)} cierres){extrema_txt}{perdida_txt}{espera_perdida_txt}{cambio_media_txt}"
                f" | qty B prom={float(resultado.get('qty_b_promedio') or 0.0):.3f} | fallbacks cobertura={int(resultado.get('fallbacks_cobertura') or 0)} | cierres pérdida={int(resultado.get('cierres_perdida') or 0)} | cierres cambio media={int(resultado.get('cierres_cambio_media') or 0)} | cerradas={len(cerradas)} | acierto={tasa_acierto:.1f}% | pnl total={float(resultado.get('pnl_total') or 0.0):.2f} | pnl medio={float(resultado.get('pnl_promedio') or 0.0):.2f}"
            )
            if media is not None else
            "Backtest cobertura: sin datos suficientes para calcular las bandas del ratio."
        )
        self._backtest_hedge_cache_key = clave_cache
        self._backtest_hedge_cache_result = resultado
        self._backtest_hedge_render_signature[slot] = clave_cache

    def _crear_vista_intradia(self, parent, slot: int) -> None:
        """Construye una subvista intradía independiente dentro del notebook intradía."""
        # Variable local para tab.
        tab = ttk.Frame(parent, padding=6)
        parent.add(tab, text=f"Vista {slot}")

        # Variable local para frame controls.
        frame_controls = ttk.Frame(tab)
        frame_controls.pack(fill=X, pady=(0, 6))

        ttk.Label(frame_controls, text="Día:").pack(side=LEFT)
        # Variable local para combo fecha.
        combo_fecha = ttk.Combobox(
            frame_controls,
            textvariable=self._intradia_vars_fecha[slot],
            state="readonly",
            width=14,
        )
        combo_fecha.pack(side=LEFT, padx=(4, 12))
        combo_fecha.bind(
            "<<ComboboxSelected>>",
            lambda _e, s=slot: self._al_cambiar_selector_intradia(s),
        )

        ttk.Label(frame_controls, text="Base A:").pack(side=LEFT)
        # Variable local para combo A.
        combo_a = ttk.Combobox(
            frame_controls,
            textvariable=self._intradia_vars_a[slot],
            state="readonly",
            width=44,
        )
        combo_a.pack(side=LEFT, padx=(4, 12))
        combo_a.bind(
            "<<ComboboxSelected>>",
            lambda _e, s=slot: self._al_cambiar_selector_intradia(s),
        )

        ttk.Label(frame_controls, text="Base B:").pack(side=LEFT)
        # Variable local para combo B.
        combo_b = ttk.Combobox(
            frame_controls,
            textvariable=self._intradia_vars_b[slot],
            state="readonly",
            width=44,
        )
        combo_b.pack(side=LEFT, padx=(4, 12))
        combo_b.bind(
            "<<ComboboxSelected>>",
            lambda _e, s=slot: self._al_cambiar_selector_intradia(s),
        )
        ttk.Button(
            frame_controls,
            textvariable=self._intradia_cost_mode_button_vars[slot],
            command=lambda s=slot: self._toggle_intradia_cost_mode(s),
        ).pack(side=LEFT, padx=(4, 0))
        ttk.Button(
            frame_controls,
            textvariable=self._intradia_price_source_button_vars[slot],
            command=lambda s=slot: self._toggle_intradia_price_source(s),
        ).pack(side=LEFT, padx=(8, 0))
        ttk.Button(
            frame_controls,
            textvariable=self._intradia_band_mode_button_vars[slot],
            command=lambda s=slot: self._toggle_intradia_band_mode(s),
        ).pack(side=LEFT, padx=(8, 0))

        # Variable local para frame superior.
        frame_superior = ttk.Frame(tab)
        frame_superior.pack(fill=BOTH, pady=(0, 4))
        # Variable local para frame table.
        frame_table = ttk.Frame(frame_superior)
        frame_table.pack(side=LEFT, fill=BOTH, expand=True, padx=(0, 6))
        # Variable local para tree.
        tree = self._crear_tree_comparador(frame_table, height=5)

        # Variable local para frame costos.
        frame_costos = ttk.Frame(frame_superior)
        frame_costos.pack(side=LEFT, fill=BOTH, expand=True, padx=(6, 0))
        # Variable local para frame toolbar costos.
        frame_toolbar_costos = ttk.Frame(frame_costos)
        frame_toolbar_costos.pack(fill=X, pady=(0, 4))
        # Variable local para fig costos.
        fig_costos = Figure(figsize=(6.4, 2.95), dpi=100)
        # Variable local para ax costos.
        ax_costos = fig_costos.add_subplot(111)
        fig_costos.subplots_adjust(left=0.08, right=0.985, top=0.90, bottom=0.20)
        # Variable local para canvas costos.
        canvas_costos = FigureCanvasTkAgg(fig_costos, master=frame_costos)
        canvas_costos.get_tk_widget().pack(fill=BOTH, expand=True)
        # Variable local para toolbar costos.
        toolbar_costos = NavigationToolbar2Tk(canvas_costos, frame_toolbar_costos)
        toolbar_costos.update()
        self._compactar_toolbar(toolbar_costos)

        # Variable local para frame chart.
        frame_chart = ttk.Frame(tab)
        frame_chart.pack(fill=BOTH, expand=True)
        # Variable local para frame toolbar.
        frame_toolbar = ttk.Frame(frame_chart)
        frame_toolbar.pack(fill=X, pady=(0, 4))

        # Variable local para fig.
        fig = Figure(figsize=(13.2, 8.2), dpi=100)
        # Variable local para ax precio.
        ax_precio = fig.add_subplot(221)
        # Variable local para ax delta.
        ax_delta = fig.add_subplot(222)
        # Variable local para ax vega.
        ax_vega = fig.add_subplot(223)
        # Variable local para ax gamma.
        ax_gamma = fig.add_subplot(224)
        fig.subplots_adjust(hspace=0.32, wspace=0.22, top=0.95, bottom=0.08, left=0.06, right=0.985)

        # Variable local para canvas.
        canvas = FigureCanvasTkAgg(fig, master=frame_chart)
        canvas.get_tk_widget().pack(fill=BOTH, expand=True)
        # Variable local para toolbar.
        toolbar = NavigationToolbar2Tk(canvas, frame_toolbar)
        toolbar.update()
        self._compactar_toolbar(toolbar)

        self._registrar_canvas_interactivo(
            canvas_costos,
            toolbar_costos,
            {
                f"intradia{slot}_costo": ax_costos,
            },
        )
        self._registrar_canvas_interactivo(
            canvas,
            toolbar,
            {
                f"intradia{slot}_precio": ax_precio,
                f"intradia{slot}_delta": ax_delta,
                f"intradia{slot}_vega": ax_vega,
                f"intradia{slot}_gamma": ax_gamma,
            },
        )

        self._intradia_widgets[slot] = {
            "tab": tab,
            "combo_fecha": combo_fecha,
            "combo_a": combo_a,
            "combo_b": combo_b,
            "tree": tree,
            "fig_costos": fig_costos,
            "canvas_costos": canvas_costos,
            "toolbar_costos": toolbar_costos,
            "ax_costos": ax_costos,
            "fig": fig,
            "canvas": canvas,
            "toolbar": toolbar,
            "ax_precio": ax_precio,
            "ax_delta": ax_delta,
            "ax_vega": ax_vega,
            "ax_gamma": ax_gamma,
        }

    def _listar_bases_disponibles_intradia(self, fecha: str) -> list[str]:
        """Devuelve las bases con datos intradía disponibles para la fecha elegida."""
        fecha_txt = str(fecha or "").strip()
        if not fecha_txt:
            return []
        try:
            return self._listar_bases_disponibles_vencimiento([], [], fecha_hist=fecha_txt)
        except Exception:
            LOGGER.debug("No se pudieron listar bases disponibles intradía para %s", fecha_txt, exc_info=True)
            return []

    def _columnas_visibles_tabla_rel_intradia(self, slot: int) -> list[str]:
        """Replica en intradía la misma lógica de columnas visibles de Tabla relaciones.

        La única diferencia funcional de esta vista es que trabaja por día elegido y puede
        remuestrear la secuencia visible con el timeframe seleccionado.
        """
        visibles = [col for col in self._columnas_visibles_tabla_rel(slot, modo="intradia") if col in self.TABLA_REL_INTRADIA_COLUMNAS]
        if "fuente" not in visibles:
            visibles.append("fuente")
        return visibles

    def _aplicar_estado_columnas_tabla_rel_intradia(self, slot: int) -> None:
        """Aplica mostrar/ocultar columnas en la vista intradía de relaciones."""
        widgets = self._intradia_rel_widgets.get(slot, {})
        tree = widgets.get("tree")
        if tree is None:
            return
        visibles = self._columnas_visibles_tabla_rel_intradia(slot)
        if isinstance(tree, SheetTableAdapter):
            tree.begin_bulk_update()
        try:
            try:
                tree.configure(displaycolumns=tuple(visibles))
            except Exception:
                LOGGER.debug("No se pudo aplicar el estado de columnas de Tabla relaciones intradía", exc_info=True)
            self._aplicar_anchos_columnas_tabla_rel(tree, slot, "intradia")
            self._actualizar_headings_tree(tree)
        finally:
            if isinstance(tree, SheetTableAdapter):
                tree.end_bulk_update(refresh=True)

    def _crear_vista_tabla_rel_intradia(self, parent, slot: int) -> None:
        """Crea una subvista para relaciones intradía con paso configurable y botones de columnas."""
        tab = ttk.Frame(parent, padding=4)
        parent.add(tab, text=f"Vista {slot}")
        frame_controls = ttk.Frame(tab)
        frame_controls.pack(fill=X, pady=(0, 6))
        frame_controls_top = ttk.Frame(frame_controls)
        frame_controls_top.pack(fill=X, pady=(0, 4))
        frame_controls_bottom = ttk.Frame(frame_controls)
        frame_controls_bottom.pack(fill=X)
        ttk.Label(frame_controls_top, text="Día:").pack(side=LEFT)
        combo_fecha = ttk.Combobox(frame_controls_top, textvariable=self._intradia_vars_fecha[slot], state="readonly", width=14)
        combo_fecha.pack(side=LEFT, padx=(4, 10))
        combo_fecha.bind("<<ComboboxSelected>>", lambda _e, s=slot: (self._programar_guardado_estado_ui(delay_ms=120), self._refrescar_ui(forzar=True)))
        ttk.Label(frame_controls_top, text="Base A:").pack(side=LEFT)
        combo_a = ttk.Combobox(frame_controls_top, textvariable=self._intradia_vars_a[slot], state="readonly", width=44)
        combo_a.pack(side=LEFT, padx=(4, 10))
        combo_a.bind("<<ComboboxSelected>>", lambda _e, s=slot: (self._programar_guardado_estado_ui(delay_ms=120), self._refrescar_ui(forzar=True)))
        ttk.Label(frame_controls_top, text="Base B:").pack(side=LEFT)
        combo_b = ttk.Combobox(frame_controls_top, textvariable=self._intradia_vars_b[slot], state="readonly", width=44)
        combo_b.pack(side=LEFT, padx=(4, 10))
        combo_b.bind("<<ComboboxSelected>>", lambda _e, s=slot: (self._programar_guardado_estado_ui(delay_ms=120), self._refrescar_ui(forzar=True)))
        ttk.Label(frame_controls_top, text="Paso:").pack(side=LEFT)
        combo_intervalo = ttk.Combobox(frame_controls_top, textvariable=self._intradia_rel_interval_vars[slot], state="readonly", width=10)
        combo_intervalo.configure(values=("Cambio", "1 min", "5 min", "10 min", "15 min", "30 min", "60 min"))
        combo_intervalo.pack(side=LEFT, padx=(4, 8))
        combo_intervalo.bind("<<ComboboxSelected>>", lambda _e, s=slot: (self._programar_guardado_estado_ui(delay_ms=120), self._refrescar_ui(forzar=True)))

        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_ratio_ab_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_ratio_ab(s), width=10).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_ab_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_ab(s), width=10).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_spread_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_spread(s), width=10).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_fill_pct_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_fill_pct(s), width=14).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_ratio_pos_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_ratio_pos(s), width=11).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_ratio_neg_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_ratio_neg(s), width=11).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_relaciones_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_relaciones(s), width=13).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_delta_symbol_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_delta_symbol(s), width=8).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_logdelta_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_logdelta(s), width=12).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_varlog_ndelta_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_varlog_ndelta(s), width=10).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_minmax_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_minmax(s), width=11).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_calc_mode_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_calc_mode(s), width=16).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_ecdf_window_mode_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_ecdf_window_mode(s), width=14).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_delta_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_delta(s), width=15).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_vega_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_vega(s), width=11).pack(side=LEFT, padx=(0, 6))
        ttk.Button(frame_controls_bottom, textvariable=self._tabla_rel_show_theta_button_vars[slot], command=lambda s=slot: self._toggle_tabla_rel_theta(s), width=11).pack(side=LEFT, padx=(0, 6))

        frame_table = ttk.Frame(tab)
        frame_table.pack(fill=BOTH, expand=True)
        tree = self._crear_tree_tabla_rel_intradia(frame_table, height=22)
        if isinstance(tree, SheetTableAdapter):
            tree.set_context(self, slot, 'intradia')
        self._tree_tabla_rel_slot_by_key[self._tree_sort_key(tree)] = slot
        tree.bind("<Control-ButtonPress-1>", lambda e, t=tree, s=slot: self._on_tabla_rel_intradia_heading_ctrl_select(e, t, s), add="+")
        tree.bind("<Button-3>", lambda e, t=tree, s=slot: self._on_tabla_rel_intradia_heading_right_click(e, t, s), add="+")
        ttk.Label(tab, textvariable=self._intradia_rel_info_vars[slot]).pack(anchor=W, pady=(6, 0))
        self._intradia_rel_widgets[slot] = {"tab": tab, "combo_fecha": combo_fecha, "combo_a": combo_a, "combo_b": combo_b, "combo_intervalo": combo_intervalo, "tree": tree}
        self._aplicar_estado_columnas_tabla_rel_intradia(slot)

    def _intervalo_minutos_intradia_rel(self, texto: str) -> int | None:
        """Convierte el selector de paso intradía a minutos, o None si es modo por cambio."""
        t = str(texto or "").strip().lower()
        if not t or t.startswith("cambio"):
            return None
        try:
            return max(1, int(re.findall(r"\d+", t)[0]))
        except Exception:
            return 1

    def _resamplear_filas_intradia_rel(self, filas: list[dict[str, Any]], intervalo_min: int | None) -> list[dict[str, Any]]:
        """Reduce filas intradía por intervalo fijo o solo cuando cambian los precios."""
        if not filas:
            return []
        if intervalo_min is None:
            precio_a = _np_float_array(fila.get("precio_a") for fila in filas)
            precio_b = _np_float_array(fila.get("precio_b") for fila in filas)
            ratio_ab = _np_float_array(fila.get("ratio_ab") for fila in filas)
            spread = _np_float_array(fila.get("a_menos_b_last") for fila in filas)
            mask = _np_mask_cambios(precio_a, precio_b, ratio_ab, spread)
            salida = []
            for idx in np.flatnonzero(mask):
                nueva = dict(filas[int(idx)])
                nueva["fuente"] = "cambio"
                salida.append(nueva)
            return salida
        marcas = np.asarray([
            float(ts.hour * 60 + ts.minute) if isinstance((ts := fila.get("_ts_obj")), datetime) else np.nan
            for fila in filas
        ], dtype=float)
        mask = np.zeros(len(filas), dtype=bool)
        ultimo_minuto = math.nan
        for idx, marca in enumerate(marcas):
            if not np.isfinite(marca):
                mask[idx] = True
                continue
            if not np.isfinite(ultimo_minuto) or (float(marca) - float(ultimo_minuto)) >= float(intervalo_min):
                mask[idx] = True
                ultimo_minuto = float(marca)
        return [dict(filas[int(idx)]) for idx in np.flatnonzero(mask)]

    def _construir_fila_viva_tabla_rel_intradia(
        self,
        fecha: str,
        ticker_a: str,
        ticker_b: str,
        filas_calls: list[dict[str, Any]],
        filas_puts: list[dict[str, Any]],
        info: dict[str, Any],
        max_spread: Any,
    ) -> dict[str, Any] | None:
        """Construye una fila viva para la tabla intradía usando los last actuales de ambas patas."""
        if self.offline_mode or not mercado_en_horario_operativo():
            return None
        fecha_txt = str(fecha or "").strip()
        if fecha_txt != ahora().strftime("%Y-%m-%d"):
            return None
        mapa_actual = {str(fila.get("ticker") or ""): fila for fila in list(filas_calls) + list(filas_puts)}
        fila_a = dict(mapa_actual.get(str(ticker_a).strip(), {}) or {})
        fila_b = dict(mapa_actual.get(str(ticker_b).strip(), {}) or {})
        last_a = convertir_a_numero(fila_a.get("last"))
        last_b = convertir_a_numero(fila_b.get("last"))
        if last_a is None or last_b is None:
            return None
        delta_a = fila_a.get("delta") if convertir_a_numero(fila_a.get("delta")) is not None else None
        delta_b = fila_b.get("delta") if convertir_a_numero(fila_b.get("delta")) is not None else None
        vega_a = fila_a.get("vega") if convertir_a_numero(fila_a.get("vega")) is not None else None
        vega_b = fila_b.get("vega") if convertir_a_numero(fila_b.get("vega")) is not None else None
        theta_a = fila_a.get("theta") if convertir_a_numero(fila_a.get("theta")) is not None else None
        theta_b = fila_b.get("theta") if convertir_a_numero(fila_b.get("theta")) is not None else None
        ask_a = fila_a.get("ask") if convertir_a_numero(fila_a.get("ask")) is not None else last_a
        bid_b = fila_b.get("bid") if convertir_a_numero(fila_b.get("bid")) is not None else last_b
        last_evento_texto = str(info.get("last_event_at") or ahora_texto())
        try:
            ts_live = datetime.strptime(last_evento_texto, "%Y-%m-%d %H:%M:%S")
        except Exception:
            ts_live = ahora().replace(tzinfo=None)
        resumen = self._calcular_resumen_relacion(
            ts_live.strftime("%H:%M:%S"),
            last_a,
            last_b,
            "vivo",
            delta_a=delta_a,
            delta_b=delta_b,
            vega_a=vega_a,
            vega_b=vega_b,
            theta_a=theta_a,
            theta_b=theta_b,
            ask_a=ask_a,
            bid_b=bid_b,
            max_spread=max_spread,
        )
        resumen["_ts_obj"] = ts_live
        return resumen

    def _construir_filas_puntas_tabla_rel_intradia(
        self,
        fecha: str,
        ticker_a: str,
        ticker_b: str,
        filas_calls: list[dict[str, Any]],
        filas_puts: list[dict[str, Any]],
        info: dict[str, Any],
        max_spread: Any,
    ) -> list[dict[str, Any]]:
        """Lógica retirada: la tabla intradía ya no agrega filas de compra/venta a puntas."""
        return []

    def _asegurar_ultima_fila_viva_tabla_rel_intradia(self, filas: list[dict[str, Any]], fila_viva: dict[str, Any] | None) -> list[dict[str, Any]]:
        """Garantiza que la última fila visible sea la fila viva actual cuando está disponible."""
        salida = [dict(fila) for fila in (filas or [])]
        if not fila_viva:
            return salida
        salida = [dict(fila) for fila in salida if str(fila.get("fuente") or "").strip().lower() != "vivo"]
        salida.append(dict(fila_viva))
        return salida

    def _recalcular_columnas_derivadas_tabla_rel_intradia_visible(self, filas: list[dict[str, Any]], slot: int) -> list[dict[str, Any]]:
        """Recalcula Δ, Ln, ECDF y MinMax sobre la secuencia visible del timeframe intradía.

        Esto evita que, al usar pasos como 5/30/60 min o modo Cambio, las columnas derivadas
        queden referidas a filas raw ocultas en vez de compararse contra la fila visible anterior.
        """
        salida = [dict(fila) for fila in (filas or [])]
        if not salida:
            return salida
        salida = self._enriquecer_variaciones_tabla_rel(salida, slot, modo="intradia")
        salida = self._enriquecer_ln_ecdf_intradia_tabla_rel(salida, slot)
        estrategias = (
            ("costo_bull", "minmax_ab_dia"),
            ("a_menos_b_last", "minmax_spread_dia"),
            ("ratio_pos_1a2b", "minmax_ratio_pos_1a2b_dia"),
            ("ratio_inv_1a2b", "minmax_ratio_inv_1a2b_dia"),
        )
        acumulados: dict[str, tuple[float | None, float | None]] = {
            clave_minmax: (None, None) for _valor, clave_minmax in estrategias
        }
        for fila in salida:
            for valor_key, minmax_key in estrategias:
                valor = convertir_a_numero(fila.get(valor_key))
                max_act, min_act = acumulados[minmax_key]
                if valor is None:
                    if max_act is not None and min_act is not None:
                        fila[minmax_key] = self._formatear_rango_tabla_rel_ab(max_act, min_act)
                    continue
                max_act = valor if max_act is None else max(max_act, valor)
                min_act = valor if min_act is None else min(min_act, valor)
                acumulados[minmax_key] = (max_act, min_act)
                fila[minmax_key] = self._formatear_rango_tabla_rel_ab(max_act, min_act)
        return salida

    def _refrescar_tabla_rel_intradia(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]], info: dict[str, Any], forzar: bool = False) -> None:
        """Refresca la nueva tabla de relaciones intradía a partir de snapshots por minuto."""
        slot = self.notebook_intradia_rel.index(self.notebook_intradia_rel.select()) + 1 if hasattr(self, 'notebook_intradia_rel') else 1
        widgets = self._intradia_rel_widgets.get(slot, {})
        tree = widgets.get("tree")
        if tree is None:
            return
        fecha = self._intradia_vars_fecha[slot].get().strip()
        ticker_a = self._intradia_vars_a[slot].get().strip()
        ticker_b = self._intradia_vars_b[slot].get().strip()
        self._aplicar_estado_columnas_tabla_rel_intradia(slot)
        opciones = self._listar_bases_disponibles_intradia(fecha)
        if ticker_a not in opciones or ticker_b not in opciones or not ticker_a or not ticker_b:
            tree.delete(*tree.get_children())
            self._intradia_rel_last_rows[slot] = []
            self._intradia_rel_info_vars[slot].set(f"Tabla relaciones intradía {slot}: elegí un día con snapshots y dos bases activas para construir relaciones intradía.")
            return
        filas_raw = self._history_db.obtener_filas_intradia_par_cobertura(fecha, ticker_a, ticker_b, "10:30", "17:00")
        if not filas_raw:
            tree.delete(*tree.get_children())
            self._intradia_rel_last_rows[slot] = []
            self._intradia_rel_info_vars[slot].set(f"Tabla relaciones intradía {slot}: no hay snapshots guardados para {fecha} en {ticker_a} / {ticker_b}.")
            return
        max_spread = self._maximo_cobro_registro_spread(ticker_a, ticker_b)
        salida = []
        max_ab = min_ab = None
        max_sp = min_sp = None
        max_pos = min_pos = None
        max_inv = min_inv = None
        for fila in filas_raw:
            ts = fila.get("ts")
            fecha_txt = ts.strftime("%H:%M") if hasattr(ts, 'strftime') else str(fila.get('ts') or '')
            resumen = self._calcular_resumen_relacion(
                fecha_txt,
                fila.get("a_last"),
                fila.get("b_last"),
                "intradia",
                delta_a=fila.get("a_delta"),
                delta_b=fila.get("b_delta"),
                vega_a=fila.get("a_vega"),
                vega_b=fila.get("b_vega"),
                theta_a=fila.get("a_theta"),
                theta_b=fila.get("b_theta"),
                ask_a=fila.get("a_ask"),
                bid_b=fila.get("b_bid"),
                max_spread=max_spread,
            )
            ab = convertir_a_numero(resumen.get("costo_bull"))
            sp = convertir_a_numero(resumen.get("a_menos_b_last"))
            pos = convertir_a_numero(resumen.get("ratio_pos_1a2b"))
            inv = convertir_a_numero(resumen.get("ratio_inv_1a2b"))
            if ab is not None:
                max_ab = ab if max_ab is None else max(max_ab, ab)
                min_ab = ab if min_ab is None else min(min_ab, ab)
                resumen["minmax_ab_dia"] = self._formatear_rango_tabla_rel_ab(max_ab, min_ab)
            if sp is not None:
                max_sp = sp if max_sp is None else max(max_sp, sp)
                min_sp = sp if min_sp is None else min(min_sp, sp)
                resumen["minmax_spread_dia"] = self._formatear_rango_tabla_rel_ab(max_sp, min_sp)
            if pos is not None:
                max_pos = pos if max_pos is None else max(max_pos, pos)
                min_pos = pos if min_pos is None else min(min_pos, pos)
                resumen["minmax_ratio_pos_1a2b_dia"] = self._formatear_rango_tabla_rel_ab(max_pos, min_pos)
            if inv is not None:
                max_inv = inv if max_inv is None else max(max_inv, inv)
                min_inv = inv if min_inv is None else min(min_inv, inv)
                resumen["minmax_ratio_inv_1a2b_dia"] = self._formatear_rango_tabla_rel_ab(max_inv, min_inv)
            resumen["_ts_obj"] = ts
            salida.append(resumen)
        fila_viva = self._construir_fila_viva_tabla_rel_intradia(fecha, ticker_a, ticker_b, filas_calls, filas_puts, info, max_spread)
        salida = self._resamplear_filas_intradia_rel(salida, self._intervalo_minutos_intradia_rel(self._intradia_rel_interval_vars[slot].get()))
        salida = self._asegurar_ultima_fila_viva_tabla_rel_intradia(salida, fila_viva)
        salida = self._recalcular_columnas_derivadas_tabla_rel_intradia_visible(salida, slot)
        for fila in salida:
            fila.pop("_ts_obj", None)
        self._intradia_rel_last_rows[slot] = [dict(f) for f in salida]
        self._cargar_tree_tabla_rel_intradia_en(tree, salida)
        paso = self._intradia_rel_interval_vars[slot].get().strip() or "1 min"
        detalle_live = " | última fila usa last actual" if fila_viva is not None else ""
        self._intradia_rel_info_vars[slot].set(
            f"Tabla relaciones intradía {slot}: {ticker_a} / {ticker_b} | fecha={fecha} | filas={len(salida)} | paso={paso} | replica la lógica de columnas, diferencias, relaciones, logs, ECDF y griegas de Tabla relaciones, pero usando snapshots del día elegido entre 10:30 y 17:00. 'Cambio' muestra solo filas cuando cambió alguna relación base.{detalle_live}"
        )

