        frame_controls_bottom2.pack(fill=X, pady=(4, 0))
        # Variable local para frame controls bottom3.
        frame_controls_bottom3 = ttk.Frame(frame_controls)
        frame_controls_bottom3.pack(fill=X, pady=(4, 0))
        # Variable local para frame controls bottom4.
        frame_controls_bottom4 = ttk.Frame(frame_controls)
        frame_controls_bottom4.pack(fill=X, pady=(4, 0))

        ttk.Label(frame_controls_top, text="Día:").pack(side=LEFT)
        # Variable local para combo fecha.
