        combo_fecha.pack(side=LEFT, padx=(4, 12))
        combo_fecha.bind("<<ComboboxSelected>>", lambda _e: self._al_cambiar_selector_backtest())
        ttk.Label(frame_controls_top, text="Base A:").pack(side=LEFT)
