        horas_bt: list[str] = []
        # Variable local para base hora.
        base_hora = datetime.strptime(f"2000-01-01 {BACKTEST_SESSION_START_TIME}:00", "%Y-%m-%d %H:%M:%S")
        # Variable local para fin hora.
        fin_hora = datetime.strptime(f"2000-01-01 {BACKTEST_SESSION_END_TIME}:00", "%Y-%m-%d %H:%M:%S")
