    # ─────────────────────────────────────────────────────────────────────────
    # Vista Cadena
    # ─────────────────────────────────────────────────────────────────────────

    def _cadena_navegar(self, delta: int) -> None:
        """Desplaza la vista Cadena delta filas respecto al ATM."""
        self._cadena_offset = int(getattr(self, "_cadena_offset", 0)) + int(delta)
        self._programar_refresco_ui(delay_ms=80, forzar=True)

    def _color_cadena_celda(self, pct: float | None) -> tuple[str, str]:
        """Devuelve (bg, fg) para un ratio porcentual en la vista Cadena."""
        if pct is None:
            return "#131a24", "#444444"
        if pct < 25:  return "#0a2e14", "#4caf50"
        if pct < 40:  return "#1a5428", "#81c784"
        if pct < 55:  return "#4a3a00", "#ffd54f"
        if pct < 70:  return "#6a2800", "#ff8a65"
        return "#6a0f0f", "#ef5350"

    def _cadena_tono_atm(self, bg_hex: str) -> str:
        """Agrega un tono azul a un color de fondo para resaltar la fila ATM."""
        try:
            r = int(bg_hex[1:3], 16)
            g = int(bg_hex[3:5], 16)
            b = int(bg_hex[5:7], 16)
            return f"#{min(255,r+15):02x}{g:02x}{min(255,b+35):02x}"
        except Exception:
            return bg_hex

    def _crear_vista_cadena(self, parent) -> None:
        """Crea la vista Cadena: strikes al centro, ratios puts a la izq, calls a la der."""
        frame_ctrl = ttk.Frame(parent)
        frame_ctrl.pack(fill=X, pady=(0, 6))
        ttk.Label(frame_ctrl, text="Bases al rededor:").pack(side=LEFT)
        self.var_cadena_nbases = StringVar(value="4")
        ttk.Spinbox(
            frame_ctrl, textvariable=self.var_cadena_nbases,
            from_=1, to=8, width=4,
            command=lambda: self._programar_refresco_ui(delay_ms=150, forzar=True),
        ).pack(side=LEFT, padx=(4, 12))
        self.var_cadena_info = StringVar(value="")
        ttk.Label(frame_ctrl, textvariable=self.var_cadena_info, foreground="#888888").pack(side=LEFT)

        frame_body = ttk.Frame(parent)
        frame_body.pack(fill=BOTH, expand=True)
        ttk.Button(frame_body, text="‹", width=2,
                   command=lambda: self._cadena_navegar(-6)).pack(side=LEFT, fill=Y)
        ttk.Button(frame_body, text="›", width=2,
                   command=lambda: self._cadena_navegar(6)).pack(side=RIGHT, fill=Y)

        frame_sheet = ttk.Frame(frame_body)
        frame_sheet.pack(fill=BOTH, expand=True)

        self._cadena_offset = 0
        self._cadena_last_key: object = None
        self.sheet_cadena = None
        if TksheetWidget is None:
            ttk.Label(frame_sheet, text="tksheet no disponible.").pack(padx=8, pady=8)
            return
        try:
            nbases = 4
            headers = (
                ["PUT"]
                + [f"P-{n}" for n in range(nbases, 0, -1)]
                + ["STRIKE"]
                + [f"C+{n}" for n in range(1, nbases + 1)]
                + ["CALL"]
            )
            self.sheet_cadena = TksheetWidget(
                frame_sheet,
                headers=headers,
                show_row_index=False,
                header_bg="#0f1726",
                header_fg="#c8c8c8",
                table_bg="#0d1117",
                table_fg="#e8e8e8",
                header_font=("Consolas", 12, "bold"),
                font=("Consolas", 14, "normal"),
            )
            self.sheet_cadena.pack(fill=BOTH, expand=True)
            self.sheet_cadena.enable_bindings("single_select")
            col_widths = [115] + [100] * nbases + [90] + [100] * nbases + [115]
            for i, w in enumerate(col_widths):
                try:
                    self.sheet_cadena.column_width(i, width=w)
                except Exception:
                    pass
        except Exception:
            LOGGER.exception("No se pudo inicializar tksheet para vista Cadena")
            ttk.Label(frame_sheet, text="No se pudo inicializar la tabla Cadena.").pack(padx=8, pady=8)

    def _refrescar_cadena(
        self,
        filas_calls: list[dict[str, Any]],
        filas_puts: list[dict[str, Any]],
        info: dict[str, Any],
        forzar: bool = False,
    ) -> None:
        """Refresca la vista Cadena con datos en vivo."""
        sheet = getattr(self, "sheet_cadena", None)
        if sheet is None:
            return
        try:
            nbases = max(1, min(int(self.var_cadena_nbases.get()), 8))
        except Exception:
            nbases = 4

        # ── Reset de columnas solo cuando cambia nbases ───────────────────
        _reset_cols = nbases != getattr(self, "_cadena_nbases_actual", -1)
        if _reset_cols:
            self._cadena_nbases_actual = nbases

        def _precio_fila(fila: dict) -> float | None:
            for campo in ("last", "bid", "ask", "ref"):
                v = convertir_a_numero(fila.get(campo))
                if v and v > 0:
                    return v
            return None

        calls: dict[float, float] = {}
        for f in filas_calls:
            try:
                k = float(str(f.get("strike") or 0).replace(",", "."))
                p = _precio_fila(f)
                if k > 0 and p:
                    calls[k] = p
            except Exception:
                pass

        puts: dict[float, float] = {}
        for f in filas_puts:
            try:
                k = float(str(f.get("strike") or 0).replace(",", "."))
                p = _precio_fila(f)
                if k > 0 and p:
                    puts[k] = p
            except Exception:
                pass

        todos = sorted(set(calls) | set(puts))
        if len(todos) < 2:
            return

        spot = self._precio_subyacente_actual
        if spot:
            atm_idx = min(range(len(todos)), key=lambda i: abs(todos[i] - spot))
        else:
            atm_idx = len(todos) // 2

        # ── Headers con strikes reales relativos al ATM ───────────────────
        def _sk(k: float) -> str:
            return f"{int(k):,}".replace(",", ".") if k == int(k) else f"{k:.1f}"

        _hdr_key = (nbases, atm_idx, tuple(todos))
        if _hdr_key != getattr(self, "_cadena_hdr_key", None):
            atm_hdrs = ["PUT"]
            for n in range(nbases, 0, -1):
                ri = atm_idx - n
                lbl = f"P-{n} ({_sk(todos[ri])})" if ri >= 0 else f"P-{n}"
                atm_hdrs.append(lbl)
            atm_hdrs.append("STRIKE")
            for n in range(1, nbases + 1):
                ri = atm_idx + n
                lbl = f"C+{n} ({_sk(todos[ri])})" if ri < len(todos) else f"C+{n}"
                atm_hdrs.append(lbl)
            atm_hdrs.append("CALL")
            try:
                sheet.headers(atm_hdrs, redraw=False)
            except Exception:
                pass
            # Ancho automático según texto de cada encabezado.
            try:
                import tkinter.font as tkfont
                hdr_font = tkfont.Font(family="Consolas", size=12, weight="bold")
                padding = 24
                for i, hdr in enumerate(atm_hdrs):
                    w = max(60, hdr_font.measure(hdr) + padding)
                    sheet.column_width(i, width=w)
            except Exception:
                pass
            self._cadena_hdr_key = _hdr_key

        cache_key = (
            tuple(todos),
            tuple(sorted(calls.items())),
            tuple(sorted(puts.items())),
            nbases,
            atm_idx,
        )
        if not forzar and cache_key == getattr(self, "_cadena_last_key", None):
            return
        self._cadena_last_key = cache_key

        offset = int(getattr(self, "_cadena_offset", 0))
        centro = max(nbases, min(len(todos) - nbases - 1, atm_idx + offset))
        visible = 20
        inicio = max(0, centro - visible // 2)
        fin = min(len(todos), inicio + visible)
        strikes_vis = todos[inicio:fin]

        def fmt_pct(v: float | None) -> str:
            return f"{v:.1f}%" if v is not None else "--"

        def fmt_precio(v: float | None) -> str:
            if v is None:
                return "--"
            s = f"{v:,.2f}"
            partes = s.split(".")
            return partes[0].replace(",", ".") + "," + partes[1]

        data: list[list[str]] = []
        cell_colors: list[tuple[int, int, str, str]] = []

        for r_idx, k in enumerate(strikes_vis):
            k_idx = todos.index(k)
            es_atm = (k_idx == atm_idx)
            call_p = calls.get(k)
            put_p = puts.get(k)

            # Put ratios: (put(K) - put(K-n)) / (K - K_ref) * 100
            put_ratios: list[float | None] = []
            for n in range(1, nbases + 1):
                ri = k_idx - n
                if ri >= 0:
                    ref_k = todos[ri]
                    ref_p = puts.get(ref_k)
                    denom = k - ref_k
                    if put_p and ref_p is not None and denom > 0:
                        put_ratios.append((put_p - ref_p) / denom * 100)
                    else:
                        put_ratios.append(None)
                else:
                    put_ratios.append(None)

            # Call ratios: (call(K) - call(K+n)) / (K_ref - K) * 100
            call_ratios: list[float | None] = []
            for n in range(1, nbases + 1):
                ri = k_idx + n
                if ri < len(todos):
                    ref_k = todos[ri]
                    ref_p = calls.get(ref_k)
                    denom = ref_k - k
                    if call_p and ref_p is not None and denom > 0:
                        call_ratios.append((call_p - ref_p) / denom * 100)
                    else:
                        call_ratios.append(None)
                else:
                    call_ratios.append(None)

            strike_col = nbases + 1
            last_col = 2 * nbases + 2

            row: list[str] = [fmt_precio(put_p)]
            for n in range(nbases - 1, -1, -1):
                row.append(fmt_pct(put_ratios[n] if n < len(put_ratios) else None))
            strike_str = f"{int(k):,}".replace(",", ".") if k == int(k) else f"{k:.1f}"
            row.append(strike_str)
            for n in range(nbases):
                row.append(fmt_pct(call_ratios[n] if n < len(call_ratios) else None))
            row.append(fmt_precio(call_p))
            data.append(row)

            # ── colores por celda ──────────────────────────────────────────
            cell_colors.append((r_idx, 0,
                                 "#152040" if es_atm else "#0d1117",
                                 "#aaaaaa" if es_atm else "#666666"))
            for col_idx, n in enumerate(range(nbases - 1, -1, -1)):
                rv = put_ratios[n] if n < len(put_ratios) else None
                bg, fg = self._color_cadena_celda(rv)
                if es_atm:
                    bg = self._cadena_tono_atm(bg)
                cell_colors.append((r_idx, col_idx + 1, bg, fg))
            cell_colors.append((r_idx, strike_col,
                                 "#1a3050" if es_atm else "#0f1726",
                                 "#f0e870" if es_atm else "#9e9e9e"))
            for col_idx in range(nbases):
                rv = call_ratios[col_idx] if col_idx < len(call_ratios) else None
                bg, fg = self._color_cadena_celda(rv)
                if es_atm:
                    bg = self._cadena_tono_atm(bg)
                cell_colors.append((r_idx, strike_col + 1 + col_idx, bg, fg))
            cell_colors.append((r_idx, last_col,
                                 "#152040" if es_atm else "#0d1117",
                                 "#f0e870" if es_atm else "#ef5350"))

        try:
            sheet.set_sheet_data(data, reset_col_positions=_reset_cols, redraw=False)
            if _reset_cols and getattr(self, "_cadena_hdr_key", None) is None:
                # Fallback solo si los headers todavía no se midieron.
                col_widths = [115] + [100] * nbases + [90] + [100] * nbases + [115]
                for i, w in enumerate(col_widths):
                    try:
                        sheet.column_width(i, width=w)
                    except Exception:
                        pass
            try:
                sheet.dehighlight_all(redraw=False)
            except Exception:
                pass
            for r, c, bg, fg in cell_colors:
                try:
                    sheet.highlight_cells(row=r, column=c, bg=bg, fg=fg, redraw=False)
                except Exception:
                    pass
            sheet.redraw()
        except Exception:
            LOGGER.debug("Error al refrescar Cadena", exc_info=True)

        spot_str = f"{spot:,.2f}".replace(",", ".") if spot else "?"
        atm_k = todos[atm_idx]
        atm_str = f"{int(atm_k):,}".replace(",", ".") if atm_k == int(atm_k) else f"{atm_k:.1f}"
        try:
            self.var_cadena_info.set(
                f"Spot ≈ {spot_str}  |  ATM: {atm_str}  |  {len(todos)} strikes  |  {nbases} bases"
            )
        except Exception:
            pass

