    def _crear_vista_registro_spread(self, parent) -> None:
        """Crea la vista independiente para seguir hasta 6 spreads A-B en un único gráfico."""
        # Variable local para frame top.
        frame_top = ttk.Frame(parent)
        frame_top.pack(fill=X, pady=(0, 6))
        # Variable local para frame controls.
        frame_controls = ttk.Frame(frame_top)
        frame_controls.pack(side=LEFT, fill=X, expand=True)
        # Variable local para frame ratio.
        frame_ratio = ttk.LabelFrame(frame_top, text="Ratios A/B seleccionados")
        frame_ratio.pack(side=RIGHT, fill=BOTH, padx=(8, 0))
        frame_ratio.configure(width=620, height=205)
        frame_ratio.pack_propagate(False)
        for slot in self._registro_spread_slots:
            # Fila temporal procesada en este paso.
            fila = ttk.Frame(frame_controls)
            fila.pack(fill=X, pady=1)
            ttk.Checkbutton(
                fila,
                text=f"Par {slot} activo",
                variable=self._registro_spread_enabled_vars[slot],
                command=lambda s=slot: self._al_cambiar_selector_registro_spread(s),
            ).pack(side=LEFT)
            ttk.Label(fila, text="Base A:").pack(side=LEFT, padx=(8, 0))
            # Variable local para combo A.
            combo_a = ttk.Combobox(fila, textvariable=self._registro_spread_vars_a[slot], state="readonly", width=44)
            combo_a.pack(side=LEFT, padx=(4, 10))
            combo_a.bind("<<ComboboxSelected>>", lambda _e, s=slot: self._al_cambiar_selector_registro_spread(s))
            ttk.Label(fila, text="Base B:").pack(side=LEFT)
            # Variable local para combo B.
            combo_b = ttk.Combobox(fila, textvariable=self._registro_spread_vars_b[slot], state="readonly", width=44)
            combo_b.pack(side=LEFT, padx=(4, 8))
            combo_b.bind("<<ComboboxSelected>>", lambda _e, s=slot: self._al_cambiar_selector_registro_spread(s))
            # Variable local para label metricas.
            label_metricas = ttk.Label(fila, textvariable=self._registro_spread_metric_vars[slot], width=36)
            label_metricas.pack(side=LEFT, padx=(6, 0))
            self._registro_spread_widgets[slot] = {"combo_a": combo_a, "combo_b": combo_b, "label_metricas": label_metricas}
        ttk.Button(frame_controls, text="Actualizar", command=self._al_cambiar_selector_registro_spread).pack(anchor=W, pady=(4, 0))
        # Variable local para fig ratio.
        fig_ratio = Figure(figsize=(6.1, 2.35), dpi=100)
        # Variable local para ax ratio.
        ax_ratio = fig_ratio.add_subplot(111)
        fig_ratio.subplots_adjust(top=0.88, bottom=0.22, left=0.10, right=0.985)
        # Variable local para canvas ratio.
        canvas_ratio = FigureCanvasTkAgg(fig_ratio, master=frame_ratio)
        canvas_ratio.get_tk_widget().pack(fill=BOTH, expand=True)
        self._registrar_canvas_interactivo(canvas_ratio, None, {"registro_spread_ratio": ax_ratio})
        # Variable local para frame chart.
        frame_chart = ttk.Frame(parent)
        frame_chart.pack(fill=BOTH, expand=True)
        # Variable local para frame toolbar.
        frame_toolbar = ttk.Frame(frame_chart)
        frame_toolbar.pack(fill=X, pady=(0, 4))
        # Variable local para fig.
        fig = Figure(figsize=(13.8, 7.8), dpi=100)
        # Variable local para ax.
        ax = fig.add_subplot(111)
        fig.subplots_adjust(top=0.94, bottom=0.10, left=0.06, right=0.985)
        # Variable local para canvas.
        canvas = FigureCanvasTkAgg(fig, master=frame_chart)
        canvas.get_tk_widget().pack(fill=BOTH, expand=True)
        # Variable local para toolbar.
        toolbar = NavigationToolbar2Tk(canvas, frame_toolbar)
        toolbar.update()
        self._compactar_toolbar(toolbar)
        self._registrar_canvas_interactivo(canvas, toolbar, {"registro_spread": ax})
        ttk.Label(parent, textvariable=self.var_registro_spread_info).pack(anchor=W, pady=(6, 0))
        # Variable interna para fig registro spread.
        self.fig_registro_spread = fig
        # Variable interna para ax registro spread.
        self.ax_registro_spread = ax
        # Variable interna para canvas registro spread.
        self.canvas_registro_spread = canvas
        # Variable interna para toolbar registro spread.
        self.toolbar_registro_spread = toolbar
        # Variable interna para fig registro spread ratio.
        self.fig_registro_spread_ratio = fig_ratio
        # Variable interna para ax registro spread ratio.
        self.ax_registro_spread_ratio = ax_ratio
        # Variable interna para canvas registro spread ratio.
        self.canvas_registro_spread_ratio = canvas_ratio

