    def _crear_vista_backtest_vencimiento(self, parent) -> None:
        """Crea la vista del backtest por vencimiento con tabla de operaciones y gráfico inferior por cierres."""
        # Variable local para frame controls.
        frame_controls = ttk.Frame(parent)
        frame_controls.pack(fill=X, pady=(0, 6))
        for slot in self._backtest_venc_slots:
            # Fila temporal procesada en este paso.
            fila = ttk.Frame(frame_controls)
            fila.pack(fill=X, pady=1)
            ttk.Checkbutton(
                fila,
                text=f"BT {slot} activo",
                variable=self._backtest_venc_enabled_vars[slot],
                command=lambda s=slot: self._al_cambiar_selector_backtest_vencimiento(s),
            ).pack(side=LEFT)
            ttk.Label(fila, text="Base A:").pack(side=LEFT, padx=(8, 0))
            # Variable local para combo A.
            combo_a = ttk.Combobox(fila, textvariable=self._backtest_venc_vars_a[slot], state="readonly", width=28)
            combo_a.pack(side=LEFT, padx=(4, 8))
            combo_a.bind("<<ComboboxSelected>>", lambda _e, s=slot: self._al_cambiar_selector_backtest_vencimiento(s))
            ttk.Label(fila, text="Base B:").pack(side=LEFT)
            # Variable local para combo B.
            combo_b = ttk.Combobox(fila, textvariable=self._backtest_venc_vars_b[slot], state="readonly", width=28)
            combo_b.pack(side=LEFT, padx=(4, 8))
            combo_b.bind("<<ComboboxSelected>>", lambda _e, s=slot: self._al_cambiar_selector_backtest_vencimiento(s))
            ttk.Label(fila, text="Estrategia:").pack(side=LEFT)
            # Variable local para combo strategy.
            combo_strategy = ttk.Combobox(fila, textvariable=self._backtest_venc_strategy_vars[slot], state="readonly", width=18)
            combo_strategy.pack(side=LEFT, padx=(4, 8))
            combo_strategy.configure(values=[texto for _clave, texto in self._backtest_venc_strategy_options])
            combo_strategy.bind("<<ComboboxSelected>>", lambda _e, s=slot: self._al_cambiar_selector_backtest_vencimiento(s))
            ttk.Label(fila, text="Ratio:").pack(side=LEFT)
            # Variable local para combo coeficiente.
            combo_coef = ttk.Combobox(fila, textvariable=self._backtest_venc_ratio_coef_vars[slot], state="readonly", width=7)
            combo_coef.pack(side=LEFT, padx=(4, 8))
            combo_coef.configure(values=[f"{x / 4.0:.2f}" for x in range(4, 13)])
            combo_coef.bind("<<ComboboxSelected>>", lambda _e, s=slot: self._al_cambiar_selector_backtest_vencimiento(s))
            # Variable local para label metricas.
            label_metricas = ttk.Label(fila, textvariable=self._backtest_venc_metric_vars[slot], width=34)
            label_metricas.pack(side=LEFT, padx=(6, 0))
            self._backtest_venc_widgets[slot] = {
                "combo_a": combo_a,
                "combo_b": combo_b,
                "combo_strategy": combo_strategy,
                "combo_coef": combo_coef,
                "label_metricas": label_metricas,
            }
        # Variable local para frame params.
        frame_params = ttk.Frame(parent)
        frame_params.pack(fill=X, pady=(0, 6))
        ttk.Label(frame_params, text="Sigma:").pack(side=LEFT)
        # Variable local para entry sigma.
        entry_sigma = ttk.Entry(frame_params, textvariable=self.var_backtest_venc_sigma, width=6)
        entry_sigma.pack(side=LEFT, padx=(4, 8))
        entry_sigma.bind("<KeyRelease>", lambda _e: self._al_cambiar_selector_backtest_vencimiento())
