    def _reconectar_ws_manual(self) -> None:
        """Intenta reabrir manualmente el WebSocket y re-suscribirse."""
        if self.offline_mode:
            self.var_estado.set("Modo offline: la reconexión WebSocket está desactivada.")
            return
        self.var_estado.set("Reconectando WebSocket manualmente...")

        def _worker() -> None:
            try:
                try:
                    cerrar_conexiones(self.environment)
                except Exception:
                    LOGGER.exception("Fallo al cerrar conexiones antes de reconectar manualmente")
                # Lista o conjunto temporal de tickers procesados en este bloque.
                tickers = list(LAST_WS_TICKERS) if LAST_WS_TICKERS else [inst.ticker for inst in self.instrumentos]
                # Variable local para profundidad.
                profundidad = int(LAST_WS_DEPTH or 1)
                # Entorno pyRofex activo de la ejecución.
                environment = LAST_WS_ENVIRONMENT if LAST_WS_ENVIRONMENT is not None else self.environment
                LOGGER.info("Reconexión manual WS | tickers=%s | profundidad=%s | environment=%s", len(tickers), profundidad, environment)
                iniciar_websocket(environment, tickers, profundidad)
                self.root.after(0, lambda: self.var_estado.set("WebSocket reconectado manualmente."))
            except Exception as exc:
                LOGGER.exception("Fallo en reconexión manual del WebSocket")
                self.root.after(0, lambda: messagebox.showerror("Reconexión WS", f"No se pudo reconectar el WebSocket:\n{exc}"))
                self.root.after(0, lambda: self.var_estado.set(f"Error al reconectar WS: {exc}"))

        threading.Thread(target=_worker, name="ws-manual-reconnect", daemon=True).start()

    def _llenar_selector_fechas(self) -> None:
        """Carga el selector superior de vencimientos disponibles."""
        self._actualizar_vencimientos_visibles(preservar_actual=True)

    def _vencimiento_es_historico(self, vencimiento: str) -> bool:
        """Indica si un vencimiento ya vencio hace mas de una semana."""
        venc = str(vencimiento or "").strip()
        try:
            fecha_venc = datetime.strptime(venc, "%Y-%m-%d").date()
        except Exception:
            return False
        return fecha_venc < (ahora().date() - timedelta(days=7))

    def _vencimientos_visibles(self) -> list[str]:
        """Devuelve vencimientos visibles segun el toggle de historicos."""
        todos = sorted({str(v or "").strip() for v in getattr(self, "_vencimientos_todos", []) if str(v or "").strip()})
        if bool(self._mostrar_vencimientos_historicos.get()):
            return todos
        visibles = [v for v in todos if not self._vencimiento_es_historico(v)]
        return visibles or todos

    def _actualizar_texto_toggle_vencimientos_historicos(self) -> None:
        """Actualiza el texto del boton de vencimientos historicos."""
        texto = "Ocultar historicos" if bool(self._mostrar_vencimientos_historicos.get()) else "Ver historicos"
        self.var_toggle_vencimientos_historicos.set(texto)

    def _actualizar_vencimientos_visibles(self, *, preservar_actual: bool = True) -> None:
        """Refresca los valores del selector superior sin perder el estado guardado."""
        actual = self.var_vencimiento.get().strip() if preservar_actual else ""
        self._vencimientos = self._vencimientos_visibles()
        if hasattr(self, "combo_vencimiento"):
            self.combo_vencimiento["values"] = self._vencimientos
        if self._vencimientos and (not actual or actual not in self._vencimientos):
            self.var_vencimiento.set(self._vencimientos[0])
        elif actual:
            self.var_vencimiento.set(actual)

    def _toggle_vencimientos_historicos(self) -> None:
        """Muestra u oculta vencimientos ya vencidos hace mas de una semana."""
        venc_anterior = self.var_vencimiento.get().strip()
        if venc_anterior:
            self._guardar_estado_vencimiento_actual(venc_anterior)
        self._mostrar_vencimientos_historicos.set(not bool(self._mostrar_vencimientos_historicos.get()))
        self._actualizar_texto_toggle_vencimientos_historicos()
        self._actualizar_vencimientos_visibles(preservar_actual=True)
        venc_nuevo = self.var_vencimiento.get().strip()
        if venc_nuevo != venc_anterior:
            self._restaurar_estado_vencimiento_ui(venc_nuevo)
        self._vencimiento_general_actual = venc_nuevo
        self._guardar_estado_ui()
        self._refrescar_ui(forzar=True)

    def _vencimiento_seleccionable(self, vencimiento: str) -> bool:
        """Indica si un vencimiento puede quedar seleccionado con el filtro actual."""
        return str(vencimiento or "").strip() in set(self._vencimientos_visibles())

    def _primer_vencimiento_visible(self) -> str:
        """Devuelve el primer vencimiento visible disponible."""
        visibles = self._vencimientos_visibles()
        return visibles[0] if visibles else ""

    def _registrar_vencimiento_disponible(self, vencimiento: str) -> None:
        """Agrega un vencimiento a la lista completa sin forzarlo visible si es historico."""
        venc = str(vencimiento or "").strip()
        if not venc:
            return
        if venc not in getattr(self, "_vencimientos_todos", []):
            self._vencimientos_todos = sorted({*getattr(self, "_vencimientos_todos", []), venc})
        self._actualizar_vencimientos_visibles(preservar_actual=True)

    def _asegurar_vencimiento_en_selector(self, vencimiento: str) -> None:
        """Mantiene en el selector el vencimiento guardado aunque el maestro actual no lo traiga."""
        venc = str(vencimiento or "").strip()
        if not venc:
            return
        self._registrar_vencimiento_disponible(venc)
        if self._vencimiento_es_historico(venc) and not bool(self._mostrar_vencimientos_historicos.get()):
            return
        if hasattr(self, "combo_vencimiento"):
            self.combo_vencimiento["values"] = self._vencimientos

    def _llenar_selector_intradia_fechas(self, fechas: list[str] | None = None) -> None:
        """Carga las fechas disponibles para el comparador intradía desde SQLite."""
        # Conjunto de fechas usado en este cálculo.
        if fechas is None:
            fechas = self._history_db.obtener_fechas_snapshots(120)
        # Variable local para fecha preferida.
        fecha_preferida = self._resolver_fecha_historial(self._history_date)
        for slot in self._intradia_slots:
            # Variable local para widgets.
            widgets = self._intradia_widgets.get(slot, {})
            # Variable local para combo fecha.
            combo_fecha = widgets.get("combo_fecha")
            if combo_fecha is not None:
                combo_fecha["values"] = fechas
            # Variable de Tkinter de texto para fecha.
            var_fecha = self._intradia_vars_fecha[slot]
            # Variable local para valor actual.
            valor_actual = var_fecha.get().strip()
            if valor_actual not in fechas:
                if fecha_preferida in fechas:
                    var_fecha.set(fecha_preferida)
                elif fechas:
                    var_fecha.set(fechas[0])
                else:
                    var_fecha.set("")

    def _llenar_selector_backtest_fechas(self, fechas: list[str] | None = None) -> None:
        """Carga fechas disponibles para las vistas de backtest intradía."""
        # Conjunto de fechas usado en este cálculo.
        if fechas is None:
            fechas = self._history_db.obtener_fechas_snapshots(120)
        # Variable local para fecha preferida.
        fecha_preferida = self._resolver_fecha_historial(self._history_date)
        for slot in self._backtest_slots:
            # Variable local para combo fecha.
            combo_fecha = self._backtest_widgets.get(slot, {}).get("combo_fecha")
            if combo_fecha is not None:
                combo_fecha["values"] = fechas
            # Variable local para combo fecha hedge.
            combo_fecha_hedge = self._backtest_hedge_widgets.get(slot, {}).get("combo_fecha")
            if combo_fecha_hedge is not None:
                combo_fecha_hedge["values"] = fechas
            # Variable local para valor actual.
            valor_actual = self._backtest_vars_fecha[slot].get().strip()
            if valor_actual not in fechas:
                if fecha_preferida in fechas:
                    self._backtest_vars_fecha[slot].set(fecha_preferida)
                elif fechas:
                    self._backtest_vars_fecha[slot].set(fechas[0])
                else:
                    self._backtest_vars_fecha[slot].set("")

    def _tab_activa_texto(self) -> str:
        """Devuelve el nombre de la pestaña activa para refrescar solo la vista visible."""
        try:
            return str(self.notebook.tab(self.notebook.select(), "text") or "")
        except Exception:
            return ""

    def _slot_activo_desde_notebook(self, notebook, slots_validos: Iterable[int] | None = None) -> int:
        """Resuelve el slot activo desde el índice real del notebook, sin depender del texto de la pestaña."""
        try:
            if notebook is None:
                return 1
            valor = self._slot_visible_desde_notebook(notebook)
            if slots_validos is not None and valor not in set(slots_validos):
                return 1
            return valor
        except Exception:
            return 1

    def _tab_intradia_activa_indice(self) -> int:
        """Devuelve el índice de la subvista intradía activa."""
        try:
            if not hasattr(self, "notebook_intradia"):
                return 1
            return self._slot_activo_desde_notebook(self.notebook_intradia, self._intradia_slots)
        except Exception:
            LOGGER.debug("No se pudo detectar la subvista intradía activa", exc_info=True)
        return 1

