    def _sincronizar_aliases_comp_activos(self) -> None:
        """Apunta los atributos legacy del comparador 2 bases a la subvista activa."""
        # Variable local para slot.
        slot = self._tab_comp_activa_indice()
        # Variable local para widgets.
        widgets = self._comp_widgets.get(slot, {})
        self.var_comp_a = self._comp_vars_a[slot]
        self.var_comp_b = self._comp_vars_b[slot]
