    def _al_cambiar_pestana(self, _event=None) -> None:
        """Programa guardado y refresco perezoso al cambiar de pestaña principal."""
        self._programar_hidratacion_de_pestana_principal_activa()
        self._programar_guardado_estado_ui(delay_ms=700)
        if self._tab_activa_texto() not in {
            "Tabla relaciones",
            "Tabla rel. intradía",
            "Backtest cobertura",
        }:
            self._programar_refresco_subvista(delay_ms=180, forzar=False)

    def _asegurar_subvista_de_pestana_principal_activa(self) -> None:
        """Construye la subvista perezosa correspondiente a la pestaña principal actual."""
        mapa = {
            "Tabla relaciones": "notebook_tabla_rel",
            "Tabla rel. intradía": "notebook_intradia_rel",
            "Backtest cobertura": "notebook_backtest_hedge",
        }
        notebook_attr = mapa.get(self._tab_activa_texto())
        if notebook_attr:
            self._asegurar_subvista_construida(notebook_attr)

    def _programar_hidratacion_de_pestana_principal_activa(self) -> None:
        """Programa hidratación perezosa de la subvista de la pestaña principal actual."""
        tab_texto = self._tab_activa_texto()
        mapa = {
            "Tabla relaciones": "notebook_tabla_rel",
            "Tabla rel. intradía": "notebook_intradia_rel",
            "Backtest cobertura": "notebook_backtest_hedge",
        }
        notebook_attr = mapa.get(tab_texto)
        if notebook_attr:
            self._programar_hidratacion_subvista(notebook_attr, tab_principal=tab_texto, delay_refresco_ms=180)

    def _definiciones_pestanas_principales(self) -> list[tuple[str, Any]]:
        """Devuelve el identificador estable y el widget de cada pestaña principal."""
        return [
            ("calls", getattr(self, "tab_calls", None)),
            ("puts", getattr(self, "tab_puts", None)),
            ("acciones", getattr(self, "tab_acciones", None)),
            ("futuros", getattr(self, "tab_futuros", None)),
            ("compacta", getattr(self, "tab_compacta", None)),
            ("smile", getattr(self, "tab_smile", None)),
            ("gex", getattr(self, "tab_gex", None)),
            ("comparador_2_bases", getattr(self, "tab_comp", None)),
            ("tabla_relaciones", getattr(self, "tab_tabla_rel", None)),
            ("registro_spread", getattr(self, "tab_registro_spread", None)),
            ("registro_ratio_invertido", getattr(self, "tab_registro_ratio_invertido", None)),
            ("matriz_bases", getattr(self, "tab_matriz_bases", None)),
            ("ratios", getattr(self, "tab_ratios", None)),
            ("comparador_intradia", getattr(self, "tab_intradia", None)),
            ("backtest_intradia", getattr(self, "tab_backtest", None)),
            ("backtest_cobertura", getattr(self, "tab_backtest_hedge", None)),
            ("backtest_vencimiento", getattr(self, "tab_backtest_vencimiento", None)),
        ]

    def _mapa_pestanas_principales(self) -> tuple[dict[str, Any], dict[str, str]]:
        """Construye mapas para traducir entre ids estables y widgets reales del notebook."""
        # Variable local para id to widget.
        id_to_widget: dict[str, Any] = {}
        # Variable local para widget to id.
        widget_to_id: dict[str, str] = {}
        for tab_id, widget in self._definiciones_pestanas_principales():
            if widget is None:
                continue
            id_to_widget[tab_id] = widget
            widget_to_id[str(widget)] = tab_id
        return id_to_widget, widget_to_id

    def _obtener_orden_pestanas_principales(self) -> list[str]:
        """Devuelve el orden actual de las pestañas principales usando ids persistentes."""
        if not hasattr(self, "notebook"):
            return []
        _id_to_widget, widget_to_id = self._mapa_pestanas_principales()
        # Variable local para orden.
        orden: list[str] = []
        for tab_name in self.notebook.tabs():
            # Variable local para tab id.
            tab_id = widget_to_id.get(str(tab_name))
            if tab_id:
                orden.append(tab_id)
        return orden

    def _aplicar_orden_pestanas_principales(self, orden_ids: Iterable[str]) -> None:
        """Reordena el notebook principal siguiendo una lista de ids estables."""
        if not hasattr(self, "notebook"):
            return
        id_to_widget, _widget_to_id = self._mapa_pestanas_principales()
        # Variable local para vistos.
        vistos: set[str] = set()
        # Variable local para destino.
        destino = 0
        for tab_id in [str(item or "").strip() for item in (orden_ids or [])]:
            # Variable local para widget.
            widget = id_to_widget.get(tab_id)
            if widget is None or tab_id in vistos:
                continue
            try:
                self.notebook.insert(destino, widget)
                destino += 1
                vistos.add(tab_id)
            except Exception:
                LOGGER.debug("No se pudo reordenar la pestaña principal %s", tab_id, exc_info=True)
        for tab_id, widget in self._definiciones_pestanas_principales():
            if widget is None or tab_id in vistos:
                continue
            try:
                self.notebook.insert(destino, widget)
                destino += 1
            except Exception:
                LOGGER.debug("No se pudo ubicar la pestaña principal faltante %s", tab_id, exc_info=True)

    def _mover_pestana_principal(self, direccion: int) -> None:
        """Mueve la pestaña principal activa una posición a izquierda o derecha."""
        if not hasattr(self, "notebook"):
            return
        try:
            # Variable local para actual.
            actual = int(self.notebook.index(self.notebook.select()))
        except Exception:
            return
        # Variable local para total.
        total = len(self.notebook.tabs())
        if total <= 1:
            return
        # Variable local para destino.
        destino = max(0, min(total - 1, actual + (1 if int(direccion or 0) > 0 else -1)))
        if destino == actual:
            return
        try:
            # Variable local para widget.
            widget = self.notebook.select()
            self.notebook.insert(destino, widget)
            self.notebook.select(widget)
            self._guardar_estado_ui()
            self._refrescar_ui(forzar=True)
        except Exception:
            LOGGER.exception("No se pudo mover la pestaña principal")

    def _indice_pestana_principal_desde_xy(self, x: int, y: int) -> int | None:
        """Devuelve el índice de la pestaña principal ubicada bajo las coordenadas dadas."""
        if not hasattr(self, "notebook"):
            return None
        try:
            # Variable local para elemento.
            elemento = str(self.notebook.identify(x, y) or "")
        except Exception:
            elemento = ""
        if elemento and not any(token in elemento for token in ("label", "padding", "focus", "tab")):
            return None
        try:
            return int(self.notebook.index(f"@{int(x)},{int(y)}"))
        except Exception:
            return None

    def _limpiar_drag_pestana_principal(self) -> None:
        """Resetea el estado temporal usado durante el drag and drop de pestañas."""
        self._drag_tab_source_index = None
        self._drag_tab_widget = None
        self._drag_tab_start_xy = None
        self._drag_tab_moved = False

    def _on_notebook_tab_press(self, event) -> None:
        """Inicia el drag and drop de una pestaña principal si el click cae sobre una solapa."""
        if event.widget is not getattr(self, "notebook", None):
            return
        # Variable local para idx.
        idx = self._indice_pestana_principal_desde_xy(event.x, event.y)
        if idx is None:
            self._limpiar_drag_pestana_principal()
            return
        try:
            self._drag_tab_widget = self.notebook.tabs()[idx]
        except Exception:
            self._limpiar_drag_pestana_principal()
            return
        self._drag_tab_source_index = idx
        self._drag_tab_start_xy = (int(event.x), int(event.y))
        self._drag_tab_moved = False

    def _on_notebook_tab_drag(self, event) -> None:
        """Reordena las pestañas principales arrastrando la solapa activa con el mouse."""
        if event.widget is not getattr(self, "notebook", None):
            return
        if self._drag_tab_source_index is None or self._drag_tab_widget is None:
            return
        if self._drag_tab_start_xy is None:
            self._drag_tab_start_xy = (int(event.x), int(event.y))
        # Variable local para dx.
        dx = abs(int(event.x) - int(self._drag_tab_start_xy[0]))
        # Variable local para dy.
        dy = abs(int(event.y) - int(self._drag_tab_start_xy[1]))
        if not self._drag_tab_moved and max(dx, dy) < 6:
            return
        # Variable local para destino.
        destino = self._indice_pestana_principal_desde_xy(event.x, event.y)
        if destino is None:
            return
        try:
            # Variable local para actual.
            actual = int(self.notebook.index(self._drag_tab_widget))
        except Exception:
            self._limpiar_drag_pestana_principal()
            return
        if destino == actual:
            self._drag_tab_moved = True
            return
        try:
            self.notebook.insert(destino, self._drag_tab_widget)
            self.notebook.select(self._drag_tab_widget)
            self._drag_tab_source_index = int(self.notebook.index(self._drag_tab_widget))
            self._drag_tab_moved = True
        except Exception:
            LOGGER.debug("No se pudo arrastrar la pestaña principal", exc_info=True)
            self._limpiar_drag_pestana_principal()

    def _on_notebook_tab_release(self, event) -> None:
        """Finaliza el drag and drop y persiste el nuevo orden de las pestañas principales."""
        if event.widget is not getattr(self, "notebook", None):
            self._limpiar_drag_pestana_principal()
            return
        # Variable local para movio.
        movio = bool(self._drag_tab_moved)
        self._limpiar_drag_pestana_principal()
        if movio:
            self._guardar_estado_ui()
            self._refrescar_ui(forzar=True)
    def _normalizar_hora_cierre(self, valor: str) -> str:
        """Valida y normaliza la hora de cierre en formato HH:MM."""
        # Texto temporal usado para armar o normalizar información.
        texto = str(valor or "17:05").strip()
        if re.fullmatch(r"\d{2}:\d{2}", texto):
            # Variable local para hora.
            hora = int(texto[:2])
            # Variable local para minuto.
            minuto = int(texto[3:5])
            if 0 <= hora <= 23 and 0 <= minuto <= 59:
                return f"{hora:02d}:{minuto:02d}"
        return "17:05"
    def _ruta_cierre_diario(self, fecha: str | None = None) -> Path:
        """Devuelve la ruta del archivo de cierre diario para una fecha dada."""
        # Fecha temporal usada en este cálculo.
        fecha = fecha or ahora().strftime("%Y-%m-%d")
        return self.salida_dir / f"cierre_diario_{self.subyacente.upper()}_{fecha}.json"
    def _ruta_precierre_manual(self, fecha: str | None = None) -> Path:
        """Devuelve una ruta fechada y horaria para guardar un pre-cierre manual."""
        # Variable local para ahora local.
        ahora_local = ahora()
        # Fecha temporal usada en este cálculo.
        fecha = fecha or ahora_local.strftime("%Y-%m-%d")
        # Variable local para hora.
        hora = ahora_local.strftime("%H-%M-%S")
        return self.salida_dir / f"cierre_diario_{self.subyacente.upper()}_{fecha}_manual_{hora}.json"
    def _construir_payload_cierre(
        self,
        filas_enriquecidas: list[dict[str, Any]],
        info: dict[str, Any],
        tasa: float,
        precio_subyacente: float | None,
        modo_guardado: str,
    ) -> dict[str, Any]:
        """Arma el JSON de cierre o pre-cierre a partir del estado enriquecido actual."""
        return {
            "version_script": VERSION_SCRIPT,
            "guardado_en": ahora_texto(),
            "subyacente": self.subyacente.upper(),
            "hora_objetivo": self._hora_cierre,
            "modo_guardado": modo_guardado,
            "ultimo_evento": info.get("last_event_at"),
            "tasa_anual": tasa,
            "spot_referencia": precio_subyacente,
            "cantidad_instrumentos": len(filas_enriquecidas),
            "instrumentos": filas_enriquecidas,
            "oi_info": info.get("oi_info") or {},
        }
    def _tomar_snapshot_enriquecido_actual(self) -> tuple[list[dict[str, Any]], dict[str, Any], float, float | None]:
        """Reconstruye el estado enriquecido actual para reutilizarlo en guardados manuales."""
        # Variable local para rows.
        rows = ESTADO.snapshot_rows()
        # Estructura temporal con metadatos o información auxiliar.
        info = ESTADO.snapshot_info()
        # Variable local para tasa.
        tasa = self._obtener_tasa_desde_ui()
        # Variable local para referencia tiempo.
        referencia_tiempo = ahora().replace(second=0, microsecond=0)
        enriquecidas, precio_subyacente = enriquecer_filas_analiticas(
            rows,
            self.instrumentos_por_ticker,
            tasa,
            analytics_cache=self._analytics_cache,
            referencia_tiempo=referencia_tiempo,
        )
        return enriquecidas, info, tasa, precio_subyacente
    def _guardar_cierre_diario_desde_payload(
        self,
        payload: dict[str, Any],
        fecha: str,
        *,
        es_oficial: bool,
    ) -> Path:
        """Guarda un cierre oficial o un pre-cierre manual según corresponda."""
        if es_oficial:
            # Ruta del archivo o recurso usado en este bloque.
            ruta = self._ruta_cierre_diario(fecha)
            guardar_json(payload, ruta)
            try:
                self._history_db.guardar_cierre_metricas(fecha, payload.get("instrumentos") or [])
                self._history_db.importar_cierre_json(ruta)
                self._invalidar_cache_historial_bases()
                self._invalidar_cache_comparador()
            except Exception:
                pass
            self._ultima_fecha_cierre_guardada = fecha
            return ruta.resolve()
        ruta = self._ruta_precierre_manual(fecha)
        guardar_json(payload, ruta)
        return ruta.resolve()

    def _clave_drive_vencimiento(self, vencimiento: str | None = None) -> str:
        """Devuelve YYYY-MM para buscar la planilla de cierres del vencimiento."""
        venc = str(vencimiento or self.var_vencimiento.get() or "").strip()
        if re.fullmatch(r"\d{4}-\d{2}-\d{2}", venc):
            return venc[:7]
        match = re.search(r"(20\d{2})[-_/ ]?(\d{2})", venc)
        if match:
            return f"{match.group(1)}-{match.group(2)}"
        return ""

    def _resolver_sheet_id_cierres_drive(self, clave_vencimiento: str) -> str:
        """Busca la planilla de Drive para el vencimiento y usa fallback conocido si hace falta."""
        clave = str(clave_vencimiento or "").strip()
        if not clave:
            return ""
        try:
            url = f"https://drive.google.com/drive/folders/{DRIVE_CIERRES_FOLDER_ID}"
            resp = requests.get(url, timeout=HTTP_TIMEOUT)
            if resp.ok:
                html = resp.text.replace('\\"', '"')
                patron = re.compile(r'\["([A-Za-z0-9_-]{20,})","([^"]*Opex[^"]*)"', re.IGNORECASE)
                candidatos: list[tuple[str, str]] = []
                for sheet_id, titulo in patron.findall(html):
                    titulo_limpio = str(titulo or "")
                    if clave in titulo_limpio and "GGAL" in titulo_limpio.upper():
                        candidatos.append((sheet_id, titulo_limpio))
                if candidatos:
                    candidatos.sort(key=lambda item: item[1], reverse=True)
                    return candidatos[0][0]
        except Exception:
            LOGGER.debug("No se pudo resolver planilla desde carpeta Drive; se usa fallback si existe", exc_info=True)
        return DRIVE_CIERRES_SHEET_FALLBACKS.get(clave, "")

    def _descargar_csv_cierres_drive(self, sheet_id: str) -> str:
        """Descarga el CSV exportado por Google Sheets."""
        sid = str(sheet_id or "").strip()
        if not sid:
            raise RuntimeError("No se encontró una planilla de cierres para este vencimiento.")
        url = f"https://docs.google.com/spreadsheets/d/{sid}/export?format=csv"
        resp = requests.get(url, timeout=max(HTTP_TIMEOUT, 30))
        resp.raise_for_status()
        return resp.text

    def _numero_csv_argentino(self, valor: Any) -> float | None:
        """Convierte números con formato argentino, por ejemplo 1.234,56."""
        texto = str(valor or "").strip().replace("%", "")
        if not texto or texto in {"-", "--"}:
            return None
        texto = texto.replace("\xa0", "").replace(" ", "")
        if "," in texto and "." in texto:
            texto = texto.replace(".", "").replace(",", ".")
        elif "," in texto:
            texto = texto.replace(",", ".")
        numero = convertir_a_numero(texto)
        return float(numero) if numero is not None else None

    def _fecha_csv_cierres_drive(self, valor: Any) -> str | None:
        """Normaliza fechas dd/mm/YYYY del CSV de cierres a YYYY-MM-DD."""
        texto = str(valor or "").strip()
        if not texto:
            return None
        for formato in ("%d/%m/%Y", "%Y-%m-%d"):
            try:
                return datetime.strptime(texto, formato).strftime("%Y-%m-%d")
            except Exception:
                continue
        return None

    def _mapa_tickers_opciones_vencimiento(self, vencimiento: str) -> dict[tuple[str, float], str]:
        """Indexa tickers activos de calls/puts por strike para importar cierres externos."""
        venc = str(vencimiento or "").strip()
        mapa: dict[tuple[str, float], str] = {}
        for inst in self.instrumentos:
            tipo = str(getattr(inst, "tipo", "") or "").strip()
            if tipo not in {"calls", "puts"}:
                continue
            if venc and str(getattr(inst, "vencimiento", "") or "").strip() != venc:
                continue
            ticker = str(getattr(inst, "ticker", "") or "").strip()
            if not ticker or ticker_es_liquidacion_24hs(ticker):
                continue
            clave_strike = _normalizar_strike_clave(getattr(inst, "strike", None))
            if clave_strike is None:
                continue
            mapa.setdefault((tipo, clave_strike), ticker)
        return mapa

    def _parsear_cierres_drive_csv(
        self,
        csv_texto: str,
        vencimiento: str,
    ) -> tuple[list[dict[str, Any]], dict[str, int]]:
        """Convierte el CSV de la planilla en payloads de cierre por fecha."""
        ticker_por_strike = self._mapa_tickers_opciones_vencimiento(vencimiento)
        reader = csv.reader(io.StringIO(csv_texto or ""))
        pares_columnas: list[tuple[int, int, float]] = []
        payloads: list[dict[str, Any]] = []
        stats = {"filas": 0, "sin_datos": 0, "sin_ticker": 0}
        hoy = ahora().strftime("%Y-%m-%d")
        for row in reader:
            if not row:
                continue
            if str(row[0] or "").strip().upper() == "FECHA":
                pares_columnas = []
                for idx in range(21, len(row), 2):
                    strike_raw = self._numero_csv_argentino(row[idx] if idx < len(row) else "")
                    if strike_raw is None:
                        continue
                    strike_activo = remap_strike_historico(vencimiento, strike_raw) or strike_raw
                    clave_strike = _normalizar_strike_clave(strike_activo)
                    if clave_strike is not None:
                        pares_columnas.append((idx, idx + 1, clave_strike))
                continue
            fecha = self._fecha_csv_cierres_drive(row[0])
            if not fecha or fecha > hoy:
                continue
            especie = str(row[1] if len(row) > 1 else "").strip().upper()
            if especie != self.subyacente.upper():
                continue
            instrumentos: list[dict[str, Any]] = []
            for col_call, col_put, clave_strike in pares_columnas:
                for tipo, col in (("calls", col_call), ("puts", col_put)):
                    precio = self._numero_csv_argentino(row[col] if col < len(row) else "")
                    if precio is None or precio <= 0:
                        continue
                    ticker = ticker_por_strike.get((tipo, clave_strike))
                    if not ticker:
                        stats["sin_ticker"] += 1
                        continue
                    inst = self.instrumentos_por_ticker.get(ticker)
                    instrumentos.append({
                        "ticker": ticker,
                        "tipo": tipo,
                        "vencimiento": vencimiento,
                        "strike": float(clave_strike),
                        "cficode": str(getattr(inst, "cficode", "") or "") if inst else "",
                        "securityDescription": getattr(inst, "security_description", None) if inst else None,
                        "underlying": getattr(inst, "underlying", self.subyacente.upper()) if inst else self.subyacente.upper(),
                        "last": float(precio),
                        "bid": None,
                        "ask": None,
                        "iv": None,
                        "delta": None,
                        "vega": None,
                        "gamma": None,
                        "theta": None,
                        "updated_at": f"{fecha} 18:05:00",
                    })
            if len(instrumentos) < 5:
                stats["sin_datos"] += 1
                continue
            stats["filas"] += 1
            payloads.append({
                "version_script": VERSION_SCRIPT,
                "guardado_en": f"{fecha} 18:05:00",
                "subyacente": self.subyacente.upper(),
                "hora_objetivo": self._hora_cierre,
                "modo_guardado": "manual_oficial",
                "fuente": "drive_sabrofrehley",
                "drive_folder_id": DRIVE_CIERRES_FOLDER_ID,
                "vencimiento": vencimiento,
                "cantidad_instrumentos": len(instrumentos),
                "instrumentos": instrumentos,
                "oi_info": {},
            })
        return payloads, stats

    def _reconstruir_cierres_desde_drive(self) -> dict[str, Any]:
        """Importa desde Drive sólo fechas de cierre que no existan localmente."""
        vencimiento = self.var_vencimiento.get().strip()
        clave = self._clave_drive_vencimiento(vencimiento)
        sheet_id = self._resolver_sheet_id_cierres_drive(clave)
        if not sheet_id:
            raise RuntimeError(f"No encontré planilla de Drive para el vencimiento {vencimiento or clave or 'actual'}.")
        csv_texto = self._descargar_csv_cierres_drive(sheet_id)
        payloads, stats = self._parsear_cierres_drive_csv(csv_texto, vencimiento)
        importadas: list[str] = []
        omitidas_existentes = 0
        instrumentos_importados = 0
        for payload in payloads:
            fecha = str(payload.get("guardado_en") or "")[:10]
            if not fecha:
                continue
            if self._history_db.obtener_tickers_cierre_fecha(fecha):
                omitidas_existentes += 1
                continue
            self._guardar_cierre_diario_desde_payload(payload, fecha, es_oficial=True)
            importadas.append(fecha)
            instrumentos_importados += int(payload.get("cantidad_instrumentos") or 0)
        return {
            "sheet_id": sheet_id,
            "vencimiento": vencimiento,
            "importadas": importadas,
            "omitidas_existentes": omitidas_existentes,
            "instrumentos_importados": instrumentos_importados,
            "stats": stats,
        }

    def reconstruir_cierres_desde_drive_async(self) -> None:
        """Ejecuta la reconstrucción de cierres desde Drive sin bloquear la ventana."""
        if bool(getattr(self, "_reconstruyendo_cierres_drive", False)):
            return
        self._reconstruyendo_cierres_drive = True
        boton = getattr(self, "btn_reconstruir_cierres", None)
        if boton is not None:
            try:
                boton.configure(state="disabled")
            except Exception:
                pass
        self.var_estado.set("Reconstruyendo cierres desde Drive...")

        def _worker() -> None:
            try:
                resultado = self._reconstruir_cierres_desde_drive()
                self.root.after(0, lambda: self._finalizar_reconstruccion_cierres_drive(resultado, None))
            except Exception as exc:
                LOGGER.exception("No se pudo reconstruir cierres desde Drive")
                self.root.after(0, lambda: self._finalizar_reconstruccion_cierres_drive(None, exc))

        threading.Thread(target=_worker, name="drive-cierres-rebuild", daemon=True).start()

    def _finalizar_reconstruccion_cierres_drive(self, resultado: dict[str, Any] | None, error: Exception | None) -> None:
        """Actualiza la UI luego de reconstruir cierres desde Drive."""
        self._reconstruyendo_cierres_drive = False
        boton = getattr(self, "btn_reconstruir_cierres", None)
        if boton is not None:
            try:
                boton.configure(state="normal")
            except Exception:
                pass
        if error is not None:
            self.var_estado.set(f"No se pudieron reconstruir cierres: {error}")
            messagebox.showerror("Reconstruir cierres", f"No se pudieron reconstruir cierres desde Drive:\n{error}")
            return
        resultado = resultado or {}
        self._invalidar_cache_historial_bases()
        self._invalidar_cache_comparador()
        self._llenar_selector_intradia_fechas()
        self._llenar_selector_backtest_fechas()
        self._programar_refresco_ui(delay_ms=250, forzar=True, reemplazar=True)
        importadas = list(resultado.get("importadas") or [])
        omitidas = int(resultado.get("omitidas_existentes") or 0)
        instrumentos = int(resultado.get("instrumentos_importados") or 0)
        stats = resultado.get("stats") or {}
        detalle = (
            f"Fechas importadas: {len(importadas)}"
            f" | instrumentos: {instrumentos}"
            f" | fechas ya existentes: {omitidas}"
            f" | filas sin datos: {int(stats.get('sin_datos') or 0)}"
        )
        self.var_estado.set(f"Cierres Drive reconstruidos. {detalle}")
        messagebox.showinfo("Reconstruir cierres", detalle)

    def _payload_cierre_es_oficial_valido(self, payload: dict[str, Any], fecha_archivo: str) -> bool:
        """Valida que un JSON represente un cierre oficial real y usable.

        Reglas:
        - modo_guardado debe ser automatico o manual_oficial
        - guardado_en debe corresponder a la misma fecha del archivo
        - hora de guardado debe ser igual o posterior a la hora objetivo
        - debe existir una cantidad mínima de instrumentos con cotización válida
        """
        if not isinstance(payload, dict):
            return False
        modo = str(payload.get("modo_guardado") or "").strip().lower()
        if modo not in {"automatico", "manual_oficial"}:
            return False
        guardado_en = str(payload.get("guardado_en") or "").strip()
        try:
            guardado_dt = datetime.strptime(guardado_en, "%Y-%m-%d %H:%M:%S")
        except Exception:
            return False
        if guardado_dt.strftime("%Y-%m-%d") != str(fecha_archivo or ""):
            return False
        hora_txt = str(payload.get("hora_objetivo") or self._hora_cierre or "17:05").strip()
        try:
            hora_obj = guardado_dt.replace(hour=int(hora_txt[:2]), minute=int(hora_txt[3:5]), second=0, microsecond=0)
        except Exception:
            hora_obj = guardado_dt.replace(hour=17, minute=5, second=0, microsecond=0)
        if guardado_dt < hora_obj:
            return False
        instrumentos = payload.get("instrumentos") or []
        if not isinstance(instrumentos, list):
            return False
        cotizados = sum(1 for fila in instrumentos if isinstance(fila, dict) and fila_tiene_cotizacion(fila))
        return cotizados >= 5

    def _leer_payload_cierre_oficial_valido(self, fecha: str) -> dict[str, Any] | None:
        """Lee un cierre diario y lo devuelve solo si pasa validaciones de cierre oficial."""
        ruta = self._ruta_cierre_diario(fecha)
        if not ruta.exists():
            return None
        try:
            payload = json.loads(ruta.read_text(encoding="utf-8"))
        except Exception:
            return None
        if not self._payload_cierre_es_oficial_valido(payload, fecha):
            return None
        return payload

    def _detectar_ultimo_cierre_guardado(self) -> str | None:
        """Detecta si ya existe un cierre diario oficial y válido para la fecha actual."""
        # Fecha temporal usada en este cálculo.
        fecha = ahora().strftime("%Y-%m-%d")
        return fecha if self._leer_payload_cierre_oficial_valido(fecha) is not None else None
    def _extraer_ticker_desde_tree(self, tree) -> str | None:
        """Obtiene el ticker de la fila actualmente seleccionada en un Treeview."""
        # Variable local para seleccion.
        seleccion = tree.selection()
        if not seleccion:
            return None
        # Colección temporal de valores usada en este cálculo.
        valores = tree.item(seleccion[0], "values")
        if not valores:
            return None
        try:
            return str(valores[-1])
        except Exception:
            return None
    def _al_seleccionar_fila_call(self, _event=None) -> None:
        """Recuerda qué call visible quedó seleccionada para priorizar su ratio sin recargar la grilla."""
        if self._updating_tree_calls:
            return
        # Variable interna para selected call ticker.
        self._selected_call_ticker = self._extraer_ticker_desde_tree(self.tree_calls)
        if self._tab_activa_texto() == "Comparador 2 bases":
            self._actualizar_selector_comparador_desde_tree("calls")
    def _al_seleccionar_fila_put(self, _event=None) -> None:
        """Recuerda qué put visible quedó seleccionado para priorizar su ratio sin recargar la grilla."""
        if self._updating_tree_puts:
            return
        # Variable interna para selected put ticker.
        self._selected_put_ticker = self._extraer_ticker_desde_tree(self.tree_puts)
        if self._tab_activa_texto() == "Comparador 2 bases":
            self._actualizar_selector_comparador_desde_tree("puts")
    def _al_seleccionar_fila_compacta(self, _event=None) -> None:
        """Sincroniza la fila compacta seleccionada con los tickers call/put activos."""
        tree = getattr(self, "tree_compact_options", None)
        if tree is None:
            return
        seleccion = tree.selection()
        if not seleccion:
            return
        valores = tree.item(seleccion[0], "values") or ()
        columnas = tuple(tree.cget("columns") or ())
        try:
            idx_call = columnas.index("call_ticker")
            idx_put = columnas.index("put_ticker")
        except ValueError:
            return
        call_ticker = str(valores[idx_call] or "").strip() if idx_call < len(valores) else ""
        put_ticker = str(valores[idx_put] or "").strip() if idx_put < len(valores) else ""
        self._selected_call_ticker = call_ticker or self._selected_call_ticker
        self._selected_put_ticker = put_ticker or self._selected_put_ticker

    def _actualizar_selector_comparador_desde_tree(self, tipo: str) -> None:
        """Sincroniza la selección del comparador 2 bases con la fila elegida en Calls o Puts.

        Convención usada:
        - si elegís una fila en Calls, esa base pasa a ser Base A
        - si elegís una fila en Puts, esa base pasa a ser Base B
        """
        # Ticker temporal procesado en este bloque.
        ticker = self._selected_call_ticker if tipo == "calls" else self._selected_put_ticker
        if not ticker:
            return
        # Variable local para opciones.
        opciones = list(self.combo_comp_a.cget("values") or [])
        if ticker not in opciones:
            return
        if tipo == "calls":
            if self.var_comp_a.get() != ticker:
                self.var_comp_a.set(ticker)
        else:
            if self.var_comp_b.get() != ticker:
                self.var_comp_b.set(ticker)
        self._invalidar_cache_comparador()
        self._invalidar_cache_intradia()
        self._refrescar_ui(forzar=True)

    def _marcar_todas_calls_visibles(self) -> None:
        """Marca todas las calls activas visibles para incluirlas en la vista de ratios."""
        # Variable interna para ratio calls seleccionadas.
        self._ratio_calls_seleccionadas = {
            str(fila.get("ticker") or "")
            for fila in self._ultimas_filas_calls
            if str(fila.get("ticker") or "")
        }
        # Variable interna para selected ratio pair.
        self._selected_ratio_pair = None
        if len(self._ratio_calls_seleccionadas) == 1:
            self._selected_call_ticker = next(iter(self._ratio_calls_seleccionadas))
        self._refrescar_ui()
    def _limpiar_calls_visibles(self) -> None:
        """Limpia la selección de calls para ratios."""
        self._ratio_calls_seleccionadas.clear()
        self._selected_call_ticker = None
        self._selected_ratio_pair = None
        self._refrescar_ui()
    def _marcar_todos_puts_visibles(self) -> None:
        """Marca todos los puts activos visibles para incluirlos en la vista de ratios."""
        # Variable interna para ratio puts seleccionadas.
        self._ratio_puts_seleccionadas = {
            str(fila.get("ticker") or "")
            for fila in self._ultimas_filas_puts
            if str(fila.get("ticker") or "")
        }
        self._selected_ratio_pair = None
        if len(self._ratio_puts_seleccionadas) == 1:
            self._selected_put_ticker = next(iter(self._ratio_puts_seleccionadas))
        self._refrescar_ui()
    def _limpiar_puts_visibles(self) -> None:
        """Limpia la selección de puts para ratios."""
        self._ratio_puts_seleccionadas.clear()
        self._selected_put_ticker = None
        self._selected_ratio_pair = None
        self._refrescar_ui()
    def _toggle_ratio_ticker(self, ticker: str, tipo: str) -> None:
        """Activa o desactiva un ticker dentro del conjunto usado para ratios."""
        if not ticker:
            return
        # Variable local para destino.
        destino = self._ratio_calls_seleccionadas if tipo == "calls" else self._ratio_puts_seleccionadas
        if ticker in destino:
            destino.remove(ticker)
        else:
            destino.add(ticker)
        if tipo == "calls":
            self._selected_call_ticker = ticker
        else:
            self._selected_put_ticker = ticker
        self._selected_ratio_pair = None
        self._refrescar_ui()
    def _al_click_tree_calls(self, event) -> str | None:
        """Interpreta clics sobre la columna Ratio de la tabla de calls."""
        return self._manejar_click_ratio_en_tree(self.tree_calls, event, "calls")
    def _al_click_tree_puts(self, event) -> str | None:
        """Interpreta clics sobre la columna Ratio de la tabla de puts."""
        return self._manejar_click_ratio_en_tree(self.tree_puts, event, "puts")
    def _manejar_click_ratio_en_tree(self, tree, event, tipo: str) -> str | None:
        """Alterna la casilla de ratio cuando el usuario hace clic en la primera columna."""
        if tree.identify_region(event.x, event.y) != "cell":
            return None
        if tree.identify_column(event.x) != "#1":
            return None
        # Variable local para item id.
        item_id = tree.identify_row(event.y)
        if not item_id:
            return None
        # Colección temporal de valores usada en este cálculo.
        valores = tree.item(item_id, "values")
        if not valores:
            return None
        try:
            # Ticker temporal procesado en este bloque.
            ticker = str(valores[-1])
        except Exception:
            return None
        self._toggle_ratio_ticker(ticker, tipo)
        return "break"
    def _anotar_seleccion_ratio(self, filas: list[dict[str, Any]], tipo: str) -> list[dict[str, Any]]:
        """Agrega una marca visual de selección a las filas de calls o puts."""
        # Variable local para seleccionadas.
        seleccionadas = self._ratio_calls_seleccionadas if tipo == "calls" else self._ratio_puts_seleccionadas
        # Variable local para salida.
        salida: list[dict[str, Any]] = []
        for fila in filas:
            # Variable local para nueva.
            nueva = dict(fila)
            # Ticker temporal procesado en este bloque.
            ticker = str(fila.get("ticker") or "")
            nueva["sel_ratio"] = "☑" if ticker and ticker in seleccionadas else "☐"
            salida.append(nueva)
        return salida
    def _al_seleccionar_ratio_tree(self, _event=None) -> None:
        """Toma la fila elegida en la tabla de ratios para graficarla."""
        if self._updating_ratio_tree:
            return
        # Variable local para seleccion.
        seleccion = self.tree_ratios.selection()
        if not seleccion:
            self._selected_ratio_pair = None
            self._refrescar_ui()
            return
        # Colección temporal de valores usada en este cálculo.
        valores = self.tree_ratios.item(seleccion[0], "values")
        if len(valores) >= len(self.RATIO_COLUMNAS):
            # Variable local para call ticker.
            call_ticker = str(valores[self.RATIO_COLUMNAS.index("call_ticker")])
            # Variable local para put ticker.
            put_ticker = str(valores[self.RATIO_COLUMNAS.index("put_ticker")])
            self._selected_ratio_pair = (call_ticker, put_ticker)
        self._refrescar_ui()
    def _actualizar_selectores_ratios(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]]) -> None:
        """Recorta selecciones inválidas cuando cambia el vencimiento o la actividad de las bases."""
        # Variable local para visibles calls.
        visibles_calls = {str(fila.get("ticker") or "") for fila in filas_calls}
        # Variable local para visibles puts.
        visibles_puts = {str(fila.get("ticker") or "") for fila in filas_puts}
        self._ratio_calls_seleccionadas &= visibles_calls
        self._ratio_puts_seleccionadas &= visibles_puts
        if self._selected_call_ticker not in visibles_calls:
            self._selected_call_ticker = None
        if self._selected_put_ticker not in visibles_puts:
            self._selected_put_ticker = None
    def _construir_ratios(self, filas_calls: list[dict[str, Any]], filas_puts: list[dict[str, Any]]) -> list[dict[str, Any]]:
        """Arma comparaciones call/put con las bases elegidas por el usuario."""
        # Variable local para seleccion calls.
        seleccion_calls = sorted(self._ratio_calls_seleccionadas)
        # Variable local para seleccion puts.
        seleccion_puts = sorted(self._ratio_puts_seleccionadas)
        # Variable local para calls map.
        calls_map = {str(f.get("ticker") or ""): f for f in filas_calls}
        # Variable local para puts map.
        puts_map = {str(f.get("ticker") or ""): f for f in filas_puts}
        # Variable local para filas ratio.
        filas_ratio: list[dict[str, Any]] = []
        for ticker_call in seleccion_calls:
            # Variable local para fila call.
            fila_call = calls_map.get(ticker_call)
            if fila_call is None:
                continue
            for ticker_put in seleccion_puts:
                # Variable local para fila put.
                fila_put = puts_map.get(ticker_put)
                if fila_put is None:
                    continue
                # Variable local para call last.
                call_last = convertir_a_numero(fila_call.get("last"))
                # Variable local para call mid.
                call_mid = convertir_a_numero(fila_call.get("mid"))
                # Variable local para put last.
                put_last = convertir_a_numero(fila_put.get("last"))
                # Variable local para put mid.
                put_mid = convertir_a_numero(fila_put.get("mid"))
                # Variable local para ratio last.
                ratio_last = (float(call_last) / float(put_last)) if call_last not in (None, 0) and put_last not in (None, 0) else None
                # Variable local para ratio mid.
                ratio_mid = (float(call_mid) / float(put_mid)) if call_mid not in (None, 0) and put_mid not in (None, 0) else None
                # Variable local para spread last.
                spread_last = (float(call_last) - float(put_last)) if call_last is not None and put_last is not None else None
                filas_ratio.append({
                    "call_strike": fila_call.get("strike"),
                    "call_last": call_last,
                    "call_mid": call_mid,
                    "put_strike": fila_put.get("strike"),
                    "put_last": put_last,
                    "put_mid": put_mid,
                    "ratio_last": ratio_last,
                    "ratio_mid": ratio_mid,
                    "spread_last": spread_last,
                    "call_ticker": ticker_call,
                    "put_ticker": ticker_put,
                })
        return sorted(
            filas_ratio,
            key=lambda item: (
                float(item.get("call_strike")) if isinstance(item.get("call_strike"), (int, float)) else float("inf"),
                float(item.get("put_strike")) if isinstance(item.get("put_strike"), (int, float)) else float("inf"),
                str(item.get("call_ticker") or ""),
                str(item.get("put_ticker") or ""),
            ),
        )
    def _resolver_par_desde_selecciones(self, filas_ratio: list[dict[str, Any]]) -> tuple[str, str] | None:
        """Determina el par activo a partir de las filas seleccionadas en calls y puts."""
        # Variable local para pares validos.
        pares_validos = {
            (str(fila.get("call_ticker") or ""), str(fila.get("put_ticker") or ""))
            for fila in filas_ratio
        }
        if self._selected_ratio_pair in pares_validos:
            return self._selected_ratio_pair
        # Variable local para call sel.
        call_sel = self._selected_call_ticker if self._selected_call_ticker in self._ratio_calls_seleccionadas else None
        # Variable local para put sel.
        put_sel = self._selected_put_ticker if self._selected_put_ticker in self._ratio_puts_seleccionadas else None
        if call_sel and put_sel and (call_sel, put_sel) in pares_validos:
            return (call_sel, put_sel)
        if call_sel and len(self._ratio_puts_seleccionadas) == 1:
            # Variable local para candidato.
            candidato = (call_sel, next(iter(self._ratio_puts_seleccionadas)))
            if candidato in pares_validos:
                return candidato
        if put_sel and len(self._ratio_calls_seleccionadas) == 1:
            candidato = (next(iter(self._ratio_calls_seleccionadas)), put_sel)
            if candidato in pares_validos:
                return candidato
        if len(self._ratio_calls_seleccionadas) == 1 and len(self._ratio_puts_seleccionadas) == 1:
            candidato = (next(iter(self._ratio_calls_seleccionadas)), next(iter(self._ratio_puts_seleccionadas)))
            if candidato in pares_validos:
                return candidato
        if filas_ratio:
            # Variable local para primera.
            primera = filas_ratio[0]
            return (str(primera.get("call_ticker") or ""), str(primera.get("put_ticker") or ""))
        return None
    def _sincronizar_ratio_seleccionado(self, filas_ratio: list[dict[str, Any]]) -> None:
        """Elige automáticamente una relación válida para que el gráfico aparezca al marcar bases."""
        self._selected_ratio_pair = self._resolver_par_desde_selecciones(filas_ratio)
    def _cargar_tree_ratios(self, filas_ratio: list[dict[str, Any]]) -> None:
        """Muestra la tabla de ratios entre bases seleccionadas y preserva la relación elegida."""
        # Variable local para objetivo.
        objetivo = self._selected_ratio_pair
        if objetivo is None and len(filas_ratio) == 1:
            objetivo = (str(filas_ratio[0].get("call_ticker") or ""), str(filas_ratio[0].get("put_ticker") or ""))
            self._selected_ratio_pair = objetivo
        # Bandera interna que evita recursión o refrescos duplicados en updating ratio tree.
        self._updating_ratio_tree = True
        self.tree_ratios.delete(*self.tree_ratios.get_children())
        # Variable local para iid objetivo.
        iid_objetivo = None
        for idx, fila in enumerate(filas_ratio):
            # Colección temporal de valores usada en este cálculo.
            valores = [self._formatear_valor(col, fila.get(col)) for col in self.RATIO_COLUMNAS]
            # Variable local para iid.
            iid = f"ratio_{idx}"
            self.tree_ratios.insert("", END, iid=iid, values=valores, tags=("par" if idx % 2 == 0 else "impar",))
            # Variable local para pair.
            pair = (str(fila.get("call_ticker") or ""), str(fila.get("put_ticker") or ""))
            if objetivo is not None and pair == objetivo:
                iid_objetivo = iid
        self._reaplicar_orden_tree(self.tree_ratios)
        if iid_objetivo is not None:
            self.tree_ratios.selection_set(iid_objetivo)
            self.tree_ratios.focus(iid_objetivo)
            self.tree_ratios.see(iid_objetivo)
        elif not filas_ratio:
            self._selected_ratio_pair = None
        self._updating_ratio_tree = False
    def _importar_cierres_existentes_a_db(self) -> None:
        """Importa una sola vez los cierres diarios JSON existentes hacia SQLite."""
        # Variable local para patron.
        patron = f"cierre_diario_{self.subyacente.upper()}_*.json"
        for ruta in sorted(self.salida_dir.glob(patron)):
            try:
                self._history_db.importar_cierre_json(ruta)
            except Exception:
                continue
        self._invalidar_cache_historial_bases()

    def _asegurar_ruta_historial_del_dia(self) -> None:
        """Rota la fecha lógica del historial cuando cambia el día de trabajo."""
        # Fecha temporal usada en este cálculo.
        fecha = ahora().strftime("%Y-%m-%d")
        if fecha == self._history_date:
            return
        self._history_date = fecha
        self._ultimo_minuto_guardado = self._history_db.obtener_ultimo_minuto(self._history_date)

    def _guardar_historial_minuto_si_corresponde(self, filas_activas: list[dict[str, Any]]) -> None:
        """Guarda snapshots por minuto en SQLite, con índices para lecturas rápidas."""
        if not filas_activas:
            return
        self._asegurar_ruta_historial_del_dia()
        # Variable local para minuto.
        minuto = ahora().strftime("%Y-%m-%d %H:%M")
        if self._ultimo_minuto_guardado == minuto:
            return
        # Variable local para timestamp.
        timestamp = ahora().replace(second=0, microsecond=0).strftime("%Y-%m-%d %H:%M:%S")
        try:
            self._history_db.guardar_snapshot_minuto(timestamp, filas_activas)
            LOGGER.info("Snapshot minuto guardado | timestamp=%s | filas=%s", timestamp, len(filas_activas))
            self._ultimo_minuto_guardado = minuto
            self._llenar_selector_intradia_fechas()
            self._llenar_selector_backtest_fechas()
            self._invalidar_cache_historial_bases()
            self._invalidar_cache_intradia()
            self._invalidar_cache_backtest()
        except Exception:
            LOGGER.exception("Error guardando snapshot minuto")

    def _obtener_par_ratio_grafico(self, filas_ratio: list[dict[str, Any]]) -> tuple[str, str] | None:
        """Determina qué relación usar para el gráfico histórico de ratios."""
        # Variable local para par.
        par = self._resolver_par_desde_selecciones(filas_ratio)
        if par is not None:
            self._selected_ratio_pair = par
        return par
    def _refrescar_grafico_ratio(
        self,
        filas_ratio: list[dict[str, Any]],
        filas_calls: list[dict[str, Any]],
        filas_puts: list[dict[str, Any]],
        info: dict[str, Any],
    ) -> None:
        """Grafica el histórico por minuto del ratio Last de la relación elegida."""
        self.ax_ratio.clear()
        # Variable local para par.
        par = self._obtener_par_ratio_grafico(filas_ratio)
        if par is None:
            self.ax_ratio.text(
                0.5,
                0.5,
                "Marcá al menos una call y un put con la casilla Ratio. Si hay varias combinaciones, seleccioná además una fila en Calls, Puts o en la tabla de ratios.",
                ha="center",
                va="center",
            )
            self.ax_ratio.set_title("Ratio Last histórico")
            self.canvas_ratio.draw_idle()
            self.var_ratio_chart.set(
                "Gráfico ratio: marcá calls y puts desde sus tablas. Si hay varias combinaciones, seleccioná una fila en Calls, Puts o en la tabla de ratios; el último punto siempre refleja el Last más reciente."
            )
            return
        call_ticker, put_ticker = par
        # Variable local para serie historica.
        serie_historica = self._history_db.obtener_serie_ratio_minuto(self._history_date, call_ticker, put_ticker)
        # Variable local para serie x.
        serie_x = [ts for ts, _ in serie_historica]
        # Variable local para serie y.
        serie_y = [valor for _, valor in serie_historica]
        # Variable local para mapa calls.
        mapa_calls = {str(fila.get("ticker") or ""): fila for fila in filas_calls}
        # Variable local para mapa puts.
        mapa_puts = {str(fila.get("ticker") or ""): fila for fila in filas_puts}
        # Variable local para fila call.
        fila_call = mapa_calls.get(call_ticker)
        # Variable local para fila put.
        fila_put = mapa_puts.get(put_ticker)
        # Variable local para call last live.
        call_last_live = convertir_a_numero((fila_call or {}).get("last"))
        # Variable local para put last live.
        put_last_live = convertir_a_numero((fila_put or {}).get("last"))
        # Variable local para ratio live.
        ratio_live = (
            float(call_last_live) / float(put_last_live)
            if call_last_live is not None and put_last_live not in (None, 0)
            else None
        )
        if ratio_live is not None:
            # Variable local para timestamp live texto.
            ts_live_texto = str(info.get("last_event_at") or ahora_texto())
            try:
                # Variable local para timestamp live.
                ts_live = datetime.strptime(ts_live_texto, "%Y-%m-%d %H:%M:%S")
            except Exception:
                ts_live = ahora().replace(tzinfo=None)
            if serie_x and ts_live <= serie_x[-1]:
                serie_x[-1] = ts_live
                serie_y[-1] = ratio_live
            else:
                serie_x.append(ts_live)
                serie_y.append(ratio_live)
        if serie_x and serie_y:
            self.ax_ratio.plot(serie_x, serie_y, marker="o")
            self.ax_ratio.scatter([serie_x[-1]], [serie_y[-1]], s=55)
            self.ax_ratio.set_title(f"Ratio Last histórico: {call_ticker} / {put_ticker}")
            self.ax_ratio.set_xlabel("Hora")
            self.ax_ratio.set_ylabel("Call Last / Put Last")
            self.ax_ratio.grid(True, alpha=0.3)
            try:
                self.fig_ratio.autofmt_xdate()
            except Exception:
                pass
            self.var_ratio_chart.set(
                f"Ratio Last actual {call_ticker} / {put_ticker} = {serie_y[-1]:.6f} | Call Last={call_last_live if call_last_live is not None else 's/d'} | Put Last={put_last_live if put_last_live is not None else 's/d'} | puntos guardados por minuto: {max(len(serie_y) - 1, 0)} | último punto siempre refleja el Last más reciente."
            )
        else:
            self.ax_ratio.text(0.5, 0.5, "No hay suficientes Last históricos para esa relación", ha="center", va="center")
            self.ax_ratio.set_title(f"Ratio Last histórico: {call_ticker} / {put_ticker}")
            self.var_ratio_chart.set(
                f"Gráfico ratio: todavía no hay suficientes snapshots minútales con Last para {call_ticker} / {put_ticker}."
            )
        self.canvas_ratio.draw_idle()
    def _obtener_filas_historicas_faltantes_desde_cierres(
        self,
        tipo: str,
        vencimiento: str,
        tickers_presentes: set[str] | None = None,
    ) -> list[dict[str, Any]]:
        """Reconstruye filas faltantes desde cierres oficiales sin depender del maestro actual.

        Esto evita que Calls/Puts desaparezcan cuando un ticker ya no vino en la
        lista actual de instrumentos, pero sí existe en cierres diarios oficiales
        y en SQLite todavía conserva último last/bid/ask histórico.
        """
        tipo_norm = str(tipo or '').strip()
        venc_norm = str(vencimiento or '').strip()
        presentes = {str(t or '').strip() for t in (tickers_presentes or set()) if str(t or '').strip()}
        if tipo_norm not in {'calls', 'puts'} or not venc_norm:
            return []
        cache = self._obtener_cache_cierres_json()
        alias_directo, _alias_inverso = self._construir_aliases_historicos_strike()
        faltantes: dict[str, dict[str, Any]] = {}
        for fecha in sorted(cache.keys(), reverse=True):
            payload = cache.get(fecha) or {}
            instrumentos = payload.get('instrumentos') or []
            for fila in instrumentos:
                if not isinstance(fila, dict):
                    continue
                if str(fila.get('tipo') or '').strip() != tipo_norm:
                    continue
                if str(fila.get('vencimiento') or '').strip() != venc_norm:
                    continue
                if not strike_activo_permitido(venc_norm, fila.get('strike')):
                    continue
                ticker = str(fila.get('ticker') or '').strip()
                if ticker_es_liquidacion_24hs(ticker):
                    continue
                ticker_destino = alias_directo.get(ticker)
                if ticker_destino:
                    continue
                if not ticker or ticker in presentes or ticker in faltantes:
                    continue
                ultimo = self._obtener_ultimo_valor_ticker_cacheado(ticker)
                last_hist = convertir_a_numero((ultimo or {}).get('last'))
                last_cierre = convertir_a_numero(fila.get('last'))
                if last_hist in (None, 0) and last_cierre in (None, 0):
                    continue
                reconstruida = {
                    'ticker': ticker,
                    'tipo': tipo_norm,
                    'vencimiento': fila.get('vencimiento'),
                    'strike': convertir_a_numero(fila.get('strike')),
                    'cficode': str(fila.get('cficode') or ''),
                    'securityDescription': fila.get('securityDescription'),
                    'underlying': fila.get('underlying'),
                    'bid': convertir_a_numero((ultimo or {}).get('bid')),
                    'bid_size': convertir_a_numero((ultimo or {}).get('bid_size')),
                    'ask': convertir_a_numero((ultimo or {}).get('ask')),
                    'ask_size': convertir_a_numero((ultimo or {}).get('ask_size')),
                    'last': last_hist if last_hist not in (None, 0) else last_cierre,
                    'last_size': convertir_a_numero((ultimo or {}).get('last_size')),
                    'updated_at': (ultimo or {}).get('timestamp') or fecha,
                    'oi': None,
                    'oi_date': None,
                    'oi_source': None,
                    'mid': None,
                    'iv': convertir_a_numero((ultimo or {}).get('iv')) if ultimo else convertir_a_numero(fila.get('iv')),
                    'delta': convertir_a_numero((ultimo or {}).get('delta')) if ultimo else convertir_a_numero(fila.get('delta')),
                    'gamma': convertir_a_numero((ultimo or {}).get('gamma')) if ultimo else convertir_a_numero(fila.get('gamma')),
                    'theta': convertir_a_numero((ultimo or {}).get('theta')) if ultimo else convertir_a_numero(fila.get('theta')),
                    'vega': convertir_a_numero((ultimo or {}).get('vega')) if ultimo else convertir_a_numero(fila.get('vega')),
                    'gex_proxy': None,
                    'gex_real': None,
                }
                reconstruida['mid'] = precio_referencia(reconstruida)
                if fila_tiene_cotizacion(reconstruida):
                    faltantes[ticker] = reconstruida
        return sorted(
            list(faltantes.values()),
            key=lambda item: (
                str(item.get('vencimiento') or ''),
                float(item.get('strike')) if isinstance(item.get('strike'), (int, float)) else float('inf'),
                str(item.get('ticker') or ''),
            ),
        )

    def _parchear_historico_liquidacion_ci_desde_24hs(self) -> None:
        """Copia histórico de opciones 24hs hacia los nuevos tickers CI solo una vez."""
        fecha_corte = ahora().strftime('%Y-%m-%d')
        procesados: set[tuple[str, str]] = set()
        total_snap = 0
        total_cierres = 0
        total_omitidos = 0
        total_registrados = 0
        for inst in self.instrumentos:
            ticker_activo = str(getattr(inst, 'ticker', '') or '').strip()
            if not ticker_activo:
                continue
            for ticker_hist in ticker_alias_liquidacion_ci_24hs(ticker_activo):
                clave = (ticker_hist, ticker_activo)
                if clave in procesados:
                    continue
                procesados.add(clave)
                patch_key = f"liq_ci_24hs::{ticker_hist}=>{ticker_activo}::{fecha_corte}"
                try:
                    if self._history_db.patch_historico_fue_aplicado(patch_key):
                        total_omitidos += 1
                        continue
                    if self._history_db.ticker_tiene_historico_antes_de(ticker_activo, fecha_hasta_exclusiva=fecha_corte):
                        self._history_db.registrar_patch_historico(patch_key, details='historico_destino_existente')
                        total_registrados += 1
                        continue
                    cambios_snap, cambios_cierre = self._history_db.aliasar_historico_ticker(
                        ticker_hist,
                        ticker_activo,
                        fecha_hasta_exclusiva=fecha_corte,
                    )
                    self._history_db.registrar_patch_historico(
                        patch_key,
                        details=f'snapshots={int(cambios_snap or 0)}|cierres={int(cambios_cierre or 0)}',
                    )
                except Exception:
                    LOGGER.debug('No se pudo parchear histórico %s -> %s', ticker_hist, ticker_activo, exc_info=True)
                    continue
                total_snap += int(cambios_snap or 0)
                total_cierres += int(cambios_cierre or 0)
        if total_snap or total_cierres:
            LOGGER.info('Parche liquidación 24hs->CI aplicado | snapshots=%s | cierres=%s | fecha_corte=%s', total_snap, total_cierres, fecha_corte)
            getattr(self, '_tickers_historicos_recientes_cache', {}).clear()
            self._tickers_cierre_todos_cache = None
            self._ultimo_valor_ticker_cache.clear()
            self._strike_alias_map_cache = None
            self._active_to_historical_aliases_cache = None
            self._comparador_series_cache.clear() if hasattr(self, '_comparador_series_cache') else None
        elif total_registrados or total_omitidos:
            LOGGER.info('Parche liquidación 24hs->CI ya estaba aplicado | registrados=%s | omitidos=%s | fecha_corte=%s', total_registrados, total_omitidos, fecha_corte)

